INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene1', 1, 0, 'BERNARDO', 'Who’s there?'), ('hamlet_act1_scene1', 2, 1, 'FRANCISCO', 'Nay, answer me: stand, and unfold yourself.'), ('hamlet_act1_scene1', 3, 2, 'BERNARDO', 'Long live the king!'), ('hamlet_act1_scene1', 3, 3, 'FRANCISCO', 'Bernardo?'), ('hamlet_act1_scene1', 4, 4, 'BERNARDO', 'He.'), ('hamlet_act1_scene1', 5, 5, 'FRANCISCO', 'You come most carefully upon your hour.'), ('hamlet_act1_scene1', 6, 6, 'BERNARDO', '’Tis now struck twelve; get thee to bed, Francisco.'), ('hamlet_act1_scene1', 7, 7, 'FRANCISCO', 'For this relief much thanks: ’tis bitter cold,'), ('hamlet_act1_scene1', 8, 8, 'FRANCISCO', 'And I am sick at heart.'), ('hamlet_act1_scene1', 8, 9, 'BERNARDO', 'Have you had quiet guard?'), ('hamlet_act1_scene1', 9, 10, 'FRANCISCO', 'Not a mouse stirring.'), ('hamlet_act1_scene1', 9, 11, 'BERNARDO', 'Well, good night.'), ('hamlet_act1_scene1', 10, 12, 'BERNARDO', 'If you do meet Horatio and Marcellus,'), ('hamlet_act1_scene1', 11, 13, 'BERNARDO', 'The rivals of my watch, bid them make haste.'), ('hamlet_act1_scene1', 12, 14, 'FRANCISCO', 'I think I hear them. Stand, ho! Who’s there?'), ('hamlet_act1_scene1', 13, 15, 'HORATIO', 'Friends to this ground.'), ('hamlet_act1_scene1', 13, 16, 'MARCELLUS', 'And liegemen to the Dane.'), ('hamlet_act1_scene1', 14, 17, 'FRANCISCO', 'Give you good night.'), ('hamlet_act1_scene1', 14, 18, 'MARCELLUS', 'O, farewell, honest soldier:'), ('hamlet_act1_scene1', 15, 19, 'MARCELLUS', 'Who hath relieved you?'), ('hamlet_act1_scene1', 15, 20, 'FRANCISCO', 'Bernardo has my place.'), ('hamlet_act1_scene1', 16, 21, 'FRANCISCO', 'Give you good night.'), ('hamlet_act1_scene1', 16, 22, 'MARCELLUS', 'Holla! Bernardo!'), ('hamlet_act1_scene1', 17, 23, 'BERNARDO', 'Say,'), ('hamlet_act1_scene1', 18, 24, 'BERNARDO', 'What, is Horatio there?'), ('hamlet_act1_scene1', 18, 25, 'HORATIO', 'A piece of him.'), ('hamlet_act1_scene1', 19, 26, 'BERNARDO', 'Welcome, Horatio: welcome, good Marcellus.'), ('hamlet_act1_scene1', 20, 27, 'MARCELLUS', 'What, has this thing appear’d again to-night?'), ('hamlet_act1_scene1', 21, 28, 'BERNARDO', 'I have seen nothing.'), ('hamlet_act1_scene1', 21, 29, 'MARCELLUS', 'Horatio says ’tis but our fantasy,'), ('hamlet_act1_scene1', 22, 30, 'MARCELLUS', 'And will not let belief take hold of him'), ('hamlet_act1_scene1', 23, 31, 'MARCELLUS', 'Touching this dreaded sight, twice seen of us:'), ('hamlet_act1_scene1', 24, 32, 'MARCELLUS', 'Therefore I have entreated him along'), ('hamlet_act1_scene1', 25, 33, 'MARCELLUS', 'With us to watch the minutes of this night;'), ('hamlet_act1_scene1', 26, 34, 'MARCELLUS', 'That if again this apparition come,'), ('hamlet_act1_scene1', 27, 35, 'MARCELLUS', 'He may approve our eyes and speak to it.'), ('hamlet_act1_scene1', 28, 36, 'HORATIO', 'Tush, tush, ’twill not appear.'), ('hamlet_act1_scene1', 28, 37, 'BERNARDO', 'Sit down awhile;'), ('hamlet_act1_scene1', 29, 38, 'BERNARDO', 'And let us once again assail your ears,'), ('hamlet_act1_scene1', 30, 39, 'BERNARDO', 'That are so fortified against our story'), ('hamlet_act1_scene1', 31, 40, 'BERNARDO', 'What we have two nights seen.'), ('hamlet_act1_scene1', 31, 41, 'HORATIO', 'Well, sit we down,'), ('hamlet_act1_scene1', 32, 42, 'HORATIO', 'And let us hear Bernardo speak of this.'), ('hamlet_act1_scene1', 33, 43, 'BERNARDO', 'Last night of all,'), ('hamlet_act1_scene1', 34, 44, 'BERNARDO', 'When yond same star that’s westward from the pole'), ('hamlet_act1_scene1', 35, 45, 'BERNARDO', 'Had made his course to illume that part of heaven'), ('hamlet_act1_scene1', 36, 46, 'BERNARDO', 'Where now it burns, Marcellus and myself,'), ('hamlet_act1_scene1', 37, 47, 'BERNARDO', 'The bell then beating one—'), ('hamlet_act1_scene1', 38, 48, 'MARCELLUS', 'Peace, break thee off; look, where it comes again!'), ('hamlet_act1_scene1', 39, 49, 'BERNARDO', 'In the same figure, like the king that’s dead.'), ('hamlet_act1_scene1', 40, 50, 'MARCELLUS', 'Thou art a scholar; speak to it, Horatio.'), ('hamlet_act1_scene1', 41, 51, 'BERNARDO', 'Looks it not like the king? mark it, Horatio.'), ('hamlet_act1_scene1', 42, 52, 'HORATIO', 'Most like: it harrows me with fear and wonder.'), ('hamlet_act1_scene1', 43, 53, 'BERNARDO', 'It would be spoke to.'), ('hamlet_act1_scene1', 43, 54, 'MARCELLUS', 'Question it, Horatio.'), ('hamlet_act1_scene1', 44, 55, 'HORATIO', 'What art thou that usurp’st this time of night,'), ('hamlet_act1_scene1', 45, 56, 'HORATIO', 'Together with that fair and warlike form'), ('hamlet_act1_scene1', 46, 57, 'HORATIO', 'In which the majesty of buried Denmark'), ('hamlet_act1_scene1', 47, 58, 'HORATIO', 'Did sometimes march? by heaven I charge thee, speak!'), ('hamlet_act1_scene1', 48, 59, 'MARCELLUS', 'It is offended.'), ('hamlet_act1_scene1', 48, 60, 'BERNARDO', 'See, it stalks away!'), ('hamlet_act1_scene1', 49, 61, 'HORATIO', 'Stay! speak, speak! I charge thee, speak!'), ('hamlet_act1_scene1', 50, 62, 'MARCELLUS', '’Tis gone, and will not answer.'), ('hamlet_act1_scene1', 51, 63, 'BERNARDO', 'How now, Horatio! you tremble and look pale:'), ('hamlet_act1_scene1', 52, 64, 'BERNARDO', 'Is not this something more than fantasy?'), ('hamlet_act1_scene1', 53, 65, 'BERNARDO', 'What think you on’t?'), ('hamlet_act1_scene1', 54, 66, 'HORATIO', 'Before my God, I might not this believe'), ('hamlet_act1_scene1', 55, 67, 'HORATIO', 'Without the sensible and true avouch'), ('hamlet_act1_scene1', 56, 68, 'HORATIO', 'Of mine own eyes.'), ('hamlet_act1_scene1', 56, 69, 'MARCELLUS', 'Is it not like the king?'), ('hamlet_act1_scene1', 57, 70, 'HORATIO', 'As thou art to thyself:'), ('hamlet_act1_scene1', 58, 71, 'HORATIO', 'Such was the very armour he had on'), ('hamlet_act1_scene1', 59, 72, 'HORATIO', 'When he the ambitious Norway combated;'), ('hamlet_act1_scene1', 60, 73, 'HORATIO', 'So frown’d he once, when, in an angry parle,'), ('hamlet_act1_scene1', 61, 74, 'HORATIO', 'He smote the sledded Polacks on the ice.'), ('hamlet_act1_scene1', 62, 75, 'HORATIO', '’Tis strange.'), ('hamlet_act1_scene1', 63, 76, 'MARCELLUS', 'Thus twice before, and jump at this dead hour,'), ('hamlet_act1_scene1', 64, 77, 'MARCELLUS', 'With martial stalk hath he gone by our watch.'), ('hamlet_act1_scene1', 65, 78, 'HORATIO', 'In what particular thought to work I know not;'), ('hamlet_act1_scene1', 66, 79, 'HORATIO', 'But in the gross and scope of my opinion,'), ('hamlet_act1_scene1', 67, 80, 'HORATIO', 'This bodes some strange eruption to our state.'), ('hamlet_act1_scene1', 68, 81, 'MARCELLUS', 'Good now, sit down, and tell me, he that knows,'), ('hamlet_act1_scene1', 69, 82, 'MARCELLUS', 'Why this same strict and most observant watch'), ('hamlet_act1_scene1', 70, 83, 'MARCELLUS', 'So nightly toils the subject of the land,'), ('hamlet_act1_scene1', 71, 84, 'MARCELLUS', 'And why such daily cast of brazen cannon,'), ('hamlet_act1_scene1', 72, 85, 'MARCELLUS', 'And foreign mart for implements of war;'), ('hamlet_act1_scene1', 73, 86, 'MARCELLUS', 'Why such impress of shipwrights, whose sore task'), ('hamlet_act1_scene1', 74, 87, 'MARCELLUS', 'Does not divide the Sunday from the week;'), ('hamlet_act1_scene1', 75, 88, 'MARCELLUS', 'What might be toward, that this sweaty haste'), ('hamlet_act1_scene1', 76, 89, 'MARCELLUS', 'Doth make the night joint-labourer with the day:'), ('hamlet_act1_scene1', 77, 90, 'MARCELLUS', 'Who is’t that can inform me?'), ('hamlet_act1_scene1', 77, 91, 'HORATIO', 'That can I;'), ('hamlet_act1_scene1', 78, 92, 'HORATIO', 'At least, the whisper goes so. Our last king,'), ('hamlet_act1_scene1', 79, 93, 'HORATIO', 'Whose image even but now appear’d to us,'), ('hamlet_act1_scene1', 80, 94, 'HORATIO', 'Was, as you know, by Fortinbras of Norway,'), ('hamlet_act1_scene1', 81, 95, 'HORATIO', 'Thereto prick’d on by a most emulate pride,'), ('hamlet_act1_scene1', 82, 96, 'HORATIO', 'Dared to the combat; in which our valiant Hamlet—'), ('hamlet_act1_scene1', 83, 97, 'HORATIO', 'For so this side of our known world esteem’d him—'), ('hamlet_act1_scene1', 84, 98, 'HORATIO', 'Did slay this Fortinbras; who, by a seal’d compact,'), ('hamlet_act1_scene1', 85, 99, 'HORATIO', 'Well ratified by law and heraldry,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene1', 86, 100, 'HORATIO', 'Did forfeit, with his life, all those his lands'), ('hamlet_act1_scene1', 87, 101, 'HORATIO', 'Which he stood seized of, to the conqueror:'), ('hamlet_act1_scene1', 88, 102, 'HORATIO', 'Against the which, a moiety competent'), ('hamlet_act1_scene1', 89, 103, 'HORATIO', 'Was gaged by our king; which had return’d'), ('hamlet_act1_scene1', 90, 104, 'HORATIO', 'To the inheritance of Fortinbras,'), ('hamlet_act1_scene1', 91, 105, 'HORATIO', 'Had he been vanquisher; as, by the same covenant,'), ('hamlet_act1_scene1', 92, 106, 'HORATIO', 'And carriage of the article design’d,'), ('hamlet_act1_scene1', 93, 107, 'HORATIO', 'His fell to Hamlet. Now, sir, young Fortinbras,'), ('hamlet_act1_scene1', 94, 108, 'HORATIO', 'Of unimproved mettle hot and full,'), ('hamlet_act1_scene1', 95, 109, 'HORATIO', 'Hath in the skirts of Norway here and there'), ('hamlet_act1_scene1', 96, 110, 'HORATIO', 'Shark’d up a list of lawless resolutes,'), ('hamlet_act1_scene1', 97, 111, 'HORATIO', 'For food and diet, to some enterprise'), ('hamlet_act1_scene1', 98, 112, 'HORATIO', 'That hath a stomach in’t; which is no other—'), ('hamlet_act1_scene1', 99, 113, 'HORATIO', 'As it doth well appear unto our state—'), ('hamlet_act1_scene1', 100, 114, 'HORATIO', 'But to recover of us, by strong hand'), ('hamlet_act1_scene1', 101, 115, 'HORATIO', 'And terms compulsatory, those foresaid lands'), ('hamlet_act1_scene1', 102, 116, 'HORATIO', 'So by his father lost: and this, I take it,'), ('hamlet_act1_scene1', 103, 117, 'HORATIO', 'Is the main motive of our preparations,'), ('hamlet_act1_scene1', 104, 118, 'HORATIO', 'The source of this our watch and the chief head'), ('hamlet_act1_scene1', 105, 119, 'HORATIO', 'Of this post-haste and romage in the land.'), ('hamlet_act1_scene1', 106, 120, 'BERNARDO', 'I think it be no other but e’en so:'), ('hamlet_act1_scene1', 107, 121, 'BERNARDO', 'Well may it sort that this portentous figure'), ('hamlet_act1_scene1', 108, 122, 'BERNARDO', 'Comes armed through our watch; so like the king'), ('hamlet_act1_scene1', 109, 123, 'BERNARDO', 'That was and is the question of these wars.'), ('hamlet_act1_scene1', 110, 124, 'HORATIO', 'A mote it is to trouble the mind’s eye.'), ('hamlet_act1_scene1', 111, 125, 'HORATIO', 'In the most high and palmy state of Rome,'), ('hamlet_act1_scene1', 112, 126, 'HORATIO', 'A little ere the mightiest Julius fell,'), ('hamlet_act1_scene1', 113, 127, 'HORATIO', 'The graves stood tenantless and the sheeted dead'), ('hamlet_act1_scene1', 114, 128, 'HORATIO', 'Did squeak and gibber in the Roman streets:'), ('hamlet_act1_scene1', 115, 129, 'HORATIO', 'As stars with trains of fire and dews of blood,'), ('hamlet_act1_scene1', 116, 130, 'HORATIO', 'Disasters in the sun; and the moist star'), ('hamlet_act1_scene1', 117, 131, 'HORATIO', 'Upon whose influence Neptune’s empire stands'), ('hamlet_act1_scene1', 118, 132, 'HORATIO', 'Was sick almost to doomsday with eclipse:'), ('hamlet_act1_scene1', 119, 133, 'HORATIO', 'And even the like precurse of fierce events,'), ('hamlet_act1_scene1', 120, 134, 'HORATIO', 'As harbingers preceding still the fates'), ('hamlet_act1_scene1', 121, 135, 'HORATIO', 'And prologue to the omen coming on,'), ('hamlet_act1_scene1', 122, 136, 'HORATIO', 'Have heaven and earth together demonstrated'), ('hamlet_act1_scene1', 123, 137, 'HORATIO', 'Unto our climatures and countrymen.—'), ('hamlet_act1_scene1', 124, 138, 'HORATIO', 'But soft, behold! lo, where it comes again!'), ('hamlet_act1_scene1', 125, 139, 'MARCELLUS', 'Shall I strike at it with my partisan?'), ('hamlet_act1_scene1', 126, 140, 'HORATIO', 'Do, if it will not stand.'), ('hamlet_act1_scene1', 126, 141, 'BERNARDO', '’Tis here!'), ('hamlet_act1_scene1', 127, 142, 'HORATIO', '’Tis here!'), ('hamlet_act1_scene1', 127, 143, 'MARCELLUS', '’Tis gone!'), ('hamlet_act1_scene1', 128, 144, 'MARCELLUS', 'We do it wrong, being so majestical,'), ('hamlet_act1_scene1', 129, 145, 'MARCELLUS', 'To offer it the show of violence;'), ('hamlet_act1_scene1', 130, 146, 'MARCELLUS', 'For it is, as the air, invulnerable,'), ('hamlet_act1_scene1', 131, 147, 'MARCELLUS', 'And our vain blows malicious mockery.'), ('hamlet_act1_scene1', 132, 148, 'BERNARDO', 'It was about to speak, when the cock crew.'), ('hamlet_act1_scene1', 133, 149, 'HORATIO', 'And then it started like a guilty thing'), ('hamlet_act1_scene1', 134, 150, 'HORATIO', 'Upon a fearful summons. I have heard,'), ('hamlet_act1_scene1', 135, 151, 'HORATIO', 'The cock, that is the trumpet to the morn,'), ('hamlet_act1_scene1', 136, 152, 'HORATIO', 'Doth with his lofty and shrill-sounding throat'), ('hamlet_act1_scene1', 137, 153, 'HORATIO', 'Awake the god of day; and, at his warning,'), ('hamlet_act1_scene1', 138, 154, 'HORATIO', 'Whether in sea or fire, in earth or air,'), ('hamlet_act1_scene1', 139, 155, 'HORATIO', 'The extravagant and erring spirit hies'), ('hamlet_act1_scene1', 140, 156, 'HORATIO', 'To his confine: and of the truth herein'), ('hamlet_act1_scene1', 141, 157, 'HORATIO', 'This present object made probation.'), ('hamlet_act1_scene1', 142, 158, 'MARCELLUS', 'It faded on the crowing of the cock.'), ('hamlet_act1_scene1', 143, 159, 'MARCELLUS', 'Some say that ever ’gainst that season comes'), ('hamlet_act1_scene1', 144, 160, 'MARCELLUS', 'Wherein our Saviour’s birth is celebrated,'), ('hamlet_act1_scene1', 145, 161, 'MARCELLUS', 'The bird of dawning singeth all night long:'), ('hamlet_act1_scene1', 146, 162, 'MARCELLUS', 'And then, they say, no spirit dare stir abroad;'), ('hamlet_act1_scene1', 147, 163, 'MARCELLUS', 'The nights are wholesome; then no planets strike,'), ('hamlet_act1_scene1', 148, 164, 'MARCELLUS', 'No fairy takes, nor witch hath power to charm,'), ('hamlet_act1_scene1', 149, 165, 'MARCELLUS', 'So hallow’d and so gracious is the time.'), ('hamlet_act1_scene1', 150, 166, 'HORATIO', 'So have I heard and do in part believe it.'), ('hamlet_act1_scene1', 151, 167, 'HORATIO', 'But, look, the morn, in russet mantle clad,'), ('hamlet_act1_scene1', 152, 168, 'HORATIO', 'Walks o’er the dew of yon high eastward hill:'), ('hamlet_act1_scene1', 153, 169, 'HORATIO', 'Break we our watch up; and by my advice,'), ('hamlet_act1_scene1', 154, 170, 'HORATIO', 'Let us impart what we have seen to-night'), ('hamlet_act1_scene1', 155, 171, 'HORATIO', 'Unto young Hamlet; for, upon my life,'), ('hamlet_act1_scene1', 156, 172, 'HORATIO', 'This spirit, dumb to us, will speak to him.'), ('hamlet_act1_scene1', 157, 173, 'HORATIO', 'Do you consent we shall acquaint him with it,'), ('hamlet_act1_scene1', 158, 174, 'HORATIO', 'As needful in our loves, fitting our duty?'), ('hamlet_act1_scene1', 159, 175, 'MARCELLUS', 'Let’s do’t, I pray; and I this morning know'), ('hamlet_act1_scene1', 160, 176, 'MARCELLUS', 'Where we shall find him most conveniently.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene2', 1, 0, 'KING', 'Though yet of Hamlet our dear brother’s death'), ('hamlet_act1_scene2', 2, 1, 'KING', 'The memory be green, and that it us befitted'), ('hamlet_act1_scene2', 3, 2, 'KING', 'To bear our hearts in grief and our whole kingdom'), ('hamlet_act1_scene2', 4, 3, 'KING', 'To be contracted in one brow of woe,'), ('hamlet_act1_scene2', 5, 4, 'KING', 'Yet so far hath discretion fought with nature'), ('hamlet_act1_scene2', 6, 5, 'KING', 'That we with wisest sorrow think on him,'), ('hamlet_act1_scene2', 7, 6, 'KING', 'Together with remembrance of ourselves.'), ('hamlet_act1_scene2', 8, 7, 'KING', 'Therefore our sometime sister, now our queen,'), ('hamlet_act1_scene2', 9, 8, 'KING', 'The imperial jointress to this warlike state,'), ('hamlet_act1_scene2', 10, 9, 'KING', 'Have we, as ’twere with a defeated joy—'), ('hamlet_act1_scene2', 11, 10, 'KING', 'With an auspicious and a dropping eye,'), ('hamlet_act1_scene2', 12, 11, 'KING', 'With mirth in funeral and with dirge in marriage,'), ('hamlet_act1_scene2', 13, 12, 'KING', 'In equal scale weighing delight and dole—'), ('hamlet_act1_scene2', 14, 13, 'KING', 'Taken to wife: nor have we herein barr’d'), ('hamlet_act1_scene2', 15, 14, 'KING', 'Your better wisdoms, which have freely gone'), ('hamlet_act1_scene2', 16, 15, 'KING', 'With this affair along. For all, our thanks.'), ('hamlet_act1_scene2', 17, 16, 'KING', 'Now follows, that you know, young Fortinbras,'), ('hamlet_act1_scene2', 18, 17, 'KING', 'Holding a weak supposal of our worth,'), ('hamlet_act1_scene2', 19, 18, 'KING', 'Or thinking by our late dear brother’s death'), ('hamlet_act1_scene2', 20, 19, 'KING', 'Our state to be disjoint and out of frame,'), ('hamlet_act1_scene2', 21, 20, 'KING', 'Colleagued with the dream of his advantage,'), ('hamlet_act1_scene2', 22, 21, 'KING', 'He hath not fail’d to pester us with message,'), ('hamlet_act1_scene2', 23, 22, 'KING', 'Importing the surrender of those lands'), ('hamlet_act1_scene2', 24, 23, 'KING', 'Lost by his father, with all bonds of law,'), ('hamlet_act1_scene2', 25, 24, 'KING', 'To our most valiant brother. So much for him.'), ('hamlet_act1_scene2', 26, 25, 'KING', 'Now for ourself and for this time of meeting:'), ('hamlet_act1_scene2', 27, 26, 'KING', 'Thus much the business is: we have here writ'), ('hamlet_act1_scene2', 28, 27, 'KING', 'To Norway, uncle of young Fortinbras—'), ('hamlet_act1_scene2', 29, 28, 'KING', 'Who, impotent and bed-rid, scarcely hears'), ('hamlet_act1_scene2', 30, 29, 'KING', 'Of this his nephew’s purpose—to suppress'), ('hamlet_act1_scene2', 31, 30, 'KING', 'His further gait herein; in that the levies,'), ('hamlet_act1_scene2', 32, 31, 'KING', 'The lists and full proportions, are all made'), ('hamlet_act1_scene2', 33, 32, 'KING', 'Out of his subject: and we here dispatch'), ('hamlet_act1_scene2', 34, 33, 'KING', 'You, good Cornelius, and you, Voltimand,'), ('hamlet_act1_scene2', 35, 34, 'KING', 'For bearers of this greeting to old Norway;'), ('hamlet_act1_scene2', 36, 35, 'KING', 'Giving to you no further personal power'), ('hamlet_act1_scene2', 37, 36, 'KING', 'To business with the king, more than the scope'), ('hamlet_act1_scene2', 38, 37, 'KING', 'Of these delated articles allow.'), ('hamlet_act1_scene2', 39, 38, 'KING', 'Farewell, and let your haste commend your duty.'), ('hamlet_act1_scene2', 40, 39, 'CORNELIUS VOLTIMAND', 'In that and all things will we show our duty.'), ('hamlet_act1_scene2', 41, 40, 'KING', 'We doubt it nothing: heartily farewell.'), ('hamlet_act1_scene2', 42, 41, 'KING', 'And now, Laertes, what’s the news with you?'), ('hamlet_act1_scene2', 43, 42, 'KING', 'You told us of some suit; what is’t, Laertes?'), ('hamlet_act1_scene2', 44, 43, 'KING', 'You cannot speak of reason to the Dane,'), ('hamlet_act1_scene2', 45, 44, 'KING', 'And lose your voice: what wouldst thou beg, Laertes,'), ('hamlet_act1_scene2', 46, 45, 'KING', 'That shall not be my offer, not thy asking?'), ('hamlet_act1_scene2', 47, 46, 'KING', 'The head is not more native to the heart,'), ('hamlet_act1_scene2', 48, 47, 'KING', 'The hand more instrumental to the mouth,'), ('hamlet_act1_scene2', 49, 48, 'KING', 'Than is the throne of Denmark to thy father.'), ('hamlet_act1_scene2', 50, 49, 'KING', 'What wouldst thou have, Laertes?'), ('hamlet_act1_scene2', 50, 50, 'LAERTES', 'My dread lord,'), ('hamlet_act1_scene2', 51, 51, 'LAERTES', 'Your leave and favour to return to France;'), ('hamlet_act1_scene2', 52, 52, 'LAERTES', 'From whence though willingly I came to Denmark,'), ('hamlet_act1_scene2', 53, 53, 'LAERTES', 'To show my duty in your coronation,'), ('hamlet_act1_scene2', 54, 54, 'LAERTES', 'Yet now, I must confess, that duty done,'), ('hamlet_act1_scene2', 55, 55, 'LAERTES', 'My thoughts and wishes bend again toward France'), ('hamlet_act1_scene2', 56, 56, 'LAERTES', 'And bow them to your gracious leave and pardon.'), ('hamlet_act1_scene2', 57, 57, 'KING', 'Have you your father’s leave? What says Polonius?'), ('hamlet_act1_scene2', 58, 58, 'POLONIUS', 'He hath, my lord, wrung from me my slow leave'), ('hamlet_act1_scene2', 59, 59, 'POLONIUS', 'By laboursome petition, and at last'), ('hamlet_act1_scene2', 60, 60, 'POLONIUS', 'Upon his will I seal’d my hard consent:'), ('hamlet_act1_scene2', 61, 61, 'POLONIUS', 'I do beseech you, give him leave to go.'), ('hamlet_act1_scene2', 62, 62, 'KING', 'Take thy fair hour, Laertes; time be thine,'), ('hamlet_act1_scene2', 63, 63, 'KING', 'And thy best graces spend it at thy will!'), ('hamlet_act1_scene2', 64, 64, 'KING', 'But now, my cousin Hamlet, and my son—'), ('hamlet_act1_scene2', 65, 65, 'HAMLET', 'A little more than kin, and less than kind.'), ('hamlet_act1_scene2', 66, 66, 'KING', 'How is it that the clouds still hang on you?'), ('hamlet_act1_scene2', 67, 67, 'HAMLET', 'Not so, my lord; I am too much i’ the sun.'), ('hamlet_act1_scene2', 68, 68, 'QUEEN', 'Good Hamlet, cast thy nighted colour off,'), ('hamlet_act1_scene2', 69, 69, 'QUEEN', 'And let thine eye look like a friend on Denmark.'), ('hamlet_act1_scene2', 70, 70, 'QUEEN', 'Do not for ever with thy vailed lids'), ('hamlet_act1_scene2', 71, 71, 'QUEEN', 'Seek for thy noble father in the dust:'), ('hamlet_act1_scene2', 72, 72, 'QUEEN', 'Thou know’st ’tis common; all that lives must die,'), ('hamlet_act1_scene2', 73, 73, 'QUEEN', 'Passing through nature to eternity.'), ('hamlet_act1_scene2', 73, 74, 'HAMLET', 'Ay, madam, it is common.'), ('hamlet_act1_scene2', 74, 75, 'QUEEN', 'If it be,'), ('hamlet_act1_scene2', 75, 76, 'QUEEN', 'Why seems it so particular with thee?'), ('hamlet_act1_scene2', 76, 77, 'HAMLET', 'Seems, madam! nay, it is; I know not “seems.”'), ('hamlet_act1_scene2', 77, 78, 'HAMLET', '’Tis not alone my inky cloak, good mother,'), ('hamlet_act1_scene2', 78, 79, 'HAMLET', 'Nor customary suits of solemn black,'), ('hamlet_act1_scene2', 79, 80, 'HAMLET', 'Nor windy suspiration of forced breath,'), ('hamlet_act1_scene2', 80, 81, 'HAMLET', 'No, nor the fruitful river in the eye,'), ('hamlet_act1_scene2', 81, 82, 'HAMLET', 'Nor the dejected ’havior of the visage,'), ('hamlet_act1_scene2', 82, 83, 'HAMLET', 'Together with all forms, moods, shapes of grief,'), ('hamlet_act1_scene2', 83, 84, 'HAMLET', 'That can denote me truly: these indeed seem,'), ('hamlet_act1_scene2', 84, 85, 'HAMLET', 'For they are actions that a man might play:'), ('hamlet_act1_scene2', 85, 86, 'HAMLET', 'But I have that within which passeth show;'), ('hamlet_act1_scene2', 86, 87, 'HAMLET', 'These but the trappings and the suits of woe.'), ('hamlet_act1_scene2', 87, 88, 'KING', '’Tis sweet and commendable in your nature, Hamlet,'), ('hamlet_act1_scene2', 88, 89, 'KING', 'To give these mourning duties to your father:'), ('hamlet_act1_scene2', 89, 90, 'KING', 'But, you must know, your father lost a father;'), ('hamlet_act1_scene2', 90, 91, 'KING', 'That father lost, lost his, and the survivor bound'), ('hamlet_act1_scene2', 91, 92, 'KING', 'In filial obligation for some term'), ('hamlet_act1_scene2', 92, 93, 'KING', 'To do obsequious sorrow: but to persever'), ('hamlet_act1_scene2', 93, 94, 'KING', 'In obstinate condolement is a course'), ('hamlet_act1_scene2', 94, 95, 'KING', 'Of impious stubbornness; ’tis unmanly grief;'), ('hamlet_act1_scene2', 95, 96, 'KING', 'It shows a will most incorrect to heaven,'), ('hamlet_act1_scene2', 96, 97, 'KING', 'A heart unfortified, a mind impatient,'), ('hamlet_act1_scene2', 97, 98, 'KING', 'An understanding simple and unschool’d:'), ('hamlet_act1_scene2', 98, 99, 'KING', 'For what we know must be and is as common');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene2', 99, 100, 'KING', 'As any the most vulgar thing to sense,'), ('hamlet_act1_scene2', 100, 101, 'KING', 'Why should we in our peevish opposition'), ('hamlet_act1_scene2', 101, 102, 'KING', 'Take it to heart? Fie! ’tis a fault to heaven,'), ('hamlet_act1_scene2', 102, 103, 'KING', 'A fault against the dead, a fault to nature,'), ('hamlet_act1_scene2', 103, 104, 'KING', 'To reason most absurd; whose common theme'), ('hamlet_act1_scene2', 104, 105, 'KING', 'Is death of fathers, and who still hath cried,'), ('hamlet_act1_scene2', 105, 106, 'KING', 'From the first corse till he that died to-day,'), ('hamlet_act1_scene2', 106, 107, 'KING', '“This must be so.” We pray you, throw to earth'), ('hamlet_act1_scene2', 107, 108, 'KING', 'This unprevailing woe, and think of us'), ('hamlet_act1_scene2', 108, 109, 'KING', 'As of a father: for let the world take note,'), ('hamlet_act1_scene2', 109, 110, 'KING', 'You are the most immediate to our throne;'), ('hamlet_act1_scene2', 110, 111, 'KING', 'And with no less nobility of love'), ('hamlet_act1_scene2', 111, 112, 'KING', 'Than that which dearest father bears his son,'), ('hamlet_act1_scene2', 112, 113, 'KING', 'Do I impart toward you. For your intent'), ('hamlet_act1_scene2', 113, 114, 'KING', 'In going back to school in Wittenberg,'), ('hamlet_act1_scene2', 114, 115, 'KING', 'It is most retrograde to our desire:'), ('hamlet_act1_scene2', 115, 116, 'KING', 'And we beseech you, bend you to remain'), ('hamlet_act1_scene2', 116, 117, 'KING', 'Here, in the cheer and comfort of our eye,'), ('hamlet_act1_scene2', 117, 118, 'KING', 'Our chiefest courtier, cousin, and our son.'), ('hamlet_act1_scene2', 118, 119, 'QUEEN', 'Let not thy mother lose her prayers, Hamlet:'), ('hamlet_act1_scene2', 119, 120, 'QUEEN', 'I pray thee, stay with us; go not to Wittenberg.'), ('hamlet_act1_scene2', 120, 121, 'HAMLET', 'I shall in all my best obey you, madam.'), ('hamlet_act1_scene2', 121, 122, 'KING', 'Why, ’tis a loving and a fair reply:'), ('hamlet_act1_scene2', 122, 123, 'KING', 'Be as ourself in Denmark. Madam, come;'), ('hamlet_act1_scene2', 123, 124, 'KING', 'This gentle and unforced accord of Hamlet'), ('hamlet_act1_scene2', 124, 125, 'KING', 'Sits smiling to my heart: in grace whereof,'), ('hamlet_act1_scene2', 125, 126, 'KING', 'No jocund health that Denmark drinks to-day,'), ('hamlet_act1_scene2', 126, 127, 'KING', 'But the great cannon to the clouds shall tell,'), ('hamlet_act1_scene2', 127, 128, 'KING', 'And the king’s rouse the heavens shall bruit again,'), ('hamlet_act1_scene2', 128, 129, 'KING', 'Re-speaking earthly thunder. Come away.'), ('hamlet_act1_scene2', 129, 130, 'HAMLET', 'O, that this too too solid flesh would melt,'), ('hamlet_act1_scene2', 130, 131, 'HAMLET', 'Thaw and resolve itself into a dew!'), ('hamlet_act1_scene2', 131, 132, 'HAMLET', 'Or that the Everlasting had not fix’d'), ('hamlet_act1_scene2', 132, 133, 'HAMLET', 'His canon ’gainst self-slaughter! O God! God!'), ('hamlet_act1_scene2', 133, 134, 'HAMLET', 'How weary, stale, flat and unprofitable,'), ('hamlet_act1_scene2', 134, 135, 'HAMLET', 'Seem to me all the uses of this world!'), ('hamlet_act1_scene2', 135, 136, 'HAMLET', 'Fie on’t! ah fie! ’tis an unweeded garden,'), ('hamlet_act1_scene2', 136, 137, 'HAMLET', 'That grows to seed; things rank and gross in nature'), ('hamlet_act1_scene2', 137, 138, 'HAMLET', 'Possess it merely. That it should come to this!'), ('hamlet_act1_scene2', 138, 139, 'HAMLET', 'But two months dead: nay, not so much, not two:'), ('hamlet_act1_scene2', 139, 140, 'HAMLET', 'So excellent a king; that was, to this,'), ('hamlet_act1_scene2', 140, 141, 'HAMLET', 'Hyperion to a satyr; so loving to my mother'), ('hamlet_act1_scene2', 141, 142, 'HAMLET', 'That he might not beteem the winds of heaven'), ('hamlet_act1_scene2', 142, 143, 'HAMLET', 'Visit her face too roughly. Heaven and earth!'), ('hamlet_act1_scene2', 143, 144, 'HAMLET', 'Must I remember? why, she would hang on him,'), ('hamlet_act1_scene2', 144, 145, 'HAMLET', 'As if increase of appetite had grown'), ('hamlet_act1_scene2', 145, 146, 'HAMLET', 'By what it fed on: and yet, within a month—'), ('hamlet_act1_scene2', 146, 147, 'HAMLET', 'Let me not think on’t—Frailty, thy name is woman!—'), ('hamlet_act1_scene2', 147, 148, 'HAMLET', 'A little month, or ere those shoes were old'), ('hamlet_act1_scene2', 148, 149, 'HAMLET', 'With which she follow’d my poor father’s body,'), ('hamlet_act1_scene2', 149, 150, 'HAMLET', 'Like Niobe, all tears:—why she, even she—'), ('hamlet_act1_scene2', 150, 151, 'HAMLET', 'O, God! a beast, that wants discourse of reason,'), ('hamlet_act1_scene2', 151, 152, 'HAMLET', 'Would have mourn’d longer—married with my uncle,'), ('hamlet_act1_scene2', 152, 153, 'HAMLET', 'My father’s brother, but no more like my father'), ('hamlet_act1_scene2', 153, 154, 'HAMLET', 'Than I to Hercules: within a month:'), ('hamlet_act1_scene2', 154, 155, 'HAMLET', 'Ere yet the salt of most unrighteous tears'), ('hamlet_act1_scene2', 155, 156, 'HAMLET', 'Had left the flushing in her galled eyes,'), ('hamlet_act1_scene2', 156, 157, 'HAMLET', 'She married. O, most wicked speed, to post'), ('hamlet_act1_scene2', 157, 158, 'HAMLET', 'With such dexterity to incestuous sheets!'), ('hamlet_act1_scene2', 158, 159, 'HAMLET', 'It is not nor it cannot come to good:'), ('hamlet_act1_scene2', 159, 160, 'HAMLET', 'But break, my heart; for I must hold my tongue.'), ('hamlet_act1_scene2', 160, 161, 'HORATIO', 'Hail to your lordship!'), ('hamlet_act1_scene2', 161, 162, 'HAMLET', 'I am glad to see you well:'), ('hamlet_act1_scene2', 162, 163, 'HAMLET', 'Horatio—or I do forget myself.'), ('hamlet_act1_scene2', 163, 164, 'HORATIO', 'The same, my lord, and your poor servant ever.'), ('hamlet_act1_scene2', 164, 165, 'HAMLET', 'Sir, my good friend; I’ll change that name with you:'), ('hamlet_act1_scene2', 165, 166, 'HAMLET', 'And what make you from Wittenberg, Horatio?'), ('hamlet_act1_scene2', 166, 167, 'HAMLET', 'Marcellus?'), ('hamlet_act1_scene2', 166, 168, 'MARCELLUS', 'My good lord—'), ('hamlet_act1_scene2', 167, 169, 'HAMLET', 'I am very glad to see you. Good even, sir.'), ('hamlet_act1_scene2', 168, 170, 'HAMLET', 'But what, in faith, make you from Wittenberg?'), ('hamlet_act1_scene2', 169, 171, 'HORATIO', 'A truant disposition, good my lord.'), ('hamlet_act1_scene2', 170, 172, 'HAMLET', 'I would not hear your enemy say so,'), ('hamlet_act1_scene2', 171, 173, 'HAMLET', 'Nor shall you do mine ear that violence,'), ('hamlet_act1_scene2', 172, 174, 'HAMLET', 'To make it truster of your own report'), ('hamlet_act1_scene2', 173, 175, 'HAMLET', 'Against yourself: I know you are no truant.'), ('hamlet_act1_scene2', 174, 176, 'HAMLET', 'But what is your affair in Elsinore?'), ('hamlet_act1_scene2', 175, 177, 'HAMLET', 'We’ll teach you to drink deep ere you depart.'), ('hamlet_act1_scene2', 176, 178, 'HORATIO', 'My lord, I came to see your father’s funeral.'), ('hamlet_act1_scene2', 177, 179, 'HAMLET', 'I pray thee, do not mock me, fellow-student;'), ('hamlet_act1_scene2', 178, 180, 'HAMLET', 'I think it was to see my mother’s wedding.'), ('hamlet_act1_scene2', 179, 181, 'HORATIO', 'Indeed, my lord, it follow’d hard upon.'), ('hamlet_act1_scene2', 180, 182, 'HAMLET', 'Thrift, thrift, Horatio! the funeral baked meats'), ('hamlet_act1_scene2', 181, 183, 'HAMLET', 'Did coldly furnish forth the marriage tables.'), ('hamlet_act1_scene2', 182, 184, 'HAMLET', 'Would I had met my dearest foe in heaven'), ('hamlet_act1_scene2', 183, 185, 'HAMLET', 'Or ever I had seen that day, Horatio!'), ('hamlet_act1_scene2', 184, 186, 'HAMLET', 'My father!—methinks I see my father.'), ('hamlet_act1_scene2', 184, 187, 'HORATIO', 'Where, my lord?'), ('hamlet_act1_scene2', 185, 188, 'HAMLET', 'In my mind’s eye, Horatio.'), ('hamlet_act1_scene2', 186, 189, 'HORATIO', 'I saw him once; he was a goodly king.'), ('hamlet_act1_scene2', 187, 190, 'HAMLET', 'He was a man, take him for all in all,'), ('hamlet_act1_scene2', 188, 191, 'HAMLET', 'I shall not look upon his like again.'), ('hamlet_act1_scene2', 189, 192, 'HORATIO', 'My lord, I think I saw him yesternight.'), ('hamlet_act1_scene2', 190, 193, 'HAMLET', 'Saw? who?'), ('hamlet_act1_scene2', 190, 194, 'HORATIO', 'My lord, the king your father.'), ('hamlet_act1_scene2', 191, 195, 'HAMLET', 'The king my father!'), ('hamlet_act1_scene2', 191, 196, 'HORATIO', 'Season your admiration for a while'), ('hamlet_act1_scene2', 192, 197, 'HORATIO', 'With an attent ear, till I may deliver,'), ('hamlet_act1_scene2', 193, 198, 'HORATIO', 'Upon the witness of these gentlemen,'), ('hamlet_act1_scene2', 194, 199, 'HORATIO', 'This marvel to you.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene2', 194, 200, 'HAMLET', 'For God’s love, let me hear.'), ('hamlet_act1_scene2', 195, 201, 'HORATIO', 'Two nights together had these gentlemen,'), ('hamlet_act1_scene2', 196, 202, 'HORATIO', 'Marcellus and Bernardo, on their watch,'), ('hamlet_act1_scene2', 197, 203, 'HORATIO', 'In the dead vast and middle of the night,'), ('hamlet_act1_scene2', 198, 204, 'HORATIO', 'Been thus encounter’d. A figure like your father,'), ('hamlet_act1_scene2', 199, 205, 'HORATIO', 'Armed at point exactly, cap-a-pe,'), ('hamlet_act1_scene2', 200, 206, 'HORATIO', 'Appears before them, and with solemn march'), ('hamlet_act1_scene2', 201, 207, 'HORATIO', 'Goes slow and stately by them: thrice he walk’d'), ('hamlet_act1_scene2', 202, 208, 'HORATIO', 'By their oppress’d and fear-surprised eyes,'), ('hamlet_act1_scene2', 203, 209, 'HORATIO', 'Within his truncheon’s length; whilst they, distill’d'), ('hamlet_act1_scene2', 204, 210, 'HORATIO', 'Almost to jelly with the act of fear,'), ('hamlet_act1_scene2', 205, 211, 'HORATIO', 'Stand dumb and speak not to him. This to me'), ('hamlet_act1_scene2', 206, 212, 'HORATIO', 'In dreadful secrecy impart they did;'), ('hamlet_act1_scene2', 207, 213, 'HORATIO', 'And I with them the third night kept the watch:'), ('hamlet_act1_scene2', 208, 214, 'HORATIO', 'Where, as they had deliver’d, both in time,'), ('hamlet_act1_scene2', 209, 215, 'HORATIO', 'Form of the thing, each word made true and good,'), ('hamlet_act1_scene2', 210, 216, 'HORATIO', 'The apparition comes: I knew your father;'), ('hamlet_act1_scene2', 211, 217, 'HORATIO', 'These hands are not more like.'), ('hamlet_act1_scene2', 211, 218, 'HAMLET', 'But where was this?'), ('hamlet_act1_scene2', 212, 219, 'MARCELLUS', 'My lord, upon the platform where we watch’d.'), ('hamlet_act1_scene2', 213, 220, 'HAMLET', 'Did you not speak to it?'), ('hamlet_act1_scene2', 213, 221, 'HORATIO', 'My lord, I did;'), ('hamlet_act1_scene2', 214, 222, 'HORATIO', 'But answer made it none: yet once methought'), ('hamlet_act1_scene2', 215, 223, 'HORATIO', 'It lifted up its head and did address'), ('hamlet_act1_scene2', 216, 224, 'HORATIO', 'Itself to motion, like as it would speak;'), ('hamlet_act1_scene2', 217, 225, 'HORATIO', 'But even then the morning cock crew loud,'), ('hamlet_act1_scene2', 218, 226, 'HORATIO', 'And at the sound it shrunk in haste away,'), ('hamlet_act1_scene2', 219, 227, 'HORATIO', 'And vanish’d from our sight.'), ('hamlet_act1_scene2', 219, 228, 'HAMLET', '’Tis very strange.'), ('hamlet_act1_scene2', 220, 229, 'HORATIO', 'As I do live, my honour’d lord, ’tis true;'), ('hamlet_act1_scene2', 221, 230, 'HORATIO', 'And we did think it writ down in our duty'), ('hamlet_act1_scene2', 222, 231, 'HORATIO', 'To let you know of it.'), ('hamlet_act1_scene2', 223, 232, 'HAMLET', 'Indeed, indeed, sirs, but this troubles me.'), ('hamlet_act1_scene2', 224, 233, 'HAMLET', 'Hold you the watch to-night?'), ('hamlet_act1_scene2', 224, 234, 'MARCELLUS BERNARDO', 'We do, my lord.'), ('hamlet_act1_scene2', 225, 235, 'HAMLET', 'Arm’d, say you?'), ('hamlet_act1_scene2', 225, 236, 'MARCELLUS BERNARDO', 'Arm’d, my lord.'), ('hamlet_act1_scene2', 226, 237, 'HAMLET', 'From top to toe?'), ('hamlet_act1_scene2', 226, 238, 'MARCELLUS BERNARDO', 'My lord, from head to foot.'), ('hamlet_act1_scene2', 227, 239, 'HAMLET', 'Then saw you not his face?'), ('hamlet_act1_scene2', 228, 240, 'HORATIO', 'O, yes, my lord; he wore his beaver up.'), ('hamlet_act1_scene2', 229, 241, 'HAMLET', 'What, look’d he frowningly?'), ('hamlet_act1_scene2', 230, 242, 'HORATIO', 'A countenance more in sorrow than in anger.'), ('hamlet_act1_scene2', 231, 243, 'HAMLET', 'Pale or red?'), ('hamlet_act1_scene2', 231, 244, 'HORATIO', 'Nay, very pale.'), ('hamlet_act1_scene2', 232, 245, 'HAMLET', 'And fix’d his eyes upon you?'), ('hamlet_act1_scene2', 232, 246, 'HORATIO', 'Most constantly.'), ('hamlet_act1_scene2', 233, 247, 'HAMLET', 'I would I had been there.'), ('hamlet_act1_scene2', 233, 248, 'HORATIO', 'It would have much amazed you.'), ('hamlet_act1_scene2', 234, 249, 'HAMLET', 'Very like, very like. Stay’d it long?'), ('hamlet_act1_scene2', 235, 250, 'HORATIO', 'While one with moderate haste might tell a hundred.'), ('hamlet_act1_scene2', 236, 251, 'MARCELLUS BERNARDO', 'Longer, longer.'), ('hamlet_act1_scene2', 236, 252, 'HORATIO', 'Not when I saw’t.'), ('hamlet_act1_scene2', 237, 253, 'HAMLET', 'His beard was grizzled—no?'), ('hamlet_act1_scene2', 238, 254, 'HORATIO', 'It was, as I have seen it in his life,'), ('hamlet_act1_scene2', 239, 255, 'HORATIO', 'A sable silver’d.'), ('hamlet_act1_scene2', 239, 256, 'HAMLET', 'I will watch to-night;'), ('hamlet_act1_scene2', 240, 257, 'HAMLET', 'Perchance ’twill walk again.'), ('hamlet_act1_scene2', 240, 258, 'HORATIO', 'I warrant it will.'), ('hamlet_act1_scene2', 241, 259, 'HAMLET', 'If it assume my noble father’s person,'), ('hamlet_act1_scene2', 242, 260, 'HAMLET', 'I’ll speak to it, though hell itself should gape'), ('hamlet_act1_scene2', 243, 261, 'HAMLET', 'And bid me hold my peace. I pray you all,'), ('hamlet_act1_scene2', 244, 262, 'HAMLET', 'If you have hitherto conceal’d this sight,'), ('hamlet_act1_scene2', 245, 263, 'HAMLET', 'Let it be tenable in your silence still;'), ('hamlet_act1_scene2', 246, 264, 'HAMLET', 'And whatsoever else shall hap to-night,'), ('hamlet_act1_scene2', 247, 265, 'HAMLET', 'Give it an understanding, but no tongue:'), ('hamlet_act1_scene2', 248, 266, 'HAMLET', 'I will requite your loves. So, fare you well:'), ('hamlet_act1_scene2', 249, 267, 'HAMLET', 'Upon the platform, ’twixt eleven and twelve,'), ('hamlet_act1_scene2', 250, 268, 'HAMLET', 'I’ll visit you.'), ('hamlet_act1_scene2', 250, 269, 'ALL', 'Our duty to your honour.'), ('hamlet_act1_scene2', 251, 270, 'HAMLET', 'Your loves, as mine to you: farewell.'), ('hamlet_act1_scene2', 252, 271, 'HAMLET', 'My father’s spirit in arms! all is not well;'), ('hamlet_act1_scene2', 253, 272, 'HAMLET', 'I doubt some foul play: would the night were come!'), ('hamlet_act1_scene2', 254, 273, 'HAMLET', 'Till then sit still, my soul: foul deeds will rise,'), ('hamlet_act1_scene2', 255, 274, 'HAMLET', 'Though all the earth o’erwhelm them, to men’s eyes.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene3', 1, 0, 'LAERTES', 'My necessaries are embark’d: farewell:'), ('hamlet_act1_scene3', 2, 1, 'LAERTES', 'And, sister, as the winds give benefit'), ('hamlet_act1_scene3', 3, 2, 'LAERTES', 'And convoy is assistant, do not sleep,'), ('hamlet_act1_scene3', 4, 3, 'LAERTES', 'But let me hear from you.'), ('hamlet_act1_scene3', 4, 4, 'OPHELIA', 'Do you doubt that?'), ('hamlet_act1_scene3', 5, 5, 'LAERTES', 'For Hamlet and the trifling of his favour,'), ('hamlet_act1_scene3', 6, 6, 'LAERTES', 'Hold it a fashion and a toy in blood,'), ('hamlet_act1_scene3', 7, 7, 'LAERTES', 'A violet in the youth of primy nature,'), ('hamlet_act1_scene3', 8, 8, 'LAERTES', 'Forward, not permanent, sweet, not lasting,'), ('hamlet_act1_scene3', 9, 9, 'LAERTES', 'The perfume and suppliance of a minute;'), ('hamlet_act1_scene3', 10, 10, 'LAERTES', 'No more.'), ('hamlet_act1_scene3', 10, 11, 'OPHELIA', 'No more but so?'), ('hamlet_act1_scene3', 11, 12, 'LAERTES', 'Think it no more:'), ('hamlet_act1_scene3', 12, 13, 'LAERTES', 'For nature, crescent, does not grow alone'), ('hamlet_act1_scene3', 13, 14, 'LAERTES', 'In thews and bulk, but, as this temple waxes,'), ('hamlet_act1_scene3', 14, 15, 'LAERTES', 'The inward service of the mind and soul'), ('hamlet_act1_scene3', 15, 16, 'LAERTES', 'Grows wide withal. Perhaps he loves you now,'), ('hamlet_act1_scene3', 16, 17, 'LAERTES', 'And now no soil nor cautel doth besmirch'), ('hamlet_act1_scene3', 17, 18, 'LAERTES', 'The virtue of his will: but you must fear,'), ('hamlet_act1_scene3', 18, 19, 'LAERTES', 'His greatness weigh’d, his will is not his own;'), ('hamlet_act1_scene3', 19, 20, 'LAERTES', 'For he himself is subject to his birth:'), ('hamlet_act1_scene3', 20, 21, 'LAERTES', 'He may not, as unvalued persons do,'), ('hamlet_act1_scene3', 21, 22, 'LAERTES', 'Carve for himself; for on his choice depends'), ('hamlet_act1_scene3', 22, 23, 'LAERTES', 'The safety and health of this whole state;'), ('hamlet_act1_scene3', 23, 24, 'LAERTES', 'And therefore must his choice be circumscribed'), ('hamlet_act1_scene3', 24, 25, 'LAERTES', 'Unto the voice and yielding of that body'), ('hamlet_act1_scene3', 25, 26, 'LAERTES', 'Whereof he is the head. Then if he says he loves you,'), ('hamlet_act1_scene3', 26, 27, 'LAERTES', 'It fits your wisdom so far to believe it'), ('hamlet_act1_scene3', 27, 28, 'LAERTES', 'As he in his particular act and place'), ('hamlet_act1_scene3', 28, 29, 'LAERTES', 'May give his saying deed; which is no further'), ('hamlet_act1_scene3', 29, 30, 'LAERTES', 'Than the main voice of Denmark goes withal.'), ('hamlet_act1_scene3', 30, 31, 'LAERTES', 'Then weigh what loss your honour may sustain,'), ('hamlet_act1_scene3', 31, 32, 'LAERTES', 'If with too credent ear you list his songs,'), ('hamlet_act1_scene3', 32, 33, 'LAERTES', 'Or lose your heart, or your chaste treasure open'), ('hamlet_act1_scene3', 33, 34, 'LAERTES', 'To his unmaster’d importunity.'), ('hamlet_act1_scene3', 34, 35, 'LAERTES', 'Fear it, Ophelia, fear it, my dear sister,'), ('hamlet_act1_scene3', 35, 36, 'LAERTES', 'And keep you in the rear of your affection,'), ('hamlet_act1_scene3', 36, 37, 'LAERTES', 'Out of the shot and danger of desire.'), ('hamlet_act1_scene3', 37, 38, 'LAERTES', 'The chariest maid is prodigal enough,'), ('hamlet_act1_scene3', 38, 39, 'LAERTES', 'If she unmask her beauty to the moon:'), ('hamlet_act1_scene3', 39, 40, 'LAERTES', 'Virtue itself ’scapes not calumnious strokes:'), ('hamlet_act1_scene3', 40, 41, 'LAERTES', 'The canker galls the infants of the spring,'), ('hamlet_act1_scene3', 41, 42, 'LAERTES', 'Too oft before their buttons be disclosed,'), ('hamlet_act1_scene3', 42, 43, 'LAERTES', 'And in the morn and liquid dew of youth'), ('hamlet_act1_scene3', 43, 44, 'LAERTES', 'Contagious blastments are most imminent.'), ('hamlet_act1_scene3', 44, 45, 'LAERTES', 'Be wary then; best safety lies in fear:'), ('hamlet_act1_scene3', 45, 46, 'LAERTES', 'Youth to itself rebels, though none else near.'), ('hamlet_act1_scene3', 46, 47, 'OPHELIA', 'I shall the effect of this good lesson keep,'), ('hamlet_act1_scene3', 47, 48, 'OPHELIA', 'As watchman to my heart. But, good my brother,'), ('hamlet_act1_scene3', 48, 49, 'OPHELIA', 'Do not, as some ungracious pastors do,'), ('hamlet_act1_scene3', 49, 50, 'OPHELIA', 'Show me the steep and thorny way to heaven;'), ('hamlet_act1_scene3', 50, 51, 'OPHELIA', 'Whiles, like a puff’d and reckless libertine,'), ('hamlet_act1_scene3', 51, 52, 'OPHELIA', 'Himself the primrose path of dalliance treads,'), ('hamlet_act1_scene3', 52, 53, 'OPHELIA', 'And recks not his own rede.'), ('hamlet_act1_scene3', 52, 54, 'LAERTES', 'O, fear me not.'), ('hamlet_act1_scene3', 53, 55, 'LAERTES', 'I stay too long: but here my father comes.'), ('hamlet_act1_scene3', 54, 56, 'POLONIUS', 'Yet here, Laertes! aboard, aboard, for shame!'), ('hamlet_act1_scene3', 55, 57, 'POLONIUS', 'The wind sits in the shoulder of your sail,'), ('hamlet_act1_scene3', 56, 58, 'POLONIUS', 'And you are stay’d for. There; my blessing with thee!'), ('hamlet_act1_scene3', 57, 59, 'POLONIUS', 'And these few precepts in thy memory'), ('hamlet_act1_scene3', 58, 60, 'POLONIUS', 'See thou character. Give thy thoughts no tongue,'), ('hamlet_act1_scene3', 59, 61, 'POLONIUS', 'Nor any unproportion’d thought his act.'), ('hamlet_act1_scene3', 60, 62, 'POLONIUS', 'Be thou familiar, but by no means vulgar.'), ('hamlet_act1_scene3', 61, 63, 'POLONIUS', 'Those friends thou hast, and their adoption tried,'), ('hamlet_act1_scene3', 62, 64, 'POLONIUS', 'Grapple them to thy soul with hoops of steel;'), ('hamlet_act1_scene3', 63, 65, 'POLONIUS', 'But do not dull thy palm with entertainment'), ('hamlet_act1_scene3', 64, 66, 'POLONIUS', 'Of each new-hatch’d, unfledged comrade. Beware'), ('hamlet_act1_scene3', 65, 67, 'POLONIUS', 'Of entrance to a quarrel, but being in,'), ('hamlet_act1_scene3', 66, 68, 'POLONIUS', 'Bear’t that the opposed may beware of thee.'), ('hamlet_act1_scene3', 67, 69, 'POLONIUS', 'Give every man thy ear, but few thy voice;'), ('hamlet_act1_scene3', 68, 70, 'POLONIUS', 'Take each man’s censure, but reserve thy judgment.'), ('hamlet_act1_scene3', 69, 71, 'POLONIUS', 'Costly thy habit as thy purse can buy,'), ('hamlet_act1_scene3', 70, 72, 'POLONIUS', 'But not express’d in fancy; rich, not gaudy;'), ('hamlet_act1_scene3', 71, 73, 'POLONIUS', 'For the apparel oft proclaims the man,'), ('hamlet_act1_scene3', 72, 74, 'POLONIUS', 'And they in France of the best rank and station'), ('hamlet_act1_scene3', 73, 75, 'POLONIUS', 'Are of a most select and generous chief in that.'), ('hamlet_act1_scene3', 74, 76, 'POLONIUS', 'Neither a borrower nor a lender be;'), ('hamlet_act1_scene3', 75, 77, 'POLONIUS', 'For loan oft loses both itself and friend,'), ('hamlet_act1_scene3', 76, 78, 'POLONIUS', 'And borrowing dulls the edge of husbandry.'), ('hamlet_act1_scene3', 77, 79, 'POLONIUS', 'This above all: to thine ownself be true,'), ('hamlet_act1_scene3', 78, 80, 'POLONIUS', 'And it must follow, as the night the day,'), ('hamlet_act1_scene3', 79, 81, 'POLONIUS', 'Thou canst not then be false to any man.'), ('hamlet_act1_scene3', 80, 82, 'POLONIUS', 'Farewell: my blessing season this in thee!'), ('hamlet_act1_scene3', 81, 83, 'LAERTES', 'Most humbly do I take my leave, my lord.'), ('hamlet_act1_scene3', 82, 84, 'POLONIUS', 'The time invites you; go; your servants tend.'), ('hamlet_act1_scene3', 83, 85, 'LAERTES', 'Farewell, Ophelia; and remember well'), ('hamlet_act1_scene3', 84, 86, 'LAERTES', 'What I have said to you.'), ('hamlet_act1_scene3', 84, 87, 'OPHELIA', '’Tis in my memory lock’d,'), ('hamlet_act1_scene3', 85, 88, 'OPHELIA', 'And you yourself shall keep the key of it.'), ('hamlet_act1_scene3', 86, 89, 'LAERTES', 'Farewell.'), ('hamlet_act1_scene3', 87, 90, 'POLONIUS', 'What is’t, Ophelia, he hath said to you?'), ('hamlet_act1_scene3', 88, 91, 'OPHELIA', 'So please you, something touching the Lord Hamlet.'), ('hamlet_act1_scene3', 89, 92, 'POLONIUS', 'Marry, well bethought:'), ('hamlet_act1_scene3', 90, 93, 'POLONIUS', '’Tis told me, he hath very oft of late'), ('hamlet_act1_scene3', 91, 94, 'POLONIUS', 'Given private time to you; and you yourself'), ('hamlet_act1_scene3', 92, 95, 'POLONIUS', 'Have of your audience been most free and bounteous:'), ('hamlet_act1_scene3', 93, 96, 'POLONIUS', 'If it be so, as so ’tis put on me,'), ('hamlet_act1_scene3', 94, 97, 'POLONIUS', 'And that in way of caution, I must tell you,'), ('hamlet_act1_scene3', 95, 98, 'POLONIUS', 'You do not understand yourself so clearly'), ('hamlet_act1_scene3', 96, 99, 'POLONIUS', 'As it behoves my daughter and your honour.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene3', 97, 100, 'POLONIUS', 'What is between you? give me up the truth.'), ('hamlet_act1_scene3', 98, 101, 'OPHELIA', 'He hath, my lord, of late made many tenders'), ('hamlet_act1_scene3', 99, 102, 'OPHELIA', 'Of his affection to me.'), ('hamlet_act1_scene3', 100, 103, 'POLONIUS', 'Affection! pooh! you speak like a green girl,'), ('hamlet_act1_scene3', 101, 104, 'POLONIUS', 'Unsifted in such perilous circumstance.'), ('hamlet_act1_scene3', 102, 105, 'POLONIUS', 'Do you believe his tenders, as you call them?'), ('hamlet_act1_scene3', 103, 106, 'OPHELIA', 'I do not know, my lord, what I should think.'), ('hamlet_act1_scene3', 104, 107, 'POLONIUS', 'Marry, I’ll teach you: think yourself a baby;'), ('hamlet_act1_scene3', 105, 108, 'POLONIUS', 'That you have ta’en these tenders for true pay,'), ('hamlet_act1_scene3', 106, 109, 'POLONIUS', 'Which are not sterling. Tender yourself more dearly;'), ('hamlet_act1_scene3', 107, 110, 'POLONIUS', 'Or—not to crack the wind of the poor phrase,'), ('hamlet_act1_scene3', 108, 111, 'POLONIUS', 'Running it thus—you’ll tender me a fool.'), ('hamlet_act1_scene3', 109, 112, 'OPHELIA', 'My lord, he hath importuned me with love'), ('hamlet_act1_scene3', 110, 113, 'OPHELIA', 'In honourable fashion.'), ('hamlet_act1_scene3', 111, 114, 'POLONIUS', 'Ay, fashion you may call it; go to, go to.'), ('hamlet_act1_scene3', 112, 115, 'OPHELIA', 'And hath given countenance to his speech, my lord,'), ('hamlet_act1_scene3', 113, 116, 'OPHELIA', 'With almost all the holy vows of heaven.'), ('hamlet_act1_scene3', 114, 117, 'POLONIUS', 'Ay, springes to catch woodcocks. I do know,'), ('hamlet_act1_scene3', 115, 118, 'POLONIUS', 'When the blood burns, how prodigal the soul'), ('hamlet_act1_scene3', 116, 119, 'POLONIUS', 'Lends the tongue vows: these blazes, daughter,'), ('hamlet_act1_scene3', 117, 120, 'POLONIUS', 'Giving more light than heat, extinct in both,'), ('hamlet_act1_scene3', 118, 121, 'POLONIUS', 'Even in their promise, as it is a-making,'), ('hamlet_act1_scene3', 119, 122, 'POLONIUS', 'You must not take for fire. From this time'), ('hamlet_act1_scene3', 120, 123, 'POLONIUS', 'Be somewhat scanter of your maiden presence;'), ('hamlet_act1_scene3', 121, 124, 'POLONIUS', 'Set your entreatments at a higher rate'), ('hamlet_act1_scene3', 122, 125, 'POLONIUS', 'Than a command to parley. For Lord Hamlet,'), ('hamlet_act1_scene3', 123, 126, 'POLONIUS', 'Believe so much in him, that he is young,'), ('hamlet_act1_scene3', 124, 127, 'POLONIUS', 'And with a larger tether may he walk'), ('hamlet_act1_scene3', 125, 128, 'POLONIUS', 'Than may be given you: in few, Ophelia,'), ('hamlet_act1_scene3', 126, 129, 'POLONIUS', 'Do not believe his vows; for they are brokers,'), ('hamlet_act1_scene3', 127, 130, 'POLONIUS', 'Not of that dye which their investments show,'), ('hamlet_act1_scene3', 128, 131, 'POLONIUS', 'But mere implorators of unholy suits,'), ('hamlet_act1_scene3', 129, 132, 'POLONIUS', 'Breathing like sanctified and pious bonds,'), ('hamlet_act1_scene3', 130, 133, 'POLONIUS', 'The better to beguile. This is for all:'), ('hamlet_act1_scene3', 131, 134, 'POLONIUS', 'I would not, in plain terms, from this time forth,'), ('hamlet_act1_scene3', 132, 135, 'POLONIUS', 'Have you so slander any moment leisure,'), ('hamlet_act1_scene3', 133, 136, 'POLONIUS', 'As to give words or talk with the Lord Hamlet.'), ('hamlet_act1_scene3', 134, 137, 'POLONIUS', 'Look to’t, I charge you: come your ways.'), ('hamlet_act1_scene3', 135, 138, 'OPHELIA', 'I shall obey, my lord.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene4', 1, 0, 'HAMLET', 'The air bites shrewdly; it is very cold.'), ('hamlet_act1_scene4', 2, 1, 'HORATIO', 'It is a nipping and an eager air.'), ('hamlet_act1_scene4', 3, 2, 'HAMLET', 'What hour now?'), ('hamlet_act1_scene4', 3, 3, 'HORATIO', 'I think it lacks of twelve.'), ('hamlet_act1_scene4', 4, 4, 'HAMLET', 'No, it is struck.'), ('hamlet_act1_scene4', 5, 5, 'HORATIO', 'Indeed? I heard it not: then it draws near the season'), ('hamlet_act1_scene4', 6, 6, 'HORATIO', 'Wherein the spirit held his wont to walk.'), ('hamlet_act1_scene4', 7, 7, 'HORATIO', 'What does this mean, my lord?'), ('hamlet_act1_scene4', 8, 8, 'HAMLET', 'The king doth wake to-night and takes his rouse,'), ('hamlet_act1_scene4', 9, 9, 'HAMLET', 'Keeps wassail, and the swaggering up-spring reels;'), ('hamlet_act1_scene4', 10, 10, 'HAMLET', 'And, as he drains his draughts of Rhenish down,'), ('hamlet_act1_scene4', 11, 11, 'HAMLET', 'The kettle-drum and trumpet thus bray out'), ('hamlet_act1_scene4', 12, 12, 'HAMLET', 'The triumph of his pledge.'), ('hamlet_act1_scene4', 12, 13, 'HORATIO', 'Is it a custom?'), ('hamlet_act1_scene4', 13, 14, 'HAMLET', 'Ay, marry, is’t:'), ('hamlet_act1_scene4', 14, 15, 'HAMLET', 'But to my mind, though I am native here'), ('hamlet_act1_scene4', 15, 16, 'HAMLET', 'And to the manner born, it is a custom'), ('hamlet_act1_scene4', 16, 17, 'HAMLET', 'More honour’d in the breach than the observance.'), ('hamlet_act1_scene4', 17, 18, 'HAMLET', 'This heavy-headed revel east and west'), ('hamlet_act1_scene4', 18, 19, 'HAMLET', 'Makes us traduced and tax’d of other nations:'), ('hamlet_act1_scene4', 19, 20, 'HAMLET', 'They clepe us drunkards, and with swinish phrase'), ('hamlet_act1_scene4', 20, 21, 'HAMLET', 'Soil our addition; and indeed it takes'), ('hamlet_act1_scene4', 21, 22, 'HAMLET', 'From our achievements, though perform’d at height,'), ('hamlet_act1_scene4', 22, 23, 'HAMLET', 'The pith and marrow of our attribute.'), ('hamlet_act1_scene4', 23, 24, 'HAMLET', 'So, oft it chances in particular men,'), ('hamlet_act1_scene4', 24, 25, 'HAMLET', 'That for some vicious mole of nature in them,'), ('hamlet_act1_scene4', 25, 26, 'HAMLET', 'As, in their birth—wherein they are not guilty,'), ('hamlet_act1_scene4', 26, 27, 'HAMLET', 'Since nature cannot choose his origin—'), ('hamlet_act1_scene4', 27, 28, 'HAMLET', 'By the o’ergrowth of some complexion,'), ('hamlet_act1_scene4', 28, 29, 'HAMLET', 'Oft breaking down the pales and forts of reason,'), ('hamlet_act1_scene4', 29, 30, 'HAMLET', 'Or by some habit that too much o’er-leavens'), ('hamlet_act1_scene4', 30, 31, 'HAMLET', 'The form of plausive manners, that these men,'), ('hamlet_act1_scene4', 31, 32, 'HAMLET', 'Carrying, I say, the stamp of one defect,'), ('hamlet_act1_scene4', 32, 33, 'HAMLET', 'Being nature’s livery, or fortune’s star—'), ('hamlet_act1_scene4', 33, 34, 'HAMLET', 'Their virtues else—be they as pure as grace,'), ('hamlet_act1_scene4', 34, 35, 'HAMLET', 'As infinite as man may undergo—'), ('hamlet_act1_scene4', 35, 36, 'HAMLET', 'Shall in the general censure take corruption'), ('hamlet_act1_scene4', 36, 37, 'HAMLET', 'From that particular fault: the dram of eale'), ('hamlet_act1_scene4', 37, 38, 'HAMLET', 'Doth all the noble substance of a doubt'), ('hamlet_act1_scene4', 38, 39, 'HAMLET', 'To his own scandal.'), ('hamlet_act1_scene4', 38, 40, 'HORATIO', 'Look, my lord, it comes!'), ('hamlet_act1_scene4', 39, 41, 'HAMLET', 'Angels and ministers of grace defend us!'), ('hamlet_act1_scene4', 40, 42, 'HAMLET', 'Be thou a spirit of health or goblin damn’d,'), ('hamlet_act1_scene4', 41, 43, 'HAMLET', 'Bring with thee airs from heaven or blasts from hell,'), ('hamlet_act1_scene4', 42, 44, 'HAMLET', 'Be thy intents wicked or charitable,'), ('hamlet_act1_scene4', 43, 45, 'HAMLET', 'Thou comest in such a questionable shape'), ('hamlet_act1_scene4', 44, 46, 'HAMLET', 'That I will speak to thee: I’ll call thee Hamlet,'), ('hamlet_act1_scene4', 45, 47, 'HAMLET', 'King, father, royal Dane: O, answer me!'), ('hamlet_act1_scene4', 46, 48, 'HAMLET', 'Let me not burst in ignorance; but tell'), ('hamlet_act1_scene4', 47, 49, 'HAMLET', 'Why thy canonized bones, hearsed in death,'), ('hamlet_act1_scene4', 48, 50, 'HAMLET', 'Have burst their cerements; why the sepulchre,'), ('hamlet_act1_scene4', 49, 51, 'HAMLET', 'Wherein we saw thee quietly inurn’d,'), ('hamlet_act1_scene4', 50, 52, 'HAMLET', 'Hath oped his ponderous and marble jaws,'), ('hamlet_act1_scene4', 51, 53, 'HAMLET', 'To cast thee up again. What may this mean,'), ('hamlet_act1_scene4', 52, 54, 'HAMLET', 'That thou, dead corse, again in complete steel'), ('hamlet_act1_scene4', 53, 55, 'HAMLET', 'Revisit’st thus the glimpses of the moon,'), ('hamlet_act1_scene4', 54, 56, 'HAMLET', 'Making night hideous; and we fools of nature'), ('hamlet_act1_scene4', 55, 57, 'HAMLET', 'So horridly to shake our disposition'), ('hamlet_act1_scene4', 56, 58, 'HAMLET', 'With thoughts beyond the reaches of our souls?'), ('hamlet_act1_scene4', 57, 59, 'HAMLET', 'Say, why is this? wherefore? what should we do?'), ('hamlet_act1_scene4', 58, 60, 'HORATIO', 'It beckons you to go away with it,'), ('hamlet_act1_scene4', 59, 61, 'HORATIO', 'As if it some impartment did desire'), ('hamlet_act1_scene4', 60, 62, 'HORATIO', 'To you alone.'), ('hamlet_act1_scene4', 60, 63, 'MARCELLUS', 'Look, with what courteous action'), ('hamlet_act1_scene4', 61, 64, 'MARCELLUS', 'It waves you to a more removed ground:'), ('hamlet_act1_scene4', 62, 65, 'MARCELLUS', 'But do not go with it.'), ('hamlet_act1_scene4', 62, 66, 'HORATIO', 'No, by no means.'), ('hamlet_act1_scene4', 63, 67, 'HAMLET', 'It will not speak; then I will follow it.'), ('hamlet_act1_scene4', 64, 68, 'HORATIO', 'Do not, my lord.'), ('hamlet_act1_scene4', 64, 69, 'HAMLET', 'Why, what should be the fear?'), ('hamlet_act1_scene4', 65, 70, 'HAMLET', 'I do not set my life in a pin’s fee;'), ('hamlet_act1_scene4', 66, 71, 'HAMLET', 'And for my soul, what can it do to that,'), ('hamlet_act1_scene4', 67, 72, 'HAMLET', 'Being a thing immortal as itself?'), ('hamlet_act1_scene4', 68, 73, 'HAMLET', 'It waves me forth again: I’ll follow it.'), ('hamlet_act1_scene4', 69, 74, 'HORATIO', 'What if it tempt you toward the flood, my lord,'), ('hamlet_act1_scene4', 70, 75, 'HORATIO', 'Or to the dreadful summit of the cliff'), ('hamlet_act1_scene4', 71, 76, 'HORATIO', 'That beetles o’er his base into the sea,'), ('hamlet_act1_scene4', 72, 77, 'HORATIO', 'And there assume some other horrible form,'), ('hamlet_act1_scene4', 73, 78, 'HORATIO', 'Which might deprive your sovereignty of reason'), ('hamlet_act1_scene4', 74, 79, 'HORATIO', 'And draw you into madness? think of it:'), ('hamlet_act1_scene4', 75, 80, 'HORATIO', 'The very place puts toys of desperation,'), ('hamlet_act1_scene4', 76, 81, 'HORATIO', 'Without more motive, into every brain'), ('hamlet_act1_scene4', 77, 82, 'HORATIO', 'That looks so many fathoms to the sea'), ('hamlet_act1_scene4', 78, 83, 'HORATIO', 'And hears it roar beneath.'), ('hamlet_act1_scene4', 78, 84, 'HAMLET', 'It waves me still.'), ('hamlet_act1_scene4', 79, 85, 'HAMLET', 'Go on; I’ll follow thee.'), ('hamlet_act1_scene4', 79, 86, 'MARCELLUS', 'You shall not go, my lord.'), ('hamlet_act1_scene4', 80, 87, 'HAMLET', 'Hold off your hands.'), ('hamlet_act1_scene4', 80, 88, 'HORATIO', 'Be ruled; you shall not go.'), ('hamlet_act1_scene4', 81, 89, 'HAMLET', 'My fate cries out,'), ('hamlet_act1_scene4', 82, 90, 'HAMLET', 'And makes each petty artery in this body'), ('hamlet_act1_scene4', 83, 91, 'HAMLET', 'As hardy as the Nemean lion’s nerve.'), ('hamlet_act1_scene4', 84, 92, 'HAMLET', 'Still am I call’d. Unhand me, gentlemen.'), ('hamlet_act1_scene4', 85, 93, 'HAMLET', 'By heaven, I’ll make a ghost of him that lets me!'), ('hamlet_act1_scene4', 86, 94, 'HAMLET', 'I say, away! Go on; I’ll follow thee.'), ('hamlet_act1_scene4', 87, 95, 'HORATIO', 'He waxes desperate with imagination.'), ('hamlet_act1_scene4', 88, 96, 'MARCELLUS', 'Let’s follow; ’tis not fit thus to obey him.'), ('hamlet_act1_scene4', 89, 97, 'HORATIO', 'Have after. To what issue will this come?'), ('hamlet_act1_scene4', 90, 98, 'MARCELLUS', 'Something is rotten in the state of Denmark.'), ('hamlet_act1_scene4', 91, 99, 'HORATIO', 'Heaven will direct it.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene4', 91, 100, 'MARCELLUS', 'Nay, let’s follow him.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene5', 1, 0, 'HAMLET', 'Where wilt thou lead me? speak; I’ll go no further.'), ('hamlet_act1_scene5', 2, 1, 'GHOST', 'Mark me.'), ('hamlet_act1_scene5', 2, 2, 'HAMLET', 'I will.'), ('hamlet_act1_scene5', 3, 3, 'GHOST', 'My hour is almost come,'), ('hamlet_act1_scene5', 4, 4, 'GHOST', 'When I to sulphurous and tormenting flames'), ('hamlet_act1_scene5', 5, 5, 'GHOST', 'Must render up myself.'), ('hamlet_act1_scene5', 5, 6, 'HAMLET', 'Alas, poor ghost!'), ('hamlet_act1_scene5', 6, 7, 'GHOST', 'Pity me not, but lend thy serious hearing'), ('hamlet_act1_scene5', 7, 8, 'GHOST', 'To what I shall unfold.'), ('hamlet_act1_scene5', 7, 9, 'HAMLET', 'Speak; I am bound to hear.'), ('hamlet_act1_scene5', 8, 10, 'GHOST', 'So art thou to revenge, when thou shalt hear.'), ('hamlet_act1_scene5', 9, 11, 'HAMLET', 'What?'), ('hamlet_act1_scene5', 9, 12, 'GHOST', 'I am thy father’s spirit,'), ('hamlet_act1_scene5', 10, 13, 'GHOST', 'Doom’d for a certain term to walk the night,'), ('hamlet_act1_scene5', 11, 14, 'GHOST', 'And for the day confined to fast in fires,'), ('hamlet_act1_scene5', 12, 15, 'GHOST', 'Till the foul crimes done in my days of nature'), ('hamlet_act1_scene5', 13, 16, 'GHOST', 'Are burnt and purged away. But that I am forbid'), ('hamlet_act1_scene5', 14, 17, 'GHOST', 'To tell the secrets of my prison-house,'), ('hamlet_act1_scene5', 15, 18, 'GHOST', 'I could a tale unfold whose lightest word'), ('hamlet_act1_scene5', 16, 19, 'GHOST', 'Would harrow up thy soul, freeze thy young blood,'), ('hamlet_act1_scene5', 17, 20, 'GHOST', 'Make thy two eyes, like stars, start from their spheres,'), ('hamlet_act1_scene5', 18, 21, 'GHOST', 'Thy knotted and combined locks to part'), ('hamlet_act1_scene5', 19, 22, 'GHOST', 'And each particular hair to stand on end,'), ('hamlet_act1_scene5', 20, 23, 'GHOST', 'Like quills upon the fretful porpentine:'), ('hamlet_act1_scene5', 21, 24, 'GHOST', 'But this eternal blazon must not be'), ('hamlet_act1_scene5', 22, 25, 'GHOST', 'To ears of flesh and blood. List, list, O, list!'), ('hamlet_act1_scene5', 23, 26, 'GHOST', 'If thou didst ever thy dear father love—'), ('hamlet_act1_scene5', 24, 27, 'HAMLET', 'O God!'), ('hamlet_act1_scene5', 25, 28, 'GHOST', 'Revenge his foul and most unnatural murder.'), ('hamlet_act1_scene5', 26, 29, 'HAMLET', 'Murder!'), ('hamlet_act1_scene5', 27, 30, 'GHOST', 'Murder most foul, as in the best it is;'), ('hamlet_act1_scene5', 28, 31, 'GHOST', 'But this most foul, strange and unnatural.'), ('hamlet_act1_scene5', 29, 32, 'HAMLET', 'Haste me to know’t, that I, with wings as swift'), ('hamlet_act1_scene5', 30, 33, 'HAMLET', 'As meditation or the thoughts of love,'), ('hamlet_act1_scene5', 31, 34, 'HAMLET', 'May sweep to my revenge.'), ('hamlet_act1_scene5', 31, 35, 'GHOST', 'I find thee apt;'), ('hamlet_act1_scene5', 32, 36, 'GHOST', 'And duller shouldst thou be than the fat weed'), ('hamlet_act1_scene5', 33, 37, 'GHOST', 'That roots itself in ease on Lethe wharf,'), ('hamlet_act1_scene5', 34, 38, 'GHOST', 'Wouldst thou not stir in this. Now, Hamlet, hear:'), ('hamlet_act1_scene5', 35, 39, 'GHOST', '’Tis given out that, sleeping in my orchard,'), ('hamlet_act1_scene5', 36, 40, 'GHOST', 'A serpent stung me; so the whole ear of Denmark'), ('hamlet_act1_scene5', 37, 41, 'GHOST', 'Is by a forged process of my death'), ('hamlet_act1_scene5', 38, 42, 'GHOST', 'Rankly abused: but know, thou noble youth,'), ('hamlet_act1_scene5', 39, 43, 'GHOST', 'The serpent that did sting thy father’s life'), ('hamlet_act1_scene5', 40, 44, 'GHOST', 'Now wears his crown.'), ('hamlet_act1_scene5', 40, 45, 'HAMLET', 'O my prophetic soul!'), ('hamlet_act1_scene5', 41, 46, 'HAMLET', 'My uncle!'), ('hamlet_act1_scene5', 41, 47, 'GHOST', 'Ay, that incestuous, that adulterate beast,'), ('hamlet_act1_scene5', 42, 48, 'GHOST', 'With witchcraft of his wit, with traitorous gifts—'), ('hamlet_act1_scene5', 43, 49, 'GHOST', 'O wicked wit and gifts, that have the power'), ('hamlet_act1_scene5', 44, 50, 'GHOST', 'So to seduce!—won to his shameful lust'), ('hamlet_act1_scene5', 45, 51, 'GHOST', 'The will of my most seeming-virtuous queen:'), ('hamlet_act1_scene5', 46, 52, 'GHOST', 'O Hamlet, what a falling-off was there!'), ('hamlet_act1_scene5', 47, 53, 'GHOST', 'From me, whose love was of that dignity'), ('hamlet_act1_scene5', 48, 54, 'GHOST', 'That it went hand in hand even with the vow'), ('hamlet_act1_scene5', 49, 55, 'GHOST', 'I made to her in marriage, and to decline'), ('hamlet_act1_scene5', 50, 56, 'GHOST', 'Upon a wretch whose natural gifts were poor'), ('hamlet_act1_scene5', 51, 57, 'GHOST', 'To those of mine!'), ('hamlet_act1_scene5', 52, 58, 'GHOST', 'But virtue, as it never will be moved,'), ('hamlet_act1_scene5', 53, 59, 'GHOST', 'Though lewdness court it in a shape of heaven,'), ('hamlet_act1_scene5', 54, 60, 'GHOST', 'So lust, though to a radiant angel link’d,'), ('hamlet_act1_scene5', 55, 61, 'GHOST', 'Will sate itself in a celestial bed,'), ('hamlet_act1_scene5', 56, 62, 'GHOST', 'And prey on garbage.'), ('hamlet_act1_scene5', 57, 63, 'GHOST', 'But, soft! methinks I scent the morning air;'), ('hamlet_act1_scene5', 58, 64, 'GHOST', 'Brief let me be. Sleeping within my orchard,'), ('hamlet_act1_scene5', 59, 65, 'GHOST', 'My custom always of the afternoon,'), ('hamlet_act1_scene5', 60, 66, 'GHOST', 'Upon my secure hour thy uncle stole,'), ('hamlet_act1_scene5', 61, 67, 'GHOST', 'With juice of cursed hebenon in a vial,'), ('hamlet_act1_scene5', 62, 68, 'GHOST', 'And in the porches of my ears did pour'), ('hamlet_act1_scene5', 63, 69, 'GHOST', 'The leperous distilment; whose effect'), ('hamlet_act1_scene5', 64, 70, 'GHOST', 'Holds such an enmity with blood of man'), ('hamlet_act1_scene5', 65, 71, 'GHOST', 'That swift as quicksilver it courses through'), ('hamlet_act1_scene5', 66, 72, 'GHOST', 'The natural gates and alleys of the body,'), ('hamlet_act1_scene5', 67, 73, 'GHOST', 'And with a sudden vigour doth posset'), ('hamlet_act1_scene5', 68, 74, 'GHOST', 'And curd, like eager droppings into milk,'), ('hamlet_act1_scene5', 69, 75, 'GHOST', 'The thin and wholesome blood: so did it mine;'), ('hamlet_act1_scene5', 70, 76, 'GHOST', 'And a most instant tetter bark’d about,'), ('hamlet_act1_scene5', 71, 77, 'GHOST', 'Most lazar-like, with vile and loathsome crust,'), ('hamlet_act1_scene5', 72, 78, 'GHOST', 'All my smooth body.'), ('hamlet_act1_scene5', 73, 79, 'GHOST', 'Thus was I, sleeping, by a brother’s hand'), ('hamlet_act1_scene5', 74, 80, 'GHOST', 'Of life, of crown, of queen, at once dispatch’d:'), ('hamlet_act1_scene5', 75, 81, 'GHOST', 'Cut off even in the blossoms of my sin,'), ('hamlet_act1_scene5', 76, 82, 'GHOST', 'Unhousel’d, disappointed, unaneled,'), ('hamlet_act1_scene5', 77, 83, 'GHOST', 'No reckoning made, but sent to my account'), ('hamlet_act1_scene5', 78, 84, 'GHOST', 'With all my imperfections on my head:'), ('hamlet_act1_scene5', 79, 85, 'GHOST', 'O, horrible! O, horrible! most horrible!'), ('hamlet_act1_scene5', 80, 86, 'GHOST', 'If thou hast nature in thee, bear it not;'), ('hamlet_act1_scene5', 81, 87, 'GHOST', 'Let not the royal bed of Denmark be'), ('hamlet_act1_scene5', 82, 88, 'GHOST', 'A couch for luxury and damned incest.'), ('hamlet_act1_scene5', 83, 89, 'GHOST', 'But, howsoever thou pursuest this act,'), ('hamlet_act1_scene5', 84, 90, 'GHOST', 'Taint not thy mind, nor let thy soul contrive'), ('hamlet_act1_scene5', 85, 91, 'GHOST', 'Against thy mother aught: leave her to heaven'), ('hamlet_act1_scene5', 86, 92, 'GHOST', 'And to those thorns that in her bosom lodge,'), ('hamlet_act1_scene5', 87, 93, 'GHOST', 'To prick and sting her. Fare thee well at once!'), ('hamlet_act1_scene5', 88, 94, 'GHOST', 'The glow-worm shows the matin to be near,'), ('hamlet_act1_scene5', 89, 95, 'GHOST', 'And ’gins to pale his uneffectual fire:'), ('hamlet_act1_scene5', 90, 96, 'GHOST', 'Adieu, adieu! Hamlet, remember me.'), ('hamlet_act1_scene5', 91, 97, 'HAMLET', 'O all you host of heaven! O earth! what else?'), ('hamlet_act1_scene5', 92, 98, 'HAMLET', 'And shall I couple hell? O, fie! Hold, hold, my heart;'), ('hamlet_act1_scene5', 93, 99, 'HAMLET', 'And you, my sinews, grow not instant old,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene5', 94, 100, 'HAMLET', 'But bear me stiffly up. Remember thee!'), ('hamlet_act1_scene5', 95, 101, 'HAMLET', 'Ay, thou poor ghost, while memory holds a seat'), ('hamlet_act1_scene5', 96, 102, 'HAMLET', 'In this distracted globe. Remember thee!'), ('hamlet_act1_scene5', 97, 103, 'HAMLET', 'Yea, from the table of my memory'), ('hamlet_act1_scene5', 98, 104, 'HAMLET', 'I’ll wipe away all trivial fond records,'), ('hamlet_act1_scene5', 99, 105, 'HAMLET', 'All saws of books, all forms, all pressures past,'), ('hamlet_act1_scene5', 100, 106, 'HAMLET', 'That youth and observation copied there;'), ('hamlet_act1_scene5', 101, 107, 'HAMLET', 'And thy commandment all alone shall live'), ('hamlet_act1_scene5', 102, 108, 'HAMLET', 'Within the book and volume of my brain,'), ('hamlet_act1_scene5', 103, 109, 'HAMLET', 'Unmix’d with baser matter: yes, by heaven!'), ('hamlet_act1_scene5', 104, 110, 'HAMLET', 'O most pernicious woman!'), ('hamlet_act1_scene5', 105, 111, 'HAMLET', 'O villain, villain, smiling, damned villain!'), ('hamlet_act1_scene5', 106, 112, 'HAMLET', 'My tables—meet it is I set it down,'), ('hamlet_act1_scene5', 107, 113, 'HAMLET', 'That one may smile, and smile, and be a villain;'), ('hamlet_act1_scene5', 108, 114, 'HAMLET', 'At least I’m sure it may be so in Denmark:'), ('hamlet_act1_scene5', 109, 115, 'HAMLET', 'So, uncle, there you are. Now to my word;'), ('hamlet_act1_scene5', 110, 116, 'HAMLET', 'It is “Adieu, adieu! remember me.”'), ('hamlet_act1_scene5', 111, 117, 'HAMLET', 'I have sworn’t.'), ('hamlet_act1_scene5', 111, 118, 'MARCELLUS HORATIO', 'My lord, my lord—'), ('hamlet_act1_scene5', 112, 119, 'MARCELLUS', 'Lord Hamlet—'), ('hamlet_act1_scene5', 112, 120, 'HORATIO', 'Heaven secure him!'), ('hamlet_act1_scene5', 113, 121, 'HAMLET', 'So be it!'), ('hamlet_act1_scene5', 113, 122, 'HORATIO', 'Hillo, ho, ho, my lord!'), ('hamlet_act1_scene5', 114, 123, 'HAMLET', 'Hillo, ho, ho, boy! come, bird, come.'), ('hamlet_act1_scene5', 115, 124, 'MARCELLUS', 'How is’t, my noble lord?'), ('hamlet_act1_scene5', 115, 125, 'HORATIO', 'What news, my lord?'), ('hamlet_act1_scene5', 116, 126, 'HAMLET', 'O, wonderful!'), ('hamlet_act1_scene5', 116, 127, 'HORATIO', 'Good my lord, tell it.'), ('hamlet_act1_scene5', 117, 128, 'HAMLET', 'No; you’ll reveal it.'), ('hamlet_act1_scene5', 117, 129, 'HORATIO', 'Not I, my lord, by heaven.'), ('hamlet_act1_scene5', 118, 130, 'MARCELLUS', 'Nor I, my lord.'), ('hamlet_act1_scene5', 119, 131, 'HAMLET', 'How say you, then; would heart of man once think it?'), ('hamlet_act1_scene5', 120, 132, 'HAMLET', 'But you’ll be secret?'), ('hamlet_act1_scene5', 120, 133, 'HORATIO MARCELLUS', 'Ay, by heaven, my lord.'), ('hamlet_act1_scene5', 121, 134, 'HAMLET', 'There’s ne’er a villain dwelling in all Denmark'), ('hamlet_act1_scene5', 122, 135, 'HAMLET', 'But he’s an arrant knave.'), ('hamlet_act1_scene5', 123, 136, 'HORATIO', 'There needs no ghost, my lord, come from the grave'), ('hamlet_act1_scene5', 124, 137, 'HORATIO', 'To tell us this.'), ('hamlet_act1_scene5', 125, 138, 'HAMLET', 'Why, right; you are i’ the right;'), ('hamlet_act1_scene5', 126, 139, 'HAMLET', 'And so, without more circumstance at all,'), ('hamlet_act1_scene5', 127, 140, 'HAMLET', 'I hold it fit that we shake hands and part:'), ('hamlet_act1_scene5', 128, 141, 'HAMLET', 'You, as your business and desire shall point you;'), ('hamlet_act1_scene5', 129, 142, 'HAMLET', 'For every man has business and desire,'), ('hamlet_act1_scene5', 130, 143, 'HAMLET', 'Such as it is; and for mine own poor part,'), ('hamlet_act1_scene5', 131, 144, 'HAMLET', 'Look you, I’ll go pray.'), ('hamlet_act1_scene5', 132, 145, 'HORATIO', 'These are but wild and whirling words, my lord.'), ('hamlet_act1_scene5', 133, 146, 'HAMLET', 'I’m sorry they offend you, heartily;'), ('hamlet_act1_scene5', 134, 147, 'HAMLET', 'Yes, ’faith heartily.'), ('hamlet_act1_scene5', 134, 148, 'HORATIO', 'There’s no offence, my lord.'), ('hamlet_act1_scene5', 135, 149, 'HAMLET', 'Yes, by Saint Patrick, but there is, Horatio,'), ('hamlet_act1_scene5', 136, 150, 'HAMLET', 'And much offence too. Touching this vision here,'), ('hamlet_act1_scene5', 137, 151, 'HAMLET', 'It is an honest ghost, that let me tell you:'), ('hamlet_act1_scene5', 138, 152, 'HAMLET', 'For your desire to know what is between us,'), ('hamlet_act1_scene5', 139, 153, 'HAMLET', 'O’ermaster’t as you may. And now, good friends,'), ('hamlet_act1_scene5', 140, 154, 'HAMLET', 'As you are friends, scholars and soldiers,'), ('hamlet_act1_scene5', 141, 155, 'HAMLET', 'Give me one poor request.'), ('hamlet_act1_scene5', 141, 156, 'HORATIO', 'What is’t, my lord? we will.'), ('hamlet_act1_scene5', 142, 157, 'HAMLET', 'Never make known what you have seen to-night.'), ('hamlet_act1_scene5', 143, 158, 'HORATIO MARCELLUS', 'My lord, we will not.'), ('hamlet_act1_scene5', 143, 159, 'HAMLET', 'Nay, but swear’t.'), ('hamlet_act1_scene5', 144, 160, 'HORATIO', 'In faith,'), ('hamlet_act1_scene5', 145, 161, 'HORATIO', 'My lord, not I.'), ('hamlet_act1_scene5', 145, 162, 'MARCELLUS', 'Nor I, my lord, in faith.'), ('hamlet_act1_scene5', 146, 163, 'HAMLET', 'Upon my sword.'), ('hamlet_act1_scene5', 146, 164, 'MARCELLUS', 'We have sworn, my lord, already.'), ('hamlet_act1_scene5', 147, 165, 'HAMLET', 'Indeed, upon my sword, indeed.'), ('hamlet_act1_scene5', 147, 166, 'GHOST', 'Swear.'), ('hamlet_act1_scene5', 148, 167, 'HAMLET', 'Ah, ha, boy! say’st thou so? art thou there, truepenny?'), ('hamlet_act1_scene5', 149, 168, 'HAMLET', 'Come on—you hear this fellow in the cellarage—'), ('hamlet_act1_scene5', 150, 169, 'HAMLET', 'Consent to swear.'), ('hamlet_act1_scene5', 150, 170, 'HORATIO', 'Propose the oath, my lord.'), ('hamlet_act1_scene5', 151, 171, 'HAMLET', 'Never to speak of this that you have seen,'), ('hamlet_act1_scene5', 152, 172, 'HAMLET', 'Swear by my sword.'), ('hamlet_act1_scene5', 152, 173, 'GHOST', 'Swear.'), ('hamlet_act1_scene5', 153, 174, 'HAMLET', 'then we’ll shift our ground.'), ('hamlet_act1_scene5', 154, 175, 'HAMLET', 'Come hither, gentlemen,'), ('hamlet_act1_scene5', 155, 176, 'HAMLET', 'And lay your hands again upon my sword:'), ('hamlet_act1_scene5', 156, 177, 'HAMLET', 'Never to speak of this that you have heard,'), ('hamlet_act1_scene5', 157, 178, 'HAMLET', 'Swear by my sword.'), ('hamlet_act1_scene5', 157, 179, 'GHOST', 'Swear.'), ('hamlet_act1_scene5', 158, 180, 'HAMLET', 'Well said, old mole! canst work i’ the earth so fast?'), ('hamlet_act1_scene5', 159, 181, 'HAMLET', 'A worthy pioner! Once more remove, good friends.'), ('hamlet_act1_scene5', 160, 182, 'HORATIO', 'O day and night, but this is wondrous strange!'), ('hamlet_act1_scene5', 161, 183, 'HAMLET', 'And therefore as a stranger give it welcome.'), ('hamlet_act1_scene5', 162, 184, 'HAMLET', 'There are more things in heaven and earth, Horatio,'), ('hamlet_act1_scene5', 163, 185, 'HAMLET', 'Than are dreamt of in your philosophy.'), ('hamlet_act1_scene5', 164, 186, 'HAMLET', 'But come;'), ('hamlet_act1_scene5', 165, 187, 'HAMLET', 'Here, as before, never, so help you mercy,'), ('hamlet_act1_scene5', 166, 188, 'HAMLET', 'How strange or odd soe’er I bear myself,'), ('hamlet_act1_scene5', 167, 189, 'HAMLET', 'As I perchance hereafter shall think meet'), ('hamlet_act1_scene5', 168, 190, 'HAMLET', 'To put an antic disposition on,'), ('hamlet_act1_scene5', 169, 191, 'HAMLET', 'That you, at such times seeing me, never shall,'), ('hamlet_act1_scene5', 170, 192, 'HAMLET', 'With arms encumber’d thus, or this headshake,'), ('hamlet_act1_scene5', 171, 193, 'HAMLET', 'Or by pronouncing of some doubtful phrase,'), ('hamlet_act1_scene5', 172, 194, 'HAMLET', 'As “Well, well, we know,” or “We could, an if we would,”'), ('hamlet_act1_scene5', 173, 195, 'HAMLET', 'Or “If we list to speak,” or “There be, an if they might,”'), ('hamlet_act1_scene5', 174, 196, 'HAMLET', 'Or such ambiguous giving out, to note'), ('hamlet_act1_scene5', 175, 197, 'HAMLET', 'That you know aught of me: this not to do,'), ('hamlet_act1_scene5', 176, 198, 'HAMLET', 'So grace and mercy at your most need help you,'), ('hamlet_act1_scene5', 177, 199, 'HAMLET', 'Swear.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act1_scene5', 177, 200, 'GHOST', 'Swear.'), ('hamlet_act1_scene5', 178, 201, 'HAMLET', 'Rest, rest, perturbed spirit! So, gentlemen,'), ('hamlet_act1_scene5', 179, 202, 'HAMLET', 'With all my love I do commend me to you:'), ('hamlet_act1_scene5', 180, 203, 'HAMLET', 'And what so poor a man as Hamlet is'), ('hamlet_act1_scene5', 181, 204, 'HAMLET', 'May do, to express his love and friending to you,'), ('hamlet_act1_scene5', 182, 205, 'HAMLET', 'God willing, shall not lack. Let us go in together;'), ('hamlet_act1_scene5', 183, 206, 'HAMLET', 'And still your fingers on your lips, I pray.'), ('hamlet_act1_scene5', 184, 207, 'HAMLET', 'The time is out of joint: O cursed spite,'), ('hamlet_act1_scene5', 185, 208, 'HAMLET', 'That ever I was born to set it right!'), ('hamlet_act1_scene5', 186, 209, 'HAMLET', 'Nay, come, let’s go together.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene1', 1, 0, 'POLONIUS', 'Give him this money and these notes, Reynaldo.'), ('hamlet_act2_scene1', 2, 1, 'REYNALDO', 'I will, my lord.'), ('hamlet_act2_scene1', 3, 2, 'POLONIUS', 'You shall do marvellous wisely, good Reynaldo,'), ('hamlet_act2_scene1', 4, 3, 'POLONIUS', 'Before you visit him, to make inquire'), ('hamlet_act2_scene1', 5, 4, 'POLONIUS', 'Of his behavior.'), ('hamlet_act2_scene1', 5, 5, 'REYNALDO', 'My lord, I did intend it.'), ('hamlet_act2_scene1', 6, 6, 'POLONIUS', 'Marry, well said; very well said. Look you, sir,'), ('hamlet_act2_scene1', 7, 7, 'POLONIUS', 'Inquire me first what Danskers are in Paris;'), ('hamlet_act2_scene1', 8, 8, 'POLONIUS', 'And how, and who, what means, and where they keep,'), ('hamlet_act2_scene1', 9, 9, 'POLONIUS', 'What company, at what expense; and finding'), ('hamlet_act2_scene1', 10, 10, 'POLONIUS', 'By this encompassment and drift of question'), ('hamlet_act2_scene1', 11, 11, 'POLONIUS', 'That they do know my son, come you more nearer'), ('hamlet_act2_scene1', 12, 12, 'POLONIUS', 'Than your particular demands will touch it:'), ('hamlet_act2_scene1', 13, 13, 'POLONIUS', 'Take you, as ’twere, some distant knowledge of him;'), ('hamlet_act2_scene1', 14, 14, 'POLONIUS', 'As thus, “I know his father and his friends,'), ('hamlet_act2_scene1', 15, 15, 'POLONIUS', 'And in part him:” do you mark this, Reynaldo?'), ('hamlet_act2_scene1', 16, 16, 'REYNALDO', 'Ay, very well, my lord.'), ('hamlet_act2_scene1', 17, 17, 'POLONIUS', '“And in part him; but” you may say “not well:'), ('hamlet_act2_scene1', 18, 18, 'POLONIUS', 'But, if’t be he I mean, he’s very wild;'), ('hamlet_act2_scene1', 19, 19, 'POLONIUS', 'Addicted so-and-so:” and there put on him'), ('hamlet_act2_scene1', 20, 20, 'POLONIUS', 'What forgeries you please; marry, none so rank'), ('hamlet_act2_scene1', 21, 21, 'POLONIUS', 'As may dishonour him; take heed of that;'), ('hamlet_act2_scene1', 22, 22, 'POLONIUS', 'But, sir, such wanton, wild and usual slips'), ('hamlet_act2_scene1', 23, 23, 'POLONIUS', 'As are companions noted and most known'), ('hamlet_act2_scene1', 24, 24, 'POLONIUS', 'To youth and liberty.'), ('hamlet_act2_scene1', 24, 25, 'REYNALDO', 'As gaming, my lord.'), ('hamlet_act2_scene1', 25, 26, 'POLONIUS', 'Ay, or drinking, fencing, swearing, quarrelling,'), ('hamlet_act2_scene1', 26, 27, 'POLONIUS', 'Drabbing: you may go so far.'), ('hamlet_act2_scene1', 26, 28, 'REYNALDO', 'My lord, that would dishonour him.'), ('hamlet_act2_scene1', 27, 29, 'POLONIUS', '’Faith, no; as you may season it in the charge.'), ('hamlet_act2_scene1', 28, 30, 'POLONIUS', 'You must not put another scandal on him,'), ('hamlet_act2_scene1', 29, 31, 'POLONIUS', 'That he is open to incontinency;'), ('hamlet_act2_scene1', 30, 32, 'POLONIUS', 'That’s not my meaning: but breathe his faults so quaintly'), ('hamlet_act2_scene1', 31, 33, 'POLONIUS', 'That they may seem the taints of liberty,'), ('hamlet_act2_scene1', 32, 34, 'POLONIUS', 'The flash and outbreak of a fiery mind,'), ('hamlet_act2_scene1', 33, 35, 'POLONIUS', 'A savageness in unreclaimed blood,'), ('hamlet_act2_scene1', 34, 36, 'POLONIUS', 'Of general assault.'), ('hamlet_act2_scene1', 34, 37, 'REYNALDO', 'But, my good lord—'), ('hamlet_act2_scene1', 35, 38, 'POLONIUS', 'Wherefore should you do this?'), ('hamlet_act2_scene1', 35, 39, 'REYNALDO', 'Ay, my lord,'), ('hamlet_act2_scene1', 36, 40, 'REYNALDO', 'I would know that.'), ('hamlet_act2_scene1', 36, 41, 'POLONIUS', 'Marry, sir, here’s my drift;'), ('hamlet_act2_scene1', 37, 42, 'POLONIUS', 'And, I believe, it is a fetch of wit:'), ('hamlet_act2_scene1', 38, 43, 'POLONIUS', 'You laying these slight sullies on my son,'), ('hamlet_act2_scene1', 39, 44, 'POLONIUS', 'As ’twere a thing a little soil’d i’ the working,'), ('hamlet_act2_scene1', 40, 45, 'POLONIUS', 'Mark you,'), ('hamlet_act2_scene1', 41, 46, 'POLONIUS', 'Your party in converse, him you would sound,'), ('hamlet_act2_scene1', 42, 47, 'POLONIUS', 'Having ever seen in the prenominate crimes'), ('hamlet_act2_scene1', 43, 48, 'POLONIUS', 'The youth you breathe of guilty, be assured'), ('hamlet_act2_scene1', 44, 49, 'POLONIUS', 'He closes with you in this consequence;'), ('hamlet_act2_scene1', 45, 50, 'POLONIUS', '“Good sir,” or so, or “friend,” or “gentleman,”'), ('hamlet_act2_scene1', 46, 51, 'POLONIUS', 'According to the phrase or the addition'), ('hamlet_act2_scene1', 47, 52, 'POLONIUS', 'Of man and country.'), ('hamlet_act2_scene1', 47, 53, 'REYNALDO', 'Very good, my lord.'), ('hamlet_act2_scene1', 48, 54, 'POLONIUS', 'And then, sir, does he this—he does—what was I about to say?'), ('hamlet_act2_scene1', 49, 55, 'POLONIUS', 'By the mass, I was about to say something: where did I'), ('hamlet_act2_scene1', 50, 56, 'POLONIUS', 'leave?'), ('hamlet_act2_scene1', 51, 57, 'REYNALDO', 'At “closes in the consequence,” at “friend or so,” and “gentleman.”'), ('hamlet_act2_scene1', 52, 58, 'POLONIUS', 'At “closes in the consequence,” ay, marry;'), ('hamlet_act2_scene1', 53, 59, 'POLONIUS', 'He closes thus: “I know the gentleman;'), ('hamlet_act2_scene1', 54, 60, 'POLONIUS', 'I saw him yesterday, or t’ other day,'), ('hamlet_act2_scene1', 55, 61, 'POLONIUS', 'Or then, or then; with such, or such; and, as you say,'), ('hamlet_act2_scene1', 56, 62, 'POLONIUS', 'There was a’ gaming; there o’ertook in’s rouse;'), ('hamlet_act2_scene1', 57, 63, 'POLONIUS', 'There falling out at tennis:” or perchance,'), ('hamlet_act2_scene1', 58, 64, 'POLONIUS', '“I saw him enter such a house of sale,”'), ('hamlet_act2_scene1', 59, 65, 'POLONIUS', 'Videlicet, a brothel, or so forth.'), ('hamlet_act2_scene1', 60, 66, 'POLONIUS', 'See you now;'), ('hamlet_act2_scene1', 61, 67, 'POLONIUS', 'Your bait of falsehood takes this carp of truth:'), ('hamlet_act2_scene1', 62, 68, 'POLONIUS', 'And thus do we of wisdom and of reach,'), ('hamlet_act2_scene1', 63, 69, 'POLONIUS', 'With windlasses and with assays of bias,'), ('hamlet_act2_scene1', 64, 70, 'POLONIUS', 'By indirections find directions out:'), ('hamlet_act2_scene1', 65, 71, 'POLONIUS', 'So by my former lecture and advice,'), ('hamlet_act2_scene1', 66, 72, 'POLONIUS', 'Shall you my son. You have me, have you not?'), ('hamlet_act2_scene1', 67, 73, 'REYNALDO', 'My lord, I have.'), ('hamlet_act2_scene1', 68, 74, 'POLONIUS', 'God be wi’ you; fare you well.'), ('hamlet_act2_scene1', 69, 75, 'REYNALDO', 'Good my lord!'), ('hamlet_act2_scene1', 69, 76, 'POLONIUS', 'Observe his inclination in yourself.'), ('hamlet_act2_scene1', 70, 77, 'REYNALDO', 'I shall, my lord.'), ('hamlet_act2_scene1', 70, 78, 'POLONIUS', 'And let him ply his music.'), ('hamlet_act2_scene1', 71, 79, 'REYNALDO', 'Well, my lord.'), ('hamlet_act2_scene1', 71, 80, 'POLONIUS', 'Farewell!'), ('hamlet_act2_scene1', 72, 81, 'OPHELIA', 'O, my lord, my lord, I have been so affrighted!'), ('hamlet_act2_scene1', 73, 82, 'POLONIUS', 'With what, i’ the name of God?'), ('hamlet_act2_scene1', 74, 83, 'OPHELIA', 'My lord, as I was sewing in my closet,'), ('hamlet_act2_scene1', 75, 84, 'OPHELIA', 'Lord Hamlet, with his doublet all unbraced;'), ('hamlet_act2_scene1', 76, 85, 'OPHELIA', 'No hat upon his head; his stockings foul’d,'), ('hamlet_act2_scene1', 77, 86, 'OPHELIA', 'Ungarter’d, and down-gyved to his ankle;'), ('hamlet_act2_scene1', 78, 87, 'OPHELIA', 'Pale as his shirt; his knees knocking each other;'), ('hamlet_act2_scene1', 79, 88, 'OPHELIA', 'And with a look so piteous in purport'), ('hamlet_act2_scene1', 80, 89, 'OPHELIA', 'As if he had been loosed out of hell'), ('hamlet_act2_scene1', 81, 90, 'OPHELIA', 'To speak of horrors—he comes before me.'), ('hamlet_act2_scene1', 82, 91, 'POLONIUS', 'Mad for thy love?'), ('hamlet_act2_scene1', 82, 92, 'OPHELIA', 'My lord, I do not know;'), ('hamlet_act2_scene1', 83, 93, 'OPHELIA', 'But truly, I do fear it.'), ('hamlet_act2_scene1', 83, 94, 'POLONIUS', 'What said he?'), ('hamlet_act2_scene1', 84, 95, 'OPHELIA', 'He took me by the wrist and held me hard;'), ('hamlet_act2_scene1', 85, 96, 'OPHELIA', 'Then goes he to the length of all his arm;'), ('hamlet_act2_scene1', 86, 97, 'OPHELIA', 'And, with his other hand thus o’er his brow,'), ('hamlet_act2_scene1', 87, 98, 'OPHELIA', 'He falls to such perusal of my face'), ('hamlet_act2_scene1', 88, 99, 'OPHELIA', 'As he would draw it. Long stay’d he so;');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene1', 89, 100, 'OPHELIA', 'At last, a little shaking of mine arm'), ('hamlet_act2_scene1', 90, 101, 'OPHELIA', 'And thrice his head thus waving up and down,'), ('hamlet_act2_scene1', 91, 102, 'OPHELIA', 'He raised a sigh so piteous and profound'), ('hamlet_act2_scene1', 92, 103, 'OPHELIA', 'As it did seem to shatter all his bulk'), ('hamlet_act2_scene1', 93, 104, 'OPHELIA', 'And end his being: that done, he lets me go:'), ('hamlet_act2_scene1', 94, 105, 'OPHELIA', 'And, with his head over his shoulder turn’d,'), ('hamlet_act2_scene1', 95, 106, 'OPHELIA', 'He seem’d to find his way without his eyes;'), ('hamlet_act2_scene1', 96, 107, 'OPHELIA', 'For out o’ doors he went without their helps,'), ('hamlet_act2_scene1', 97, 108, 'OPHELIA', 'And, to the last, bended their light on me.'), ('hamlet_act2_scene1', 98, 109, 'POLONIUS', 'Come, go with me: I will go seek the king.'), ('hamlet_act2_scene1', 99, 110, 'POLONIUS', 'This is the very ecstasy of love,'), ('hamlet_act2_scene1', 100, 111, 'POLONIUS', 'Whose violent property fordoes itself'), ('hamlet_act2_scene1', 101, 112, 'POLONIUS', 'And leads the will to desperate undertakings'), ('hamlet_act2_scene1', 102, 113, 'POLONIUS', 'As oft as any passion under heaven'), ('hamlet_act2_scene1', 103, 114, 'POLONIUS', 'That does afflict our natures. I am sorry.'), ('hamlet_act2_scene1', 104, 115, 'POLONIUS', 'What, have you given him any hard words of late?'), ('hamlet_act2_scene1', 105, 116, 'OPHELIA', 'No, my good lord, but, as you did command,'), ('hamlet_act2_scene1', 106, 117, 'OPHELIA', 'I did repel his letters and denied'), ('hamlet_act2_scene1', 107, 118, 'OPHELIA', 'His access to me.'), ('hamlet_act2_scene1', 107, 119, 'POLONIUS', 'That hath made him mad.'), ('hamlet_act2_scene1', 108, 120, 'POLONIUS', 'I am sorry that with better heed and judgment'), ('hamlet_act2_scene1', 109, 121, 'POLONIUS', 'I had not quoted him: I fear’d he did but trifle,'), ('hamlet_act2_scene1', 110, 122, 'POLONIUS', 'And meant to wreck thee; but, beshrew my jealousy!'), ('hamlet_act2_scene1', 111, 123, 'POLONIUS', 'By heaven, it is as proper to our age'), ('hamlet_act2_scene1', 112, 124, 'POLONIUS', 'To cast beyond ourselves in our opinions'), ('hamlet_act2_scene1', 113, 125, 'POLONIUS', 'As it is common for the younger sort'), ('hamlet_act2_scene1', 114, 126, 'POLONIUS', 'To lack discretion. Come, go we to the king:'), ('hamlet_act2_scene1', 115, 127, 'POLONIUS', 'This must be known; which, being kept close, might move'), ('hamlet_act2_scene1', 116, 128, 'POLONIUS', 'More grief to hide than hate to utter love.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene2', 1, 0, 'KING', 'Welcome, dear Rosencrantz and Guildenstern!'), ('hamlet_act2_scene2', 2, 1, 'KING', 'Moreover that we much did long to see you,'), ('hamlet_act2_scene2', 3, 2, 'KING', 'The need we have to use you did provoke'), ('hamlet_act2_scene2', 4, 3, 'KING', 'Our hasty sending. Something have you heard'), ('hamlet_act2_scene2', 5, 4, 'KING', 'Of Hamlet’s transformation; so call it,'), ('hamlet_act2_scene2', 6, 5, 'KING', 'Sith nor the exterior nor the inward man'), ('hamlet_act2_scene2', 7, 6, 'KING', 'Resembles that it was. What it should be,'), ('hamlet_act2_scene2', 8, 7, 'KING', 'More than his father’s death, that thus hath put him'), ('hamlet_act2_scene2', 9, 8, 'KING', 'So much from the understanding of himself,'), ('hamlet_act2_scene2', 10, 9, 'KING', 'I cannot dream of: I entreat you both,'), ('hamlet_act2_scene2', 11, 10, 'KING', 'That, being of so young days brought up with him,'), ('hamlet_act2_scene2', 12, 11, 'KING', 'And sith so neighbour’d to his youth and havior,'), ('hamlet_act2_scene2', 13, 12, 'KING', 'That you vouchsafe your rest here in our court'), ('hamlet_act2_scene2', 14, 13, 'KING', 'Some little time: so by your companies'), ('hamlet_act2_scene2', 15, 14, 'KING', 'To draw him on to pleasures, and to gather,'), ('hamlet_act2_scene2', 16, 15, 'KING', 'So much as from occasion you may glean,'), ('hamlet_act2_scene2', 17, 16, 'KING', 'Whether aught, to us unknown, afflicts him thus,'), ('hamlet_act2_scene2', 18, 17, 'KING', 'That, open’d, lies within our remedy.'), ('hamlet_act2_scene2', 19, 18, 'QUEEN', 'Good gentlemen, he hath much talk’d of you;'), ('hamlet_act2_scene2', 20, 19, 'QUEEN', 'And sure I am two men there are not living'), ('hamlet_act2_scene2', 21, 20, 'QUEEN', 'To whom he more adheres. If it will please you'), ('hamlet_act2_scene2', 22, 21, 'QUEEN', 'To show us so much gentry and good will'), ('hamlet_act2_scene2', 23, 22, 'QUEEN', 'As to expend your time with us awhile,'), ('hamlet_act2_scene2', 24, 23, 'QUEEN', 'For the supply and profit of our hope,'), ('hamlet_act2_scene2', 25, 24, 'QUEEN', 'Your visitation shall receive such thanks'), ('hamlet_act2_scene2', 26, 25, 'QUEEN', 'As fits a king’s remembrance.'), ('hamlet_act2_scene2', 26, 26, 'ROSENCRANTZ', 'Both your majesties'), ('hamlet_act2_scene2', 27, 27, 'ROSENCRANTZ', 'Might, by the sovereign power you have of us,'), ('hamlet_act2_scene2', 28, 28, 'ROSENCRANTZ', 'Put your dread pleasures more into command'), ('hamlet_act2_scene2', 29, 29, 'ROSENCRANTZ', 'Than to entreaty.'), ('hamlet_act2_scene2', 29, 30, 'GUILDENSTERN', 'But we both obey,'), ('hamlet_act2_scene2', 30, 31, 'GUILDENSTERN', 'And here give up ourselves, in the full bent'), ('hamlet_act2_scene2', 31, 32, 'GUILDENSTERN', 'To lay our service freely at your feet,'), ('hamlet_act2_scene2', 32, 33, 'GUILDENSTERN', 'To be commanded.'), ('hamlet_act2_scene2', 32, 34, 'KING', 'Thanks, Rosencrantz and gentle Guildenstern.'), ('hamlet_act2_scene2', 33, 35, 'QUEEN', 'Thanks, Guildenstern and gentle Rosencrantz:'), ('hamlet_act2_scene2', 34, 36, 'QUEEN', 'And I beseech you instantly to visit'), ('hamlet_act2_scene2', 35, 37, 'QUEEN', 'My too much changed son. Go, some of you,'), ('hamlet_act2_scene2', 36, 38, 'QUEEN', 'And bring these gentlemen where Hamlet is.'), ('hamlet_act2_scene2', 37, 39, 'GUILDENSTERN', 'Heavens make our presence and our practices'), ('hamlet_act2_scene2', 38, 40, 'GUILDENSTERN', 'Pleasant and helpful to him!'), ('hamlet_act2_scene2', 38, 41, 'QUEEN', 'Ay, amen!'), ('hamlet_act2_scene2', 39, 42, 'POLONIUS', 'The ambassadors from Norway, my good lord,'), ('hamlet_act2_scene2', 40, 43, 'POLONIUS', 'Are joyfully return’d.'), ('hamlet_act2_scene2', 41, 44, 'KING', 'Thou still hast been the father of good news.'), ('hamlet_act2_scene2', 42, 45, 'POLONIUS', 'Have I, my lord? I assure my good liege,'), ('hamlet_act2_scene2', 43, 46, 'POLONIUS', 'I hold my duty, as I hold my soul,'), ('hamlet_act2_scene2', 44, 47, 'POLONIUS', 'Both to my God and to my gracious king:'), ('hamlet_act2_scene2', 45, 48, 'POLONIUS', 'And I do think, or else this brain of mine'), ('hamlet_act2_scene2', 46, 49, 'POLONIUS', 'Hunts not the trail of policy so sure'), ('hamlet_act2_scene2', 47, 50, 'POLONIUS', 'As it hath used to do, that I have found'), ('hamlet_act2_scene2', 48, 51, 'POLONIUS', 'The very cause of Hamlet’s lunacy.'), ('hamlet_act2_scene2', 49, 52, 'KING', 'O, speak of that; that do I long to hear.'), ('hamlet_act2_scene2', 50, 53, 'POLONIUS', 'Give first admittance to the ambassadors;'), ('hamlet_act2_scene2', 51, 54, 'POLONIUS', 'My news shall be the fruit to that great feast.'), ('hamlet_act2_scene2', 52, 55, 'KING', 'Thyself do grace to them, and bring them in.'), ('hamlet_act2_scene2', 53, 56, 'KING', 'He tells me, my dear Gertrude, he hath found'), ('hamlet_act2_scene2', 54, 57, 'KING', 'The head and source of all your son’s distemper.'), ('hamlet_act2_scene2', 55, 58, 'QUEEN', 'I doubt it is no other but the main;'), ('hamlet_act2_scene2', 56, 59, 'QUEEN', 'His father’s death, and our o’erhasty marriage.'), ('hamlet_act2_scene2', 57, 60, 'KING', 'Well, we shall sift him.'), ('hamlet_act2_scene2', 58, 61, 'VOLTIMAND', 'Most fair return of greetings and desires.'), ('hamlet_act2_scene2', 59, 62, 'VOLTIMAND', 'Upon our first, he sent out to suppress'), ('hamlet_act2_scene2', 60, 63, 'VOLTIMAND', 'His nephew’s levies; which to him appear’d'), ('hamlet_act2_scene2', 61, 64, 'VOLTIMAND', 'To be a preparation ’gainst the Polack;'), ('hamlet_act2_scene2', 62, 65, 'VOLTIMAND', 'But, better look’d into, he truly found'), ('hamlet_act2_scene2', 63, 66, 'VOLTIMAND', 'It was against your highness: whereat grieved,'), ('hamlet_act2_scene2', 64, 67, 'VOLTIMAND', 'That so his sickness, age and impotence'), ('hamlet_act2_scene2', 65, 68, 'VOLTIMAND', 'Was falsely borne in hand, sends out arrests'), ('hamlet_act2_scene2', 66, 69, 'VOLTIMAND', 'On Fortinbras; which he, in brief, obeys;'), ('hamlet_act2_scene2', 67, 70, 'VOLTIMAND', 'Receives rebuke from Norway, and in fine'), ('hamlet_act2_scene2', 68, 71, 'VOLTIMAND', 'Makes vow before his uncle never more'), ('hamlet_act2_scene2', 69, 72, 'VOLTIMAND', 'To give the assay of arms against your majesty.'), ('hamlet_act2_scene2', 70, 73, 'VOLTIMAND', 'Whereon old Norway, overcome with joy,'), ('hamlet_act2_scene2', 71, 74, 'VOLTIMAND', 'Gives him three thousand crowns in annual fee,'), ('hamlet_act2_scene2', 72, 75, 'VOLTIMAND', 'And his commission to employ those soldiers,'), ('hamlet_act2_scene2', 73, 76, 'VOLTIMAND', 'So levied as before, against the Polack:'), ('hamlet_act2_scene2', 74, 77, 'VOLTIMAND', 'With an entreaty, herein further shown,'), ('hamlet_act2_scene2', 75, 78, 'VOLTIMAND', 'That it might please you to give quiet pass'), ('hamlet_act2_scene2', 76, 79, 'VOLTIMAND', 'Through your dominions for this enterprise,'), ('hamlet_act2_scene2', 77, 80, 'VOLTIMAND', 'On such regards of safety and allowance'), ('hamlet_act2_scene2', 78, 81, 'VOLTIMAND', 'As therein are set down.'), ('hamlet_act2_scene2', 78, 82, 'KING', 'It likes us well;'), ('hamlet_act2_scene2', 79, 83, 'KING', 'And at our more consider’d time well read,'), ('hamlet_act2_scene2', 80, 84, 'KING', 'Answer, and think upon this business.'), ('hamlet_act2_scene2', 81, 85, 'KING', 'Meantime we thank you for your well-took labour:'), ('hamlet_act2_scene2', 82, 86, 'KING', 'Go to your rest; at night we’ll feast together:'), ('hamlet_act2_scene2', 83, 87, 'KING', 'Most welcome home!'), ('hamlet_act2_scene2', 83, 88, 'POLONIUS', 'This business is well ended.'), ('hamlet_act2_scene2', 84, 89, 'POLONIUS', 'My liege, and madam, to expostulate'), ('hamlet_act2_scene2', 85, 90, 'POLONIUS', 'What majesty should be, what duty is,'), ('hamlet_act2_scene2', 86, 91, 'POLONIUS', 'Why day is day, night night, and time is time,'), ('hamlet_act2_scene2', 87, 92, 'POLONIUS', 'Were nothing but to waste night, day and time.'), ('hamlet_act2_scene2', 88, 93, 'POLONIUS', 'Therefore, since brevity is the soul of wit,'), ('hamlet_act2_scene2', 89, 94, 'POLONIUS', 'And tediousness the limbs and outward flourishes,'), ('hamlet_act2_scene2', 90, 95, 'POLONIUS', 'I will be brief: your noble son is mad:'), ('hamlet_act2_scene2', 91, 96, 'POLONIUS', 'Mad call I it; for, to define true madness,'), ('hamlet_act2_scene2', 92, 97, 'POLONIUS', 'What is’t but to be nothing else but mad?'), ('hamlet_act2_scene2', 93, 98, 'POLONIUS', 'But let that go.'), ('hamlet_act2_scene2', 93, 99, 'QUEEN', 'More matter, with less art.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene2', 94, 100, 'POLONIUS', 'Madam, I swear I use no art at all. That he is'), ('hamlet_act2_scene2', 95, 101, 'POLONIUS', 'mad, ’tis true: ’tis true ’tis pity; And pity ’tis ’tis true:'), ('hamlet_act2_scene2', 96, 102, 'POLONIUS', 'a foolish figure; But farewell it, for I will use no art.'), ('hamlet_act2_scene2', 97, 103, 'POLONIUS', 'Mad let us grant him, then: and now remains That we find'), ('hamlet_act2_scene2', 98, 104, 'POLONIUS', 'out the cause of this effect, Or rather say, the cause of'), ('hamlet_act2_scene2', 99, 105, 'POLONIUS', 'this defect, For this effect defective comes by cause: Thus it remains,'), ('hamlet_act2_scene2', 100, 106, 'POLONIUS', 'and the remainder thus. Perpend. I have a daughter—have while she is'), ('hamlet_act2_scene2', 101, 107, 'POLONIUS', 'mine— Who, in her duty and obedience, mark, Hath given me this:'), ('hamlet_act2_scene2', 102, 108, 'POLONIUS', 'now gather, and surmise. “To the celestial and my soul’s idol, the'), ('hamlet_act2_scene2', 103, 109, 'POLONIUS', 'most beautified Ophelia,”— That’s an ill phrase, a vile phrase; “beautified” is'), ('hamlet_act2_scene2', 104, 110, 'POLONIUS', 'a vile phrase: but you shall hear. Thus: “In her excellent white'), ('hamlet_act2_scene2', 105, 111, 'POLONIUS', 'bosom, these, etc.”'), ('hamlet_act2_scene2', 105, 112, 'QUEEN', 'Came this from Hamlet to her?'), ('hamlet_act2_scene2', 106, 113, 'POLONIUS', 'Good madam, stay awhile; I will be faithful. “Doubt thou the stars'), ('hamlet_act2_scene2', 107, 114, 'POLONIUS', 'are fire; Doubt that the sun doth move; Doubt truth to be'), ('hamlet_act2_scene2', 108, 115, 'POLONIUS', 'a liar; But never doubt I love. “O dear Ophelia, I am'), ('hamlet_act2_scene2', 109, 116, 'POLONIUS', 'ill at these numbers; I have not art to reckon my groans:'), ('hamlet_act2_scene2', 110, 117, 'POLONIUS', 'but that I love thee best, O most best, believe it. Adieu.'), ('hamlet_act2_scene2', 111, 118, 'POLONIUS', '“Thine evermore most dear lady, whilst this machine is to him, Hamlet.”'), ('hamlet_act2_scene2', 112, 119, 'POLONIUS', 'This, in obedience, hath my daughter shown me, And more above, hath'), ('hamlet_act2_scene2', 113, 120, 'POLONIUS', 'his solicitings, As they fell out by time, by means and place,'), ('hamlet_act2_scene2', 114, 121, 'POLONIUS', 'All given to mine ear.'), ('hamlet_act2_scene2', 114, 122, 'KING', 'But how hath she'), ('hamlet_act2_scene2', 115, 123, 'KING', 'Received his love?'), ('hamlet_act2_scene2', 115, 124, 'POLONIUS', 'What do you think of me?'), ('hamlet_act2_scene2', 116, 125, 'KING', 'As of a man faithful and honourable.'), ('hamlet_act2_scene2', 117, 126, 'POLONIUS', 'I would fain prove so. But what might you think,'), ('hamlet_act2_scene2', 118, 127, 'POLONIUS', 'When I had seen this hot love on the wing—'), ('hamlet_act2_scene2', 119, 128, 'POLONIUS', 'As I perceived it, I must tell you that,'), ('hamlet_act2_scene2', 120, 129, 'POLONIUS', 'Before my daughter told me—what might you,'), ('hamlet_act2_scene2', 121, 130, 'POLONIUS', 'Or my dear majesty your queen here, think,'), ('hamlet_act2_scene2', 122, 131, 'POLONIUS', 'If I had play’d the desk or table-book,'), ('hamlet_act2_scene2', 123, 132, 'POLONIUS', 'Or given my heart a winking, mute and dumb,'), ('hamlet_act2_scene2', 124, 133, 'POLONIUS', 'Or look’d upon this love with idle sight;'), ('hamlet_act2_scene2', 125, 134, 'POLONIUS', 'What might you think? No, I went round to work,'), ('hamlet_act2_scene2', 126, 135, 'POLONIUS', 'And my young mistress thus I did bespeak:'), ('hamlet_act2_scene2', 127, 136, 'POLONIUS', '“Lord Hamlet is a prince, out of thy star;'), ('hamlet_act2_scene2', 128, 137, 'POLONIUS', 'This must not be:” and then I precepts gave her,'), ('hamlet_act2_scene2', 129, 138, 'POLONIUS', 'That she should lock herself from his resort,'), ('hamlet_act2_scene2', 130, 139, 'POLONIUS', 'Admit no messengers, receive no tokens.'), ('hamlet_act2_scene2', 131, 140, 'POLONIUS', 'Which done, she took the fruits of my advice;'), ('hamlet_act2_scene2', 132, 141, 'POLONIUS', 'And he, repulsed—a short tale to make—'), ('hamlet_act2_scene2', 133, 142, 'POLONIUS', 'Fell into a sadness, then into a fast,'), ('hamlet_act2_scene2', 134, 143, 'POLONIUS', 'Thence to a watch, thence into a weakness,'), ('hamlet_act2_scene2', 135, 144, 'POLONIUS', 'Thence to a lightness, and, by this declension,'), ('hamlet_act2_scene2', 136, 145, 'POLONIUS', 'Into the madness wherein now he raves,'), ('hamlet_act2_scene2', 137, 146, 'POLONIUS', 'And all we mourn for.'), ('hamlet_act2_scene2', 137, 147, 'KING', 'Do you think ’tis this?'), ('hamlet_act2_scene2', 138, 148, 'QUEEN', 'It may be, very likely.'), ('hamlet_act2_scene2', 139, 149, 'POLONIUS', 'Hath there been such a time—I’d fain know that—'), ('hamlet_act2_scene2', 140, 150, 'POLONIUS', 'That I have positively said “ ’Tis so,”'), ('hamlet_act2_scene2', 141, 151, 'POLONIUS', 'When it proved otherwise?'), ('hamlet_act2_scene2', 141, 152, 'KING', 'Not that I know.'), ('hamlet_act2_scene2', 142, 153, 'POLONIUS', 'Take this from this, if this be otherwise:'), ('hamlet_act2_scene2', 143, 154, 'POLONIUS', 'If circumstances lead me, I will find'), ('hamlet_act2_scene2', 144, 155, 'POLONIUS', 'Where truth is hid, though it were hid indeed'), ('hamlet_act2_scene2', 145, 156, 'POLONIUS', 'Within the centre.'), ('hamlet_act2_scene2', 145, 157, 'KING', 'How may we try it further?'), ('hamlet_act2_scene2', 146, 158, 'POLONIUS', 'You know, sometimes he walks four hours together'), ('hamlet_act2_scene2', 147, 159, 'POLONIUS', 'Here in the lobby.'), ('hamlet_act2_scene2', 147, 160, 'QUEEN', 'So he does indeed.'), ('hamlet_act2_scene2', 148, 161, 'POLONIUS', 'At such a time I’ll loose my daughter to him:'), ('hamlet_act2_scene2', 149, 162, 'POLONIUS', 'Be you and I behind an arras then;'), ('hamlet_act2_scene2', 150, 163, 'POLONIUS', 'Mark the encounter: if he love her not'), ('hamlet_act2_scene2', 151, 164, 'POLONIUS', 'And be not from his reason fall’n thereon,'), ('hamlet_act2_scene2', 152, 165, 'POLONIUS', 'Let me be no assistant for a state,'), ('hamlet_act2_scene2', 153, 166, 'POLONIUS', 'But keep a farm and carters.'), ('hamlet_act2_scene2', 153, 167, 'KING', 'We will try it.'), ('hamlet_act2_scene2', 154, 168, 'QUEEN', 'But, look, where sadly the poor wretch comes reading.'), ('hamlet_act2_scene2', 155, 169, 'POLONIUS', 'Away, I do beseech you, both away:'), ('hamlet_act2_scene2', 156, 170, 'POLONIUS', 'I’ll board him presently.'), ('hamlet_act2_scene2', 156, 171, 'HAMLET', 'Well, God-a-mercy.'), ('hamlet_act2_scene2', 157, 172, 'POLONIUS', 'Do you know me, my lord?'), ('hamlet_act2_scene2', 157, 173, 'HAMLET', 'Excellent well; you are a fishmonger.'), ('hamlet_act2_scene2', 158, 174, 'POLONIUS', 'Not I, my lord.'), ('hamlet_act2_scene2', 159, 175, 'HAMLET', 'Then I would you were so honest a man.'), ('hamlet_act2_scene2', 160, 176, 'POLONIUS', 'Honest, my lord!'), ('hamlet_act2_scene2', 161, 177, 'HAMLET', 'Ay, sir; to be honest, as this world goes, is to be'), ('hamlet_act2_scene2', 162, 178, 'HAMLET', 'one man picked out of ten thousand.'), ('hamlet_act2_scene2', 163, 179, 'POLONIUS', 'That’s very true, my lord.'), ('hamlet_act2_scene2', 164, 180, 'HAMLET', 'For if the sun breed maggots in a dead dog, being a'), ('hamlet_act2_scene2', 165, 181, 'HAMLET', 'god kissing carrion—Have you a daughter?'), ('hamlet_act2_scene2', 165, 182, 'POLONIUS', 'I have, my lord.'), ('hamlet_act2_scene2', 166, 183, 'HAMLET', 'Let her not walk i’ the sun: conception is a blessing: but'), ('hamlet_act2_scene2', 167, 184, 'HAMLET', 'not as your daughter may conceive. Friend, look to’t.'), ('hamlet_act2_scene2', 168, 185, 'POLONIUS', 'How say you by that? Still harping on my daughter: yet he'), ('hamlet_act2_scene2', 169, 186, 'POLONIUS', 'knew me not at first; he said I was a fishmonger: he'), ('hamlet_act2_scene2', 170, 187, 'POLONIUS', 'is far gone, far gone: and truly in my youth I suffered'), ('hamlet_act2_scene2', 171, 188, 'POLONIUS', 'much extremity for love; very near this. I’ll speak to him again.'), ('hamlet_act2_scene2', 172, 189, 'POLONIUS', 'What do you read, my lord?'), ('hamlet_act2_scene2', 172, 190, 'HAMLET', 'Words, words, words.'), ('hamlet_act2_scene2', 173, 191, 'POLONIUS', 'What is the matter, my lord?'), ('hamlet_act2_scene2', 173, 192, 'HAMLET', 'Between who?'), ('hamlet_act2_scene2', 174, 193, 'POLONIUS', 'I mean, the matter that you read, my lord.'), ('hamlet_act2_scene2', 175, 194, 'HAMLET', 'Slanders, sir: for the satirical rogue says here that old men have'), ('hamlet_act2_scene2', 176, 195, 'HAMLET', 'grey beards, that their faces are wrinkled, their eyes purging thick amber'), ('hamlet_act2_scene2', 177, 196, 'HAMLET', 'and plum-tree gum and that they have a plentiful lack of wit,'), ('hamlet_act2_scene2', 178, 197, 'HAMLET', 'together with most weak hams: all which, sir, though I most powerfully'), ('hamlet_act2_scene2', 179, 198, 'HAMLET', 'and potently believe, yet I hold it not honesty to have it'), ('hamlet_act2_scene2', 180, 199, 'HAMLET', 'thus set down, for yourself, sir, should be old as I am,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene2', 181, 200, 'HAMLET', 'if like a crab you could go backward.'), ('hamlet_act2_scene2', 182, 201, 'POLONIUS', 'Though this be madness, yet there is method in’t. Will you walk'), ('hamlet_act2_scene2', 183, 202, 'POLONIUS', 'out of the air, my lord?'), ('hamlet_act2_scene2', 183, 203, 'HAMLET', 'Into my grave.'), ('hamlet_act2_scene2', 184, 204, 'POLONIUS', 'Indeed, that is out o’ the air. How pregnant sometimes his replies'), ('hamlet_act2_scene2', 185, 205, 'POLONIUS', 'are! a happiness that often madness hits on, which reason and sanity'), ('hamlet_act2_scene2', 186, 206, 'POLONIUS', 'could not so prosperously be delivered of. I will leave him, and'), ('hamlet_act2_scene2', 187, 207, 'POLONIUS', 'suddenly contrive the means of meeting between him and my daughter.—My honourable'), ('hamlet_act2_scene2', 188, 208, 'POLONIUS', 'lord, I will most humbly take my leave of you.'), ('hamlet_act2_scene2', 189, 209, 'HAMLET', 'You cannot, sir, take from me any thing that I will more'), ('hamlet_act2_scene2', 190, 210, 'HAMLET', 'willingly part withal: except my life, except my life, except my life.'), ('hamlet_act2_scene2', 191, 211, 'POLONIUS', 'Fare you well, my lord.'), ('hamlet_act2_scene2', 191, 212, 'HAMLET', 'These tedious old fools!'), ('hamlet_act2_scene2', 192, 213, 'POLONIUS', 'You go to seek the Lord Hamlet; there he is.'), ('hamlet_act2_scene2', 193, 214, 'ROSENCRANTZ', 'God save you, sir!'), ('hamlet_act2_scene2', 193, 215, 'GUILDENSTERN', 'My honoured lord!'), ('hamlet_act2_scene2', 194, 216, 'ROSENCRANTZ', 'My most dear lord!'), ('hamlet_act2_scene2', 195, 217, 'HAMLET', 'My excellent good friends! How dost thou, Guildenstern? Ah, Rosencrantz! Good lads,'), ('hamlet_act2_scene2', 196, 218, 'HAMLET', 'how do ye both?'), ('hamlet_act2_scene2', 197, 219, 'ROSENCRANTZ', 'As the indifferent children of the earth.'), ('hamlet_act2_scene2', 198, 220, 'GUILDENSTERN', 'Happy, in that we are not over-happy;'), ('hamlet_act2_scene2', 199, 221, 'GUILDENSTERN', 'On fortune’s cap we are not the very button.'), ('hamlet_act2_scene2', 200, 222, 'HAMLET', 'Nor the soles of her shoe?'), ('hamlet_act2_scene2', 200, 223, 'ROSENCRANTZ', 'Neither, my lord.'), ('hamlet_act2_scene2', 201, 224, 'HAMLET', 'Then you live about her waist, or in the middle of her favours?'), ('hamlet_act2_scene2', 202, 225, 'GUILDENSTERN', '’Faith, her privates we.'), ('hamlet_act2_scene2', 203, 226, 'HAMLET', 'In the secret parts of fortune? O, most true; she is a'), ('hamlet_act2_scene2', 204, 227, 'HAMLET', 'strumpet. What’s the news?'), ('hamlet_act2_scene2', 205, 228, 'ROSENCRANTZ', 'None, my lord, but that the world’s grown honest.'), ('hamlet_act2_scene2', 206, 229, 'HAMLET', 'Then is doomsday near: but your news is not true. Let me'), ('hamlet_act2_scene2', 207, 230, 'HAMLET', 'question more in particular: what have you, my good friends, deserved at'), ('hamlet_act2_scene2', 208, 231, 'HAMLET', 'the hands of fortune, that she sends you to prison hither?'), ('hamlet_act2_scene2', 209, 232, 'GUILDENSTERN', 'Prison, my lord!'), ('hamlet_act2_scene2', 209, 233, 'HAMLET', 'Denmark’s a prison.'), ('hamlet_act2_scene2', 210, 234, 'ROSENCRANTZ', 'Then is the world one.'), ('hamlet_act2_scene2', 211, 235, 'HAMLET', 'A goodly one; in which there are many confines, wards and dungeons,'), ('hamlet_act2_scene2', 212, 236, 'HAMLET', 'Denmark being one o’ the worst.'), ('hamlet_act2_scene2', 212, 237, 'ROSENCRANTZ', 'We think not so, my lord.'), ('hamlet_act2_scene2', 213, 238, 'HAMLET', 'Why, then, ’tis none to you; for there is nothing either good'), ('hamlet_act2_scene2', 214, 239, 'HAMLET', 'or bad, but thinking makes it so: to me it is a'), ('hamlet_act2_scene2', 215, 240, 'HAMLET', 'prison.'), ('hamlet_act2_scene2', 216, 241, 'ROSENCRANTZ', 'Why then, your ambition makes it one; ’tis too narrow for your mind.'), ('hamlet_act2_scene2', 217, 242, 'HAMLET', 'O God, I could be bounded in a nut-shell and count myself'), ('hamlet_act2_scene2', 218, 243, 'HAMLET', 'a king of infinite space, were it not that I have bad'), ('hamlet_act2_scene2', 219, 244, 'HAMLET', 'dreams.'), ('hamlet_act2_scene2', 220, 245, 'GUILDENSTERN', 'Which dreams indeed are ambition, for the very substance of the ambitious'), ('hamlet_act2_scene2', 221, 246, 'GUILDENSTERN', 'is merely the shadow of a dream.'), ('hamlet_act2_scene2', 222, 247, 'HAMLET', 'A dream itself is but a shadow.'), ('hamlet_act2_scene2', 223, 248, 'ROSENCRANTZ', 'Truly, and I hold ambition of so airy and light a quality'), ('hamlet_act2_scene2', 224, 249, 'ROSENCRANTZ', 'that it is but a shadow’s shadow.'), ('hamlet_act2_scene2', 225, 250, 'HAMLET', 'Then are our beggars bodies, and our monarchs and outstretched heroes the'), ('hamlet_act2_scene2', 226, 251, 'HAMLET', 'beggars’ shadows. Shall we to the court? for, by my fay, I'), ('hamlet_act2_scene2', 227, 252, 'HAMLET', 'cannot reason.'), ('hamlet_act2_scene2', 227, 253, 'ROSENCRANTZ GUILDENSTERN', 'We’ll wait upon you.'), ('hamlet_act2_scene2', 228, 254, 'HAMLET', 'No such matter: I will not sort you with the rest of'), ('hamlet_act2_scene2', 229, 255, 'HAMLET', 'my servants, for, to speak to you like an honest man, I'), ('hamlet_act2_scene2', 230, 256, 'HAMLET', 'am most dreadfully attended. But, in the beaten way of friendship, what'), ('hamlet_act2_scene2', 231, 257, 'HAMLET', 'make you at Elsinore?'), ('hamlet_act2_scene2', 232, 258, 'ROSENCRANTZ', 'To visit you, my lord; no other occasion.'), ('hamlet_act2_scene2', 233, 259, 'HAMLET', 'Beggar that I am, I am even poor in thanks; but I'), ('hamlet_act2_scene2', 234, 260, 'HAMLET', 'thank you: and sure, dear friends, my thanks are too dear a'), ('hamlet_act2_scene2', 235, 261, 'HAMLET', 'halfpenny. Were you not sent for? Is it your own inclining? Is'), ('hamlet_act2_scene2', 236, 262, 'HAMLET', 'it a free visitation? Come, deal justly with me: come, come; nay,'), ('hamlet_act2_scene2', 237, 263, 'HAMLET', 'speak.'), ('hamlet_act2_scene2', 237, 264, 'GUILDENSTERN', 'What should we say, my lord?'), ('hamlet_act2_scene2', 238, 265, 'HAMLET', 'Why, any thing, but to the purpose. You were sent for; and'), ('hamlet_act2_scene2', 239, 266, 'HAMLET', 'there is a kind of confession in your looks which your modesties'), ('hamlet_act2_scene2', 240, 267, 'HAMLET', 'have not craft enough to colour: I know the good king and'), ('hamlet_act2_scene2', 241, 268, 'HAMLET', 'queen have sent for you.'), ('hamlet_act2_scene2', 241, 269, 'ROSENCRANTZ', 'To what end, my lord?'), ('hamlet_act2_scene2', 242, 270, 'HAMLET', 'That you must teach me. But let me conjure you, by the'), ('hamlet_act2_scene2', 243, 271, 'HAMLET', 'rights of our fellowship, by the consonancy of our youth, by the'), ('hamlet_act2_scene2', 244, 272, 'HAMLET', 'obligation of our ever-preserved love, and by what more dear a better'), ('hamlet_act2_scene2', 245, 273, 'HAMLET', 'proposer could charge you withal, be even and direct with me, whether'), ('hamlet_act2_scene2', 246, 274, 'HAMLET', 'you were sent for, or no?'), ('hamlet_act2_scene2', 246, 275, 'ROSENCRANTZ', 'What say you?'), ('hamlet_act2_scene2', 247, 276, 'HAMLET', 'Nay, then, I have an eye of you.—If you love me, hold not off.'), ('hamlet_act2_scene2', 248, 277, 'GUILDENSTERN', 'My lord, we were sent for.'), ('hamlet_act2_scene2', 249, 278, 'HAMLET', 'I will tell you why; so shall my anticipation prevent your discovery,'), ('hamlet_act2_scene2', 250, 279, 'HAMLET', 'and your secrecy to the king and queen moult no feather. I'), ('hamlet_act2_scene2', 251, 280, 'HAMLET', 'have of late—but wherefore I know not—lost all my mirth, forgone all'), ('hamlet_act2_scene2', 252, 281, 'HAMLET', 'custom of exercises; and indeed it goes so heavily with my disposition'), ('hamlet_act2_scene2', 253, 282, 'HAMLET', 'that this goodly frame, the earth, seems to me a sterile promontory,'), ('hamlet_act2_scene2', 254, 283, 'HAMLET', 'this most excellent canopy, the air, look you, this brave o’erhanging firmament,'), ('hamlet_act2_scene2', 255, 284, 'HAMLET', 'this majestical roof fretted with golden fire, why, it appears no other'), ('hamlet_act2_scene2', 256, 285, 'HAMLET', 'thing to me than a foul and pestilent congregation of vapours. What'), ('hamlet_act2_scene2', 257, 286, 'HAMLET', 'a piece of work is a man! how noble in reason! how'), ('hamlet_act2_scene2', 258, 287, 'HAMLET', 'infinite in faculty! in form and moving how express and admirable! in'), ('hamlet_act2_scene2', 259, 288, 'HAMLET', 'action how like an angel! in apprehension how like a god! the'), ('hamlet_act2_scene2', 260, 289, 'HAMLET', 'beauty of the world! the paragon of animals! And yet, to me,'), ('hamlet_act2_scene2', 261, 290, 'HAMLET', 'what is this quintessence of dust? man delights not me: no, nor'), ('hamlet_act2_scene2', 262, 291, 'HAMLET', 'woman neither, though by your smiling you seem to say so.'), ('hamlet_act2_scene2', 263, 292, 'ROSENCRANTZ', 'My lord, there was no such stuff in my thoughts.'), ('hamlet_act2_scene2', 264, 293, 'HAMLET', 'Why did you laugh then, when I said “man delights not me”?'), ('hamlet_act2_scene2', 265, 294, 'ROSENCRANTZ', 'To think, my lord, if you delight not in man, what lenten'), ('hamlet_act2_scene2', 266, 295, 'ROSENCRANTZ', 'entertainment the players shall receive from you: we coted them on the'), ('hamlet_act2_scene2', 267, 296, 'ROSENCRANTZ', 'way; and hither are they coming, to offer you service.'), ('hamlet_act2_scene2', 268, 297, 'HAMLET', 'He that plays the king shall be welcome; his majesty shall have'), ('hamlet_act2_scene2', 269, 298, 'HAMLET', 'tribute of me; the adventurous knight shall use his foil and target;'), ('hamlet_act2_scene2', 270, 299, 'HAMLET', 'the lover shall not sigh gratis; the humourous man shall end his');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene2', 271, 300, 'HAMLET', 'part in peace; the clown shall make those laugh whose lungs are'), ('hamlet_act2_scene2', 272, 301, 'HAMLET', 'tickled o’ the sere; and the lady shall say her mind freely,'), ('hamlet_act2_scene2', 273, 302, 'HAMLET', 'or the blank verse shall halt for’t. What players are they?'), ('hamlet_act2_scene2', 274, 303, 'ROSENCRANTZ', 'Even those you were wont to take delight in, the tragedians of the city.'), ('hamlet_act2_scene2', 275, 304, 'HAMLET', 'How chances it they travel? their residence, both in reputation and profit,'), ('hamlet_act2_scene2', 276, 305, 'HAMLET', 'was better both ways.'), ('hamlet_act2_scene2', 277, 306, 'ROSENCRANTZ', 'I think their inhibition comes by the means of the late innovation.'), ('hamlet_act2_scene2', 278, 307, 'HAMLET', 'Do they hold the same estimation they did when I was in'), ('hamlet_act2_scene2', 279, 308, 'HAMLET', 'the city? are they so followed?'), ('hamlet_act2_scene2', 279, 309, 'ROSENCRANTZ', 'No, indeed, are they not.'), ('hamlet_act2_scene2', 280, 310, 'HAMLET', 'How comes it? do they grow rusty?'), ('hamlet_act2_scene2', 281, 311, 'ROSENCRANTZ', 'Nay, their endeavour keeps in the wonted pace: but there is, sir,'), ('hamlet_act2_scene2', 282, 312, 'ROSENCRANTZ', 'an aery of children, little eyases, that cry out on the top'), ('hamlet_act2_scene2', 283, 313, 'ROSENCRANTZ', 'of question, and are most tyrannically clapped for’t: these are now the'), ('hamlet_act2_scene2', 284, 314, 'ROSENCRANTZ', 'fashion, and so berattle the common stages—so they call them—that many wearing'), ('hamlet_act2_scene2', 285, 315, 'ROSENCRANTZ', 'rapiers are afraid of goose-quills and dare scarce come thither.'), ('hamlet_act2_scene2', 286, 316, 'HAMLET', 'What, are they children? who maintains ’em? how are they escoted? Will'), ('hamlet_act2_scene2', 287, 317, 'HAMLET', 'they pursue the quality no longer than they can sing? will they'), ('hamlet_act2_scene2', 288, 318, 'HAMLET', 'not say afterwards, if they should grow themselves to common players—as it'), ('hamlet_act2_scene2', 289, 319, 'HAMLET', 'is most like, if their means are no better—their writers do them'), ('hamlet_act2_scene2', 290, 320, 'HAMLET', 'wrong, to make them exclaim against their own succession?'), ('hamlet_act2_scene2', 291, 321, 'ROSENCRANTZ', '’Faith, there has been much to do on both sides; and the'), ('hamlet_act2_scene2', 292, 322, 'ROSENCRANTZ', 'nation holds it no sin to tarre them to controversy: there was,'), ('hamlet_act2_scene2', 293, 323, 'ROSENCRANTZ', 'for a while, no money bid for argument, unless the poet and'), ('hamlet_act2_scene2', 294, 324, 'ROSENCRANTZ', 'the player went to cuffs in the question.'), ('hamlet_act2_scene2', 295, 325, 'HAMLET', 'Is’t possible?'), ('hamlet_act2_scene2', 296, 326, 'GUILDENSTERN', 'O, there has been much throwing about of brains.'), ('hamlet_act2_scene2', 297, 327, 'HAMLET', 'Do the boys carry it away?'), ('hamlet_act2_scene2', 298, 328, 'ROSENCRANTZ', 'Ay, that they do, my lord; Hercules and his load too.'), ('hamlet_act2_scene2', 299, 329, 'HAMLET', 'It is not very strange; for mine uncle is king of Denmark,'), ('hamlet_act2_scene2', 300, 330, 'HAMLET', 'and those that would make mows at him while my father lived,'), ('hamlet_act2_scene2', 301, 331, 'HAMLET', 'give twenty, forty, fifty, an hundred ducats a-piece for his picture in'), ('hamlet_act2_scene2', 302, 332, 'HAMLET', 'little. ’Sblood, there is something in this more than natural, if philosophy'), ('hamlet_act2_scene2', 303, 333, 'HAMLET', 'could find it out.'), ('hamlet_act2_scene2', 303, 334, 'GUILDENSTERN', 'There are the players.'), ('hamlet_act2_scene2', 304, 335, 'HAMLET', 'Gentlemen, you are welcome to Elsinore. Your hands, come then: the appurtenance'), ('hamlet_act2_scene2', 305, 336, 'HAMLET', 'of welcome is fashion and ceremony: let me comply with you in'), ('hamlet_act2_scene2', 306, 337, 'HAMLET', 'this garb, lest my extent to the players, which, I tell you,'), ('hamlet_act2_scene2', 307, 338, 'HAMLET', 'must show fairly outward, should more appear like entertainment than yours. You'), ('hamlet_act2_scene2', 308, 339, 'HAMLET', 'are welcome: but my uncle-father and aunt-mother are deceived.'), ('hamlet_act2_scene2', 309, 340, 'GUILDENSTERN', 'In what, my dear lord?'), ('hamlet_act2_scene2', 310, 341, 'HAMLET', 'I am but mad north-north-west: when the wind is southerly I know'), ('hamlet_act2_scene2', 311, 342, 'HAMLET', 'a hawk from a handsaw.'), ('hamlet_act2_scene2', 311, 343, 'POLONIUS', 'Well be with you, gentlemen!'), ('hamlet_act2_scene2', 312, 344, 'HAMLET', 'Hark you, Guildenstern; and you too: at each ear a hearer: that'), ('hamlet_act2_scene2', 313, 345, 'HAMLET', 'great baby you see there is not yet out of his swaddling-clouts.'), ('hamlet_act2_scene2', 314, 346, 'ROSENCRANTZ', 'Happily he’s the second time come to them; for they say an'), ('hamlet_act2_scene2', 315, 347, 'ROSENCRANTZ', 'old man is twice a child.'), ('hamlet_act2_scene2', 316, 348, 'HAMLET', 'I will prophesy he comes to tell me of the players; mark'), ('hamlet_act2_scene2', 317, 349, 'HAMLET', 'it. You say right, sir: o’ Monday morning; ’twas so indeed.'), ('hamlet_act2_scene2', 318, 350, 'POLONIUS', 'My lord, I have news to tell you.'), ('hamlet_act2_scene2', 319, 351, 'HAMLET', 'My lord, I have news to tell you. When Roscius was an actor in Rome—'), ('hamlet_act2_scene2', 320, 352, 'POLONIUS', 'The actors are come hither, my lord.'), ('hamlet_act2_scene2', 321, 353, 'HAMLET', 'Buz, buz!'), ('hamlet_act2_scene2', 321, 354, 'POLONIUS', 'Upon mine honour—'), ('hamlet_act2_scene2', 322, 355, 'HAMLET', 'Then came each actor on his ass—'), ('hamlet_act2_scene2', 323, 356, 'POLONIUS', 'The best actors in the world, either for tragedy, comedy, history, pastoral,'), ('hamlet_act2_scene2', 324, 357, 'POLONIUS', 'pastoral-comical, historical-pastoral, tragical-historical, tragical-comical-historical-pastoral, scene individable, or poem unlimited: Seneca cannot be'), ('hamlet_act2_scene2', 325, 358, 'POLONIUS', 'too heavy, nor Plautus too light. For the law of writ and'), ('hamlet_act2_scene2', 326, 359, 'POLONIUS', 'the liberty, these are the only men.'), ('hamlet_act2_scene2', 327, 360, 'HAMLET', 'O Jephthah, judge of Israel, what a treasure hadst thou!'), ('hamlet_act2_scene2', 328, 361, 'POLONIUS', 'What a treasure had he, my lord?'), ('hamlet_act2_scene2', 329, 362, 'HAMLET', 'Why, “One fair daughter and no more, The which he loved passing well.”'), ('hamlet_act2_scene2', 330, 363, 'POLONIUS', 'Still on my daughter.'), ('hamlet_act2_scene2', 331, 364, 'HAMLET', 'Am I not i’ the right, old Jephthah?'), ('hamlet_act2_scene2', 332, 365, 'POLONIUS', 'If you call me Jephthah, my lord, I have a daughter that'), ('hamlet_act2_scene2', 333, 366, 'POLONIUS', 'I love passing well.'), ('hamlet_act2_scene2', 333, 367, 'HAMLET', 'Nay, that follows not.'), ('hamlet_act2_scene2', 334, 368, 'POLONIUS', 'What follows, then, my lord?'), ('hamlet_act2_scene2', 335, 369, 'HAMLET', 'Why, “As by lot, God wot,” and then, you know, “It came'), ('hamlet_act2_scene2', 336, 370, 'HAMLET', 'to pass, as most like it was,”— the first row of the'), ('hamlet_act2_scene2', 337, 371, 'HAMLET', 'pious chanson will show you more; for look, where my abridgement comes.'), ('hamlet_act2_scene2', 338, 372, 'FIRST PLAYER', 'What speech, my lord?'), ('hamlet_act2_scene2', 339, 373, 'HAMLET', 'I heard thee speak me a speech once, but it was never'), ('hamlet_act2_scene2', 340, 374, 'HAMLET', 'acted; or, if it was, not above once; for the play, I'), ('hamlet_act2_scene2', 341, 375, 'HAMLET', 'remember, pleased not the million; ’twas caviare to the general: but it'), ('hamlet_act2_scene2', 342, 376, 'HAMLET', 'was—as I received it, and others, whose judgments in such matters cried'), ('hamlet_act2_scene2', 343, 377, 'HAMLET', 'in the top of mine—an excellent play, well digested in the scenes,'), ('hamlet_act2_scene2', 344, 378, 'HAMLET', 'set down with as much modesty as cunning. I remember, one said'), ('hamlet_act2_scene2', 345, 379, 'HAMLET', 'there were no sallets in the lines to make the matter savoury,'), ('hamlet_act2_scene2', 346, 380, 'HAMLET', 'nor no matter in the phrase that might indict the author of'), ('hamlet_act2_scene2', 347, 381, 'HAMLET', 'affectation; but called it an honest method, as wholesome as sweet, and'), ('hamlet_act2_scene2', 348, 382, 'HAMLET', 'by very much more handsome than fine. One speech in it I'), ('hamlet_act2_scene2', 349, 383, 'HAMLET', 'chiefly loved: ’twas Aeneas’ tale to Dido; and thereabout of it especially,'), ('hamlet_act2_scene2', 350, 384, 'HAMLET', 'where he speaks of Priam’s slaughter: if it live in your memory,'), ('hamlet_act2_scene2', 351, 385, 'HAMLET', 'begin at this line: let me see, let me see— “The rugged'), ('hamlet_act2_scene2', 352, 386, 'HAMLET', 'Pyrrhus, like the Hyrcanian beast,” —it is not so:—it begins with Pyrrhus:—'), ('hamlet_act2_scene2', 353, 387, 'HAMLET', '“The rugged Pyrrhus, he whose sable arms, Black as his purpose, did'), ('hamlet_act2_scene2', 354, 388, 'HAMLET', 'the night resemble When he lay couched in the ominous horse, Hath'), ('hamlet_act2_scene2', 355, 389, 'HAMLET', 'now this dread and black complexion smear’d With heraldry more dismal; head'), ('hamlet_act2_scene2', 356, 390, 'HAMLET', 'to foot Now is he total gules; horridly trick’d With blood of'), ('hamlet_act2_scene2', 357, 391, 'HAMLET', 'fathers, mothers, daughters, sons, Baked and impasted with the parching streets, That'), ('hamlet_act2_scene2', 358, 392, 'HAMLET', 'lend a tyrannous and damned light To their lord’s murder: roasted in'), ('hamlet_act2_scene2', 359, 393, 'HAMLET', 'wrath and fire, And thus o’er-sized with coagulate gore, With eyes like'), ('hamlet_act2_scene2', 360, 394, 'HAMLET', 'carbuncles, the hellish Pyrrhus Old grandsire Priam seeks.” So, proceed you.'), ('hamlet_act2_scene2', 361, 395, 'POLONIUS', '’Fore God, my lord, well spoken, with good accent and good discretion.'), ('hamlet_act2_scene2', 362, 396, 'FIRST PLAYER', '“Anon he finds him Striking too short at Greeks; his antique sword,'), ('hamlet_act2_scene2', 363, 397, 'FIRST PLAYER', 'Rebellious to his arm, lies where it falls, Repugnant to command: unequal'), ('hamlet_act2_scene2', 364, 398, 'FIRST PLAYER', 'match’d, Pyrrhus at Priam drives; in rage strikes wide; But with the'), ('hamlet_act2_scene2', 365, 399, 'FIRST PLAYER', 'whiff and wind of his fell sword The unnerved father falls. Then');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene2', 366, 400, 'FIRST PLAYER', 'senseless Ilium, Seeming to feel this blow, with flaming top Stoops to'), ('hamlet_act2_scene2', 367, 401, 'FIRST PLAYER', 'his base, and with a hideous crash Takes prisoner Pyrrhus’ ear: for,'), ('hamlet_act2_scene2', 368, 402, 'FIRST PLAYER', 'lo! his sword, Which was declining on the milky head Of reverend'), ('hamlet_act2_scene2', 369, 403, 'FIRST PLAYER', 'Priam, seem’d i’ the air to stick: So, as a painted tyrant,'), ('hamlet_act2_scene2', 370, 404, 'FIRST PLAYER', 'Pyrrhus stood, And like a neutral to his will and matter, Did'), ('hamlet_act2_scene2', 371, 405, 'FIRST PLAYER', 'nothing. But, as we often see, against some storm, A silence in'), ('hamlet_act2_scene2', 372, 406, 'FIRST PLAYER', 'the heavens, the rack stand still, The bold winds speechless and the'), ('hamlet_act2_scene2', 373, 407, 'FIRST PLAYER', 'orb below As hush as death, anon the dreadful thunder Doth rend'), ('hamlet_act2_scene2', 374, 408, 'FIRST PLAYER', 'the region, so, after Pyrrhus’ pause, Aroused vengeance sets him new a-work;'), ('hamlet_act2_scene2', 375, 409, 'FIRST PLAYER', 'And never did the Cyclops’ hammers fall On Mars’s armour forged for'), ('hamlet_act2_scene2', 376, 410, 'FIRST PLAYER', 'proof eterne With less remorse than Pyrrhus’ bleeding sword Now falls on'), ('hamlet_act2_scene2', 377, 411, 'FIRST PLAYER', 'Priam. Out, out, thou strumpet, Fortune! All you gods, In general synod'), ('hamlet_act2_scene2', 378, 412, 'FIRST PLAYER', 'take away her power; Break all the spokes and fellies from her'), ('hamlet_act2_scene2', 379, 413, 'FIRST PLAYER', 'wheel, And bowl the round nave down the hill of heaven, As'), ('hamlet_act2_scene2', 380, 414, 'FIRST PLAYER', 'low as to the fiends!”'), ('hamlet_act2_scene2', 380, 415, 'POLONIUS', 'This is too long.'), ('hamlet_act2_scene2', 381, 416, 'HAMLET', 'It shall to the barber’s, with your beard. Prithee, say on: he’s'), ('hamlet_act2_scene2', 382, 417, 'HAMLET', 'for a jig or a tale of bawdry, or he sleeps: say'), ('hamlet_act2_scene2', 383, 418, 'HAMLET', 'on: come to Hecuba.'), ('hamlet_act2_scene2', 384, 419, 'FIRST PLAYER', '“But who, O, who had seen the mobled queen—”'), ('hamlet_act2_scene2', 385, 420, 'HAMLET', '“The mobled queen?”'), ('hamlet_act2_scene2', 385, 421, 'POLONIUS', 'That’s good; “mobled queen” is good.'), ('hamlet_act2_scene2', 386, 422, 'FIRST PLAYER', '“Run barefoot up and down, threatening the flames With bisson rheum; a'), ('hamlet_act2_scene2', 387, 423, 'FIRST PLAYER', 'clout upon that head Where late the diadem stood, and for a'), ('hamlet_act2_scene2', 388, 424, 'FIRST PLAYER', 'robe, About her lank and all o’er-teemed loins, A blanket, in the'), ('hamlet_act2_scene2', 389, 425, 'FIRST PLAYER', 'alarm of fear caught up; Who this had seen, with tongue in'), ('hamlet_act2_scene2', 390, 426, 'FIRST PLAYER', 'venom steep’d, ’Gainst Fortune’s state would treason have pronounced: But if the'), ('hamlet_act2_scene2', 391, 427, 'FIRST PLAYER', 'gods themselves did see her then When she saw Pyrrhus make malicious'), ('hamlet_act2_scene2', 392, 428, 'FIRST PLAYER', 'sport In mincing with his sword her husband’s limbs, The instant burst'), ('hamlet_act2_scene2', 393, 429, 'FIRST PLAYER', 'of clamour that she made, Unless things mortal move them not at'), ('hamlet_act2_scene2', 394, 430, 'FIRST PLAYER', 'all, Would have made milch the burning eyes of heaven, And passion'), ('hamlet_act2_scene2', 395, 431, 'FIRST PLAYER', 'in the gods.”'), ('hamlet_act2_scene2', 396, 432, 'POLONIUS', 'Look, whether he has not turned his colour and has tears in’s'), ('hamlet_act2_scene2', 397, 433, 'POLONIUS', 'eyes. Pray you, no more.'), ('hamlet_act2_scene2', 398, 434, 'HAMLET', '’Tis well; I’ll have thee speak out the rest soon. Good my'), ('hamlet_act2_scene2', 399, 435, 'HAMLET', 'lord, will you see the players well bestowed? Do you hear, let'), ('hamlet_act2_scene2', 400, 436, 'HAMLET', 'them be well used; for they are the abstract and brief chronicles'), ('hamlet_act2_scene2', 401, 437, 'HAMLET', 'of the time: after your death you were better have a bad'), ('hamlet_act2_scene2', 402, 438, 'HAMLET', 'epitaph than their ill report while you live.'), ('hamlet_act2_scene2', 403, 439, 'POLONIUS', 'My lord, I will use them according to their desert.'), ('hamlet_act2_scene2', 404, 440, 'HAMLET', 'God’s bodykins, man, much better: use every man after his desert, and'), ('hamlet_act2_scene2', 405, 441, 'HAMLET', 'who should ’scape whipping? Use them after your own honour and dignity:'), ('hamlet_act2_scene2', 406, 442, 'HAMLET', 'the less they deserve, the more merit is in your bounty. Take'), ('hamlet_act2_scene2', 407, 443, 'HAMLET', 'them in.'), ('hamlet_act2_scene2', 407, 444, 'POLONIUS', 'Come, sirs.'), ('hamlet_act2_scene2', 408, 445, 'HAMLET', 'Follow him, friends: we’ll hear a play to-morrow. Dost thou hear me,'), ('hamlet_act2_scene2', 409, 446, 'HAMLET', 'old friend; can you play the Murder of Gonzago?'), ('hamlet_act2_scene2', 410, 447, 'FIRST PLAYER', 'Ay, my lord.'), ('hamlet_act2_scene2', 411, 448, 'HAMLET', 'We’ll ha’t to-morrow night. You could, for a need, study a speech'), ('hamlet_act2_scene2', 412, 449, 'HAMLET', 'of some dozen or sixteen lines, which I would set down and'), ('hamlet_act2_scene2', 413, 450, 'HAMLET', 'insert in’t, could you not?'), ('hamlet_act2_scene2', 413, 451, 'FIRST PLAYER', 'Ay, my lord.'), ('hamlet_act2_scene2', 414, 452, 'HAMLET', 'Very well. Follow that lord; and look you mock him not. My'), ('hamlet_act2_scene2', 415, 453, 'HAMLET', 'good friends, I’ll leave you till night: you are welcome to Elsinore.'), ('hamlet_act2_scene2', 416, 454, 'ROSENCRANTZ', 'Good my lord!'), ('hamlet_act2_scene2', 417, 455, 'HAMLET', 'Ay, so, God be wi’ ye; Now I am alone.'), ('hamlet_act2_scene2', 418, 456, 'HAMLET', 'O, what a rogue and peasant slave am I!'), ('hamlet_act2_scene2', 419, 457, 'HAMLET', 'Is it not monstrous that this player here,'), ('hamlet_act2_scene2', 420, 458, 'HAMLET', 'But in a fiction, in a dream of passion,'), ('hamlet_act2_scene2', 421, 459, 'HAMLET', 'Could force his soul so to his own conceit'), ('hamlet_act2_scene2', 422, 460, 'HAMLET', 'That from her working all his visage wann’d,'), ('hamlet_act2_scene2', 423, 461, 'HAMLET', 'Tears in his eyes, distraction in’s aspect,'), ('hamlet_act2_scene2', 424, 462, 'HAMLET', 'A broken voice, and his whole function suiting'), ('hamlet_act2_scene2', 425, 463, 'HAMLET', 'With forms to his conceit? and all for nothing!'), ('hamlet_act2_scene2', 426, 464, 'HAMLET', 'For Hecuba!'), ('hamlet_act2_scene2', 427, 465, 'HAMLET', 'What’s Hecuba to him, or he to Hecuba,'), ('hamlet_act2_scene2', 428, 466, 'HAMLET', 'That he should weep for her? What would he do,'), ('hamlet_act2_scene2', 429, 467, 'HAMLET', 'Had he the motive and the cue for passion'), ('hamlet_act2_scene2', 430, 468, 'HAMLET', 'That I have? He would drown the stage with tears'), ('hamlet_act2_scene2', 431, 469, 'HAMLET', 'And cleave the general ear with horrid speech,'), ('hamlet_act2_scene2', 432, 470, 'HAMLET', 'Make mad the guilty and appal the free,'), ('hamlet_act2_scene2', 433, 471, 'HAMLET', 'Confound the ignorant, and amaze indeed'), ('hamlet_act2_scene2', 434, 472, 'HAMLET', 'The very faculties of eyes and ears.'), ('hamlet_act2_scene2', 435, 473, 'HAMLET', 'Yet I,'), ('hamlet_act2_scene2', 436, 474, 'HAMLET', 'A dull and muddy-mettled rascal, peak,'), ('hamlet_act2_scene2', 437, 475, 'HAMLET', 'Like John-a-dreams, unpregnant of my cause,'), ('hamlet_act2_scene2', 438, 476, 'HAMLET', 'And can say nothing; no, not for a king,'), ('hamlet_act2_scene2', 439, 477, 'HAMLET', 'Upon whose property and most dear life'), ('hamlet_act2_scene2', 440, 478, 'HAMLET', 'A damn’d defeat was made. Am I a coward?'), ('hamlet_act2_scene2', 441, 479, 'HAMLET', 'Who calls me villain? breaks my pate across?'), ('hamlet_act2_scene2', 442, 480, 'HAMLET', 'Plucks off my beard, and blows it in my face?'), ('hamlet_act2_scene2', 443, 481, 'HAMLET', 'Tweaks me by the nose? gives me the lie i’ the throat,'), ('hamlet_act2_scene2', 444, 482, 'HAMLET', 'As deep as to the lungs? who does me this?'), ('hamlet_act2_scene2', 445, 483, 'HAMLET', 'Ha!'), ('hamlet_act2_scene2', 446, 484, 'HAMLET', '’Swounds, I should take it: for it cannot be'), ('hamlet_act2_scene2', 447, 485, 'HAMLET', 'But I am pigeon-liver’d and lack gall'), ('hamlet_act2_scene2', 448, 486, 'HAMLET', 'To make oppression bitter, or ere this'), ('hamlet_act2_scene2', 449, 487, 'HAMLET', 'I should have fatted all the region kites'), ('hamlet_act2_scene2', 450, 488, 'HAMLET', 'With this slave’s offal: bloody, bawdy villain!'), ('hamlet_act2_scene2', 451, 489, 'HAMLET', 'Remorseless, treacherous, lecherous, kindless villain!'), ('hamlet_act2_scene2', 452, 490, 'HAMLET', 'O, vengeance!'), ('hamlet_act2_scene2', 453, 491, 'HAMLET', 'Why, what an ass am I! This is most brave,'), ('hamlet_act2_scene2', 454, 492, 'HAMLET', 'That I, the son of a dear father murder’d,'), ('hamlet_act2_scene2', 455, 493, 'HAMLET', 'Prompted to my revenge by heaven and hell,'), ('hamlet_act2_scene2', 456, 494, 'HAMLET', 'Must, like a whore, unpack my heart with words,'), ('hamlet_act2_scene2', 457, 495, 'HAMLET', 'And fall a-cursing, like a very drab,'), ('hamlet_act2_scene2', 458, 496, 'HAMLET', 'A scullion!'), ('hamlet_act2_scene2', 459, 497, 'HAMLET', 'Fie upon’t! foh! About, my brain! I have heard'), ('hamlet_act2_scene2', 460, 498, 'HAMLET', 'That guilty creatures sitting at a play'), ('hamlet_act2_scene2', 461, 499, 'HAMLET', 'Have by the very cunning of the scene');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act2_scene2', 462, 500, 'HAMLET', 'Been struck so to the soul that presently'), ('hamlet_act2_scene2', 463, 501, 'HAMLET', 'They have proclaim’d their malefactions;'), ('hamlet_act2_scene2', 464, 502, 'HAMLET', 'For murder, though it have no tongue, will speak'), ('hamlet_act2_scene2', 465, 503, 'HAMLET', 'With most miraculous organ. I’ll have these players'), ('hamlet_act2_scene2', 466, 504, 'HAMLET', 'Play something like the murder of my father'), ('hamlet_act2_scene2', 467, 505, 'HAMLET', 'Before mine uncle: I’ll observe his looks;'), ('hamlet_act2_scene2', 468, 506, 'HAMLET', 'I’ll tent him to the quick: if he but blench,'), ('hamlet_act2_scene2', 469, 507, 'HAMLET', 'I know my course. The spirit that I have seen'), ('hamlet_act2_scene2', 470, 508, 'HAMLET', 'May be the devil: and the devil hath power'), ('hamlet_act2_scene2', 471, 509, 'HAMLET', 'To assume a pleasing shape; yea, and perhaps'), ('hamlet_act2_scene2', 472, 510, 'HAMLET', 'Out of my weakness and my melancholy,'), ('hamlet_act2_scene2', 473, 511, 'HAMLET', 'As he is very potent with such spirits,'), ('hamlet_act2_scene2', 474, 512, 'HAMLET', 'Abuses me to damn me: I’ll have grounds'), ('hamlet_act2_scene2', 475, 513, 'HAMLET', 'More relative than this: the play’s the thing'), ('hamlet_act2_scene2', 476, 514, 'HAMLET', 'Wherein I’ll catch the conscience of the king.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene1', 1, 0, 'KING', 'And can you, by no drift of circumstance,'), ('hamlet_act3_scene1', 2, 1, 'KING', 'Get from him why he puts on this confusion,'), ('hamlet_act3_scene1', 3, 2, 'KING', 'Grating so harshly all his days of quiet'), ('hamlet_act3_scene1', 4, 3, 'KING', 'With turbulent and dangerous lunacy?'), ('hamlet_act3_scene1', 5, 4, 'ROSENCRANTZ', 'He does confess he feels himself distracted;'), ('hamlet_act3_scene1', 6, 5, 'ROSENCRANTZ', 'But from what cause he will by no means speak.'), ('hamlet_act3_scene1', 7, 6, 'GUILDENSTERN', 'Nor do we find him forward to be sounded,'), ('hamlet_act3_scene1', 8, 7, 'GUILDENSTERN', 'But, with a crafty madness, keeps aloof,'), ('hamlet_act3_scene1', 9, 8, 'GUILDENSTERN', 'When we would bring him on to some confession'), ('hamlet_act3_scene1', 10, 9, 'GUILDENSTERN', 'Of his true state.'), ('hamlet_act3_scene1', 10, 10, 'QUEEN', 'Did he receive you well?'), ('hamlet_act3_scene1', 11, 11, 'ROSENCRANTZ', 'Most like a gentleman.'), ('hamlet_act3_scene1', 12, 12, 'GUILDENSTERN', 'But with much forcing of his disposition.'), ('hamlet_act3_scene1', 13, 13, 'ROSENCRANTZ', 'Niggard of question; but, of our demands,'), ('hamlet_act3_scene1', 14, 14, 'ROSENCRANTZ', 'Most free in his reply.'), ('hamlet_act3_scene1', 14, 15, 'QUEEN', 'Did you assay him'), ('hamlet_act3_scene1', 15, 16, 'QUEEN', 'To any pastime?'), ('hamlet_act3_scene1', 16, 17, 'ROSENCRANTZ', 'Madam, it so fell out, that certain players'), ('hamlet_act3_scene1', 17, 18, 'ROSENCRANTZ', 'We o’er-raught on the way: of these we told him;'), ('hamlet_act3_scene1', 18, 19, 'ROSENCRANTZ', 'And there did seem in him a kind of joy'), ('hamlet_act3_scene1', 19, 20, 'ROSENCRANTZ', 'To hear of it: they are about the court,'), ('hamlet_act3_scene1', 20, 21, 'ROSENCRANTZ', 'And, as I think, they have already order'), ('hamlet_act3_scene1', 21, 22, 'ROSENCRANTZ', 'This night to play before him.'), ('hamlet_act3_scene1', 21, 23, 'POLONIUS', '’Tis most true:'), ('hamlet_act3_scene1', 22, 24, 'POLONIUS', 'And he beseech’d me to entreat your majesties'), ('hamlet_act3_scene1', 23, 25, 'POLONIUS', 'To hear and see the matter.'), ('hamlet_act3_scene1', 24, 26, 'KING', 'With all my heart; and it doth much content me'), ('hamlet_act3_scene1', 25, 27, 'KING', 'To hear him so inclined.'), ('hamlet_act3_scene1', 26, 28, 'KING', 'Good gentlemen, give him a further edge,'), ('hamlet_act3_scene1', 27, 29, 'KING', 'And drive his purpose on to these delights.'), ('hamlet_act3_scene1', 28, 30, 'ROSENCRANTZ', 'We shall, my lord.'), ('hamlet_act3_scene1', 28, 31, 'KING', 'Sweet Gertrude, leave us too;'), ('hamlet_act3_scene1', 29, 32, 'KING', 'For we have closely sent for Hamlet hither,'), ('hamlet_act3_scene1', 30, 33, 'KING', 'That he, as ’twere by accident, may here'), ('hamlet_act3_scene1', 31, 34, 'KING', 'Affront Ophelia:'), ('hamlet_act3_scene1', 32, 35, 'KING', 'Her father and myself, lawful espials,'), ('hamlet_act3_scene1', 33, 36, 'KING', 'Will so bestow ourselves that, seeing, unseen,'), ('hamlet_act3_scene1', 34, 37, 'KING', 'We may of their encounter frankly judge,'), ('hamlet_act3_scene1', 35, 38, 'KING', 'And gather by him, as he is behaved,'), ('hamlet_act3_scene1', 36, 39, 'KING', 'If’t be the affliction of his love or no'), ('hamlet_act3_scene1', 37, 40, 'KING', 'That thus he suffers for.'), ('hamlet_act3_scene1', 37, 41, 'QUEEN', 'I shall obey you.'), ('hamlet_act3_scene1', 38, 42, 'QUEEN', 'And for your part, Ophelia, I do wish'), ('hamlet_act3_scene1', 39, 43, 'QUEEN', 'That your good beauties be the happy cause'), ('hamlet_act3_scene1', 40, 44, 'QUEEN', 'Of Hamlet’s wildness: so shall I hope your virtues'), ('hamlet_act3_scene1', 41, 45, 'QUEEN', 'Will bring him to his wonted way again,'), ('hamlet_act3_scene1', 42, 46, 'QUEEN', 'To both your honours.'), ('hamlet_act3_scene1', 42, 47, 'OPHELIA', 'Madam, I wish it may.'), ('hamlet_act3_scene1', 43, 48, 'POLONIUS', 'Ophelia, walk you here. Gracious, so please you,'), ('hamlet_act3_scene1', 44, 49, 'POLONIUS', 'We will bestow ourselves. Read on this book;'), ('hamlet_act3_scene1', 45, 50, 'POLONIUS', 'That show of such an exercise may colour'), ('hamlet_act3_scene1', 46, 51, 'POLONIUS', 'Your loneliness. We are oft to blame in this—'), ('hamlet_act3_scene1', 47, 52, 'POLONIUS', '’Tis too much proved—that with devotion’s visage'), ('hamlet_act3_scene1', 48, 53, 'POLONIUS', 'And pious action we do sugar o’er'), ('hamlet_act3_scene1', 49, 54, 'POLONIUS', 'The devil himself.'), ('hamlet_act3_scene1', 49, 55, 'KING', 'O, ’tis too true!'), ('hamlet_act3_scene1', 50, 56, 'KING', 'How smart a lash that speech doth give my conscience!'), ('hamlet_act3_scene1', 51, 57, 'KING', 'The harlot’s cheek, beautied with plastering art,'), ('hamlet_act3_scene1', 52, 58, 'KING', 'Is not more ugly to the thing that helps it'), ('hamlet_act3_scene1', 53, 59, 'KING', 'Than is my deed to my most painted word:'), ('hamlet_act3_scene1', 54, 60, 'KING', 'O heavy burthen!'), ('hamlet_act3_scene1', 55, 61, 'POLONIUS', 'I hear him coming: let’s withdraw, my lord.'), ('hamlet_act3_scene1', 56, 62, 'HAMLET', 'To be, or not to be: that is the question:'), ('hamlet_act3_scene1', 57, 63, 'HAMLET', 'Whether ’tis nobler in the mind to suffer'), ('hamlet_act3_scene1', 58, 64, 'HAMLET', 'The slings and arrows of outrageous fortune,'), ('hamlet_act3_scene1', 59, 65, 'HAMLET', 'Or to take arms against a sea of troubles,'), ('hamlet_act3_scene1', 60, 66, 'HAMLET', 'And by opposing end them? To die: to sleep;'), ('hamlet_act3_scene1', 61, 67, 'HAMLET', 'No more; and by a sleep to say we end'), ('hamlet_act3_scene1', 62, 68, 'HAMLET', 'The heart-ache and the thousand natural shocks'), ('hamlet_act3_scene1', 63, 69, 'HAMLET', 'That flesh is heir to, ’tis a consummation'), ('hamlet_act3_scene1', 64, 70, 'HAMLET', 'Devoutly to be wish’d. To die, to sleep;'), ('hamlet_act3_scene1', 65, 71, 'HAMLET', 'To sleep: perchance to dream: ay, there’s the rub;'), ('hamlet_act3_scene1', 66, 72, 'HAMLET', 'For in that sleep of death what dreams may come'), ('hamlet_act3_scene1', 67, 73, 'HAMLET', 'When we have shuffled off this mortal coil,'), ('hamlet_act3_scene1', 68, 74, 'HAMLET', 'Must give us pause: there’s the respect'), ('hamlet_act3_scene1', 69, 75, 'HAMLET', 'That makes calamity of so long life;'), ('hamlet_act3_scene1', 70, 76, 'HAMLET', 'For who would bear the whips and scorns of time,'), ('hamlet_act3_scene1', 71, 77, 'HAMLET', 'The oppressor’s wrong, the proud man’s contumely,'), ('hamlet_act3_scene1', 72, 78, 'HAMLET', 'The pangs of despised love, the law’s delay,'), ('hamlet_act3_scene1', 73, 79, 'HAMLET', 'The insolence of office and the spurns'), ('hamlet_act3_scene1', 74, 80, 'HAMLET', 'That patient merit of the unworthy takes,'), ('hamlet_act3_scene1', 75, 81, 'HAMLET', 'When he himself might his quietus make'), ('hamlet_act3_scene1', 76, 82, 'HAMLET', 'With a bare bodkin? who would fardels bear,'), ('hamlet_act3_scene1', 77, 83, 'HAMLET', 'To grunt and sweat under a weary life,'), ('hamlet_act3_scene1', 78, 84, 'HAMLET', 'But that the dread of something after death,'), ('hamlet_act3_scene1', 79, 85, 'HAMLET', 'The undiscover’d country from whose bourn'), ('hamlet_act3_scene1', 80, 86, 'HAMLET', 'No traveller returns, puzzles the will'), ('hamlet_act3_scene1', 81, 87, 'HAMLET', 'And makes us rather bear those ills we have'), ('hamlet_act3_scene1', 82, 88, 'HAMLET', 'Than fly to others that we know not of?'), ('hamlet_act3_scene1', 83, 89, 'HAMLET', 'Thus conscience does make cowards of us all;'), ('hamlet_act3_scene1', 84, 90, 'HAMLET', 'And thus the native hue of resolution'), ('hamlet_act3_scene1', 85, 91, 'HAMLET', 'Is sicklied o’er with the pale cast of thought,'), ('hamlet_act3_scene1', 86, 92, 'HAMLET', 'And enterprises of great pitch and moment'), ('hamlet_act3_scene1', 87, 93, 'HAMLET', 'With this regard their currents turn awry,'), ('hamlet_act3_scene1', 88, 94, 'HAMLET', 'And lose the name of action.—Soft you now!'), ('hamlet_act3_scene1', 89, 95, 'HAMLET', 'The fair Ophelia! Nymph, in thy orisons'), ('hamlet_act3_scene1', 90, 96, 'HAMLET', 'Be all my sins remember’d.'), ('hamlet_act3_scene1', 90, 97, 'OPHELIA', 'Good my lord,'), ('hamlet_act3_scene1', 91, 98, 'OPHELIA', 'How does your honour for this many a day?'), ('hamlet_act3_scene1', 92, 99, 'HAMLET', 'I humbly thank you; well, well, well.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene1', 93, 100, 'OPHELIA', 'My lord, I have remembrances of yours,'), ('hamlet_act3_scene1', 94, 101, 'OPHELIA', 'That I have longed long to re-deliver;'), ('hamlet_act3_scene1', 95, 102, 'OPHELIA', 'I pray you, now receive them.'), ('hamlet_act3_scene1', 95, 103, 'HAMLET', 'No, not I;'), ('hamlet_act3_scene1', 96, 104, 'HAMLET', 'I never gave you aught.'), ('hamlet_act3_scene1', 97, 105, 'OPHELIA', 'My honour’d lord, you know right well you did;'), ('hamlet_act3_scene1', 98, 106, 'OPHELIA', 'And, with them, words of so sweet breath composed'), ('hamlet_act3_scene1', 99, 107, 'OPHELIA', 'As made the things more rich: their perfume lost,'), ('hamlet_act3_scene1', 100, 108, 'OPHELIA', 'Take these again; for to the noble mind'), ('hamlet_act3_scene1', 101, 109, 'OPHELIA', 'Rich gifts wax poor when givers prove unkind.'), ('hamlet_act3_scene1', 102, 110, 'OPHELIA', 'There, my lord.'), ('hamlet_act3_scene1', 102, 111, 'HAMLET', 'Ha, ha! are you honest?'), ('hamlet_act3_scene1', 103, 112, 'OPHELIA', 'My lord?'), ('hamlet_act3_scene1', 103, 113, 'HAMLET', 'Are you fair?'), ('hamlet_act3_scene1', 104, 114, 'OPHELIA', 'What means your lordship?'), ('hamlet_act3_scene1', 105, 115, 'HAMLET', 'That if you be honest and fair, your honesty should admit no'), ('hamlet_act3_scene1', 106, 116, 'HAMLET', 'discourse to your beauty.'), ('hamlet_act3_scene1', 107, 117, 'OPHELIA', 'Could beauty, my lord, have better commerce than with honesty?'), ('hamlet_act3_scene1', 108, 118, 'HAMLET', 'Ay, truly; for the power of beauty will sooner transform honesty from'), ('hamlet_act3_scene1', 109, 119, 'HAMLET', 'what it is to a bawd than the force of honesty can'), ('hamlet_act3_scene1', 110, 120, 'HAMLET', 'translate beauty into his likeness: this was sometime a paradox, but now'), ('hamlet_act3_scene1', 111, 121, 'HAMLET', 'the time gives it proof. I did love you once.'), ('hamlet_act3_scene1', 112, 122, 'OPHELIA', 'Indeed, my lord, you made me believe so.'), ('hamlet_act3_scene1', 113, 123, 'HAMLET', 'You should not have believed me; for virtue cannot so inoculate our'), ('hamlet_act3_scene1', 114, 124, 'HAMLET', 'old stock but we shall relish of it: I loved you not.'), ('hamlet_act3_scene1', 115, 125, 'OPHELIA', 'I was the more deceived.'), ('hamlet_act3_scene1', 116, 126, 'HAMLET', 'Get thee to a nunnery: why wouldst thou be a breeder of'), ('hamlet_act3_scene1', 117, 127, 'HAMLET', 'sinners? I am myself indifferent honest; but yet I could accuse me'), ('hamlet_act3_scene1', 118, 128, 'HAMLET', 'of such things that it were better my mother had not borne'), ('hamlet_act3_scene1', 119, 129, 'HAMLET', 'me: I am very proud, revengeful, ambitious, with more offences at my'), ('hamlet_act3_scene1', 120, 130, 'HAMLET', 'beck than I have thoughts to put them in, imagination to give'), ('hamlet_act3_scene1', 121, 131, 'HAMLET', 'them shape, or time to act them in. What should such fellows'), ('hamlet_act3_scene1', 122, 132, 'HAMLET', 'as I do crawling between earth and heaven? We are arrant knaves,'), ('hamlet_act3_scene1', 123, 133, 'HAMLET', 'all; believe none of us. Go thy ways to a nunnery. Where’s'), ('hamlet_act3_scene1', 124, 134, 'HAMLET', 'your father?'), ('hamlet_act3_scene1', 124, 135, 'OPHELIA', 'At home, my lord.'), ('hamlet_act3_scene1', 125, 136, 'HAMLET', 'Let the doors be shut upon him, that he may play the'), ('hamlet_act3_scene1', 126, 137, 'HAMLET', 'fool nowhere but in’s own house. Farewell.'), ('hamlet_act3_scene1', 127, 138, 'OPHELIA', 'O, help him, you sweet heavens!'), ('hamlet_act3_scene1', 128, 139, 'HAMLET', 'If thou dost marry, I’ll give thee this plague for thy dowry:'), ('hamlet_act3_scene1', 129, 140, 'HAMLET', 'be thou as chaste as ice, as pure as snow, thou shalt'), ('hamlet_act3_scene1', 130, 141, 'HAMLET', 'not escape calumny. Get thee to a nunnery, go: farewell. Or, if'), ('hamlet_act3_scene1', 131, 142, 'HAMLET', 'thou wilt needs marry, marry a fool; for wise men know well'), ('hamlet_act3_scene1', 132, 143, 'HAMLET', 'enough what monsters you make of them. To a nunnery, go, and'), ('hamlet_act3_scene1', 133, 144, 'HAMLET', 'quickly too. Farewell.'), ('hamlet_act3_scene1', 133, 145, 'OPHELIA', 'O heavenly powers, restore him!'), ('hamlet_act3_scene1', 134, 146, 'HAMLET', 'I have heard of your paintings too, well enough; God has given'), ('hamlet_act3_scene1', 135, 147, 'HAMLET', 'you one face, and you make yourselves another: you jig, you amble,'), ('hamlet_act3_scene1', 136, 148, 'HAMLET', 'and you lisp, and nick-name God’s creatures, and make your wantonness your'), ('hamlet_act3_scene1', 137, 149, 'HAMLET', 'ignorance. Go to, I’ll no more on’t; it hath made me mad.'), ('hamlet_act3_scene1', 138, 150, 'HAMLET', 'I say, we will have no more marriages: those that are married'), ('hamlet_act3_scene1', 139, 151, 'HAMLET', 'already, all but one, shall live; the rest shall keep as they'), ('hamlet_act3_scene1', 140, 152, 'HAMLET', 'are. To a nunnery, go.'), ('hamlet_act3_scene1', 141, 153, 'OPHELIA', 'O, what a noble mind is here o’erthrown!'), ('hamlet_act3_scene1', 142, 154, 'OPHELIA', 'The courtier’s, soldier’s, scholar’s, eye, tongue, sword;'), ('hamlet_act3_scene1', 143, 155, 'OPHELIA', 'The expectancy and rose of the fair state,'), ('hamlet_act3_scene1', 144, 156, 'OPHELIA', 'The glass of fashion and the mould of form,'), ('hamlet_act3_scene1', 145, 157, 'OPHELIA', 'The observed of all observers, quite, quite down!'), ('hamlet_act3_scene1', 146, 158, 'OPHELIA', 'And I, of ladies most deject and wretched,'), ('hamlet_act3_scene1', 147, 159, 'OPHELIA', 'That suck’d the honey of his music vows,'), ('hamlet_act3_scene1', 148, 160, 'OPHELIA', 'Now see that noble and most sovereign reason,'), ('hamlet_act3_scene1', 149, 161, 'OPHELIA', 'Like sweet bells jangled, out of tune and harsh;'), ('hamlet_act3_scene1', 150, 162, 'OPHELIA', 'That unmatch’d form and feature of blown youth'), ('hamlet_act3_scene1', 151, 163, 'OPHELIA', 'Blasted with ecstasy: O, woe is me,'), ('hamlet_act3_scene1', 152, 164, 'OPHELIA', 'To have seen what I have seen, see what I see!'), ('hamlet_act3_scene1', 153, 165, 'KING', 'Love! his affections do not that way tend;'), ('hamlet_act3_scene1', 154, 166, 'KING', 'Nor what he spake, though it lack’d form a little,'), ('hamlet_act3_scene1', 155, 167, 'KING', 'Was not like madness. There’s something in his soul,'), ('hamlet_act3_scene1', 156, 168, 'KING', 'O’er which his melancholy sits on brood;'), ('hamlet_act3_scene1', 157, 169, 'KING', 'And I do doubt the hatch and the disclose'), ('hamlet_act3_scene1', 158, 170, 'KING', 'Will be some danger: which for to prevent,'), ('hamlet_act3_scene1', 159, 171, 'KING', 'I have in quick determination'), ('hamlet_act3_scene1', 160, 172, 'KING', 'Thus set it down: he shall with speed to England,'), ('hamlet_act3_scene1', 161, 173, 'KING', 'For the demand of our neglected tribute:'), ('hamlet_act3_scene1', 162, 174, 'KING', 'Haply the seas and countries different'), ('hamlet_act3_scene1', 163, 175, 'KING', 'With variable objects shall expel'), ('hamlet_act3_scene1', 164, 176, 'KING', 'This something-settled matter in his heart,'), ('hamlet_act3_scene1', 165, 177, 'KING', 'Whereon his brains still beating puts him thus'), ('hamlet_act3_scene1', 166, 178, 'KING', 'From fashion of himself. What think you on’t?'), ('hamlet_act3_scene1', 167, 179, 'POLONIUS', 'It shall do well: but yet do I believe'), ('hamlet_act3_scene1', 168, 180, 'POLONIUS', 'The origin and commencement of his grief'), ('hamlet_act3_scene1', 169, 181, 'POLONIUS', 'Sprung from neglected love. How now, Ophelia!'), ('hamlet_act3_scene1', 170, 182, 'POLONIUS', 'You need not tell us what Lord Hamlet said;'), ('hamlet_act3_scene1', 171, 183, 'POLONIUS', 'We heard it all. My lord, do as you please;'), ('hamlet_act3_scene1', 172, 184, 'POLONIUS', 'But, if you hold it fit, after the play'), ('hamlet_act3_scene1', 173, 185, 'POLONIUS', 'Let his queen mother all alone entreat him'), ('hamlet_act3_scene1', 174, 186, 'POLONIUS', 'To show his grief: let her be round with him;'), ('hamlet_act3_scene1', 175, 187, 'POLONIUS', 'And I’ll be placed, so please you, in the ear'), ('hamlet_act3_scene1', 176, 188, 'POLONIUS', 'Of all their conference. If she find him not,'), ('hamlet_act3_scene1', 177, 189, 'POLONIUS', 'To England send him, or confine him where'), ('hamlet_act3_scene1', 178, 190, 'POLONIUS', 'Your wisdom best shall think.'), ('hamlet_act3_scene1', 178, 191, 'KING', 'It shall be so:'), ('hamlet_act3_scene1', 179, 192, 'KING', 'Madness in great ones must not unwatch’d go.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene2', 1, 0, 'HAMLET', 'Speak the speech, I pray you, as I pronounced it to you,'), ('hamlet_act3_scene2', 2, 1, 'HAMLET', 'trippingly on the tongue: but if you mouth it, as many of'), ('hamlet_act3_scene2', 3, 2, 'HAMLET', 'your players do, I had as lief the town-crier spoke my lines.'), ('hamlet_act3_scene2', 4, 3, 'HAMLET', 'Nor do not saw the air too much with your hand, thus,'), ('hamlet_act3_scene2', 5, 4, 'HAMLET', 'but use all gently; for in the very torrent, tempest, and, as'), ('hamlet_act3_scene2', 6, 5, 'HAMLET', 'I may say, the whirlwind of passion, you must acquire and beget'), ('hamlet_act3_scene2', 7, 6, 'HAMLET', 'a temperance that may give it smoothness. O, it offends me to'), ('hamlet_act3_scene2', 8, 7, 'HAMLET', 'the soul to hear a robustious periwig-pated fellow tear a passion to'), ('hamlet_act3_scene2', 9, 8, 'HAMLET', 'tatters, to very rags, to split the ears of the groundlings, who'), ('hamlet_act3_scene2', 10, 9, 'HAMLET', 'for the most part are capable of nothing but inexplicable dumbshows and'), ('hamlet_act3_scene2', 11, 10, 'HAMLET', 'noise: I would have such a fellow whipped for o’erdoing Termagant; it'), ('hamlet_act3_scene2', 12, 11, 'HAMLET', 'out-herods Herod: pray you, avoid it.'), ('hamlet_act3_scene2', 12, 12, 'FIRST PLAYER', 'I warrant your honour.'), ('hamlet_act3_scene2', 13, 13, 'HAMLET', 'Be not too tame neither, but let your own discretion be your'), ('hamlet_act3_scene2', 14, 14, 'HAMLET', 'tutor: suit the action to the word, the word to the action;'), ('hamlet_act3_scene2', 15, 15, 'HAMLET', 'with this special observance, that you o’erstep not the modesty of nature:'), ('hamlet_act3_scene2', 16, 16, 'HAMLET', 'for any thing so overdone is from the purpose of playing, whose'), ('hamlet_act3_scene2', 17, 17, 'HAMLET', 'end, both at the first and now, was and is, to hold,'), ('hamlet_act3_scene2', 18, 18, 'HAMLET', 'as ’twere, the mirror up to nature; to show virtue her own'), ('hamlet_act3_scene2', 19, 19, 'HAMLET', 'feature, scorn her own image, and the very age and body of'), ('hamlet_act3_scene2', 20, 20, 'HAMLET', 'the time his form and pressure. Now this overdone, or come tardy'), ('hamlet_act3_scene2', 21, 21, 'HAMLET', 'off, though it make the unskilful laugh, cannot but make the judicious'), ('hamlet_act3_scene2', 22, 22, 'HAMLET', 'grieve; the censure of the which one must in your allowance o’erweigh'), ('hamlet_act3_scene2', 23, 23, 'HAMLET', 'a whole theatre of others. O, there be players that I have'), ('hamlet_act3_scene2', 24, 24, 'HAMLET', 'seen play, and heard others praise, and that highly, not to speak'), ('hamlet_act3_scene2', 25, 25, 'HAMLET', 'it profanely, that, neither having the accent of Christians nor the gait'), ('hamlet_act3_scene2', 26, 26, 'HAMLET', 'of Christian, pagan, nor man, have so strutted and bellowed that I'), ('hamlet_act3_scene2', 27, 27, 'HAMLET', 'have thought some of nature’s journeymen had made men and not made'), ('hamlet_act3_scene2', 28, 28, 'HAMLET', 'them well, they imitated humanity so abominably.'), ('hamlet_act3_scene2', 29, 29, 'FIRST PLAYER', 'I hope we have reformed that indifferently with us, sir.'), ('hamlet_act3_scene2', 30, 30, 'HAMLET', 'O, reform it altogether. And let those that play your clowns speak'), ('hamlet_act3_scene2', 31, 31, 'HAMLET', 'no more than is set down for them; for there be of'), ('hamlet_act3_scene2', 32, 32, 'HAMLET', 'them that will themselves laugh, to set on some quantity of barren'), ('hamlet_act3_scene2', 33, 33, 'HAMLET', 'spectators to laugh too; though, in the mean time, some necessary question'), ('hamlet_act3_scene2', 34, 34, 'HAMLET', 'of the play be then to be considered: that’s villainous, and shows'), ('hamlet_act3_scene2', 35, 35, 'HAMLET', 'a most pitiful ambition in the fool that uses it. Go, make'), ('hamlet_act3_scene2', 36, 36, 'HAMLET', 'you ready.'), ('hamlet_act3_scene2', 37, 37, 'POLONIUS', 'And the queen too, and that presently.'), ('hamlet_act3_scene2', 38, 38, 'HAMLET', 'Bid the players make haste. Will you two help to hasten them?'), ('hamlet_act3_scene2', 39, 39, 'ROSENCRANTZ GUILDENSTERN', 'We will, my lord.'), ('hamlet_act3_scene2', 39, 40, 'HAMLET', 'What ho! Horatio!'), ('hamlet_act3_scene2', 40, 41, 'HORATIO', 'Here, sweet lord, at your service.'), ('hamlet_act3_scene2', 41, 42, 'HAMLET', 'Horatio, thou art e’en as just a man'), ('hamlet_act3_scene2', 42, 43, 'HAMLET', 'As e’er my conversation coped withal.'), ('hamlet_act3_scene2', 42, 44, 'HORATIO', 'O, my dear lord—'), ('hamlet_act3_scene2', 43, 45, 'HAMLET', 'Nay, do not think I flatter;'), ('hamlet_act3_scene2', 44, 46, 'HAMLET', 'For what advancement may I hope from thee'), ('hamlet_act3_scene2', 45, 47, 'HAMLET', 'That no revenue hast but thy good spirits,'), ('hamlet_act3_scene2', 46, 48, 'HAMLET', 'To feed and clothe thee? Why should the poor be flatter’d?'), ('hamlet_act3_scene2', 47, 49, 'HAMLET', 'No, let the candied tongue lick absurd pomp,'), ('hamlet_act3_scene2', 48, 50, 'HAMLET', 'And crook the pregnant hinges of the knee'), ('hamlet_act3_scene2', 49, 51, 'HAMLET', 'Where thrift may follow fawning. Dost thou hear?'), ('hamlet_act3_scene2', 50, 52, 'HAMLET', 'Since my dear soul was mistress of her choice'), ('hamlet_act3_scene2', 51, 53, 'HAMLET', 'And could of men distinguish, her election'), ('hamlet_act3_scene2', 52, 54, 'HAMLET', 'Hath seal’d thee for herself; for thou hast been'), ('hamlet_act3_scene2', 53, 55, 'HAMLET', 'As one, in suffering all, that suffers nothing,'), ('hamlet_act3_scene2', 54, 56, 'HAMLET', 'A man that fortune’s buffets and rewards'), ('hamlet_act3_scene2', 55, 57, 'HAMLET', 'Hast ta’en with equal thanks: and blest are those'), ('hamlet_act3_scene2', 56, 58, 'HAMLET', 'Whose blood and judgment are so well commingled,'), ('hamlet_act3_scene2', 57, 59, 'HAMLET', 'That they are not a pipe for fortune’s finger'), ('hamlet_act3_scene2', 58, 60, 'HAMLET', 'To sound what stop she please. Give me that man'), ('hamlet_act3_scene2', 59, 61, 'HAMLET', 'That is not passion’s slave, and I will wear him'), ('hamlet_act3_scene2', 60, 62, 'HAMLET', 'In my heart’s core, ay, in my heart of heart,'), ('hamlet_act3_scene2', 61, 63, 'HAMLET', 'As I do thee.—Something too much of this.—'), ('hamlet_act3_scene2', 62, 64, 'HAMLET', 'There is a play to-night before the king;'), ('hamlet_act3_scene2', 63, 65, 'HAMLET', 'One scene of it comes near the circumstance'), ('hamlet_act3_scene2', 64, 66, 'HAMLET', 'Which I have told thee of my father’s death:'), ('hamlet_act3_scene2', 65, 67, 'HAMLET', 'I prithee, when thou seest that act afoot,'), ('hamlet_act3_scene2', 66, 68, 'HAMLET', 'Even with the very comment of thy soul'), ('hamlet_act3_scene2', 67, 69, 'HAMLET', 'Observe mine uncle: if his occulted guilt'), ('hamlet_act3_scene2', 68, 70, 'HAMLET', 'Do not itself unkennel in one speech,'), ('hamlet_act3_scene2', 69, 71, 'HAMLET', 'It is a damned ghost that we have seen,'), ('hamlet_act3_scene2', 70, 72, 'HAMLET', 'And my imaginations are as foul'), ('hamlet_act3_scene2', 71, 73, 'HAMLET', 'As Vulcan’s stithy. Give him heedful note;'), ('hamlet_act3_scene2', 72, 74, 'HAMLET', 'For I mine eyes will rivet to his face,'), ('hamlet_act3_scene2', 73, 75, 'HAMLET', 'And after we will both our judgments join'), ('hamlet_act3_scene2', 74, 76, 'HAMLET', 'In censure of his seeming.'), ('hamlet_act3_scene2', 74, 77, 'HORATIO', 'Well, my lord:'), ('hamlet_act3_scene2', 75, 78, 'HORATIO', 'If he steal aught the whilst this play is playing,'), ('hamlet_act3_scene2', 76, 79, 'HORATIO', 'And ’scape detecting, I will pay the theft.'), ('hamlet_act3_scene2', 77, 80, 'HAMLET', 'They are coming to the play; I must be idle:'), ('hamlet_act3_scene2', 78, 81, 'HAMLET', 'Get you a place.'), ('hamlet_act3_scene2', 78, 82, 'KING', 'How fares our cousin Hamlet?'), ('hamlet_act3_scene2', 79, 83, 'HAMLET', 'Excellent, i’ faith; of the chameleon’s dish: I eat the air, promise-crammed:'), ('hamlet_act3_scene2', 80, 84, 'HAMLET', 'you cannot feed capons so.'), ('hamlet_act3_scene2', 81, 85, 'KING', 'I have nothing with this answer, Hamlet; these words are not mine.'), ('hamlet_act3_scene2', 82, 86, 'HAMLET', 'No, nor mine now. My lord, you played once i’ the university, you say?'), ('hamlet_act3_scene2', 83, 87, 'POLONIUS', 'That did I, my lord; and was accounted a good actor.'), ('hamlet_act3_scene2', 84, 88, 'HAMLET', 'What did you enact?'), ('hamlet_act3_scene2', 85, 89, 'POLONIUS', 'I did enact Julius Caesar: I was killed i’ the Capitol; Brutus killed me.'), ('hamlet_act3_scene2', 86, 90, 'HAMLET', 'It was a brute part of him to kill so capital a'), ('hamlet_act3_scene2', 87, 91, 'HAMLET', 'calf there. Be the players ready?'), ('hamlet_act3_scene2', 88, 92, 'ROSENCRANTZ', 'Ay, my lord; they stay upon your patience.'), ('hamlet_act3_scene2', 89, 93, 'QUEEN', 'Come hither, my dear Hamlet, sit by me.'), ('hamlet_act3_scene2', 90, 94, 'HAMLET', 'No, good mother, here’s metal more attractive.'), ('hamlet_act3_scene2', 91, 95, 'POLONIUS', 'O, ho! do you mark that?'), ('hamlet_act3_scene2', 92, 96, 'HAMLET', 'Lady, shall I lie in your lap?'), ('hamlet_act3_scene2', 93, 97, 'OPHELIA', 'No, my lord.'), ('hamlet_act3_scene2', 94, 98, 'HAMLET', 'I mean, my head upon your lap?'), ('hamlet_act3_scene2', 95, 99, 'OPHELIA', 'Ay, my lord.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene2', 96, 100, 'HAMLET', 'Do you think I meant country matters?'), ('hamlet_act3_scene2', 97, 101, 'OPHELIA', 'I think nothing, my lord.'), ('hamlet_act3_scene2', 98, 102, 'HAMLET', 'That’s a fair thought to lie between maids’ legs.'), ('hamlet_act3_scene2', 99, 103, 'OPHELIA', 'What is, my lord?'), ('hamlet_act3_scene2', 99, 104, 'HAMLET', 'Nothing.'), ('hamlet_act3_scene2', 100, 105, 'OPHELIA', 'You are merry, my lord.'), ('hamlet_act3_scene2', 100, 106, 'HAMLET', 'Who, I?'), ('hamlet_act3_scene2', 101, 107, 'OPHELIA', 'Ay, my lord.'), ('hamlet_act3_scene2', 102, 108, 'HAMLET', 'O God, your only jig-maker. What should a man do but be'), ('hamlet_act3_scene2', 103, 109, 'HAMLET', 'merry? for, look you, how cheerfully my mother looks, and my father'), ('hamlet_act3_scene2', 104, 110, 'HAMLET', 'died within these two hours.'), ('hamlet_act3_scene2', 105, 111, 'OPHELIA', 'Nay, ’tis twice two months, my lord.'), ('hamlet_act3_scene2', 106, 112, 'HAMLET', 'So long? Nay then, let the devil wear black, for I’ll have'), ('hamlet_act3_scene2', 107, 113, 'HAMLET', 'a suit of sables. O heavens! die two months ago, and not'), ('hamlet_act3_scene2', 108, 114, 'HAMLET', 'forgotten yet? Then there’s hope a great man’s memory may outlive his'), ('hamlet_act3_scene2', 109, 115, 'HAMLET', 'life half a year: but, by’r lady, he must build churches, then;'), ('hamlet_act3_scene2', 110, 116, 'HAMLET', 'or else shall he suffer not thinking on, with the hobby-horse, whose'), ('hamlet_act3_scene2', 111, 117, 'HAMLET', 'epitaph is “For, O, for, O, the hobby-horse is forgot.”'), ('hamlet_act3_scene2', 112, 118, 'OPHELIA', 'What means this, my lord?'), ('hamlet_act3_scene2', 113, 119, 'HAMLET', 'Marry, this is miching mallecho; it means mischief.'), ('hamlet_act3_scene2', 114, 120, 'OPHELIA', 'Belike this show imports the argument of the play.'), ('hamlet_act3_scene2', 115, 121, 'HAMLET', 'We shall know by this fellow: the players cannot keep counsel; they’ll tell all.'), ('hamlet_act3_scene2', 116, 122, 'OPHELIA', 'Will he tell us what this show meant?'), ('hamlet_act3_scene2', 117, 123, 'HAMLET', 'Ay, or any show that you’ll show him: be not you ashamed'), ('hamlet_act3_scene2', 118, 124, 'HAMLET', 'to show, he’ll not shame to tell you what it means.'), ('hamlet_act3_scene2', 119, 125, 'OPHELIA', 'You are naught, you are naught: I’ll mark the play.'), ('hamlet_act3_scene2', 120, 126, 'PROLOGUE', 'For us, and for our tragedy,'), ('hamlet_act3_scene2', 121, 127, 'PROLOGUE', 'Here stooping to your clemency,'), ('hamlet_act3_scene2', 122, 128, 'PROLOGUE', 'We beg your hearing patiently.'), ('hamlet_act3_scene2', 123, 129, 'HAMLET', 'Is this a prologue, or the posy of a ring?'), ('hamlet_act3_scene2', 124, 130, 'OPHELIA', '’Tis brief, my lord.'), ('hamlet_act3_scene2', 124, 131, 'HAMLET', 'As woman’s love.'), ('hamlet_act3_scene2', 125, 132, 'PLAYER KING', 'Full thirty times hath Phoebus’ cart gone round'), ('hamlet_act3_scene2', 126, 133, 'PLAYER KING', 'Neptune’s salt wash and Tellus’ orbed ground,'), ('hamlet_act3_scene2', 127, 134, 'PLAYER KING', 'And thirty dozen moons with borrow’d sheen'), ('hamlet_act3_scene2', 128, 135, 'PLAYER KING', 'About the world have times twelve thirties been'), ('hamlet_act3_scene2', 129, 136, 'PLAYER KING', 'Since love our hearts and Hymen did our hands'), ('hamlet_act3_scene2', 130, 137, 'PLAYER KING', 'Unite commutual in most sacred bands.'), ('hamlet_act3_scene2', 131, 138, 'PLAYER QUEEN', 'So many journeys may the sun and moon'), ('hamlet_act3_scene2', 132, 139, 'PLAYER QUEEN', 'Make us again count o’er ere love be done!'), ('hamlet_act3_scene2', 133, 140, 'PLAYER QUEEN', 'But, woe is me, you are so sick of late,'), ('hamlet_act3_scene2', 134, 141, 'PLAYER QUEEN', 'So far from cheer and from your former state,'), ('hamlet_act3_scene2', 135, 142, 'PLAYER QUEEN', 'That I distrust you. Yet, though I distrust,'), ('hamlet_act3_scene2', 136, 143, 'PLAYER QUEEN', 'Discomfort you, my lord, it nothing must:'), ('hamlet_act3_scene2', 137, 144, 'PLAYER QUEEN', 'For women’s fear and love holds quantity;'), ('hamlet_act3_scene2', 138, 145, 'PLAYER QUEEN', 'In neither aught, or in extremity.'), ('hamlet_act3_scene2', 139, 146, 'PLAYER QUEEN', 'Now, what my love is, proof hath made you know;'), ('hamlet_act3_scene2', 140, 147, 'PLAYER QUEEN', 'And as my love is sized, my fear is so:'), ('hamlet_act3_scene2', 141, 148, 'PLAYER QUEEN', 'Where love is great, the littlest doubts are fear;'), ('hamlet_act3_scene2', 142, 149, 'PLAYER QUEEN', 'Where little fears grow great, great love grows there.'), ('hamlet_act3_scene2', 143, 150, 'PLAYER KING', '’Faith, I must leave thee, love, and shortly too;'), ('hamlet_act3_scene2', 144, 151, 'PLAYER KING', 'My operant powers their functions leave to do:'), ('hamlet_act3_scene2', 145, 152, 'PLAYER KING', 'And thou shalt live in this fair world behind,'), ('hamlet_act3_scene2', 146, 153, 'PLAYER KING', 'Honour’d, beloved; and haply one as kind'), ('hamlet_act3_scene2', 147, 154, 'PLAYER KING', 'For husband shalt thou—'), ('hamlet_act3_scene2', 147, 155, 'PLAYER QUEEN', 'O, confound the rest!'), ('hamlet_act3_scene2', 148, 156, 'PLAYER QUEEN', 'Such love must needs be treason in my breast:'), ('hamlet_act3_scene2', 149, 157, 'PLAYER QUEEN', 'In second husband let me be accurst!'), ('hamlet_act3_scene2', 150, 158, 'PLAYER QUEEN', 'None wed the second but who kill’d the first.'), ('hamlet_act3_scene2', 151, 159, 'HAMLET', 'Wormwood, wormwood.'), ('hamlet_act3_scene2', 151, 160, 'PLAYER QUEEN', 'The instances that second marriage move'), ('hamlet_act3_scene2', 152, 161, 'PLAYER QUEEN', 'Are base respects of thrift, but none of love:'), ('hamlet_act3_scene2', 153, 162, 'PLAYER QUEEN', 'A second time I kill my husband dead,'), ('hamlet_act3_scene2', 154, 163, 'PLAYER QUEEN', 'When second husband kisses me in bed.'), ('hamlet_act3_scene2', 155, 164, 'PLAYER KING', 'I do believe you think what now you speak;'), ('hamlet_act3_scene2', 156, 165, 'PLAYER KING', 'But what we do determine oft we break.'), ('hamlet_act3_scene2', 157, 166, 'PLAYER KING', 'Purpose is but the slave to memory,'), ('hamlet_act3_scene2', 158, 167, 'PLAYER KING', 'Of violent birth, but poor validity:'), ('hamlet_act3_scene2', 159, 168, 'PLAYER KING', 'Which now, like fruit unripe, sticks on the tree;'), ('hamlet_act3_scene2', 160, 169, 'PLAYER KING', 'But fall, unshaken, when they mellow be.'), ('hamlet_act3_scene2', 161, 170, 'PLAYER KING', 'Most necessary ’tis that we forget'), ('hamlet_act3_scene2', 162, 171, 'PLAYER KING', 'To pay ourselves what to ourselves is debt:'), ('hamlet_act3_scene2', 163, 172, 'PLAYER KING', 'What to ourselves in passion we propose,'), ('hamlet_act3_scene2', 164, 173, 'PLAYER KING', 'The passion ending, doth the purpose lose.'), ('hamlet_act3_scene2', 165, 174, 'PLAYER KING', 'The violence of either grief or joy'), ('hamlet_act3_scene2', 166, 175, 'PLAYER KING', 'Their own enactures with themselves destroy:'), ('hamlet_act3_scene2', 167, 176, 'PLAYER KING', 'Where joy most revels, grief doth most lament;'), ('hamlet_act3_scene2', 168, 177, 'PLAYER KING', 'Grief joys, joy grieves, on slender accident.'), ('hamlet_act3_scene2', 169, 178, 'PLAYER KING', 'This world is not for aye, nor ’tis not strange'), ('hamlet_act3_scene2', 170, 179, 'PLAYER KING', 'That even our loves should with our fortunes change;'), ('hamlet_act3_scene2', 171, 180, 'PLAYER KING', 'For ’tis a question left us yet to prove,'), ('hamlet_act3_scene2', 172, 181, 'PLAYER KING', 'Whether love lead fortune, or else fortune love.'), ('hamlet_act3_scene2', 173, 182, 'PLAYER KING', 'The great man down, you mark his favourite flies;'), ('hamlet_act3_scene2', 174, 183, 'PLAYER KING', 'The poor advanced makes friends of enemies.'), ('hamlet_act3_scene2', 175, 184, 'PLAYER KING', 'And hitherto doth love on fortune tend;'), ('hamlet_act3_scene2', 176, 185, 'PLAYER KING', 'For who not needs shall never lack a friend,'), ('hamlet_act3_scene2', 177, 186, 'PLAYER KING', 'And who in want a hollow friend doth try,'), ('hamlet_act3_scene2', 178, 187, 'PLAYER KING', 'Directly seasons him his enemy.'), ('hamlet_act3_scene2', 179, 188, 'PLAYER KING', 'But, orderly to end where I begun,'), ('hamlet_act3_scene2', 180, 189, 'PLAYER KING', 'Our wills and fates do so contrary run'), ('hamlet_act3_scene2', 181, 190, 'PLAYER KING', 'That our devices still are overthrown;'), ('hamlet_act3_scene2', 182, 191, 'PLAYER KING', 'Our thoughts are ours, their ends none of our own:'), ('hamlet_act3_scene2', 183, 192, 'PLAYER KING', 'So think thou wilt no second husband wed;'), ('hamlet_act3_scene2', 184, 193, 'PLAYER KING', 'But die thy thoughts when thy first lord is dead.'), ('hamlet_act3_scene2', 185, 194, 'PLAYER QUEEN', 'Nor earth to me give food, nor heaven light!'), ('hamlet_act3_scene2', 186, 195, 'PLAYER QUEEN', 'Sport and repose lock from me day and night!'), ('hamlet_act3_scene2', 187, 196, 'PLAYER QUEEN', 'To desperation turn my trust and hope!'), ('hamlet_act3_scene2', 188, 197, 'PLAYER QUEEN', 'An anchor’s cheer in prison be my scope!'), ('hamlet_act3_scene2', 189, 198, 'PLAYER QUEEN', 'Each opposite that blanks the face of joy'), ('hamlet_act3_scene2', 190, 199, 'PLAYER QUEEN', 'Meet what I would have well and it destroy!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene2', 191, 200, 'PLAYER QUEEN', 'Both here and hence pursue me lasting strife,'), ('hamlet_act3_scene2', 192, 201, 'PLAYER QUEEN', 'If, once a widow, ever I be wife!'), ('hamlet_act3_scene2', 193, 202, 'HAMLET', 'If she should break it now!'), ('hamlet_act3_scene2', 194, 203, 'PLAYER KING', '’Tis deeply sworn. Sweet, leave me here awhile;'), ('hamlet_act3_scene2', 195, 204, 'PLAYER KING', 'My spirits grow dull, and fain I would beguile'), ('hamlet_act3_scene2', 196, 205, 'PLAYER KING', 'The tedious day with sleep.'), ('hamlet_act3_scene2', 196, 206, 'PLAYER QUEEN', 'Sleep rock thy brain;'), ('hamlet_act3_scene2', 197, 207, 'PLAYER QUEEN', 'And never come mischance between us twain!'), ('hamlet_act3_scene2', 198, 208, 'HAMLET', 'Madam, how like you this play?'), ('hamlet_act3_scene2', 199, 209, 'QUEEN', 'The lady doth protest too much, methinks.'), ('hamlet_act3_scene2', 200, 210, 'HAMLET', 'O, but she’ll keep her word.'), ('hamlet_act3_scene2', 201, 211, 'KING', 'Have you heard the argument? Is there no offence in’t?'), ('hamlet_act3_scene2', 202, 212, 'HAMLET', 'No, no, they do but jest, poison in jest; no offence i’ the world.'), ('hamlet_act3_scene2', 203, 213, 'KING', 'What do you call the play?'), ('hamlet_act3_scene2', 204, 214, 'HAMLET', 'The Mouse-trap. Marry, how? Tropically. This play is the image of a'), ('hamlet_act3_scene2', 205, 215, 'HAMLET', 'murder done in Vienna: Gonzago is the duke’s name; his wife, Baptista:'), ('hamlet_act3_scene2', 206, 216, 'HAMLET', 'you shall see anon; ’tis a knavish piece of work: but what'), ('hamlet_act3_scene2', 207, 217, 'HAMLET', 'o’ that? your majesty and we that have free souls, it touches'), ('hamlet_act3_scene2', 208, 218, 'HAMLET', 'us not: let the galled jade wince, our withers are unwrung.'), ('hamlet_act3_scene2', 209, 219, 'OPHELIA', 'You are as good as a chorus, my lord.'), ('hamlet_act3_scene2', 210, 220, 'HAMLET', 'I could interpret between you and your love, if I could see the puppets dallying.'), ('hamlet_act3_scene2', 211, 221, 'OPHELIA', 'You are keen, my lord, you are keen.'), ('hamlet_act3_scene2', 212, 222, 'HAMLET', 'It would cost you a groaning to take off my edge.'), ('hamlet_act3_scene2', 213, 223, 'OPHELIA', 'Still better, and worse.'), ('hamlet_act3_scene2', 214, 224, 'HAMLET', 'So you must take your husbands. Begin, murderer; pox, leave thy damnable'), ('hamlet_act3_scene2', 215, 225, 'HAMLET', 'faces, and begin. Come: “the croaking raven doth bellow for revenge.”'), ('hamlet_act3_scene2', 216, 226, 'LUCIANUS', 'Thoughts black, hands apt, drugs fit, and time agreeing;'), ('hamlet_act3_scene2', 217, 227, 'LUCIANUS', 'Confederate season, else no creature seeing;'), ('hamlet_act3_scene2', 218, 228, 'LUCIANUS', 'Thou mixture rank, of midnight weeds collected,'), ('hamlet_act3_scene2', 219, 229, 'LUCIANUS', 'With Hecate’s ban thrice blasted, thrice infected,'), ('hamlet_act3_scene2', 220, 230, 'LUCIANUS', 'Thy natural magic and dire property,'), ('hamlet_act3_scene2', 221, 231, 'LUCIANUS', 'On wholesome life usurp immediately.'), ('hamlet_act3_scene2', 222, 232, 'HAMLET', 'He poisons him i’ the garden for’s estate. His name’s Gonzago: the'), ('hamlet_act3_scene2', 223, 233, 'HAMLET', 'story is extant, and writ in choice Italian: you shall see anon'), ('hamlet_act3_scene2', 224, 234, 'HAMLET', 'how the murderer gets the love of Gonzago’s wife.'), ('hamlet_act3_scene2', 225, 235, 'OPHELIA', 'The king rises.'), ('hamlet_act3_scene2', 225, 236, 'HAMLET', 'What, frighted with false fire!'), ('hamlet_act3_scene2', 226, 237, 'QUEEN', 'How fares my lord?'), ('hamlet_act3_scene2', 226, 238, 'POLONIUS', 'Give o’er the play.'), ('hamlet_act3_scene2', 227, 239, 'KING', 'Give me some light: away!'), ('hamlet_act3_scene2', 227, 240, 'ALL', 'Lights, lights, lights!'), ('hamlet_act3_scene2', 228, 241, 'HAMLET', 'Why, let the stricken deer go weep, The hart ungalled play; For'), ('hamlet_act3_scene2', 229, 242, 'HAMLET', 'some must watch, while some must sleep: So runs the world away.'), ('hamlet_act3_scene2', 230, 243, 'HAMLET', 'Would not this, sir, and a forest of feathers—if the rest of'), ('hamlet_act3_scene2', 231, 244, 'HAMLET', 'my fortunes turn Turk with me—with two Provincial roses on my razed'), ('hamlet_act3_scene2', 232, 245, 'HAMLET', 'shoes, get me a fellowship in a cry of players, sir?'), ('hamlet_act3_scene2', 233, 246, 'HORATIO', 'Half a share.'), ('hamlet_act3_scene2', 234, 247, 'HAMLET', 'A whole one, I. For thou dost know, O Damon dear, This'), ('hamlet_act3_scene2', 235, 248, 'HAMLET', 'realm dismantled was Of Jove himself; and now reigns here A very,'), ('hamlet_act3_scene2', 236, 249, 'HAMLET', 'very—pajock.'), ('hamlet_act3_scene2', 236, 250, 'HORATIO', 'You might have rhymed.'), ('hamlet_act3_scene2', 237, 251, 'HAMLET', 'O good Horatio, I’ll take the ghost’s word for a thousand pound. Didst perceive?'), ('hamlet_act3_scene2', 238, 252, 'HORATIO', 'Very well, my lord.'), ('hamlet_act3_scene2', 238, 253, 'HAMLET', 'Upon the talk of the poisoning?'), ('hamlet_act3_scene2', 239, 254, 'HORATIO', 'I did very well note him.'), ('hamlet_act3_scene2', 240, 255, 'HAMLET', 'Ah, ha! Come, some music! come, the recorders!'), ('hamlet_act3_scene2', 241, 256, 'HAMLET', 'For if the king like not the comedy,'), ('hamlet_act3_scene2', 242, 257, 'HAMLET', 'Why then, belike, he likes it not, perdy.'), ('hamlet_act3_scene2', 243, 258, 'HAMLET', 'Come, some music!'), ('hamlet_act3_scene2', 244, 259, 'GUILDENSTERN', 'Good my lord, vouchsafe me a word with you.'), ('hamlet_act3_scene2', 245, 260, 'HAMLET', 'Sir, a whole history.'), ('hamlet_act3_scene2', 245, 261, 'GUILDENSTERN', 'The king, sir—'), ('hamlet_act3_scene2', 246, 262, 'HAMLET', 'Ay, sir, what of him?'), ('hamlet_act3_scene2', 246, 263, 'GUILDENSTERN', 'Is in his retirement marvellous distempered.'), ('hamlet_act3_scene2', 247, 264, 'HAMLET', 'With drink, sir?'), ('hamlet_act3_scene2', 247, 265, 'GUILDENSTERN', 'No, my lord, rather with choler.'), ('hamlet_act3_scene2', 248, 266, 'HAMLET', 'Your wisdom should show itself more richer to signify this to his'), ('hamlet_act3_scene2', 249, 267, 'HAMLET', 'doctor; for, for me to put him to his purgation would perhaps'), ('hamlet_act3_scene2', 250, 268, 'HAMLET', 'plunge him into far more choler.'), ('hamlet_act3_scene2', 251, 269, 'GUILDENSTERN', 'Good my lord, put your discourse into some frame and start not'), ('hamlet_act3_scene2', 252, 270, 'GUILDENSTERN', 'so wildly from my affair.'), ('hamlet_act3_scene2', 252, 271, 'HAMLET', 'I am tame, sir: pronounce.'), ('hamlet_act3_scene2', 253, 272, 'GUILDENSTERN', 'The queen, your mother, in most great affliction of spirit, hath sent me to you.'), ('hamlet_act3_scene2', 254, 273, 'HAMLET', 'You are welcome.'), ('hamlet_act3_scene2', 255, 274, 'GUILDENSTERN', 'Nay, good my lord, this courtesy is not of the right breed.'), ('hamlet_act3_scene2', 256, 275, 'GUILDENSTERN', 'If it shall please you to make me a wholesome answer, I'), ('hamlet_act3_scene2', 257, 276, 'GUILDENSTERN', 'will do your mother’s commandment: if not, your pardon and my return'), ('hamlet_act3_scene2', 258, 277, 'GUILDENSTERN', 'shall be the end of my business.'), ('hamlet_act3_scene2', 259, 278, 'HAMLET', 'Sir, I cannot.'), ('hamlet_act3_scene2', 259, 279, 'GUILDENSTERN', 'What, my lord?'), ('hamlet_act3_scene2', 260, 280, 'HAMLET', 'Make you a wholesome answer; my wit’s diseased: but, sir, such answer'), ('hamlet_act3_scene2', 261, 281, 'HAMLET', 'as I can make, you shall command; or, rather, as you say,'), ('hamlet_act3_scene2', 262, 282, 'HAMLET', 'my mother: therefore no more, but to the matter: my mother, you'), ('hamlet_act3_scene2', 263, 283, 'HAMLET', 'say—'), ('hamlet_act3_scene2', 264, 284, 'ROSENCRANTZ', 'Then thus she says; your behavior hath struck her into amazement and admiration.'), ('hamlet_act3_scene2', 265, 285, 'HAMLET', 'O wonderful son, that can so astonish a mother! But is there'), ('hamlet_act3_scene2', 266, 286, 'HAMLET', 'no sequel at the heels of this mother’s admiration? Impart.'), ('hamlet_act3_scene2', 267, 287, 'ROSENCRANTZ', 'She desires to speak with you in her closet, ere you go to bed.'), ('hamlet_act3_scene2', 268, 288, 'HAMLET', 'We shall obey, were she ten times our mother. Have you any'), ('hamlet_act3_scene2', 269, 289, 'HAMLET', 'further trade with us?'), ('hamlet_act3_scene2', 270, 290, 'ROSENCRANTZ', 'My lord, you once did love me.'), ('hamlet_act3_scene2', 271, 291, 'HAMLET', 'So I do still, by these pickers and stealers.'), ('hamlet_act3_scene2', 272, 292, 'ROSENCRANTZ', 'Good my lord, what is your cause of distemper? you do, surely,'), ('hamlet_act3_scene2', 273, 293, 'ROSENCRANTZ', 'bar the door upon your own liberty, if you deny your griefs'), ('hamlet_act3_scene2', 274, 294, 'ROSENCRANTZ', 'to your friend.'), ('hamlet_act3_scene2', 274, 295, 'HAMLET', 'Sir, I lack advancement.'), ('hamlet_act3_scene2', 275, 296, 'ROSENCRANTZ', 'How can that be, when you have the voice of the king'), ('hamlet_act3_scene2', 276, 297, 'ROSENCRANTZ', 'himself for your succession in Denmark?'), ('hamlet_act3_scene2', 277, 298, 'HAMLET', 'Ay, but sir, “While the grass grows,”—the proverb is something musty.'), ('hamlet_act3_scene2', 278, 299, 'GUILDENSTERN', 'O, my lord, if my duty be too bold, my love is too unmannerly.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene2', 279, 300, 'HAMLET', 'I do not well understand that. Will you play upon this pipe?'), ('hamlet_act3_scene2', 280, 301, 'GUILDENSTERN', 'My lord, I cannot.'), ('hamlet_act3_scene2', 280, 302, 'HAMLET', 'I pray you.'), ('hamlet_act3_scene2', 281, 303, 'GUILDENSTERN', 'Believe me, I cannot.'), ('hamlet_act3_scene2', 281, 304, 'HAMLET', 'I do beseech you.'), ('hamlet_act3_scene2', 282, 305, 'GUILDENSTERN', 'I know no touch of it, my lord.'), ('hamlet_act3_scene2', 283, 306, 'HAMLET', '’Tis as easy as lying: govern these ventages with your fingers and'), ('hamlet_act3_scene2', 284, 307, 'HAMLET', 'thumb, give it breath with your mouth, and it will discourse most'), ('hamlet_act3_scene2', 285, 308, 'HAMLET', 'eloquent music. Look you, these are the stops.'), ('hamlet_act3_scene2', 286, 309, 'GUILDENSTERN', 'But these cannot I command to any utterance of harmony; I have not the skill.'), ('hamlet_act3_scene2', 287, 310, 'HAMLET', 'Why, look you now, how unworthy a thing you make of me!'), ('hamlet_act3_scene2', 288, 311, 'HAMLET', 'You would play upon me; you would seem to know my stops;'), ('hamlet_act3_scene2', 289, 312, 'HAMLET', 'you would pluck out the heart of my mystery; you would sound'), ('hamlet_act3_scene2', 290, 313, 'HAMLET', 'me from my lowest note to the top of my compass: and'), ('hamlet_act3_scene2', 291, 314, 'HAMLET', 'there is much music, excellent voice, in this little organ; yet cannot'), ('hamlet_act3_scene2', 292, 315, 'HAMLET', 'you make it speak. ’Sblood, do you think I am easier to'), ('hamlet_act3_scene2', 293, 316, 'HAMLET', 'be played on than a pipe? Call me what instrument you will,'), ('hamlet_act3_scene2', 294, 317, 'HAMLET', 'though you can fret me, yet you cannot play upon me.'), ('hamlet_act3_scene2', 295, 318, 'POLONIUS', 'My lord, the queen would speak with you, and presently.'), ('hamlet_act3_scene2', 296, 319, 'HAMLET', 'Do you see yonder cloud that’s almost in shape of a camel?'), ('hamlet_act3_scene2', 297, 320, 'POLONIUS', 'By the mass, and ’tis like a camel, indeed.'), ('hamlet_act3_scene2', 298, 321, 'HAMLET', 'Methinks it is like a weasel.'), ('hamlet_act3_scene2', 298, 322, 'POLONIUS', 'It is backed like a weasel.'), ('hamlet_act3_scene2', 299, 323, 'HAMLET', 'Or like a whale?'), ('hamlet_act3_scene2', 299, 324, 'POLONIUS', 'Very like a whale.'), ('hamlet_act3_scene2', 300, 325, 'HAMLET', 'Then I will come to my mother by and by. They fool'), ('hamlet_act3_scene2', 301, 326, 'HAMLET', 'me to the top of my bent. I will come by and'), ('hamlet_act3_scene2', 302, 327, 'HAMLET', 'by.'), ('hamlet_act3_scene2', 302, 328, 'POLONIUS', 'I will say so.'), ('hamlet_act3_scene2', 303, 329, 'HAMLET', 'By and by is easily said. Leave me, friends.'), ('hamlet_act3_scene2', 304, 330, 'HAMLET', 'Tis now the very witching time of night,'), ('hamlet_act3_scene2', 305, 331, 'HAMLET', 'When churchyards yawn and hell itself breathes out'), ('hamlet_act3_scene2', 306, 332, 'HAMLET', 'Contagion to this world: now could I drink hot blood,'), ('hamlet_act3_scene2', 307, 333, 'HAMLET', 'And do such bitter business as the day'), ('hamlet_act3_scene2', 308, 334, 'HAMLET', 'Would quake to look on. Soft! now to my mother.'), ('hamlet_act3_scene2', 309, 335, 'HAMLET', 'O heart, lose not thy nature; let not ever'), ('hamlet_act3_scene2', 310, 336, 'HAMLET', 'The soul of Nero enter this firm bosom:'), ('hamlet_act3_scene2', 311, 337, 'HAMLET', 'Let me be cruel, not unnatural:'), ('hamlet_act3_scene2', 312, 338, 'HAMLET', 'I will speak daggers to her, but use none;'), ('hamlet_act3_scene2', 313, 339, 'HAMLET', 'My tongue and soul in this be hypocrites;'), ('hamlet_act3_scene2', 314, 340, 'HAMLET', 'How in my words soever she be shent,'), ('hamlet_act3_scene2', 315, 341, 'HAMLET', 'To give them seals never, my soul, consent!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene3', 1, 0, 'KING', 'I like him not, nor stands it safe with us'), ('hamlet_act3_scene3', 2, 1, 'KING', 'To let his madness range. Therefore prepare you;'), ('hamlet_act3_scene3', 3, 2, 'KING', 'I your commission will forthwith dispatch,'), ('hamlet_act3_scene3', 4, 3, 'KING', 'And he to England shall along with you:'), ('hamlet_act3_scene3', 5, 4, 'KING', 'The terms of our estate may not endure'), ('hamlet_act3_scene3', 6, 5, 'KING', 'Hazard so dangerous as doth hourly grow'), ('hamlet_act3_scene3', 7, 6, 'KING', 'Out of his lunacies.'), ('hamlet_act3_scene3', 7, 7, 'GUILDENSTERN', 'We will ourselves provide:'), ('hamlet_act3_scene3', 8, 8, 'GUILDENSTERN', 'Most holy and religious fear it is'), ('hamlet_act3_scene3', 9, 9, 'GUILDENSTERN', 'To keep those many many bodies safe'), ('hamlet_act3_scene3', 10, 10, 'GUILDENSTERN', 'That live and feed upon your majesty.'), ('hamlet_act3_scene3', 11, 11, 'ROSENCRANTZ', 'The single and peculiar life is bound,'), ('hamlet_act3_scene3', 12, 12, 'ROSENCRANTZ', 'With all the strength and armour of the mind,'), ('hamlet_act3_scene3', 13, 13, 'ROSENCRANTZ', 'To keep itself from noyance; but much more'), ('hamlet_act3_scene3', 14, 14, 'ROSENCRANTZ', 'That spirit upon whose weal depend and rest'), ('hamlet_act3_scene3', 15, 15, 'ROSENCRANTZ', 'The lives of many. The cease of majesty'), ('hamlet_act3_scene3', 16, 16, 'ROSENCRANTZ', 'Dies not alone; but, like a gulf, doth draw'), ('hamlet_act3_scene3', 17, 17, 'ROSENCRANTZ', 'What’s near it with it: it is a massy wheel,'), ('hamlet_act3_scene3', 18, 18, 'ROSENCRANTZ', 'Fix’d on the summit of the highest mount,'), ('hamlet_act3_scene3', 19, 19, 'ROSENCRANTZ', 'To whose huge spokes ten thousand lesser things'), ('hamlet_act3_scene3', 20, 20, 'ROSENCRANTZ', 'Are mortised and adjoin’d; which, when it falls,'), ('hamlet_act3_scene3', 21, 21, 'ROSENCRANTZ', 'Each small annexment, petty consequence,'), ('hamlet_act3_scene3', 22, 22, 'ROSENCRANTZ', 'Attends the boisterous ruin. Never alone'), ('hamlet_act3_scene3', 23, 23, 'ROSENCRANTZ', 'Did the king sigh, but with a general groan.'), ('hamlet_act3_scene3', 24, 24, 'KING', 'Arm you, I pray you, to this speedy voyage;'), ('hamlet_act3_scene3', 25, 25, 'KING', 'For we will fetters put upon this fear,'), ('hamlet_act3_scene3', 26, 26, 'KING', 'Which now goes too free-footed.'), ('hamlet_act3_scene3', 26, 27, 'ROSENCRANTZ GUILDENSTERN', 'We will haste us.'), ('hamlet_act3_scene3', 27, 28, 'POLONIUS', 'My lord, he’s going to his mother’s closet:'), ('hamlet_act3_scene3', 28, 29, 'POLONIUS', 'Behind the arras I’ll convey myself,'), ('hamlet_act3_scene3', 29, 30, 'POLONIUS', 'To hear the process; and warrant she’ll tax him home:'), ('hamlet_act3_scene3', 30, 31, 'POLONIUS', 'And, as you said, and wisely was it said,'), ('hamlet_act3_scene3', 31, 32, 'POLONIUS', '’Tis meet that some more audience than a mother,'), ('hamlet_act3_scene3', 32, 33, 'POLONIUS', 'Since nature makes them partial, should o’erhear'), ('hamlet_act3_scene3', 33, 34, 'POLONIUS', 'The speech, of vantage. Fare you well, my liege:'), ('hamlet_act3_scene3', 34, 35, 'POLONIUS', 'I’ll call upon you ere you go to bed,'), ('hamlet_act3_scene3', 35, 36, 'POLONIUS', 'And tell you what I know.'), ('hamlet_act3_scene3', 35, 37, 'KING', 'Thanks, dear my lord.'), ('hamlet_act3_scene3', 36, 38, 'KING', 'O, my offence is rank, it smells to heaven;'), ('hamlet_act3_scene3', 37, 39, 'KING', 'It hath the primal eldest curse upon’t,'), ('hamlet_act3_scene3', 38, 40, 'KING', 'A brother’s murder. Pray can I not,'), ('hamlet_act3_scene3', 39, 41, 'KING', 'Though inclination be as sharp as will:'), ('hamlet_act3_scene3', 40, 42, 'KING', 'My stronger guilt defeats my strong intent;'), ('hamlet_act3_scene3', 41, 43, 'KING', 'And, like a man to double business bound,'), ('hamlet_act3_scene3', 42, 44, 'KING', 'I stand in pause where I shall first begin,'), ('hamlet_act3_scene3', 43, 45, 'KING', 'And both neglect. What if this cursed hand'), ('hamlet_act3_scene3', 44, 46, 'KING', 'Were thicker than itself with brother’s blood,'), ('hamlet_act3_scene3', 45, 47, 'KING', 'Is there not rain enough in the sweet heavens'), ('hamlet_act3_scene3', 46, 48, 'KING', 'To wash it white as snow? Whereto serves mercy'), ('hamlet_act3_scene3', 47, 49, 'KING', 'But to confront the visage of offence?'), ('hamlet_act3_scene3', 48, 50, 'KING', 'And what’s in prayer but this two-fold force,'), ('hamlet_act3_scene3', 49, 51, 'KING', 'To be forestalled ere we come to fall,'), ('hamlet_act3_scene3', 50, 52, 'KING', 'Or pardon’d being down? Then I’ll look up;'), ('hamlet_act3_scene3', 51, 53, 'KING', 'My fault is past. But, O, what form of prayer'), ('hamlet_act3_scene3', 52, 54, 'KING', 'Can serve my turn? “Forgive me my foul murder”?'), ('hamlet_act3_scene3', 53, 55, 'KING', 'That cannot be; since I am still possess’d'), ('hamlet_act3_scene3', 54, 56, 'KING', 'Of those effects for which I did the murder,'), ('hamlet_act3_scene3', 55, 57, 'KING', 'My crown, mine own ambition and my queen.'), ('hamlet_act3_scene3', 56, 58, 'KING', 'May one be pardon’d and retain the offence?'), ('hamlet_act3_scene3', 57, 59, 'KING', 'In the corrupted currents of this world'), ('hamlet_act3_scene3', 58, 60, 'KING', 'Offence’s gilded hand may shove by justice,'), ('hamlet_act3_scene3', 59, 61, 'KING', 'And oft ’tis seen the wicked prize itself'), ('hamlet_act3_scene3', 60, 62, 'KING', 'Buys out the law: but ’tis not so above;'), ('hamlet_act3_scene3', 61, 63, 'KING', 'There is no shuffling, there the action lies'), ('hamlet_act3_scene3', 62, 64, 'KING', 'In his true nature; and we ourselves compell’d,'), ('hamlet_act3_scene3', 63, 65, 'KING', 'Even to the teeth and forehead of our faults,'), ('hamlet_act3_scene3', 64, 66, 'KING', 'To give in evidence. What then? what rests?'), ('hamlet_act3_scene3', 65, 67, 'KING', 'Try what repentance can: what can it not?'), ('hamlet_act3_scene3', 66, 68, 'KING', 'Yet what can it when one can not repent?'), ('hamlet_act3_scene3', 67, 69, 'KING', 'O wretched state! O bosom black as death!'), ('hamlet_act3_scene3', 68, 70, 'KING', 'O limed soul, that, struggling to be free,'), ('hamlet_act3_scene3', 69, 71, 'KING', 'Art more engaged! Help, angels! Make assay!'), ('hamlet_act3_scene3', 70, 72, 'KING', 'Bow, stubborn knees; and, heart with strings of steel,'), ('hamlet_act3_scene3', 71, 73, 'KING', 'Be soft as sinews of the newborn babe!'), ('hamlet_act3_scene3', 72, 74, 'KING', 'All may be well.'), ('hamlet_act3_scene3', 73, 75, 'HAMLET', 'Now might I do it pat, now he is praying;'), ('hamlet_act3_scene3', 74, 76, 'HAMLET', 'And now I’ll do’t. And so he goes to heaven;'), ('hamlet_act3_scene3', 75, 77, 'HAMLET', 'And so am I revenged. That would be scann’d:'), ('hamlet_act3_scene3', 76, 78, 'HAMLET', 'A villain kills my father; and for that,'), ('hamlet_act3_scene3', 77, 79, 'HAMLET', 'I, his sole son, do this same villain send'), ('hamlet_act3_scene3', 78, 80, 'HAMLET', 'To heaven.'), ('hamlet_act3_scene3', 79, 81, 'HAMLET', 'O, this is hire and salary, not revenge.'), ('hamlet_act3_scene3', 80, 82, 'HAMLET', 'He took my father grossly, full of bread;'), ('hamlet_act3_scene3', 81, 83, 'HAMLET', 'With all his crimes broad blown, as flush as May;'), ('hamlet_act3_scene3', 82, 84, 'HAMLET', 'And how his audit stands who knows save heaven?'), ('hamlet_act3_scene3', 83, 85, 'HAMLET', 'But in our circumstance and course of thought,'), ('hamlet_act3_scene3', 84, 86, 'HAMLET', '’Tis heavy with him: and am I then revenged,'), ('hamlet_act3_scene3', 85, 87, 'HAMLET', 'To take him in the purging of his soul,'), ('hamlet_act3_scene3', 86, 88, 'HAMLET', 'When he is fit and season’d for his passage?'), ('hamlet_act3_scene3', 87, 89, 'HAMLET', 'No!'), ('hamlet_act3_scene3', 88, 90, 'HAMLET', 'Up, sword; and know thou a more horrid hent:'), ('hamlet_act3_scene3', 89, 91, 'HAMLET', 'When he is drunk asleep, or in his rage,'), ('hamlet_act3_scene3', 90, 92, 'HAMLET', 'Or in the incestuous pleasure of his bed;'), ('hamlet_act3_scene3', 91, 93, 'HAMLET', 'At gaming, swearing, or about some act'), ('hamlet_act3_scene3', 92, 94, 'HAMLET', 'That has no relish of salvation in’t;'), ('hamlet_act3_scene3', 93, 95, 'HAMLET', 'Then trip him, that his heels may kick at heaven,'), ('hamlet_act3_scene3', 94, 96, 'HAMLET', 'And that his soul may be as damn’d and black'), ('hamlet_act3_scene3', 95, 97, 'HAMLET', 'As hell, whereto it goes. My mother stays:'), ('hamlet_act3_scene3', 96, 98, 'HAMLET', 'This physic but prolongs thy sickly days.'), ('hamlet_act3_scene3', 97, 99, 'KING', 'My words fly up, my thoughts remain below:');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene3', 98, 100, 'KING', 'Words without thoughts never to heaven go.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene4', 1, 0, 'POLONIUS', 'He will come straight. Look you lay home to him:'), ('hamlet_act3_scene4', 2, 1, 'POLONIUS', 'Tell him his pranks have been too broad to bear with,'), ('hamlet_act3_scene4', 3, 2, 'POLONIUS', 'And that your grace hath screen’d and stood between'), ('hamlet_act3_scene4', 4, 3, 'POLONIUS', 'Much heat and him. I’ll sconce me even here.'), ('hamlet_act3_scene4', 5, 4, 'POLONIUS', 'Pray you, be round with him.'), ('hamlet_act3_scene4', 5, 5, 'HAMLET', 'Mother, mother, mother!'), ('hamlet_act3_scene4', 6, 6, 'QUEEN', 'I’ll warrant you,'), ('hamlet_act3_scene4', 7, 7, 'QUEEN', 'Fear me not: withdraw, I hear him coming.'), ('hamlet_act3_scene4', 8, 8, 'HAMLET', 'Now, mother, what’s the matter?'), ('hamlet_act3_scene4', 9, 9, 'QUEEN', 'Hamlet, thou hast thy father much offended.'), ('hamlet_act3_scene4', 10, 10, 'HAMLET', 'Mother, you have my father much offended.'), ('hamlet_act3_scene4', 11, 11, 'QUEEN', 'Come, come, you answer with an idle tongue.'), ('hamlet_act3_scene4', 12, 12, 'HAMLET', 'Go, go, you question with a wicked tongue.'), ('hamlet_act3_scene4', 13, 13, 'QUEEN', 'Why, how now, Hamlet!'), ('hamlet_act3_scene4', 13, 14, 'HAMLET', 'What’s the matter now?'), ('hamlet_act3_scene4', 14, 15, 'QUEEN', 'Have you forgot me?'), ('hamlet_act3_scene4', 14, 16, 'HAMLET', 'No, by the rood, not so:'), ('hamlet_act3_scene4', 15, 17, 'HAMLET', 'You are the queen, your husband’s brother’s wife;'), ('hamlet_act3_scene4', 16, 18, 'HAMLET', 'And—would it were not so!—you are my mother.'), ('hamlet_act3_scene4', 17, 19, 'QUEEN', 'Nay, then, I’ll set those to you that can speak.'), ('hamlet_act3_scene4', 18, 20, 'HAMLET', 'Come, come, and sit you down; you shall not budge;'), ('hamlet_act3_scene4', 19, 21, 'HAMLET', 'You go not till I set you up a glass'), ('hamlet_act3_scene4', 20, 22, 'HAMLET', 'Where you may see the inmost part of you.'), ('hamlet_act3_scene4', 21, 23, 'QUEEN', 'What wilt thou do? thou wilt not murder me?'), ('hamlet_act3_scene4', 22, 24, 'QUEEN', 'Help, help, ho!'), ('hamlet_act3_scene4', 22, 25, 'POLONIUS', 'What, ho! help, help, help!'), ('hamlet_act3_scene4', 23, 26, 'HAMLET', 'How now! a rat? Dead, for a ducat, dead!'), ('hamlet_act3_scene4', 24, 27, 'POLONIUS', 'O, I am slain!'), ('hamlet_act3_scene4', 24, 28, 'QUEEN', 'O me, what hast thou done?'), ('hamlet_act3_scene4', 25, 29, 'HAMLET', 'Nay, I know not:'), ('hamlet_act3_scene4', 26, 30, 'HAMLET', 'Is it the king?'), ('hamlet_act3_scene4', 27, 31, 'QUEEN', 'O, what a rash and bloody deed is this!'), ('hamlet_act3_scene4', 28, 32, 'HAMLET', 'A bloody deed! almost as bad, good mother,'), ('hamlet_act3_scene4', 29, 33, 'HAMLET', 'As kill a king, and marry with his brother.'), ('hamlet_act3_scene4', 30, 34, 'QUEEN', 'As kill a king!'), ('hamlet_act3_scene4', 30, 35, 'HAMLET', 'Ay, lady, ’twas my word.'), ('hamlet_act3_scene4', 31, 36, 'HAMLET', 'Thou wretched, rash, intruding fool, farewell!'), ('hamlet_act3_scene4', 32, 37, 'HAMLET', 'I took thee for thy better: take thy fortune;'), ('hamlet_act3_scene4', 33, 38, 'HAMLET', 'Thou find’st to be too busy is some danger.'), ('hamlet_act3_scene4', 34, 39, 'HAMLET', 'Leave wringing of your hands: peace! sit you down,'), ('hamlet_act3_scene4', 35, 40, 'HAMLET', 'And let me wring your heart; for so I shall,'), ('hamlet_act3_scene4', 36, 41, 'HAMLET', 'If it be made of penetrable stuff,'), ('hamlet_act3_scene4', 37, 42, 'HAMLET', 'If damned custom have not brass’d it so'), ('hamlet_act3_scene4', 38, 43, 'HAMLET', 'That it be proof and bulwark against sense.'), ('hamlet_act3_scene4', 39, 44, 'QUEEN', 'What have I done, that thou darest wag thy tongue'), ('hamlet_act3_scene4', 40, 45, 'QUEEN', 'In noise so rude against me?'), ('hamlet_act3_scene4', 40, 46, 'HAMLET', 'Such an act'), ('hamlet_act3_scene4', 41, 47, 'HAMLET', 'That blurs the grace and blush of modesty,'), ('hamlet_act3_scene4', 42, 48, 'HAMLET', 'Calls virtue hypocrite, takes off the rose'), ('hamlet_act3_scene4', 43, 49, 'HAMLET', 'From the fair forehead of an innocent love'), ('hamlet_act3_scene4', 44, 50, 'HAMLET', 'And sets a blister there, makes marriage-vows'), ('hamlet_act3_scene4', 45, 51, 'HAMLET', 'As false as dicers’ oaths: O, such a deed'), ('hamlet_act3_scene4', 46, 52, 'HAMLET', 'As from the body of contraction plucks'), ('hamlet_act3_scene4', 47, 53, 'HAMLET', 'The very soul, and sweet religion makes'), ('hamlet_act3_scene4', 48, 54, 'HAMLET', 'A rhapsody of words: heaven’s face doth glow;'), ('hamlet_act3_scene4', 49, 55, 'HAMLET', 'Yea, this solidity and compound mass,'), ('hamlet_act3_scene4', 50, 56, 'HAMLET', 'With tristful visage, as against the doom,'), ('hamlet_act3_scene4', 51, 57, 'HAMLET', 'Is thought-sick at the act.'), ('hamlet_act3_scene4', 51, 58, 'QUEEN', 'Ay me, what act,'), ('hamlet_act3_scene4', 52, 59, 'QUEEN', 'That roars so loud, and thunders in the index?'), ('hamlet_act3_scene4', 53, 60, 'HAMLET', 'Look here, upon this picture, and on this,'), ('hamlet_act3_scene4', 54, 61, 'HAMLET', 'The counterfeit presentment of two brothers.'), ('hamlet_act3_scene4', 55, 62, 'HAMLET', 'See, what a grace was seated on this brow;'), ('hamlet_act3_scene4', 56, 63, 'HAMLET', 'Hyperion’s curls; the front of Jove himself;'), ('hamlet_act3_scene4', 57, 64, 'HAMLET', 'An eye like Mars, to threaten and command;'), ('hamlet_act3_scene4', 58, 65, 'HAMLET', 'A station like the herald Mercury'), ('hamlet_act3_scene4', 59, 66, 'HAMLET', 'New-lighted on a heaven-kissing hill;'), ('hamlet_act3_scene4', 60, 67, 'HAMLET', 'A combination and a form indeed,'), ('hamlet_act3_scene4', 61, 68, 'HAMLET', 'Where every god did seem to set his seal,'), ('hamlet_act3_scene4', 62, 69, 'HAMLET', 'To give the world assurance of a man:'), ('hamlet_act3_scene4', 63, 70, 'HAMLET', 'This was your husband. Look you now, what follows:'), ('hamlet_act3_scene4', 64, 71, 'HAMLET', 'Here is your husband; like a mildew’d ear,'), ('hamlet_act3_scene4', 65, 72, 'HAMLET', 'Blasting his wholesome brother. Have you eyes?'), ('hamlet_act3_scene4', 66, 73, 'HAMLET', 'Could you on this fair mountain leave to feed,'), ('hamlet_act3_scene4', 67, 74, 'HAMLET', 'And batten on this moor? Ha! have you eyes?'), ('hamlet_act3_scene4', 68, 75, 'HAMLET', 'You cannot call it love; for at your age'), ('hamlet_act3_scene4', 69, 76, 'HAMLET', 'The hey-day in the blood is tame, it’s humble,'), ('hamlet_act3_scene4', 70, 77, 'HAMLET', 'And waits upon the judgment: and what judgment'), ('hamlet_act3_scene4', 71, 78, 'HAMLET', 'Would step from this to this? Sense, sure, you have,'), ('hamlet_act3_scene4', 72, 79, 'HAMLET', 'Else could you not have motion; but sure, that sense'), ('hamlet_act3_scene4', 73, 80, 'HAMLET', 'Is apoplex’d; for madness would not err,'), ('hamlet_act3_scene4', 74, 81, 'HAMLET', 'Nor sense to ecstasy was ne’er so thrall’d'), ('hamlet_act3_scene4', 75, 82, 'HAMLET', 'But it reserved some quantity of choice,'), ('hamlet_act3_scene4', 76, 83, 'HAMLET', 'To serve in such a difference. What devil was’t'), ('hamlet_act3_scene4', 77, 84, 'HAMLET', 'That thus hath cozen’d you at hoodman-blind?'), ('hamlet_act3_scene4', 78, 85, 'HAMLET', 'Eyes without feeling, feeling without sight,'), ('hamlet_act3_scene4', 79, 86, 'HAMLET', 'Ears without hands or eyes, smelling sans all,'), ('hamlet_act3_scene4', 80, 87, 'HAMLET', 'Or but a sickly part of one true sense'), ('hamlet_act3_scene4', 81, 88, 'HAMLET', 'Could not so mope.'), ('hamlet_act3_scene4', 82, 89, 'HAMLET', 'O shame! where is thy blush? Rebellious hell,'), ('hamlet_act3_scene4', 83, 90, 'HAMLET', 'If thou canst mutine in a matron’s bones,'), ('hamlet_act3_scene4', 84, 91, 'HAMLET', 'To flaming youth let virtue be as wax,'), ('hamlet_act3_scene4', 85, 92, 'HAMLET', 'And melt in her own fire: proclaim no shame'), ('hamlet_act3_scene4', 86, 93, 'HAMLET', 'When the compulsive ardour gives the charge,'), ('hamlet_act3_scene4', 87, 94, 'HAMLET', 'Since frost itself as actively doth burn'), ('hamlet_act3_scene4', 88, 95, 'HAMLET', 'And reason panders will.'), ('hamlet_act3_scene4', 88, 96, 'QUEEN', 'O Hamlet, speak no more:'), ('hamlet_act3_scene4', 89, 97, 'QUEEN', 'Thou turn’st mine eyes into my very soul;'), ('hamlet_act3_scene4', 90, 98, 'QUEEN', 'And there I see such black and grained spots'), ('hamlet_act3_scene4', 91, 99, 'QUEEN', 'As will not leave their tinct.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene4', 91, 100, 'HAMLET', 'Nay, but to live'), ('hamlet_act3_scene4', 92, 101, 'HAMLET', 'In the rank sweat of an enseamed bed,'), ('hamlet_act3_scene4', 93, 102, 'HAMLET', 'Stew’d in corruption, honeying and making love'), ('hamlet_act3_scene4', 94, 103, 'HAMLET', 'Over the nasty sty—'), ('hamlet_act3_scene4', 94, 104, 'QUEEN', 'O, speak to me no more;'), ('hamlet_act3_scene4', 95, 105, 'QUEEN', 'These words, like daggers, enter in mine ears;'), ('hamlet_act3_scene4', 96, 106, 'QUEEN', 'No more, sweet Hamlet!'), ('hamlet_act3_scene4', 96, 107, 'HAMLET', 'A murderer and a villain;'), ('hamlet_act3_scene4', 97, 108, 'HAMLET', 'A slave that is not twentieth part the tithe'), ('hamlet_act3_scene4', 98, 109, 'HAMLET', 'Of your precedent lord; a vice of kings;'), ('hamlet_act3_scene4', 99, 110, 'HAMLET', 'A cutpurse of the empire and the rule,'), ('hamlet_act3_scene4', 100, 111, 'HAMLET', 'That from a shelf the precious diadem stole,'), ('hamlet_act3_scene4', 101, 112, 'HAMLET', 'And put it in his pocket!'), ('hamlet_act3_scene4', 101, 113, 'QUEEN', 'No more!'), ('hamlet_act3_scene4', 102, 114, 'HAMLET', 'A king of shreds and patches—'), ('hamlet_act3_scene4', 102, 115, 'QUEEN', 'Alas, he’s mad!'), ('hamlet_act3_scene4', 103, 116, 'HAMLET', 'Do you not come your tardy son to chide,'), ('hamlet_act3_scene4', 104, 117, 'HAMLET', 'That, lapsed in time and passion, lets go by'), ('hamlet_act3_scene4', 105, 118, 'HAMLET', 'The important acting of your dread command?'), ('hamlet_act3_scene4', 106, 119, 'HAMLET', 'O, say!'), ('hamlet_act3_scene4', 106, 120, 'GHOST', 'Do not forget: this visitation'), ('hamlet_act3_scene4', 107, 121, 'GHOST', 'Is but to whet thy almost blunted purpose.'), ('hamlet_act3_scene4', 108, 122, 'GHOST', 'But, look, amazement on thy mother sits:'), ('hamlet_act3_scene4', 109, 123, 'GHOST', 'O, step between her and her fighting soul:'), ('hamlet_act3_scene4', 110, 124, 'GHOST', 'Conceit in weakest bodies strongest works:'), ('hamlet_act3_scene4', 111, 125, 'GHOST', 'Speak to her, Hamlet.'), ('hamlet_act3_scene4', 111, 126, 'HAMLET', 'How is it with you, lady?'), ('hamlet_act3_scene4', 112, 127, 'QUEEN', 'Alas, how is’t with you,'), ('hamlet_act3_scene4', 113, 128, 'QUEEN', 'That you do bend your eye on vacancy'), ('hamlet_act3_scene4', 114, 129, 'QUEEN', 'And with the incorporal air do hold discourse?'), ('hamlet_act3_scene4', 115, 130, 'QUEEN', 'Forth at your eyes your spirits wildly peep;'), ('hamlet_act3_scene4', 116, 131, 'QUEEN', 'And, as the sleeping soldiers in the alarm,'), ('hamlet_act3_scene4', 117, 132, 'QUEEN', 'Your bedded hair, like life in excrements,'), ('hamlet_act3_scene4', 118, 133, 'QUEEN', 'Start up, and stand an end. O gentle son,'), ('hamlet_act3_scene4', 119, 134, 'QUEEN', 'Upon the heat and flame of thy distemper'), ('hamlet_act3_scene4', 120, 135, 'QUEEN', 'Sprinkle cool patience. Whereon do you look?'), ('hamlet_act3_scene4', 121, 136, 'HAMLET', 'On him, on him! Look you, how pale he glares!'), ('hamlet_act3_scene4', 122, 137, 'HAMLET', 'His form and cause conjoin’d, preaching to stones,'), ('hamlet_act3_scene4', 123, 138, 'HAMLET', 'Would make them capable. Do not look upon me;'), ('hamlet_act3_scene4', 124, 139, 'HAMLET', 'Lest with this piteous action you convert'), ('hamlet_act3_scene4', 125, 140, 'HAMLET', 'My stern effects: then what I have to do'), ('hamlet_act3_scene4', 126, 141, 'HAMLET', 'Will want true colour; tears perchance for blood.'), ('hamlet_act3_scene4', 127, 142, 'QUEEN', 'To whom do you speak this?'), ('hamlet_act3_scene4', 127, 143, 'HAMLET', 'Do you see nothing there?'), ('hamlet_act3_scene4', 128, 144, 'QUEEN', 'Nothing at all; yet all that is I see.'), ('hamlet_act3_scene4', 129, 145, 'HAMLET', 'Nor did you nothing hear?'), ('hamlet_act3_scene4', 129, 146, 'QUEEN', 'No, nothing but ourselves.'), ('hamlet_act3_scene4', 130, 147, 'HAMLET', 'Why, look you there! look, how it steals away!'), ('hamlet_act3_scene4', 131, 148, 'HAMLET', 'My father, in his habit as he lived!'), ('hamlet_act3_scene4', 132, 149, 'HAMLET', 'Look, where he goes, even now, out at the portal!'), ('hamlet_act3_scene4', 133, 150, 'QUEEN', 'This the very coinage of your brain:'), ('hamlet_act3_scene4', 134, 151, 'QUEEN', 'This bodiless creation ecstasy'), ('hamlet_act3_scene4', 135, 152, 'QUEEN', 'Is very cunning in.'), ('hamlet_act3_scene4', 135, 153, 'HAMLET', 'Ecstasy!'), ('hamlet_act3_scene4', 136, 154, 'HAMLET', 'My pulse, as yours, doth temperately keep time,'), ('hamlet_act3_scene4', 137, 155, 'HAMLET', 'And makes as healthful music: it is not madness'), ('hamlet_act3_scene4', 138, 156, 'HAMLET', 'That I have utter’d: bring me to the test,'), ('hamlet_act3_scene4', 139, 157, 'HAMLET', 'And I the matter will re-word; which madness'), ('hamlet_act3_scene4', 140, 158, 'HAMLET', 'Would gambol from. Mother, for love of grace,'), ('hamlet_act3_scene4', 141, 159, 'HAMLET', 'Lay not that flattering unction to your soul,'), ('hamlet_act3_scene4', 142, 160, 'HAMLET', 'That not your trespass, but my madness speaks:'), ('hamlet_act3_scene4', 143, 161, 'HAMLET', 'It will but skin and film the ulcerous place,'), ('hamlet_act3_scene4', 144, 162, 'HAMLET', 'Whilst rank corruption, mining all within,'), ('hamlet_act3_scene4', 145, 163, 'HAMLET', 'Infects unseen. Confess yourself to heaven;'), ('hamlet_act3_scene4', 146, 164, 'HAMLET', 'Repent what’s past; avoid what is to come;'), ('hamlet_act3_scene4', 147, 165, 'HAMLET', 'And do not spread the compost on the weeds,'), ('hamlet_act3_scene4', 148, 166, 'HAMLET', 'To make them ranker. Forgive me this my virtue;'), ('hamlet_act3_scene4', 149, 167, 'HAMLET', 'For in the fatness of these pursy times'), ('hamlet_act3_scene4', 150, 168, 'HAMLET', 'Virtue itself of vice must pardon beg,'), ('hamlet_act3_scene4', 151, 169, 'HAMLET', 'Yea, curb and woo for leave to do him good.'), ('hamlet_act3_scene4', 152, 170, 'QUEEN', 'O Hamlet, thou hast cleft my heart in twain.'), ('hamlet_act3_scene4', 153, 171, 'HAMLET', 'O, throw away the worser part of it,'), ('hamlet_act3_scene4', 154, 172, 'HAMLET', 'And live the purer with the other half.'), ('hamlet_act3_scene4', 155, 173, 'HAMLET', 'Good night: but go not to mine uncle’s bed;'), ('hamlet_act3_scene4', 156, 174, 'HAMLET', 'Assume a virtue, if you have it not.'), ('hamlet_act3_scene4', 157, 175, 'HAMLET', 'That monster, custom, who all sense doth eat,'), ('hamlet_act3_scene4', 158, 176, 'HAMLET', 'Of habits devil, is angel yet in this,'), ('hamlet_act3_scene4', 159, 177, 'HAMLET', 'That to the use of actions fair and good'), ('hamlet_act3_scene4', 160, 178, 'HAMLET', 'He likewise gives a frock or livery,'), ('hamlet_act3_scene4', 161, 179, 'HAMLET', 'That aptly is put on. Refrain to-night,'), ('hamlet_act3_scene4', 162, 180, 'HAMLET', 'And that shall lend a kind of easiness'), ('hamlet_act3_scene4', 163, 181, 'HAMLET', 'To the next abstinence: the next more easy;'), ('hamlet_act3_scene4', 164, 182, 'HAMLET', 'For use almost can change the stamp of nature,'), ('hamlet_act3_scene4', 165, 183, 'HAMLET', 'And either master1 the devil, or throw him out'), ('hamlet_act3_scene4', 166, 184, 'HAMLET', 'With wondrous potency. Once more, good night:'), ('hamlet_act3_scene4', 167, 185, 'HAMLET', 'And when you are desirous to be bless’d,'), ('hamlet_act3_scene4', 168, 186, 'HAMLET', 'I’ll blessing beg of you. For this same lord,'), ('hamlet_act3_scene4', 169, 187, 'HAMLET', 'I do repent: but heaven hath pleased it so,'), ('hamlet_act3_scene4', 170, 188, 'HAMLET', 'To punish me with this and this with me,'), ('hamlet_act3_scene4', 171, 189, 'HAMLET', 'That I must be their scourge and minister.'), ('hamlet_act3_scene4', 172, 190, 'HAMLET', 'I will bestow him, and will answer well'), ('hamlet_act3_scene4', 173, 191, 'HAMLET', 'The death I gave him. So, again, good night.'), ('hamlet_act3_scene4', 174, 192, 'HAMLET', 'I must be cruel, only to be kind:'), ('hamlet_act3_scene4', 175, 193, 'HAMLET', 'Thus bad begins and worse remains behind.'), ('hamlet_act3_scene4', 176, 194, 'HAMLET', 'One word more, good lady.'), ('hamlet_act3_scene4', 176, 195, 'QUEEN', 'What shall I do?'), ('hamlet_act3_scene4', 177, 196, 'HAMLET', 'Not this, by no means, that I bid you do:'), ('hamlet_act3_scene4', 178, 197, 'HAMLET', 'Let the bloat king tempt you again to bed;'), ('hamlet_act3_scene4', 179, 198, 'HAMLET', 'Pinch wanton on your cheek; call you his mouse;'), ('hamlet_act3_scene4', 180, 199, 'HAMLET', 'And let him, for a pair of reechy kisses,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act3_scene4', 181, 200, 'HAMLET', 'Or paddling in your neck with his damn’d fingers,'), ('hamlet_act3_scene4', 182, 201, 'HAMLET', 'Make you to ravel all this matter out,'), ('hamlet_act3_scene4', 183, 202, 'HAMLET', 'That I essentially am not in madness,'), ('hamlet_act3_scene4', 184, 203, 'HAMLET', 'But mad in craft. ’Twere good you let him know;'), ('hamlet_act3_scene4', 185, 204, 'HAMLET', 'For who, that’s but a queen, fair, sober, wise,'), ('hamlet_act3_scene4', 186, 205, 'HAMLET', 'Would from a paddock, from a bat, a gib,'), ('hamlet_act3_scene4', 187, 206, 'HAMLET', 'Such dear concernings hide? who would do so?'), ('hamlet_act3_scene4', 188, 207, 'HAMLET', 'No, in despite of sense and secrecy,'), ('hamlet_act3_scene4', 189, 208, 'HAMLET', 'Unpeg the basket on the house’s top,'), ('hamlet_act3_scene4', 190, 209, 'HAMLET', 'Let the birds fly, and, like the famous ape,'), ('hamlet_act3_scene4', 191, 210, 'HAMLET', 'To try conclusions, in the basket creep,'), ('hamlet_act3_scene4', 192, 211, 'HAMLET', 'And break your own neck down.'), ('hamlet_act3_scene4', 193, 212, 'QUEEN', 'Be thou assured, if words be made of breath,'), ('hamlet_act3_scene4', 194, 213, 'QUEEN', 'And breath of life, I have no life to breathe'), ('hamlet_act3_scene4', 195, 214, 'QUEEN', 'What thou hast said to me.'), ('hamlet_act3_scene4', 196, 215, 'HAMLET', 'I must to England; you know that?'), ('hamlet_act3_scene4', 197, 216, 'QUEEN', 'Alack,'), ('hamlet_act3_scene4', 198, 217, 'QUEEN', 'I had forgot: ’tis so concluded on.'), ('hamlet_act3_scene4', 199, 218, 'HAMLET', 'There’s letters seal’d: and my two schoolfellows,'), ('hamlet_act3_scene4', 200, 219, 'HAMLET', 'Whom I will trust as I will adders fang’d,'), ('hamlet_act3_scene4', 201, 220, 'HAMLET', 'They bear the mandate; they must sweep my way,'), ('hamlet_act3_scene4', 202, 221, 'HAMLET', 'And marshal me to knavery. Let it work;'), ('hamlet_act3_scene4', 203, 222, 'HAMLET', 'For ’tis the sport to have the enginer'), ('hamlet_act3_scene4', 204, 223, 'HAMLET', 'Hoist with his own petar: and’t shall go hard'), ('hamlet_act3_scene4', 205, 224, 'HAMLET', 'But I will delve one yard below their mines,'), ('hamlet_act3_scene4', 206, 225, 'HAMLET', 'And blow them at the moon: O, ’tis most sweet,'), ('hamlet_act3_scene4', 207, 226, 'HAMLET', 'When in one line two crafts directly meet.'), ('hamlet_act3_scene4', 208, 227, 'HAMLET', 'This man shall set me packing:'), ('hamlet_act3_scene4', 209, 228, 'HAMLET', 'I’ll lug the guts into the neighbour room.'), ('hamlet_act3_scene4', 210, 229, 'HAMLET', 'Mother, good night. Indeed this counsellor'), ('hamlet_act3_scene4', 211, 230, 'HAMLET', 'Is now most still, most secret and most grave,'), ('hamlet_act3_scene4', 212, 231, 'HAMLET', 'Who was in life a foolish prating knave.'), ('hamlet_act3_scene4', 213, 232, 'HAMLET', 'Come, sir, to draw toward an end with you.'), ('hamlet_act3_scene4', 214, 233, 'HAMLET', 'Good night, mother.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene1', 1, 0, 'KING', 'There’s matter in these sighs, these profound heaves:'), ('hamlet_act4_scene1', 2, 1, 'KING', 'You must translate: ’tis fit we understand them.'), ('hamlet_act4_scene1', 3, 2, 'KING', 'Where is your son?'), ('hamlet_act4_scene1', 4, 3, 'QUEEN', 'Bestow this place on us a little while.'), ('hamlet_act4_scene1', 5, 4, 'QUEEN', 'Ah, mine good lord, what have I seen to-night!'), ('hamlet_act4_scene1', 6, 5, 'KING', 'What, Gertrude? How does Hamlet?'), ('hamlet_act4_scene1', 7, 6, 'QUEEN', 'Mad as the sea and wind, when both contend'), ('hamlet_act4_scene1', 8, 7, 'QUEEN', 'Which is the mightier: in his lawless fit,'), ('hamlet_act4_scene1', 9, 8, 'QUEEN', 'Behind the arras hearing something stir,'), ('hamlet_act4_scene1', 10, 9, 'QUEEN', 'Whips out his rapier, cries, “A rat, a rat!”'), ('hamlet_act4_scene1', 11, 10, 'QUEEN', 'And, in this brainish apprehension, kills'), ('hamlet_act4_scene1', 12, 11, 'QUEEN', 'The unseen good old man.'), ('hamlet_act4_scene1', 12, 12, 'KING', 'O heavy deed!'), ('hamlet_act4_scene1', 13, 13, 'KING', 'It had been so with us, had we been there:'), ('hamlet_act4_scene1', 14, 14, 'KING', 'His liberty is full of threats to all;'), ('hamlet_act4_scene1', 15, 15, 'KING', 'To you yourself, to us, to every one.'), ('hamlet_act4_scene1', 16, 16, 'KING', 'Alas, how shall this bloody deed be answer’d?'), ('hamlet_act4_scene1', 17, 17, 'KING', 'It will be laid to us, whose providence'), ('hamlet_act4_scene1', 18, 18, 'KING', 'Should have kept short, restrain’d and out of haunt,'), ('hamlet_act4_scene1', 19, 19, 'KING', 'This mad young man: but so much was our love,'), ('hamlet_act4_scene1', 20, 20, 'KING', 'We would not understand what was most fit;'), ('hamlet_act4_scene1', 21, 21, 'KING', 'But, like the owner of a foul disease,'), ('hamlet_act4_scene1', 22, 22, 'KING', 'To keep it from divulging, let it feed'), ('hamlet_act4_scene1', 23, 23, 'KING', 'Even on the pith of Life. Where is he gone?'), ('hamlet_act4_scene1', 24, 24, 'QUEEN', 'To draw apart the body he hath kill’d:'), ('hamlet_act4_scene1', 25, 25, 'QUEEN', 'O’er whom his very madness, like some ore'), ('hamlet_act4_scene1', 26, 26, 'QUEEN', 'Among a mineral of metals base,'), ('hamlet_act4_scene1', 27, 27, 'QUEEN', 'Shows itself pure; he weeps for what is done.'), ('hamlet_act4_scene1', 28, 28, 'KING', 'O Gertrude, come away!'), ('hamlet_act4_scene1', 29, 29, 'KING', 'The sun no sooner shall the mountains touch,'), ('hamlet_act4_scene1', 30, 30, 'KING', 'But we will ship him hence: and this vile deed'), ('hamlet_act4_scene1', 31, 31, 'KING', 'We must, with all our majesty and skill,'), ('hamlet_act4_scene1', 32, 32, 'KING', 'Both countenance and excuse. Ho, Guildenstern!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene2', 1, 0, 'HAMLET', 'Safely stowed.'), ('hamlet_act4_scene2', 1, 1, 'ROSENCRANTZ GUILDENSTERN', 'Hamlet! Lord Hamlet!'), ('hamlet_act4_scene2', 2, 2, 'HAMLET', 'But soft, what noise? who calls on Hamlet? O, here they come.'), ('hamlet_act4_scene2', 3, 3, 'ROSENCRANTZ', 'What have you done, my lord, with the dead body?'), ('hamlet_act4_scene2', 4, 4, 'HAMLET', 'Compounded it with dust, whereto ’tis kin.'), ('hamlet_act4_scene2', 5, 5, 'ROSENCRANTZ', 'Tell us where ’tis, that we may take it thence'), ('hamlet_act4_scene2', 6, 6, 'ROSENCRANTZ', 'And bear it to the chapel.'), ('hamlet_act4_scene2', 6, 7, 'HAMLET', 'Do not believe it.'), ('hamlet_act4_scene2', 7, 8, 'ROSENCRANTZ', 'Believe what?'), ('hamlet_act4_scene2', 8, 9, 'HAMLET', 'That I can keep your counsel and not mine own. Besides, to'), ('hamlet_act4_scene2', 9, 10, 'HAMLET', 'be demanded of a sponge! what replication should be made by the'), ('hamlet_act4_scene2', 10, 11, 'HAMLET', 'son of a king?'), ('hamlet_act4_scene2', 11, 12, 'ROSENCRANTZ', 'Take you me for a sponge, my lord?'), ('hamlet_act4_scene2', 12, 13, 'HAMLET', 'Ay, sir, that soaks up the king’s countenance, his rewards, his authorities.'), ('hamlet_act4_scene2', 13, 14, 'HAMLET', 'But such officers do the king best service in the end: he'), ('hamlet_act4_scene2', 14, 15, 'HAMLET', 'keeps them, like an ape, in the corner of his jaw; first'), ('hamlet_act4_scene2', 15, 16, 'HAMLET', 'mouthed, to be last swallowed: when he needs what you have gleaned,'), ('hamlet_act4_scene2', 16, 17, 'HAMLET', 'it is but squeezing you, and, sponge, you shall be dry again.'), ('hamlet_act4_scene2', 17, 18, 'ROSENCRANTZ', 'I understand you not, my lord.'), ('hamlet_act4_scene2', 18, 19, 'HAMLET', 'I am glad of it: a knavish speech sleeps in a foolish ear.'), ('hamlet_act4_scene2', 19, 20, 'ROSENCRANTZ', 'My lord, you must tell us where the body is, and go'), ('hamlet_act4_scene2', 20, 21, 'ROSENCRANTZ', 'with us to the king.'), ('hamlet_act4_scene2', 21, 22, 'HAMLET', 'The body is with the king, but the king is not with'), ('hamlet_act4_scene2', 22, 23, 'HAMLET', 'the body. The king is a thing—'), ('hamlet_act4_scene2', 23, 24, 'GUILDENSTERN', 'A thing, my lord!'), ('hamlet_act4_scene2', 24, 25, 'HAMLET', 'Of nothing: bring me to him. Hide fox, and all after.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene3', 1, 0, 'KING', 'I have sent to seek him, and to find the body.'), ('hamlet_act4_scene3', 2, 1, 'KING', 'How dangerous is it that this man goes loose!'), ('hamlet_act4_scene3', 3, 2, 'KING', 'Yet must not we put the strong law on him:'), ('hamlet_act4_scene3', 4, 3, 'KING', 'He’s loved of the distracted multitude,'), ('hamlet_act4_scene3', 5, 4, 'KING', 'Who like not in their judgment, but their eyes:'), ('hamlet_act4_scene3', 6, 5, 'KING', 'And where ’tis so, the offender’s scourge is weigh’d,'), ('hamlet_act4_scene3', 7, 6, 'KING', 'But never the offence. To bear all smooth and even,'), ('hamlet_act4_scene3', 8, 7, 'KING', 'This sudden sending him away must seem'), ('hamlet_act4_scene3', 9, 8, 'KING', 'Deliberate pause: diseases desperate grown'), ('hamlet_act4_scene3', 10, 9, 'KING', 'By desperate appliance are relieved,'), ('hamlet_act4_scene3', 11, 10, 'KING', 'Or not at all.'), ('hamlet_act4_scene3', 12, 11, 'ROSENCRANTZ', 'Where the dead body is bestow’d, my lord,'), ('hamlet_act4_scene3', 13, 12, 'ROSENCRANTZ', 'We cannot get from him.'), ('hamlet_act4_scene3', 13, 13, 'KING', 'But where is he?'), ('hamlet_act4_scene3', 14, 14, 'ROSENCRANTZ', 'Without, my lord; guarded, to know your pleasure.'), ('hamlet_act4_scene3', 15, 15, 'KING', 'Bring him before us.'), ('hamlet_act4_scene3', 15, 16, 'ROSENCRANTZ', 'Ho, Guildenstern! bring in my lord.'), ('hamlet_act4_scene3', 16, 17, 'KING', 'Now, Hamlet, where’s Polonius?'), ('hamlet_act4_scene3', 16, 18, 'HAMLET', 'At supper.'), ('hamlet_act4_scene3', 17, 19, 'KING', 'At supper! where?'), ('hamlet_act4_scene3', 18, 20, 'HAMLET', 'Not where he eats, but where he is eaten: a certain convocation'), ('hamlet_act4_scene3', 19, 21, 'HAMLET', 'of politic worms are e’en at him. Your worm is your only'), ('hamlet_act4_scene3', 20, 22, 'HAMLET', 'emperor for diet: we fat all creatures else to fat us, and'), ('hamlet_act4_scene3', 21, 23, 'HAMLET', 'we fat ourselves for maggots: your fat king and your lean beggar'), ('hamlet_act4_scene3', 22, 24, 'HAMLET', 'is but variable service, two dishes, but to one table: that’s the'), ('hamlet_act4_scene3', 23, 25, 'HAMLET', 'end.'), ('hamlet_act4_scene3', 23, 26, 'KING', 'Alas, alas!'), ('hamlet_act4_scene3', 24, 27, 'HAMLET', 'A man may fish with the worm that hath eat of a'), ('hamlet_act4_scene3', 25, 28, 'HAMLET', 'king, and eat of the fish that hath fed of that worm.'), ('hamlet_act4_scene3', 26, 29, 'KING', 'What dost you mean by this?'), ('hamlet_act4_scene3', 27, 30, 'HAMLET', 'Nothing but to show you how a king may go a progress'), ('hamlet_act4_scene3', 28, 31, 'HAMLET', 'through the guts of a beggar.'), ('hamlet_act4_scene3', 28, 32, 'KING', 'Where is Polonius?'), ('hamlet_act4_scene3', 29, 33, 'HAMLET', 'In heaven; send hither to see: if your messenger find him not'), ('hamlet_act4_scene3', 30, 34, 'HAMLET', 'there, seek him i’ the other place yourself. But indeed, if you'), ('hamlet_act4_scene3', 31, 35, 'HAMLET', 'find him not within this month, you shall nose him as you'), ('hamlet_act4_scene3', 32, 36, 'HAMLET', 'go up the stairs into the lobby.'), ('hamlet_act4_scene3', 33, 37, 'KING', 'Go seek him there.'), ('hamlet_act4_scene3', 33, 38, 'HAMLET', 'He will stay till ye come.'), ('hamlet_act4_scene3', 34, 39, 'KING', 'Hamlet, this deed, for thine especial safety—'), ('hamlet_act4_scene3', 35, 40, 'KING', 'Which we do tender, as we dearly grieve'), ('hamlet_act4_scene3', 36, 41, 'KING', 'For that which thou hast done—must send thee hence'), ('hamlet_act4_scene3', 37, 42, 'KING', 'With fiery quickness: therefore prepare thyself;'), ('hamlet_act4_scene3', 38, 43, 'KING', 'The bark is ready, and the wind at help,'), ('hamlet_act4_scene3', 39, 44, 'KING', 'The associates tend, and every thing is bent'), ('hamlet_act4_scene3', 40, 45, 'KING', 'For England.'), ('hamlet_act4_scene3', 40, 46, 'HAMLET', 'For England!'), ('hamlet_act4_scene3', 41, 47, 'KING', 'Ay, Hamlet.'), ('hamlet_act4_scene3', 41, 48, 'HAMLET', 'Good.'), ('hamlet_act4_scene3', 42, 49, 'KING', 'So is it, if thou knew’st our purposes.'), ('hamlet_act4_scene3', 43, 50, 'HAMLET', 'I see a cherub that sees them. But, come; for England! Farewell, dear mother.'), ('hamlet_act4_scene3', 44, 51, 'KING', 'Thy loving father, Hamlet.'), ('hamlet_act4_scene3', 45, 52, 'HAMLET', 'My mother: father and mother is man and wife; man and wife'), ('hamlet_act4_scene3', 46, 53, 'HAMLET', 'is one flesh; and so, my mother. Come, for England!'), ('hamlet_act4_scene3', 47, 54, 'KING', 'Follow him at foot; tempt him with speed aboard;'), ('hamlet_act4_scene3', 48, 55, 'KING', 'Delay it not; I’ll have him hence to-night:'), ('hamlet_act4_scene3', 49, 56, 'KING', 'Away! for every thing is seal’d and done'), ('hamlet_act4_scene3', 50, 57, 'KING', 'That else leans on the affair: pray you, make haste.'), ('hamlet_act4_scene3', 51, 58, 'KING', 'And, England, if my love thou hold’st at aught—'), ('hamlet_act4_scene3', 52, 59, 'KING', 'As my great power thereof may give thee sense,'), ('hamlet_act4_scene3', 53, 60, 'KING', 'Since yet thy cicatrice looks raw and red'), ('hamlet_act4_scene3', 54, 61, 'KING', 'After the Danish sword, and thy free awe'), ('hamlet_act4_scene3', 55, 62, 'KING', 'Pays homage to us—thou mayst not coldly set'), ('hamlet_act4_scene3', 56, 63, 'KING', 'Our sovereign process; which imports at full,'), ('hamlet_act4_scene3', 57, 64, 'KING', 'By letters congruing to that effect,'), ('hamlet_act4_scene3', 58, 65, 'KING', 'The present death of Hamlet. Do it, England;'), ('hamlet_act4_scene3', 59, 66, 'KING', 'For like the hectic in my blood he rages,'), ('hamlet_act4_scene3', 60, 67, 'KING', 'And thou must cure me: till I know ’tis done,'), ('hamlet_act4_scene3', 61, 68, 'KING', 'Howe’er my haps, my joys were ne’er begun.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene4', 1, 0, 'PRINCE FORTINBRAS', 'Go, captain, from me greet the Danish king;'), ('hamlet_act4_scene4', 2, 1, 'PRINCE FORTINBRAS', 'Tell him that, by his license, Fortinbras'), ('hamlet_act4_scene4', 3, 2, 'PRINCE FORTINBRAS', 'Craves the conveyance of a promised march'), ('hamlet_act4_scene4', 4, 3, 'PRINCE FORTINBRAS', 'Over his kingdom. You know the rendezvous.'), ('hamlet_act4_scene4', 5, 4, 'PRINCE FORTINBRAS', 'If that his majesty would aught with us,'), ('hamlet_act4_scene4', 6, 5, 'PRINCE FORTINBRAS', 'We shall express our duty in his eye;'), ('hamlet_act4_scene4', 7, 6, 'PRINCE FORTINBRAS', 'And let him know so.'), ('hamlet_act4_scene4', 7, 7, 'CAPTAIN', 'I will do’t, my lord.'), ('hamlet_act4_scene4', 8, 8, 'PRINCE FORTINBRAS', 'Go softly on.'), ('hamlet_act4_scene4', 8, 9, 'HAMLET', 'Good sir, whose powers are these?'), ('hamlet_act4_scene4', 9, 10, 'CAPTAIN', 'They are of Norway, sir.'), ('hamlet_act4_scene4', 9, 11, 'HAMLET', 'How purposed, sir, I pray you?'), ('hamlet_act4_scene4', 10, 12, 'CAPTAIN', 'Against some part of Poland.'), ('hamlet_act4_scene4', 10, 13, 'HAMLET', 'Who commands them, sir?'), ('hamlet_act4_scene4', 11, 14, 'CAPTAIN', 'The nephews to old Norway, Fortinbras.'), ('hamlet_act4_scene4', 12, 15, 'HAMLET', 'Goes it against the main of Poland, sir,'), ('hamlet_act4_scene4', 13, 16, 'HAMLET', 'Or for some frontier?'), ('hamlet_act4_scene4', 14, 17, 'CAPTAIN', 'Truly to speak, and with no addition,'), ('hamlet_act4_scene4', 15, 18, 'CAPTAIN', 'We go to gain a little patch of ground'), ('hamlet_act4_scene4', 16, 19, 'CAPTAIN', 'That hath in it no profit but the name.'), ('hamlet_act4_scene4', 17, 20, 'CAPTAIN', 'To pay five ducats, five, I would not farm it;'), ('hamlet_act4_scene4', 18, 21, 'CAPTAIN', 'Nor will it yield to Norway or the Pole'), ('hamlet_act4_scene4', 19, 22, 'CAPTAIN', 'A ranker rate, should it be sold in fee.'), ('hamlet_act4_scene4', 20, 23, 'HAMLET', 'Why, then the Polack never will defend it.'), ('hamlet_act4_scene4', 21, 24, 'CAPTAIN', 'Yes, it is already garrison’d.'), ('hamlet_act4_scene4', 22, 25, 'HAMLET', 'Two thousand souls and twenty thousand ducats'), ('hamlet_act4_scene4', 23, 26, 'HAMLET', 'Will not debate the question of this straw:'), ('hamlet_act4_scene4', 24, 27, 'HAMLET', 'This is the imposthume of much wealth and peace,'), ('hamlet_act4_scene4', 25, 28, 'HAMLET', 'That inward breaks, and shows no cause without'), ('hamlet_act4_scene4', 26, 29, 'HAMLET', 'Why the man dies. I humbly thank you, sir.'), ('hamlet_act4_scene4', 27, 30, 'CAPTAIN', 'God be wi’ you, sir.'), ('hamlet_act4_scene4', 27, 31, 'ROSENCRANTZ', 'Will’t please you go, my lord?'), ('hamlet_act4_scene4', 28, 32, 'HAMLET', 'I’ll be with you straight. Go a little before.'), ('hamlet_act4_scene4', 29, 33, 'HAMLET', 'How all occasions do inform against me,'), ('hamlet_act4_scene4', 30, 34, 'HAMLET', 'And spur my dull revenge! What is a man,'), ('hamlet_act4_scene4', 31, 35, 'HAMLET', 'If his chief good and market of his time'), ('hamlet_act4_scene4', 32, 36, 'HAMLET', 'Be but to sleep and feed? a beast, no more.'), ('hamlet_act4_scene4', 33, 37, 'HAMLET', 'Sure, he that made us with such large discourse,'), ('hamlet_act4_scene4', 34, 38, 'HAMLET', 'Looking before and after, gave us not'), ('hamlet_act4_scene4', 35, 39, 'HAMLET', 'That capability and god-like reason'), ('hamlet_act4_scene4', 36, 40, 'HAMLET', 'To fust in us unused. Now, whether it be'), ('hamlet_act4_scene4', 37, 41, 'HAMLET', 'Bestial oblivion, or some craven scruple'), ('hamlet_act4_scene4', 38, 42, 'HAMLET', 'Of thinking too precisely on the event,'), ('hamlet_act4_scene4', 39, 43, 'HAMLET', 'A thought which, quarter’d, hath but one part wisdom'), ('hamlet_act4_scene4', 40, 44, 'HAMLET', 'And ever three parts coward, I do not know'), ('hamlet_act4_scene4', 41, 45, 'HAMLET', 'Why yet I live to say “This thing’s to do;”'), ('hamlet_act4_scene4', 42, 46, 'HAMLET', 'Sith I have cause and will and strength and means'), ('hamlet_act4_scene4', 43, 47, 'HAMLET', 'To do’t. Examples gross as earth exhort me:'), ('hamlet_act4_scene4', 44, 48, 'HAMLET', 'Witness this army of such mass and charge'), ('hamlet_act4_scene4', 45, 49, 'HAMLET', 'Led by a delicate and tender prince,'), ('hamlet_act4_scene4', 46, 50, 'HAMLET', 'Whose spirit with divine ambition puff’d'), ('hamlet_act4_scene4', 47, 51, 'HAMLET', 'Makes mouths at the invisible event,'), ('hamlet_act4_scene4', 48, 52, 'HAMLET', 'Exposing what is mortal and unsure'), ('hamlet_act4_scene4', 49, 53, 'HAMLET', 'To all that fortune, death and danger dare,'), ('hamlet_act4_scene4', 50, 54, 'HAMLET', 'Even for an egg-shell. Rightly to be great'), ('hamlet_act4_scene4', 51, 55, 'HAMLET', 'Is not to stir without great argument,'), ('hamlet_act4_scene4', 52, 56, 'HAMLET', 'But greatly to find quarrel in a straw'), ('hamlet_act4_scene4', 53, 57, 'HAMLET', 'When honour’s at the stake. How stand I then,'), ('hamlet_act4_scene4', 54, 58, 'HAMLET', 'That have a father kill’d, a mother stain’d,'), ('hamlet_act4_scene4', 55, 59, 'HAMLET', 'Excitements of my reason and my blood'), ('hamlet_act4_scene4', 56, 60, 'HAMLET', 'And let all sleep? while, to my shame, I see'), ('hamlet_act4_scene4', 57, 61, 'HAMLET', 'The imminent death of twenty thousand men,'), ('hamlet_act4_scene4', 58, 62, 'HAMLET', 'That, for a fantasy and trick of fame,'), ('hamlet_act4_scene4', 59, 63, 'HAMLET', 'Go to their graves like beds, fight for a plot'), ('hamlet_act4_scene4', 60, 64, 'HAMLET', 'Whereon the numbers cannot try the cause,'), ('hamlet_act4_scene4', 61, 65, 'HAMLET', 'Which is not tomb enough and continent'), ('hamlet_act4_scene4', 62, 66, 'HAMLET', 'To hide the slain? O, from this time forth,'), ('hamlet_act4_scene4', 63, 67, 'HAMLET', 'My thoughts be bloody, or be nothing worth!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene5', 1, 0, 'QUEEN', 'I will not speak with her.'), ('hamlet_act4_scene5', 1, 1, 'GENTLEMAN', 'She is importunate, indeed distract:'), ('hamlet_act4_scene5', 2, 2, 'GENTLEMAN', 'Her mood will needs be pitied.'), ('hamlet_act4_scene5', 2, 3, 'QUEEN', 'What would she have?'), ('hamlet_act4_scene5', 3, 4, 'GENTLEMAN', 'She speaks much of her father; says she hears'), ('hamlet_act4_scene5', 4, 5, 'GENTLEMAN', 'There’s tricks i’ the world; and hems, and beats her heart;'), ('hamlet_act4_scene5', 5, 6, 'GENTLEMAN', 'Spurns enviously at straws; speaks things in doubt,'), ('hamlet_act4_scene5', 6, 7, 'GENTLEMAN', 'That carry but half sense: her speech is nothing,'), ('hamlet_act4_scene5', 7, 8, 'GENTLEMAN', 'Yet the unshaped use of it doth move'), ('hamlet_act4_scene5', 8, 9, 'GENTLEMAN', 'The hearers to collection; they aim at it,'), ('hamlet_act4_scene5', 9, 10, 'GENTLEMAN', 'And botch the words up fit to their own thoughts;'), ('hamlet_act4_scene5', 10, 11, 'GENTLEMAN', 'Which, as her winks, and nods, and gestures yield them,'), ('hamlet_act4_scene5', 11, 12, 'GENTLEMAN', 'Indeed would make one think there might be thought,'), ('hamlet_act4_scene5', 12, 13, 'GENTLEMAN', 'Though nothing sure, yet much unhappily.'), ('hamlet_act4_scene5', 13, 14, 'HORATIO', '’Twere good she were spoken with; for she may strew'), ('hamlet_act4_scene5', 14, 15, 'HORATIO', 'Dangerous conjectures in ill-breeding minds.'), ('hamlet_act4_scene5', 14, 16, 'QUEEN', 'Let her come in.'), ('hamlet_act4_scene5', 15, 17, 'QUEEN', 'To my sick soul, as sin’s true nature is,'), ('hamlet_act4_scene5', 16, 18, 'QUEEN', 'Each toy seems prologue to some great amiss:'), ('hamlet_act4_scene5', 17, 19, 'QUEEN', 'So full of artless jealousy is guilt,'), ('hamlet_act4_scene5', 18, 20, 'QUEEN', 'It spills itself in fearing to be spilt.'), ('hamlet_act4_scene5', 19, 21, 'OPHELIA', 'Where is the beauteous majesty of Denmark?'), ('hamlet_act4_scene5', 20, 22, 'QUEEN', 'How now, Ophelia!'), ('hamlet_act4_scene5', 21, 23, 'OPHELIA', 'How should I your true love know From another one? By his'), ('hamlet_act4_scene5', 22, 24, 'OPHELIA', 'cockle hat and staff, And his sandal shoon.'), ('hamlet_act4_scene5', 23, 25, 'QUEEN', 'Alas, sweet lady, what imports this song?'), ('hamlet_act4_scene5', 24, 26, 'OPHELIA', 'Say you? nay, pray you, mark. He is dead and gone, lady,'), ('hamlet_act4_scene5', 25, 27, 'OPHELIA', 'He is dead and gone; At his head a grass-green turf, At'), ('hamlet_act4_scene5', 26, 28, 'OPHELIA', 'his heels a stone.'), ('hamlet_act4_scene5', 26, 29, 'QUEEN', 'Nay, but, Ophelia—'), ('hamlet_act4_scene5', 27, 30, 'OPHELIA', 'Pray you, mark. White his shroud as the mountain snow—'), ('hamlet_act4_scene5', 28, 31, 'QUEEN', 'Alas, look here, my lord.'), ('hamlet_act4_scene5', 29, 32, 'OPHELIA', 'Larded with sweet flowers; Which bewept to the grave did go With true-love showers.'), ('hamlet_act4_scene5', 30, 33, 'KING', 'How do you, pretty lady?'), ('hamlet_act4_scene5', 31, 34, 'OPHELIA', 'Well, God ’ild you! They say the owl was a baker’s daughter.'), ('hamlet_act4_scene5', 32, 35, 'OPHELIA', 'Lord, we know what we are, but know not what we may'), ('hamlet_act4_scene5', 33, 36, 'OPHELIA', 'be. God be at your table!'), ('hamlet_act4_scene5', 33, 37, 'KING', 'Conceit upon her father.'), ('hamlet_act4_scene5', 34, 38, 'OPHELIA', 'Pray you, let’s have no words of this; but when they ask'), ('hamlet_act4_scene5', 35, 39, 'OPHELIA', 'you what it means, say you this: To-morrow is Saint Valentine’s day,'), ('hamlet_act4_scene5', 36, 40, 'OPHELIA', 'All in the morning betime, And I a maid at your window,'), ('hamlet_act4_scene5', 37, 41, 'OPHELIA', 'To be your Valentine. Then up he rose, and donn’d his clothes,'), ('hamlet_act4_scene5', 38, 42, 'OPHELIA', 'And dupp’d the chamber-door; Let in the maid, that out a maid'), ('hamlet_act4_scene5', 39, 43, 'OPHELIA', 'Never departed more.'), ('hamlet_act4_scene5', 39, 44, 'KING', 'Pretty Ophelia!'), ('hamlet_act4_scene5', 40, 45, 'OPHELIA', 'Indeed, la, without an oath, I’ll make an end on’t: By Gis'), ('hamlet_act4_scene5', 41, 46, 'OPHELIA', 'and by Saint Charity, Alack, and fie for shame! Young men will'), ('hamlet_act4_scene5', 42, 47, 'OPHELIA', 'do’t, if they come to’t; By cock, they are to blame. Quoth'), ('hamlet_act4_scene5', 43, 48, 'OPHELIA', 'she, before you tumbled me, You promised me to wed. So would'), ('hamlet_act4_scene5', 44, 49, 'OPHELIA', 'I ha’ done, by yonder sun, An thou hadst not come to'), ('hamlet_act4_scene5', 45, 50, 'OPHELIA', 'my bed.'), ('hamlet_act4_scene5', 45, 51, 'KING', 'How long hath she been thus?'), ('hamlet_act4_scene5', 46, 52, 'OPHELIA', 'I hope all will be well. We must be patient: but I'), ('hamlet_act4_scene5', 47, 53, 'OPHELIA', 'cannot choose but weep, to think they should lay him i’ the'), ('hamlet_act4_scene5', 48, 54, 'OPHELIA', 'cold ground. My brother shall know of it: and so I thank'), ('hamlet_act4_scene5', 49, 55, 'OPHELIA', 'you for your good counsel. Come, my coach! Good night, ladies; good'), ('hamlet_act4_scene5', 50, 56, 'OPHELIA', 'night, sweet ladies; good night, good night.'), ('hamlet_act4_scene5', 51, 57, 'KING', 'Follow her close; give her good watch, I pray you.'), ('hamlet_act4_scene5', 52, 58, 'KING', 'O, this is the poison of deep grief; it springs'), ('hamlet_act4_scene5', 53, 59, 'KING', 'All from her father’s death. O Gertrude, Gertrude,'), ('hamlet_act4_scene5', 54, 60, 'KING', 'When sorrows come, they come not single spies,'), ('hamlet_act4_scene5', 55, 61, 'KING', 'But in battalions. First, her father slain:'), ('hamlet_act4_scene5', 56, 62, 'KING', 'Next, your son gone; and he most violent author'), ('hamlet_act4_scene5', 57, 63, 'KING', 'Of his own just remove: the people muddied,'), ('hamlet_act4_scene5', 58, 64, 'KING', 'Thick and unwholesome in their thoughts and whispers,'), ('hamlet_act4_scene5', 59, 65, 'KING', 'For good Polonius’ death; and we have done but greenly,'), ('hamlet_act4_scene5', 60, 66, 'KING', 'In hugger-mugger to inter him: poor Ophelia'), ('hamlet_act4_scene5', 61, 67, 'KING', 'Divided from herself and her fair judgment,'), ('hamlet_act4_scene5', 62, 68, 'KING', 'Without the which we are pictures, or mere beasts:'), ('hamlet_act4_scene5', 63, 69, 'KING', 'Last, and as much containing as all these,'), ('hamlet_act4_scene5', 64, 70, 'KING', 'Her brother is in secret come from France;'), ('hamlet_act4_scene5', 65, 71, 'KING', 'Feeds on his wonder, keeps himself in clouds,'), ('hamlet_act4_scene5', 66, 72, 'KING', 'And wants not buzzers to infect his ear'), ('hamlet_act4_scene5', 67, 73, 'KING', 'With pestilent speeches of his father’s death;'), ('hamlet_act4_scene5', 68, 74, 'KING', 'Wherein necessity, of matter beggar’d,'), ('hamlet_act4_scene5', 69, 75, 'KING', 'Will nothing stick our person to arraign'), ('hamlet_act4_scene5', 70, 76, 'KING', 'In ear and ear. O my dear Gertrude, this,'), ('hamlet_act4_scene5', 71, 77, 'KING', 'Like to a murdering-piece, in many places'), ('hamlet_act4_scene5', 72, 78, 'KING', 'Gives me superfluous death.'), ('hamlet_act4_scene5', 72, 79, 'QUEEN', 'Alack, what noise is this?'), ('hamlet_act4_scene5', 73, 80, 'KING', 'Where are my Switzers? Let them guard the door.'), ('hamlet_act4_scene5', 74, 81, 'GENTLEMAN', 'Save yourself, my lord:'), ('hamlet_act4_scene5', 75, 82, 'GENTLEMAN', 'The ocean, overpeering of his list,'), ('hamlet_act4_scene5', 76, 83, 'GENTLEMAN', 'Eats not the flats with more impetuous haste'), ('hamlet_act4_scene5', 77, 84, 'GENTLEMAN', 'Than young Laertes, in a riotous head,'), ('hamlet_act4_scene5', 78, 85, 'GENTLEMAN', 'O’erbears your officers. The rabble call him lord;'), ('hamlet_act4_scene5', 79, 86, 'GENTLEMAN', 'And, as the world were now but to begin,'), ('hamlet_act4_scene5', 80, 87, 'GENTLEMAN', 'Antiquity forgot, custom not known,'), ('hamlet_act4_scene5', 81, 88, 'GENTLEMAN', 'The ratifiers and props of every word,'), ('hamlet_act4_scene5', 82, 89, 'GENTLEMAN', 'They cry “Choose we: Laertes shall be king:”'), ('hamlet_act4_scene5', 83, 90, 'GENTLEMAN', 'Caps, hands, and tongues, applaud it to the clouds:'), ('hamlet_act4_scene5', 84, 91, 'GENTLEMAN', '“Laertes shall be king, Laertes king!”'), ('hamlet_act4_scene5', 85, 92, 'QUEEN', 'How cheerfully on the false trail they cry!'), ('hamlet_act4_scene5', 86, 93, 'QUEEN', 'O, this is counter, you false Danish dogs!'), ('hamlet_act4_scene5', 87, 94, 'KING', 'The doors are broke.'), ('hamlet_act4_scene5', 88, 95, 'LAERTES', 'Where is this king? Sirs, stand you all without.'), ('hamlet_act4_scene5', 89, 96, 'DANES', 'No, let’s come in.'), ('hamlet_act4_scene5', 89, 97, 'LAERTES', 'I pray you, give me leave.'), ('hamlet_act4_scene5', 90, 98, 'DANES', 'We will, we will.'), ('hamlet_act4_scene5', 91, 99, 'LAERTES', 'I thank you: keep the door. O thou vile king,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene5', 92, 100, 'LAERTES', 'Give me my father!'), ('hamlet_act4_scene5', 92, 101, 'QUEEN', 'Calmly, good Laertes.'), ('hamlet_act4_scene5', 93, 102, 'LAERTES', 'That drop of blood that’s calm proclaims me bastard,'), ('hamlet_act4_scene5', 94, 103, 'LAERTES', 'Cries cuckold to my father, brands the harlot'), ('hamlet_act4_scene5', 95, 104, 'LAERTES', 'Even here, between the chaste unsmirched brow'), ('hamlet_act4_scene5', 96, 105, 'LAERTES', 'Of my true mother.'), ('hamlet_act4_scene5', 96, 106, 'KING', 'What is the cause, Laertes,'), ('hamlet_act4_scene5', 97, 107, 'KING', 'That thy rebellion looks so giant-like?'), ('hamlet_act4_scene5', 98, 108, 'KING', 'Let him go, Gertrude; do not fear our person:'), ('hamlet_act4_scene5', 99, 109, 'KING', 'There’s such divinity doth hedge a king,'), ('hamlet_act4_scene5', 100, 110, 'KING', 'That treason can but peep to what it would,'), ('hamlet_act4_scene5', 101, 111, 'KING', 'Acts little of his will. Tell me, Laertes,'), ('hamlet_act4_scene5', 102, 112, 'KING', 'Why thou art thus incensed. Let him go, Gertrude.'), ('hamlet_act4_scene5', 103, 113, 'KING', 'Speak, man.'), ('hamlet_act4_scene5', 103, 114, 'LAERTES', 'Where is my father?'), ('hamlet_act4_scene5', 104, 115, 'KING', 'Dead.'), ('hamlet_act4_scene5', 104, 116, 'QUEEN', 'But not by him.'), ('hamlet_act4_scene5', 105, 117, 'KING', 'Let him demand his fill.'), ('hamlet_act4_scene5', 106, 118, 'LAERTES', 'How came he dead? I’ll not be juggled with:'), ('hamlet_act4_scene5', 107, 119, 'LAERTES', 'To hell, allegiance! vows, to the blackest devil!'), ('hamlet_act4_scene5', 108, 120, 'LAERTES', 'Conscience and grace, to the profoundest pit!'), ('hamlet_act4_scene5', 109, 121, 'LAERTES', 'I dare damnation. To this point I stand,'), ('hamlet_act4_scene5', 110, 122, 'LAERTES', 'That both the worlds I give to negligence,'), ('hamlet_act4_scene5', 111, 123, 'LAERTES', 'Let come what comes; only I’ll be revenged'), ('hamlet_act4_scene5', 112, 124, 'LAERTES', 'Most thoroughly for my father.'), ('hamlet_act4_scene5', 112, 125, 'KING', 'Who shall stay you?'), ('hamlet_act4_scene5', 113, 126, 'LAERTES', 'My will, not all the world:'), ('hamlet_act4_scene5', 114, 127, 'LAERTES', 'And for my means, I’ll husband them so well,'), ('hamlet_act4_scene5', 115, 128, 'LAERTES', 'They shall go far with little.'), ('hamlet_act4_scene5', 115, 129, 'KING', 'Good Laertes,'), ('hamlet_act4_scene5', 116, 130, 'KING', 'If you desire to know the certainty'), ('hamlet_act4_scene5', 117, 131, 'KING', 'Of your dear father’s death, is’t writ in your revenge,'), ('hamlet_act4_scene5', 118, 132, 'KING', 'That, swoopstake, you will draw both friend and foe,'), ('hamlet_act4_scene5', 119, 133, 'KING', 'Winner and loser?'), ('hamlet_act4_scene5', 119, 134, 'LAERTES', 'None but his enemies.'), ('hamlet_act4_scene5', 120, 135, 'KING', 'Will you know them then?'), ('hamlet_act4_scene5', 121, 136, 'LAERTES', 'To his good friends thus wide I’ll ope my arms;'), ('hamlet_act4_scene5', 122, 137, 'LAERTES', 'And like the kind life-rendering pelican,'), ('hamlet_act4_scene5', 123, 138, 'LAERTES', 'Repast them with my blood.'), ('hamlet_act4_scene5', 123, 139, 'KING', 'Why, now you speak'), ('hamlet_act4_scene5', 124, 140, 'KING', 'Like a good child and a true gentleman.'), ('hamlet_act4_scene5', 125, 141, 'KING', 'That I am guiltless of your father’s death,'), ('hamlet_act4_scene5', 126, 142, 'KING', 'And am most sensible in grief for it,'), ('hamlet_act4_scene5', 127, 143, 'KING', 'It shall as level to your judgment pierce'), ('hamlet_act4_scene5', 128, 144, 'KING', 'As day does to your eye.'), ('hamlet_act4_scene5', 128, 145, 'DANES', 'Let her come in.'), ('hamlet_act4_scene5', 129, 146, 'LAERTES', 'How now! what noise is that?'), ('hamlet_act4_scene5', 130, 147, 'OPHELIA', 'They bore him barefaced on the bier; Hey non nonny, nonny, hey'), ('hamlet_act4_scene5', 131, 148, 'OPHELIA', 'nonny; And in his grave rain’d many a tear:— Fare you well,'), ('hamlet_act4_scene5', 132, 149, 'OPHELIA', 'my dove!'), ('hamlet_act4_scene5', 133, 150, 'LAERTES', 'Hadst thou thy wits, and didst persuade revenge,'), ('hamlet_act4_scene5', 134, 151, 'LAERTES', 'It could not move thus.'), ('hamlet_act4_scene5', 135, 152, 'OPHELIA', 'You must sing a-down a-down, An you call him a-down-a. O, how'), ('hamlet_act4_scene5', 136, 153, 'OPHELIA', 'the wheel becomes it! It is the false steward, that stole his'), ('hamlet_act4_scene5', 137, 154, 'OPHELIA', 'master’s daughter.'), ('hamlet_act4_scene5', 137, 155, 'LAERTES', 'This nothing’s more than matter.'), ('hamlet_act4_scene5', 138, 156, 'OPHELIA', 'There’s rosemary, that’s for remembrance; pray, love, remember: and there is pansies, that’s for thoughts.'), ('hamlet_act4_scene5', 139, 157, 'LAERTES', 'A document in madness, thoughts and remembrance fitted.'), ('hamlet_act4_scene5', 140, 158, 'OPHELIA', 'There’s fennel for you, and columbines: there’s rue for you; and here’s'), ('hamlet_act4_scene5', 141, 159, 'OPHELIA', 'some for me: we may call it herb-grace o’ Sundays: O you'), ('hamlet_act4_scene5', 142, 160, 'OPHELIA', 'must wear your rue with a difference. There’s a daisy: I would'), ('hamlet_act4_scene5', 143, 161, 'OPHELIA', 'give you some violets, but they withered all when my father died:'), ('hamlet_act4_scene5', 144, 162, 'OPHELIA', 'they say he made a good end— For bonny sweet Robin is'), ('hamlet_act4_scene5', 145, 163, 'OPHELIA', 'all my joy.'), ('hamlet_act4_scene5', 145, 164, 'LAERTES', 'Thought and affliction, passion, hell itself,'), ('hamlet_act4_scene5', 146, 165, 'LAERTES', 'She turns to favour and to prettiness.'), ('hamlet_act4_scene5', 147, 166, 'OPHELIA', 'And will he not come again? And will he not come again?'), ('hamlet_act4_scene5', 148, 167, 'OPHELIA', 'No, no, he is dead: Go to thy death-bed: He never will'), ('hamlet_act4_scene5', 149, 168, 'OPHELIA', 'come again. His beard was as white as snow, All flaxen was'), ('hamlet_act4_scene5', 150, 169, 'OPHELIA', 'his poll: He is gone, he is gone, And we cast away'), ('hamlet_act4_scene5', 151, 170, 'OPHELIA', 'moan: God ha’ mercy on his soul! And of all Christian souls,'), ('hamlet_act4_scene5', 152, 171, 'OPHELIA', 'I pray God. God be wi’ ye.'), ('hamlet_act4_scene5', 153, 172, 'LAERTES', 'Do you see this, O God?'), ('hamlet_act4_scene5', 154, 173, 'KING', 'Laertes, I must commune with your grief,'), ('hamlet_act4_scene5', 155, 174, 'KING', 'Or you deny me right. Go but apart,'), ('hamlet_act4_scene5', 156, 175, 'KING', 'Make choice of whom your wisest friends you will,'), ('hamlet_act4_scene5', 157, 176, 'KING', 'And they shall hear and judge ’twixt you and me:'), ('hamlet_act4_scene5', 158, 177, 'KING', 'If by direct or by collateral hand'), ('hamlet_act4_scene5', 159, 178, 'KING', 'They find us touch’d, we will our kingdom give,'), ('hamlet_act4_scene5', 160, 179, 'KING', 'Our crown, our life, and all that we can ours,'), ('hamlet_act4_scene5', 161, 180, 'KING', 'To you in satisfaction; but if not,'), ('hamlet_act4_scene5', 162, 181, 'KING', 'Be you content to lend your patience to us,'), ('hamlet_act4_scene5', 163, 182, 'KING', 'And we shall jointly labour with your soul'), ('hamlet_act4_scene5', 164, 183, 'KING', 'To give it due content.'), ('hamlet_act4_scene5', 164, 184, 'LAERTES', 'Let this be so;'), ('hamlet_act4_scene5', 165, 185, 'LAERTES', 'His means of death, his obscure funeral—'), ('hamlet_act4_scene5', 166, 186, 'LAERTES', 'No trophy, sword, nor hatchment o’er his bones,'), ('hamlet_act4_scene5', 167, 187, 'LAERTES', 'No noble rite nor formal ostentation—'), ('hamlet_act4_scene5', 168, 188, 'LAERTES', 'Cry to be heard, as ’twere from heaven to earth,'), ('hamlet_act4_scene5', 169, 189, 'LAERTES', 'That I must call’t in question.'), ('hamlet_act4_scene5', 169, 190, 'KING', 'So you shall;'), ('hamlet_act4_scene5', 170, 191, 'KING', 'And where the offence is let the great axe fall.'), ('hamlet_act4_scene5', 171, 192, 'KING', 'I pray you, go with me.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene6', 1, 0, 'HORATIO', 'What are they that would speak with me?'), ('hamlet_act4_scene6', 2, 1, 'SERVANT', 'Sailors, sir: they say they have letters for you.'), ('hamlet_act4_scene6', 3, 2, 'HORATIO', 'Let them come in. I do not know from what part of'), ('hamlet_act4_scene6', 4, 3, 'HORATIO', 'the world I should be greeted, if not from Lord Hamlet.'), ('hamlet_act4_scene6', 5, 4, 'FIRST SAILOR', 'God bless you, sir.'), ('hamlet_act4_scene6', 5, 5, 'HORATIO', 'Let him bless thee too.'), ('hamlet_act4_scene6', 6, 6, 'FIRST SAILOR', 'He shall, sir, an’t please him. There’s a letter for you, sir;'), ('hamlet_act4_scene6', 7, 7, 'FIRST SAILOR', 'it comes from the ambassador that was bound for England; if your'), ('hamlet_act4_scene6', 8, 8, 'FIRST SAILOR', 'name be Horatio, as I am let to know it is.'), ('hamlet_act4_scene6', 9, 9, 'HORATIO', '“Horatio, when thou shalt have overlooked this, give these fellows some means'), ('hamlet_act4_scene6', 10, 10, 'HORATIO', 'to the king: they have letters for him. Ere we were two'), ('hamlet_act4_scene6', 11, 11, 'HORATIO', 'days old at sea, a pirate of very warlike appointment gave us'), ('hamlet_act4_scene6', 12, 12, 'HORATIO', 'chase. Finding ourselves too slow of sail, we put on a compelled'), ('hamlet_act4_scene6', 13, 13, 'HORATIO', 'valour, and in the grapple I boarded them: on the instant they'), ('hamlet_act4_scene6', 14, 14, 'HORATIO', 'got clear of our ship; so I alone became their prisoner. They'), ('hamlet_act4_scene6', 15, 15, 'HORATIO', 'have dealt with me like thieves of mercy: but they knew what'), ('hamlet_act4_scene6', 16, 16, 'HORATIO', 'they did; I am to do a good turn for them. Let'), ('hamlet_act4_scene6', 17, 17, 'HORATIO', 'the king have the letters I have sent; and repair thou to'), ('hamlet_act4_scene6', 18, 18, 'HORATIO', 'me with as much speed as thou wouldst fly death. I have'), ('hamlet_act4_scene6', 19, 19, 'HORATIO', 'words to speak in thine ear will make thee dumb; yet are'), ('hamlet_act4_scene6', 20, 20, 'HORATIO', 'they much too light for the bore of the matter. These good'), ('hamlet_act4_scene6', 21, 21, 'HORATIO', 'fellows will bring thee where I am. Rosencrantz and Guildenstern hold their'), ('hamlet_act4_scene6', 22, 22, 'HORATIO', 'course for England: of them I have much to tell thee. Farewell.'), ('hamlet_act4_scene6', 23, 23, 'HORATIO', 'Come, I will make you way for these your letters; And do’t'), ('hamlet_act4_scene6', 24, 24, 'HORATIO', 'the speedier, that you may direct me To him from whom you'), ('hamlet_act4_scene6', 25, 25, 'HORATIO', 'brought them.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene7', 1, 0, 'KING', 'Now must your conscience my acquittance seal,'), ('hamlet_act4_scene7', 2, 1, 'KING', 'And you must put me in your heart for friend,'), ('hamlet_act4_scene7', 3, 2, 'KING', 'Sith you have heard, and with a knowing ear,'), ('hamlet_act4_scene7', 4, 3, 'KING', 'That he which hath your noble father slain'), ('hamlet_act4_scene7', 5, 4, 'KING', 'Pursued my life.'), ('hamlet_act4_scene7', 5, 5, 'LAERTES', 'It well appears: but tell me'), ('hamlet_act4_scene7', 6, 6, 'LAERTES', 'Why you proceeded not against these feats,'), ('hamlet_act4_scene7', 7, 7, 'LAERTES', 'So crimeful and so capital in nature,'), ('hamlet_act4_scene7', 8, 8, 'LAERTES', 'As by your safety, wisdom, all things else,'), ('hamlet_act4_scene7', 9, 9, 'LAERTES', 'You mainly were stirr’d up.'), ('hamlet_act4_scene7', 9, 10, 'KING', 'O, for two special reasons;'), ('hamlet_act4_scene7', 10, 11, 'KING', 'Which may to you, perhaps, seem much unsinew’d,'), ('hamlet_act4_scene7', 11, 12, 'KING', 'But yet to me they are strong. The queen his mother'), ('hamlet_act4_scene7', 12, 13, 'KING', 'Lives almost by his looks; and for myself—'), ('hamlet_act4_scene7', 13, 14, 'KING', 'My virtue or my plague, be it either which—'), ('hamlet_act4_scene7', 14, 15, 'KING', 'She’s so conjunctive to my life and soul,'), ('hamlet_act4_scene7', 15, 16, 'KING', 'That, as the star moves not but in his sphere,'), ('hamlet_act4_scene7', 16, 17, 'KING', 'I could not but by her. The other motive,'), ('hamlet_act4_scene7', 17, 18, 'KING', 'Why to a public count I might not go,'), ('hamlet_act4_scene7', 18, 19, 'KING', 'Is the great love the general gender bear him;'), ('hamlet_act4_scene7', 19, 20, 'KING', 'Who, dipping all his faults in their affection,'), ('hamlet_act4_scene7', 20, 21, 'KING', 'Would, like the spring that turneth wood to stone,'), ('hamlet_act4_scene7', 21, 22, 'KING', 'Convert his gyves to graces; so that my arrows,'), ('hamlet_act4_scene7', 22, 23, 'KING', 'Too slightly timber’d for so loud a wind,'), ('hamlet_act4_scene7', 23, 24, 'KING', 'Would have reverted to my bow again,'), ('hamlet_act4_scene7', 24, 25, 'KING', 'And not where I had aim’d them.'), ('hamlet_act4_scene7', 25, 26, 'LAERTES', 'And so have I a noble father lost;'), ('hamlet_act4_scene7', 26, 27, 'LAERTES', 'A sister driven into desperate terms,'), ('hamlet_act4_scene7', 27, 28, 'LAERTES', 'Whose worth, if praises may go back again,'), ('hamlet_act4_scene7', 28, 29, 'LAERTES', 'Stood challenger on mount of all the age'), ('hamlet_act4_scene7', 29, 30, 'LAERTES', 'For her perfections: but my revenge will come.'), ('hamlet_act4_scene7', 30, 31, 'KING', 'Break not your sleeps for that: you must not think'), ('hamlet_act4_scene7', 31, 32, 'KING', 'That we are made of stuff so flat and dull'), ('hamlet_act4_scene7', 32, 33, 'KING', 'That we can let our beard be shook with danger'), ('hamlet_act4_scene7', 33, 34, 'KING', 'And think it pastime. You shortly shall hear more:'), ('hamlet_act4_scene7', 34, 35, 'KING', 'I loved your father, and we love ourself;'), ('hamlet_act4_scene7', 35, 36, 'KING', 'And that, I hope, will teach you to imagine—'), ('hamlet_act4_scene7', 36, 37, 'MESSENGER', 'Letters, my lord, from Hamlet:'), ('hamlet_act4_scene7', 37, 38, 'MESSENGER', 'This to your majesty; this to the queen.'), ('hamlet_act4_scene7', 38, 39, 'KING', 'From Hamlet! who brought them?'), ('hamlet_act4_scene7', 39, 40, 'MESSENGER', 'Sailors, my lord, they say; I saw them not:'), ('hamlet_act4_scene7', 40, 41, 'MESSENGER', 'They were given me by Claudio; he received them'), ('hamlet_act4_scene7', 41, 42, 'MESSENGER', 'Of him that brought them.'), ('hamlet_act4_scene7', 42, 43, 'KING', 'Laertes, you shall hear them. Leave us. “High and mighty, You shall'), ('hamlet_act4_scene7', 43, 44, 'KING', 'know I am set naked on your kingdom. To-morrow shall I beg'), ('hamlet_act4_scene7', 44, 45, 'KING', 'leave to see your kingly eyes: when I shall, first asking your'), ('hamlet_act4_scene7', 45, 46, 'KING', 'pardon thereunto, recount the occasion of my sudden and more strange return.'), ('hamlet_act4_scene7', 46, 47, 'KING', 'What should this mean? Are all the rest come back? Or is'), ('hamlet_act4_scene7', 47, 48, 'KING', 'it some abuse, and no such thing?'), ('hamlet_act4_scene7', 48, 49, 'LAERTES', 'Know you the hand?'), ('hamlet_act4_scene7', 48, 50, 'KING', '’Tis Hamlet’s character. “Naked!”'), ('hamlet_act4_scene7', 49, 51, 'KING', 'And in a postscript here, he says “alone.”'), ('hamlet_act4_scene7', 50, 52, 'KING', 'Can you advise me?'), ('hamlet_act4_scene7', 51, 53, 'LAERTES', 'I’m lost in it, my lord. But let him come;'), ('hamlet_act4_scene7', 52, 54, 'LAERTES', 'It warms the very sickness in my heart,'), ('hamlet_act4_scene7', 53, 55, 'LAERTES', 'That I shall live and tell him to his teeth,'), ('hamlet_act4_scene7', 54, 56, 'LAERTES', '“Thus didest thou.”'), ('hamlet_act4_scene7', 54, 57, 'KING', 'If it be so, Laertes—'), ('hamlet_act4_scene7', 55, 58, 'KING', 'As how should it be so? how otherwise?—'), ('hamlet_act4_scene7', 56, 59, 'KING', 'Will you be ruled by me?'), ('hamlet_act4_scene7', 56, 60, 'LAERTES', 'Ay, my lord;'), ('hamlet_act4_scene7', 57, 61, 'LAERTES', 'So you will not o’errule me to a peace.'), ('hamlet_act4_scene7', 58, 62, 'KING', 'To thine own peace. If he be now return’d,'), ('hamlet_act4_scene7', 59, 63, 'KING', 'As checking at his voyage, and that he means'), ('hamlet_act4_scene7', 60, 64, 'KING', 'No more to undertake it, I will work him'), ('hamlet_act4_scene7', 61, 65, 'KING', 'To an exploit, now ripe in my device,'), ('hamlet_act4_scene7', 62, 66, 'KING', 'Under the which he shall not choose but fall:'), ('hamlet_act4_scene7', 63, 67, 'KING', 'And for his death no wind of blame shall breathe,'), ('hamlet_act4_scene7', 64, 68, 'KING', 'But even his mother shall uncharge the practice'), ('hamlet_act4_scene7', 65, 69, 'KING', 'And call it accident.'), ('hamlet_act4_scene7', 65, 70, 'LAERTES', 'My lord, I will be ruled;'), ('hamlet_act4_scene7', 66, 71, 'LAERTES', 'The rather, if you could devise it so'), ('hamlet_act4_scene7', 67, 72, 'LAERTES', 'That I might be the organ.'), ('hamlet_act4_scene7', 67, 73, 'KING', 'It falls right.'), ('hamlet_act4_scene7', 68, 74, 'KING', 'You have been talk’d of since your travel much,'), ('hamlet_act4_scene7', 69, 75, 'KING', 'And that in Hamlet’s hearing, for a quality'), ('hamlet_act4_scene7', 70, 76, 'KING', 'Wherein, they say, you shine: your sum of parts'), ('hamlet_act4_scene7', 71, 77, 'KING', 'Did not together pluck such envy from him'), ('hamlet_act4_scene7', 72, 78, 'KING', 'As did that one, and that, in my regard,'), ('hamlet_act4_scene7', 73, 79, 'KING', 'Of the unworthiest siege.'), ('hamlet_act4_scene7', 73, 80, 'LAERTES', 'What part is that, my lord?'), ('hamlet_act4_scene7', 74, 81, 'KING', 'A very riband in the cap of youth,'), ('hamlet_act4_scene7', 75, 82, 'KING', 'Yet needful too; for youth no less becomes'), ('hamlet_act4_scene7', 76, 83, 'KING', 'The light and careless livery that it wears'), ('hamlet_act4_scene7', 77, 84, 'KING', 'Than settled age his sables and his weeds,'), ('hamlet_act4_scene7', 78, 85, 'KING', 'Importing health and graveness. Two months since,'), ('hamlet_act4_scene7', 79, 86, 'KING', 'Here was a gentleman of Normandy:—'), ('hamlet_act4_scene7', 80, 87, 'KING', 'I’ve seen myself, and served against, the French,'), ('hamlet_act4_scene7', 81, 88, 'KING', 'And they can well on horseback: but this gallant'), ('hamlet_act4_scene7', 82, 89, 'KING', 'Had witchcraft in’t; he grew unto his seat;'), ('hamlet_act4_scene7', 83, 90, 'KING', 'And to such wondrous doing brought his horse,'), ('hamlet_act4_scene7', 84, 91, 'KING', 'As he had been incorpsed and demi-natured'), ('hamlet_act4_scene7', 85, 92, 'KING', 'With the brave beast: so far he topp’d my thought,'), ('hamlet_act4_scene7', 86, 93, 'KING', 'That I, in forgery of shapes and tricks,'), ('hamlet_act4_scene7', 87, 94, 'KING', 'Come short of what he did.'), ('hamlet_act4_scene7', 87, 95, 'LAERTES', 'A Norman was’t?'), ('hamlet_act4_scene7', 88, 96, 'KING', 'A Norman.'), ('hamlet_act4_scene7', 88, 97, 'LAERTES', 'Upon my life, Lamond.'), ('hamlet_act4_scene7', 89, 98, 'KING', 'The very same.'), ('hamlet_act4_scene7', 90, 99, 'LAERTES', 'I know him well: he is the brooch indeed');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene7', 91, 100, 'LAERTES', 'And gem of all the nation.'), ('hamlet_act4_scene7', 91, 101, 'KING', 'He made confession of you,'), ('hamlet_act4_scene7', 92, 102, 'KING', 'And gave you such a masterly report'), ('hamlet_act4_scene7', 93, 103, 'KING', 'For art and exercise in your defence'), ('hamlet_act4_scene7', 94, 104, 'KING', 'And for your rapier most especial,'), ('hamlet_act4_scene7', 95, 105, 'KING', 'That he cried out, ’twould be a sight indeed,'), ('hamlet_act4_scene7', 96, 106, 'KING', 'If one could match you: the scrimers of their nation,'), ('hamlet_act4_scene7', 97, 107, 'KING', 'He swore, had had neither motion, guard, nor eye,'), ('hamlet_act4_scene7', 98, 108, 'KING', 'If you opposed them. Sir, this report of his'), ('hamlet_act4_scene7', 99, 109, 'KING', 'Did Hamlet so envenom with his envy'), ('hamlet_act4_scene7', 100, 110, 'KING', 'That he could nothing do but wish and beg'), ('hamlet_act4_scene7', 101, 111, 'KING', 'Your sudden coming o’er, to play with him.'), ('hamlet_act4_scene7', 102, 112, 'KING', 'Now, out of this—'), ('hamlet_act4_scene7', 102, 113, 'LAERTES', 'What out of this, my lord?'), ('hamlet_act4_scene7', 103, 114, 'KING', 'Laertes, was your father dear to you?'), ('hamlet_act4_scene7', 104, 115, 'KING', 'Or are you like the painting of a sorrow,'), ('hamlet_act4_scene7', 105, 116, 'KING', 'A face without a heart?'), ('hamlet_act4_scene7', 105, 117, 'LAERTES', 'Why ask you this?'), ('hamlet_act4_scene7', 106, 118, 'KING', 'Not that I think you did not love your father;'), ('hamlet_act4_scene7', 107, 119, 'KING', 'But that I know love is begun by time;'), ('hamlet_act4_scene7', 108, 120, 'KING', 'And that I see, in passages of proof,'), ('hamlet_act4_scene7', 109, 121, 'KING', 'Time qualifies the spark and fire of it.'), ('hamlet_act4_scene7', 110, 122, 'KING', 'There lives within the very flame of love'), ('hamlet_act4_scene7', 111, 123, 'KING', 'A kind of wick or snuff that will abate it;'), ('hamlet_act4_scene7', 112, 124, 'KING', 'And nothing is at a like goodness still;'), ('hamlet_act4_scene7', 113, 125, 'KING', 'For goodness, growing to a plurisy,'), ('hamlet_act4_scene7', 114, 126, 'KING', 'Dies in his own too much: that we would do,'), ('hamlet_act4_scene7', 115, 127, 'KING', 'We should do when we would; for this “would” changes'), ('hamlet_act4_scene7', 116, 128, 'KING', 'And hath abatements and delays as many'), ('hamlet_act4_scene7', 117, 129, 'KING', 'As there are tongues, are hands, are accidents;'), ('hamlet_act4_scene7', 118, 130, 'KING', 'And then this “should” is like a spendthrift sigh,'), ('hamlet_act4_scene7', 119, 131, 'KING', 'That hurts by easing. But, to the quick o’ the ulcer:—'), ('hamlet_act4_scene7', 120, 132, 'KING', 'Hamlet comes back: what would you undertake,'), ('hamlet_act4_scene7', 121, 133, 'KING', 'To show yourself your father’s son in deed'), ('hamlet_act4_scene7', 122, 134, 'KING', 'More than in words?'), ('hamlet_act4_scene7', 123, 135, 'LAERTES', 'To cut his throat i’ the church.'), ('hamlet_act4_scene7', 124, 136, 'KING', 'No place, indeed, should murder sanctuarize;'), ('hamlet_act4_scene7', 125, 137, 'KING', 'Revenge should have no bounds. But, good Laertes,'), ('hamlet_act4_scene7', 126, 138, 'KING', 'Will you do this, keep close within your chamber.'), ('hamlet_act4_scene7', 127, 139, 'KING', 'Hamlet return’d shall know you are come home:'), ('hamlet_act4_scene7', 128, 140, 'KING', 'We’ll put on those shall praise your excellence'), ('hamlet_act4_scene7', 129, 141, 'KING', 'And set a double varnish on the fame'), ('hamlet_act4_scene7', 130, 142, 'KING', 'The Frenchman gave you, bring you in fine together'), ('hamlet_act4_scene7', 131, 143, 'KING', 'And wager on your heads: he, being remiss,'), ('hamlet_act4_scene7', 132, 144, 'KING', 'Most generous and free from all contriving,'), ('hamlet_act4_scene7', 133, 145, 'KING', 'Will not peruse the foils; so that, with ease,'), ('hamlet_act4_scene7', 134, 146, 'KING', 'Or with a little shuffling, you may choose'), ('hamlet_act4_scene7', 135, 147, 'KING', 'A sword unbated, and in a pass of practice'), ('hamlet_act4_scene7', 136, 148, 'KING', 'Requite him for your father.'), ('hamlet_act4_scene7', 136, 149, 'LAERTES', 'I will do’t:'), ('hamlet_act4_scene7', 137, 150, 'LAERTES', 'And, for that purpose, I’ll anoint my sword.'), ('hamlet_act4_scene7', 138, 151, 'LAERTES', 'I bought an unction of a mountebank,'), ('hamlet_act4_scene7', 139, 152, 'LAERTES', 'So mortal that, but dip a knife in it,'), ('hamlet_act4_scene7', 140, 153, 'LAERTES', 'Where it draws blood no cataplasm so rare,'), ('hamlet_act4_scene7', 141, 154, 'LAERTES', 'Collected from all simples that have virtue'), ('hamlet_act4_scene7', 142, 155, 'LAERTES', 'Under the moon, can save the thing from death'), ('hamlet_act4_scene7', 143, 156, 'LAERTES', 'That is but scratch’d withal: I’ll touch my point'), ('hamlet_act4_scene7', 144, 157, 'LAERTES', 'With this contagion, that, if I gall him slightly,'), ('hamlet_act4_scene7', 145, 158, 'LAERTES', 'It may be death.'), ('hamlet_act4_scene7', 145, 159, 'KING', 'Let’s further think of this;'), ('hamlet_act4_scene7', 146, 160, 'KING', 'Weigh what convenience both of time and means'), ('hamlet_act4_scene7', 147, 161, 'KING', 'May fit us to our shape: if this should fail,'), ('hamlet_act4_scene7', 148, 162, 'KING', 'And that our drift look through our bad performance,'), ('hamlet_act4_scene7', 149, 163, 'KING', '’Twere better not assay’d: therefore this project'), ('hamlet_act4_scene7', 150, 164, 'KING', 'Should have a back or second, that might hold,'), ('hamlet_act4_scene7', 151, 165, 'KING', 'If this should blast in proof. Soft! let me see:'), ('hamlet_act4_scene7', 152, 166, 'KING', 'We’ll make a solemn wager on your cunnings:'), ('hamlet_act4_scene7', 153, 167, 'KING', 'I ha’t.'), ('hamlet_act4_scene7', 154, 168, 'KING', 'When in your motion you are hot and dry—'), ('hamlet_act4_scene7', 155, 169, 'KING', 'As make your bouts more violent to that end—'), ('hamlet_act4_scene7', 156, 170, 'KING', 'And that he calls for drink, I’ll have prepared him'), ('hamlet_act4_scene7', 157, 171, 'KING', 'A chalice for the nonce, whereon but sipping,'), ('hamlet_act4_scene7', 158, 172, 'KING', 'If he by chance escape your venom’d stuck,'), ('hamlet_act4_scene7', 159, 173, 'KING', 'Our purpose may hold there.'), ('hamlet_act4_scene7', 160, 174, 'QUEEN', 'One woe doth tread upon another’s heel,'), ('hamlet_act4_scene7', 161, 175, 'QUEEN', 'So fast they follow: your sister’s drown’d, Laertes.'), ('hamlet_act4_scene7', 162, 176, 'LAERTES', 'Drown’d! O, where?'), ('hamlet_act4_scene7', 163, 177, 'QUEEN', 'There is a willow grows aslant a brook,'), ('hamlet_act4_scene7', 164, 178, 'QUEEN', 'That shows his hoar leaves in the glassy stream;'), ('hamlet_act4_scene7', 165, 179, 'QUEEN', 'There with fantastic garlands did she come'), ('hamlet_act4_scene7', 166, 180, 'QUEEN', 'Of crow-flowers, nettles, daisies, and long purples'), ('hamlet_act4_scene7', 167, 181, 'QUEEN', 'That liberal shepherds give a grosser name,'), ('hamlet_act4_scene7', 168, 182, 'QUEEN', 'But our cold maids do dead men’s fingers call them:'), ('hamlet_act4_scene7', 169, 183, 'QUEEN', 'There, on the pendent boughs her coronet weeds'), ('hamlet_act4_scene7', 170, 184, 'QUEEN', 'Clambering to hang, an envious sliver broke;'), ('hamlet_act4_scene7', 171, 185, 'QUEEN', 'When down her weedy trophies and herself'), ('hamlet_act4_scene7', 172, 186, 'QUEEN', 'Fell in the weeping brook. Her clothes spread wide;'), ('hamlet_act4_scene7', 173, 187, 'QUEEN', 'And, mermaid-like, awhile they bore her up:'), ('hamlet_act4_scene7', 174, 188, 'QUEEN', 'Which time she chanted snatches of old tunes;'), ('hamlet_act4_scene7', 175, 189, 'QUEEN', 'As one incapable of her own distress,'), ('hamlet_act4_scene7', 176, 190, 'QUEEN', 'Or like a creature native and indued'), ('hamlet_act4_scene7', 177, 191, 'QUEEN', 'Unto that element: but long it could not be'), ('hamlet_act4_scene7', 178, 192, 'QUEEN', 'Till that her garments, heavy with their drink,'), ('hamlet_act4_scene7', 179, 193, 'QUEEN', 'Pull’d the poor wretch from her melodious lay'), ('hamlet_act4_scene7', 180, 194, 'QUEEN', 'To muddy death.'), ('hamlet_act4_scene7', 180, 195, 'LAERTES', 'Alas, then, she is drown’d?'), ('hamlet_act4_scene7', 181, 196, 'QUEEN', 'Drown’d, drown’d.'), ('hamlet_act4_scene7', 182, 197, 'LAERTES', 'Too much of water hast thou, poor Ophelia,'), ('hamlet_act4_scene7', 183, 198, 'LAERTES', 'And therefore I forbid my tears: but yet'), ('hamlet_act4_scene7', 184, 199, 'LAERTES', 'It is our trick; nature her custom holds,');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act4_scene7', 185, 200, 'LAERTES', 'Let shame say what it will: when these are gone,'), ('hamlet_act4_scene7', 186, 201, 'LAERTES', 'The woman will be out. Adieu, my lord:'), ('hamlet_act4_scene7', 187, 202, 'LAERTES', 'I have a speech of fire, that fain would blaze,'), ('hamlet_act4_scene7', 188, 203, 'LAERTES', 'But that this folly douts it.'), ('hamlet_act4_scene7', 188, 204, 'KING', 'Let’s follow, Gertrude:'), ('hamlet_act4_scene7', 189, 205, 'KING', 'How much I had to do to calm his rage!'), ('hamlet_act4_scene7', 190, 206, 'KING', 'Now fear I this will give it start again;'), ('hamlet_act4_scene7', 191, 207, 'KING', 'Therefore let’s follow.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene1', 1, 0, 'FIRST CLOWN', 'Is she to be buried in Christian burial that wilfully seeks her own salvation?'), ('hamlet_act5_scene1', 2, 1, 'SECOND CLOWN', 'I tell thee she is: and therefore make her grave straight: the'), ('hamlet_act5_scene1', 3, 2, 'SECOND CLOWN', 'crowner hath sat on her, and finds it Christian burial.'), ('hamlet_act5_scene1', 4, 3, 'FIRST CLOWN', 'How can that be, unless she drowned herself in her own defence?'), ('hamlet_act5_scene1', 5, 4, 'SECOND CLOWN', 'Why, ’tis found so.'), ('hamlet_act5_scene1', 6, 5, 'FIRST CLOWN', 'It must be “se offendendo;” it cannot be else. For here lies'), ('hamlet_act5_scene1', 7, 6, 'FIRST CLOWN', 'the point: if I drown myself wittingly, it argues an act: and'), ('hamlet_act5_scene1', 8, 7, 'FIRST CLOWN', 'an act hath three branches; it is, to act, to do, to'), ('hamlet_act5_scene1', 9, 8, 'FIRST CLOWN', 'perform: argal, she drowned herself wittingly.'), ('hamlet_act5_scene1', 9, 9, 'SECOND CLOWN', 'Nay, but hear you, goodman delver—'), ('hamlet_act5_scene1', 10, 10, 'FIRST CLOWN', 'Give me leave. Here lies the water; good: here stands the man;'), ('hamlet_act5_scene1', 11, 11, 'FIRST CLOWN', 'good: if the man go to this water, and drown himself, it'), ('hamlet_act5_scene1', 12, 12, 'FIRST CLOWN', 'is, will he, nill he, he goes—mark you that; but if the'), ('hamlet_act5_scene1', 13, 13, 'FIRST CLOWN', 'water come to him and drown him, he drowns not himself: argal,'), ('hamlet_act5_scene1', 14, 14, 'FIRST CLOWN', 'he that is not guilty of his own death shortens not his'), ('hamlet_act5_scene1', 15, 15, 'FIRST CLOWN', 'own life.'), ('hamlet_act5_scene1', 15, 16, 'SECOND CLOWN', 'But is this law?'), ('hamlet_act5_scene1', 16, 17, 'FIRST CLOWN', 'Ay, marry, is’t; crowner’s quest law.'), ('hamlet_act5_scene1', 17, 18, 'SECOND CLOWN', 'Will you ha’ the truth on’t? If this had not been a'), ('hamlet_act5_scene1', 18, 19, 'SECOND CLOWN', 'gentlewoman, she should have been buried out o’ Christian burial.'), ('hamlet_act5_scene1', 19, 20, 'FIRST CLOWN', 'Why, there thou say’st: and the more pity that great folk should'), ('hamlet_act5_scene1', 20, 21, 'FIRST CLOWN', 'have countenance in this world to drown or hang themselves, more than'), ('hamlet_act5_scene1', 21, 22, 'FIRST CLOWN', 'their even Christian. Come, my spade. There is no ancient gentleman but'), ('hamlet_act5_scene1', 22, 23, 'FIRST CLOWN', 'gardeners, ditchers, and grave-makers: they hold up Adam’s profession.'), ('hamlet_act5_scene1', 23, 24, 'SECOND CLOWN', 'Was he a gentleman?'), ('hamlet_act5_scene1', 24, 25, 'FIRST CLOWN', 'A’ was the first that ever bore arms.'), ('hamlet_act5_scene1', 25, 26, 'SECOND CLOWN', 'Why, he had none.'), ('hamlet_act5_scene1', 26, 27, 'FIRST CLOWN', 'What, art a heathen? How dost thou understand the Scripture? The Scripture'), ('hamlet_act5_scene1', 27, 28, 'FIRST CLOWN', 'says “Adam digged:” could he dig without arms? I’ll put another question'), ('hamlet_act5_scene1', 28, 29, 'FIRST CLOWN', 'to thee: if thou answerest me not to the purpose, confess thyself—'), ('hamlet_act5_scene1', 29, 30, 'SECOND CLOWN', 'Go to.'), ('hamlet_act5_scene1', 30, 31, 'FIRST CLOWN', 'What is he that builds stronger than either the mason, the shipwright, or the carpenter?'), ('hamlet_act5_scene1', 31, 32, 'SECOND CLOWN', 'The gallows-maker; for that frame outlives a thousand tenants.'), ('hamlet_act5_scene1', 32, 33, 'FIRST CLOWN', 'I like thy wit well, in good faith: the gallows does well;'), ('hamlet_act5_scene1', 33, 34, 'FIRST CLOWN', 'but how does it well? it does well to those that do'), ('hamlet_act5_scene1', 34, 35, 'FIRST CLOWN', 'ill: now thou dost ill to say the gallows is built stronger'), ('hamlet_act5_scene1', 35, 36, 'FIRST CLOWN', 'than the church: argal, the gallows may do well to thee. To’t'), ('hamlet_act5_scene1', 36, 37, 'FIRST CLOWN', 'again, come.'), ('hamlet_act5_scene1', 37, 38, 'SECOND CLOWN', '“Who builds stronger than a mason, a shipwright, or a carpenter?”'), ('hamlet_act5_scene1', 38, 39, 'FIRST CLOWN', 'Ay, tell me that, and unyoke.'), ('hamlet_act5_scene1', 38, 40, 'SECOND CLOWN', 'Marry, now I can tell.'), ('hamlet_act5_scene1', 39, 41, 'FIRST CLOWN', 'To’t.'), ('hamlet_act5_scene1', 39, 42, 'SECOND CLOWN', 'Mass, I cannot tell.'), ('hamlet_act5_scene1', 40, 43, 'FIRST CLOWN', 'Cudgel thy brains no more about it, for your dull ass will'), ('hamlet_act5_scene1', 41, 44, 'FIRST CLOWN', 'not mend his pace with beating; and, when you are asked this'), ('hamlet_act5_scene1', 42, 45, 'FIRST CLOWN', 'question next, say “a grave-maker:” the houses that he makes last till'), ('hamlet_act5_scene1', 43, 46, 'FIRST CLOWN', 'doomsday. Go, get thee to Yaughan: fetch me a stoup of liquor.'), ('hamlet_act5_scene1', 44, 47, 'FIRST CLOWN', 'In youth, when I did love, did love, Methought it was very'), ('hamlet_act5_scene1', 45, 48, 'FIRST CLOWN', 'sweet, To contract, O, the time, for, ah, my behove, O, methought,'), ('hamlet_act5_scene1', 46, 49, 'FIRST CLOWN', 'there was nothing meet.'), ('hamlet_act5_scene1', 47, 50, 'HAMLET', 'Has this fellow no feeling of his business, that he sings at grave-making?'), ('hamlet_act5_scene1', 48, 51, 'HORATIO', 'Custom hath made it in him a property of easiness.'), ('hamlet_act5_scene1', 49, 52, 'HAMLET', '’Tis e’en so: the hand of little employment hath the daintier sense.'), ('hamlet_act5_scene1', 50, 53, 'FIRST CLOWN', 'But age, with his stealing steps, Hath claw’d me in his clutch,'), ('hamlet_act5_scene1', 51, 54, 'FIRST CLOWN', 'And hath shipped me intil the land, As if I had never'), ('hamlet_act5_scene1', 52, 55, 'FIRST CLOWN', 'been such.'), ('hamlet_act5_scene1', 53, 56, 'HAMLET', 'That skull had a tongue in it, and could sing once: how'), ('hamlet_act5_scene1', 54, 57, 'HAMLET', 'the knave jowls it to the ground, as if it were Cain’s'), ('hamlet_act5_scene1', 55, 58, 'HAMLET', 'jaw-bone, that did the first murder! It might be the pate of'), ('hamlet_act5_scene1', 56, 59, 'HAMLET', 'a politician, which this ass now o’er-reaches; one that would circumvent God,'), ('hamlet_act5_scene1', 57, 60, 'HAMLET', 'might it not?'), ('hamlet_act5_scene1', 57, 61, 'HORATIO', 'It might, my lord.'), ('hamlet_act5_scene1', 58, 62, 'HAMLET', 'Or of a courtier; which could say “Good morrow, sweet lord! How'), ('hamlet_act5_scene1', 59, 63, 'HAMLET', 'dost thou, good lord?” This might be my lord such-a-one, that praised'), ('hamlet_act5_scene1', 60, 64, 'HAMLET', 'my lord such-a-one’s horse, when he meant to beg it; might it'), ('hamlet_act5_scene1', 61, 65, 'HAMLET', 'not?'), ('hamlet_act5_scene1', 61, 66, 'HORATIO', 'Ay, my lord.'), ('hamlet_act5_scene1', 62, 67, 'HAMLET', 'Why, e’en so: and now my Lady Worm’s; chapless, and knocked about'), ('hamlet_act5_scene1', 63, 68, 'HAMLET', 'the mazzard with a sexton’s spade: here’s fine revolution, an we had'), ('hamlet_act5_scene1', 64, 69, 'HAMLET', 'the trick to see’t. Did these bones cost no more the breeding,'), ('hamlet_act5_scene1', 65, 70, 'HAMLET', 'but to play at loggats with ’em? mine ache to think on’t.'), ('hamlet_act5_scene1', 66, 71, 'FIRST CLOWN', 'A pick-axe, and a spade, a spade, For and a shrouding sheet:'), ('hamlet_act5_scene1', 67, 72, 'FIRST CLOWN', 'O, a pit of clay for to be made For such a'), ('hamlet_act5_scene1', 68, 73, 'FIRST CLOWN', 'guest is meet.'), ('hamlet_act5_scene1', 69, 74, 'HAMLET', 'There’s another: why may not that be the skull of a lawyer?'), ('hamlet_act5_scene1', 70, 75, 'HAMLET', 'Where be his quiddities now, his quillets, his cases, his tenures, and'), ('hamlet_act5_scene1', 71, 76, 'HAMLET', 'his tricks? why does he suffer this rude knave now to knock'), ('hamlet_act5_scene1', 72, 77, 'HAMLET', 'him about the sconce with a dirty shovel, and will not tell'), ('hamlet_act5_scene1', 73, 78, 'HAMLET', 'him of his action of battery? Hum! This fellow might be in’s'), ('hamlet_act5_scene1', 74, 79, 'HAMLET', 'time a great buyer of land, with his statutes, his recognizances, his'), ('hamlet_act5_scene1', 75, 80, 'HAMLET', 'fines, his double vouchers, his recoveries: is this the fine of his'), ('hamlet_act5_scene1', 76, 81, 'HAMLET', 'fines, and the recovery of his recoveries, to have his fine pate'), ('hamlet_act5_scene1', 77, 82, 'HAMLET', 'full of fine dirt? will his vouchers vouch him no more of'), ('hamlet_act5_scene1', 78, 83, 'HAMLET', 'his purchases, and double ones too, than the length and breadth of'), ('hamlet_act5_scene1', 79, 84, 'HAMLET', 'a pair of indentures? The very conveyances of his lands will hardly'), ('hamlet_act5_scene1', 80, 85, 'HAMLET', 'lie in this box; and must the inheritor himself have no more,'), ('hamlet_act5_scene1', 81, 86, 'HAMLET', 'ha?'), ('hamlet_act5_scene1', 81, 87, 'HORATIO', 'Not a jot more, my lord.'), ('hamlet_act5_scene1', 82, 88, 'HAMLET', 'Is not parchment made of sheepskins?'), ('hamlet_act5_scene1', 83, 89, 'HORATIO', 'Ay, my lord, and of calf-skins too.'), ('hamlet_act5_scene1', 84, 90, 'HAMLET', 'They are sheep and calves which seek out assurance in that. I'), ('hamlet_act5_scene1', 85, 91, 'HAMLET', 'will speak to this fellow. Whose grave’s this, sirrah?'), ('hamlet_act5_scene1', 86, 92, 'FIRST CLOWN', 'Mine, sir. O, a pit of clay for to be made For'), ('hamlet_act5_scene1', 87, 93, 'FIRST CLOWN', 'such a guest is meet.'), ('hamlet_act5_scene1', 88, 94, 'HAMLET', 'I think it be thine, indeed; for thou liest in’t.'), ('hamlet_act5_scene1', 89, 95, 'FIRST CLOWN', 'You lie out on’t, sir, and therefore it is not yours: for'), ('hamlet_act5_scene1', 90, 96, 'FIRST CLOWN', 'my part, I do not lie in’t, and yet it is mine.'), ('hamlet_act5_scene1', 91, 97, 'HAMLET', 'Thou dost lie in’t, to be in’t and say it is thine:'), ('hamlet_act5_scene1', 92, 98, 'HAMLET', '’tis for the dead, not for the quick; therefore thou liest.'), ('hamlet_act5_scene1', 93, 99, 'FIRST CLOWN', '’Tis a quick lie, sir; ’twill away again, from me to you.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene1', 94, 100, 'HAMLET', 'What man dost thou dig it for?'), ('hamlet_act5_scene1', 95, 101, 'FIRST CLOWN', 'For no man, sir.'), ('hamlet_act5_scene1', 95, 102, 'HAMLET', 'What woman, then?'), ('hamlet_act5_scene1', 96, 103, 'FIRST CLOWN', 'For none, neither.'), ('hamlet_act5_scene1', 96, 104, 'HAMLET', 'Who is to be buried in’t?'), ('hamlet_act5_scene1', 97, 105, 'FIRST CLOWN', 'One that was a woman, sir; but, rest her soul, she’s dead.'), ('hamlet_act5_scene1', 98, 106, 'HAMLET', 'How absolute the knave is! we must speak by the card, or'), ('hamlet_act5_scene1', 99, 107, 'HAMLET', 'equivocation will undo us. By the Lord, Horatio, these three years I'), ('hamlet_act5_scene1', 100, 108, 'HAMLET', 'have taken a note of it; the age is grown so picked'), ('hamlet_act5_scene1', 101, 109, 'HAMLET', 'that the toe of the peasant comes so near the heel of'), ('hamlet_act5_scene1', 102, 110, 'HAMLET', 'the courtier, he galls his kibe. How long hast thou been a'), ('hamlet_act5_scene1', 103, 111, 'HAMLET', 'grave-maker?'), ('hamlet_act5_scene1', 104, 112, 'FIRST CLOWN', 'Of all the days i’ the year, I came to’t that day'), ('hamlet_act5_scene1', 105, 113, 'FIRST CLOWN', 'that our last king Hamlet overcame Fortinbras.'), ('hamlet_act5_scene1', 106, 114, 'HAMLET', 'How long is that since?'), ('hamlet_act5_scene1', 107, 115, 'FIRST CLOWN', 'Cannot you tell that? every fool can tell that: it was the'), ('hamlet_act5_scene1', 108, 116, 'FIRST CLOWN', 'very day that young Hamlet was born; he that is mad, and'), ('hamlet_act5_scene1', 109, 117, 'FIRST CLOWN', 'sent into England.'), ('hamlet_act5_scene1', 110, 118, 'HAMLET', 'Ay, marry, why was he sent into England?'), ('hamlet_act5_scene1', 111, 119, 'FIRST CLOWN', 'Why, because he was mad: he shall recover his wits there; or,'), ('hamlet_act5_scene1', 112, 120, 'FIRST CLOWN', 'if he do not, it’s no great matter there.'), ('hamlet_act5_scene1', 113, 121, 'HAMLET', 'Why?'), ('hamlet_act5_scene1', 114, 122, 'FIRST CLOWN', '’Twill not be seen in him there; there the men are as mad as he.'), ('hamlet_act5_scene1', 115, 123, 'HAMLET', 'How came he mad?'), ('hamlet_act5_scene1', 115, 124, 'FIRST CLOWN', 'Very strangely, they say.'), ('hamlet_act5_scene1', 116, 125, 'HAMLET', 'How strangely?'), ('hamlet_act5_scene1', 116, 126, 'FIRST CLOWN', 'Faith, e’en with losing his wits.'), ('hamlet_act5_scene1', 117, 127, 'HAMLET', 'Upon what ground?'), ('hamlet_act5_scene1', 118, 128, 'FIRST CLOWN', 'Why, here in Denmark: I have been sexton here, man and boy, thirty years.'), ('hamlet_act5_scene1', 119, 129, 'HAMLET', 'How long will a man lie i’ the earth ere he rot?'), ('hamlet_act5_scene1', 120, 130, 'FIRST CLOWN', 'I’ faith, if he be not rotten before he die—as we have'), ('hamlet_act5_scene1', 121, 131, 'FIRST CLOWN', 'many pocky corses now-a-days, that will scarce hold the laying in—he will'), ('hamlet_act5_scene1', 122, 132, 'FIRST CLOWN', 'last you some eight year or nine year: a tanner will last'), ('hamlet_act5_scene1', 123, 133, 'FIRST CLOWN', 'you nine year.'), ('hamlet_act5_scene1', 123, 134, 'HAMLET', 'Why he more than another?'), ('hamlet_act5_scene1', 124, 135, 'FIRST CLOWN', 'Why, sir, his hide is so tanned with his trade, that he'), ('hamlet_act5_scene1', 125, 136, 'FIRST CLOWN', 'will keep out water a great while; and your water is a'), ('hamlet_act5_scene1', 126, 137, 'FIRST CLOWN', 'sore decayer of your whoreson dead body. Here’s a skull now; this'), ('hamlet_act5_scene1', 127, 138, 'FIRST CLOWN', 'skull has lain in the earth three and twenty years.'), ('hamlet_act5_scene1', 128, 139, 'HAMLET', 'Whose was it?'), ('hamlet_act5_scene1', 129, 140, 'FIRST CLOWN', 'A whoreson mad fellow’s it was: whose do you think it was?'), ('hamlet_act5_scene1', 130, 141, 'HAMLET', 'Nay, I know not.'), ('hamlet_act5_scene1', 131, 142, 'FIRST CLOWN', 'A pestilence on him for a mad rogue! a’ poured a flagon'), ('hamlet_act5_scene1', 132, 143, 'FIRST CLOWN', 'of Rhenish on my head once. This same skull, sir, was Yorick’s'), ('hamlet_act5_scene1', 133, 144, 'FIRST CLOWN', 'skull, the king’s jester.'), ('hamlet_act5_scene1', 133, 145, 'HAMLET', 'This?'), ('hamlet_act5_scene1', 134, 146, 'FIRST CLOWN', 'E’en that.'), ('hamlet_act5_scene1', 135, 147, 'HAMLET', 'Let me see. Alas, poor Yorick! I knew him, Horatio: a fellow'), ('hamlet_act5_scene1', 136, 148, 'HAMLET', 'of infinite jest, of most excellent fancy: he hath borne me on'), ('hamlet_act5_scene1', 137, 149, 'HAMLET', 'his back a thousand times; and now, how abhorred in my imagination'), ('hamlet_act5_scene1', 138, 150, 'HAMLET', 'it is! my gorge rises at it. Here hung those lips that'), ('hamlet_act5_scene1', 139, 151, 'HAMLET', 'I have kissed I know not how oft. Where be your gibes'), ('hamlet_act5_scene1', 140, 152, 'HAMLET', 'now? your gambols? your songs? your flashes of merriment, that were wont'), ('hamlet_act5_scene1', 141, 153, 'HAMLET', 'to set the table on a roar? Not one now, to mock'), ('hamlet_act5_scene1', 142, 154, 'HAMLET', 'your own grinning? quite chap-fallen? Now get you to my lady’s chamber,'), ('hamlet_act5_scene1', 143, 155, 'HAMLET', 'and tell her, let her paint an inch thick, to this favour'), ('hamlet_act5_scene1', 144, 156, 'HAMLET', 'she must come; make her laugh at that. Prithee, Horatio, tell me'), ('hamlet_act5_scene1', 145, 157, 'HAMLET', 'one thing.'), ('hamlet_act5_scene1', 145, 158, 'HORATIO', 'What’s that, my lord?'), ('hamlet_act5_scene1', 146, 159, 'HAMLET', 'Dost thou think Alexander looked o’ this fashion i’ the earth?'), ('hamlet_act5_scene1', 147, 160, 'HORATIO', 'E’en so.'), ('hamlet_act5_scene1', 147, 161, 'HAMLET', 'And smelt so? pah!'), ('hamlet_act5_scene1', 148, 162, 'HORATIO', 'E’en so, my lord.'), ('hamlet_act5_scene1', 149, 163, 'HAMLET', 'To what base uses we may return, Horatio! Why may not imagination'), ('hamlet_act5_scene1', 150, 164, 'HAMLET', 'trace the noble dust of Alexander, till he find it stopping a'), ('hamlet_act5_scene1', 151, 165, 'HAMLET', 'bung-hole?'), ('hamlet_act5_scene1', 152, 166, 'HORATIO', '’Twere to consider too curiously, to consider so.'), ('hamlet_act5_scene1', 153, 167, 'HAMLET', 'No, faith, not a jot; but to follow him thither with modesty'), ('hamlet_act5_scene1', 154, 168, 'HAMLET', 'enough, and likelihood to lead it: as thus: Alexander died, Alexander was'), ('hamlet_act5_scene1', 155, 169, 'HAMLET', 'buried, Alexander returneth into dust; the dust is earth; of earth we'), ('hamlet_act5_scene1', 156, 170, 'HAMLET', 'make loam; and why of that loam, whereto he was converted, might'), ('hamlet_act5_scene1', 157, 171, 'HAMLET', 'they not stop a beer-barrel? Imperious Caesar, dead and turn’d to clay,'), ('hamlet_act5_scene1', 158, 172, 'HAMLET', 'Might stop a hole to keep the wind away: O, that that'), ('hamlet_act5_scene1', 159, 173, 'HAMLET', 'earth, which kept the world in awe, Should patch a wall to'), ('hamlet_act5_scene1', 160, 174, 'HAMLET', 'expel the winter flaw! But soft! but soft! aside: here comes the'), ('hamlet_act5_scene1', 161, 175, 'HAMLET', 'king,'), ('hamlet_act5_scene1', 161, 176, 'LAERTES', 'What ceremony else?'), ('hamlet_act5_scene1', 162, 177, 'HAMLET', 'That is Laertes,'), ('hamlet_act5_scene1', 163, 178, 'HAMLET', 'A very noble youth: mark.'), ('hamlet_act5_scene1', 163, 179, 'LAERTES', 'What ceremony else?'), ('hamlet_act5_scene1', 164, 180, 'FIRST PRIEST', 'Her obsequies have been as far enlarged'), ('hamlet_act5_scene1', 165, 181, 'FIRST PRIEST', 'As we have warranty: her death was doubtful;'), ('hamlet_act5_scene1', 166, 182, 'FIRST PRIEST', 'And, but that great command o’ersways the order,'), ('hamlet_act5_scene1', 167, 183, 'FIRST PRIEST', 'She should in ground unsanctified have lodged'), ('hamlet_act5_scene1', 168, 184, 'FIRST PRIEST', 'Till the last trumpet; for charitable prayers,'), ('hamlet_act5_scene1', 169, 185, 'FIRST PRIEST', 'Shards, flints and pebbles should be thrown on her:'), ('hamlet_act5_scene1', 170, 186, 'FIRST PRIEST', 'Yet here she is allow’d her virgin crants,'), ('hamlet_act5_scene1', 171, 187, 'FIRST PRIEST', 'Her maiden strewments and the bringing home'), ('hamlet_act5_scene1', 172, 188, 'FIRST PRIEST', 'Of bell and burial.'), ('hamlet_act5_scene1', 172, 189, 'LAERTES', 'Must there no more be done?'), ('hamlet_act5_scene1', 173, 190, 'FIRST PRIEST', 'No more be done:'), ('hamlet_act5_scene1', 174, 191, 'FIRST PRIEST', 'We should profane the service of the dead'), ('hamlet_act5_scene1', 175, 192, 'FIRST PRIEST', 'To sing a requiem and such rest to her'), ('hamlet_act5_scene1', 176, 193, 'FIRST PRIEST', 'As to peace-parted souls.'), ('hamlet_act5_scene1', 176, 194, 'LAERTES', 'Lay her i’ the earth:'), ('hamlet_act5_scene1', 177, 195, 'LAERTES', 'And from her fair and unpolluted flesh'), ('hamlet_act5_scene1', 178, 196, 'LAERTES', 'May violets spring! I tell thee, churlish priest,'), ('hamlet_act5_scene1', 179, 197, 'LAERTES', 'A ministering angel shall my sister be,'), ('hamlet_act5_scene1', 180, 198, 'LAERTES', 'When thou liest howling.'), ('hamlet_act5_scene1', 180, 199, 'HAMLET', 'What, the fair Ophelia!');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene1', 181, 200, 'QUEEN', 'Sweets to the sweet: farewell!'), ('hamlet_act5_scene1', 182, 201, 'QUEEN', 'I hoped thou shouldst have been my Hamlet’s wife;'), ('hamlet_act5_scene1', 183, 202, 'QUEEN', 'I thought thy bride-bed to have deck’d, sweet maid,'), ('hamlet_act5_scene1', 184, 203, 'QUEEN', 'And not have strew’d thy grave.'), ('hamlet_act5_scene1', 184, 204, 'LAERTES', 'O, treble woe'), ('hamlet_act5_scene1', 185, 205, 'LAERTES', 'Fall ten times treble on that cursed head,'), ('hamlet_act5_scene1', 186, 206, 'LAERTES', 'Whose wicked deed thy most ingenious sense'), ('hamlet_act5_scene1', 187, 207, 'LAERTES', 'Deprived thee of! Hold off the earth awhile,'), ('hamlet_act5_scene1', 188, 208, 'LAERTES', 'Till I have caught her once more in mine arms:'), ('hamlet_act5_scene1', 189, 209, 'LAERTES', 'Now pile your dust upon the quick and dead,'), ('hamlet_act5_scene1', 190, 210, 'LAERTES', 'Till of this flat a mountain you have made,'), ('hamlet_act5_scene1', 191, 211, 'LAERTES', 'To o’ertop old Pelion, or the skyish head'), ('hamlet_act5_scene1', 192, 212, 'LAERTES', 'Of blue Olympus.'), ('hamlet_act5_scene1', 192, 213, 'HAMLET', 'What is he whose grief'), ('hamlet_act5_scene1', 193, 214, 'HAMLET', 'Bears such an emphasis? whose phrase of sorrow'), ('hamlet_act5_scene1', 194, 215, 'HAMLET', 'Conjures the wandering stars, and makes them stand'), ('hamlet_act5_scene1', 195, 216, 'HAMLET', 'Like wonder-wounded hearers? This is I,'), ('hamlet_act5_scene1', 196, 217, 'HAMLET', 'Hamlet the Dane.'), ('hamlet_act5_scene1', 196, 218, 'LAERTES', 'The devil take thy soul!'), ('hamlet_act5_scene1', 197, 219, 'HAMLET', 'Thou pray’st not well.'), ('hamlet_act5_scene1', 198, 220, 'HAMLET', 'I prithee, take thy fingers from my throat;'), ('hamlet_act5_scene1', 199, 221, 'HAMLET', 'For, though I am not splenitive and rash,'), ('hamlet_act5_scene1', 200, 222, 'HAMLET', 'Yet have I something in me dangerous,'), ('hamlet_act5_scene1', 201, 223, 'HAMLET', 'Which let thy wiseness fear: hold off thy hand.'), ('hamlet_act5_scene1', 202, 224, 'KING', 'Pluck them asunder.'), ('hamlet_act5_scene1', 202, 225, 'QUEEN', 'Hamlet, Hamlet!'), ('hamlet_act5_scene1', 203, 226, 'ALL', 'Gentlemen—'), ('hamlet_act5_scene1', 203, 227, 'HORATIO', 'Good my lord, be quiet.'), ('hamlet_act5_scene1', 204, 228, 'HAMLET', 'Why, I will fight with him upon this theme'), ('hamlet_act5_scene1', 205, 229, 'HAMLET', 'Until my eyelids will no longer wag.'), ('hamlet_act5_scene1', 206, 230, 'QUEEN', 'O my son, what theme?'), ('hamlet_act5_scene1', 206, 231, 'HAMLET', 'I loved Ophelia: forty thousand brothers'), ('hamlet_act5_scene1', 207, 232, 'HAMLET', 'Could not, with all their quantity of love,'), ('hamlet_act5_scene1', 208, 233, 'HAMLET', 'Make up my sum. What wilt thou do for her?'), ('hamlet_act5_scene1', 209, 234, 'KING', 'O, he is mad, Laertes.'), ('hamlet_act5_scene1', 209, 235, 'QUEEN', 'For love of God, forbear him.'), ('hamlet_act5_scene1', 210, 236, 'HAMLET', '’Swounds, show me what thou’lt do:'), ('hamlet_act5_scene1', 211, 237, 'HAMLET', 'Woo’t weep? woo’t fight? woo’t fast? woo’t tear thyself?'), ('hamlet_act5_scene1', 212, 238, 'HAMLET', 'Woo’t drink up eisel? eat a crocodile?'), ('hamlet_act5_scene1', 213, 239, 'HAMLET', 'I’ll do’t. Dost thou come here to whine?'), ('hamlet_act5_scene1', 214, 240, 'HAMLET', 'To outface me with leaping in her grave?'), ('hamlet_act5_scene1', 215, 241, 'HAMLET', 'Be buried quick with her, and so will I:'), ('hamlet_act5_scene1', 216, 242, 'HAMLET', 'And, if thou prate of mountains, let them throw'), ('hamlet_act5_scene1', 217, 243, 'HAMLET', 'Millions of acres on us, till our ground,'), ('hamlet_act5_scene1', 218, 244, 'HAMLET', 'Singeing his pate against the burning zone,'), ('hamlet_act5_scene1', 219, 245, 'HAMLET', 'Make Ossa like a wart! Nay, an thou’lt mouth,'), ('hamlet_act5_scene1', 220, 246, 'HAMLET', 'I’ll rant as well as thou.'), ('hamlet_act5_scene1', 220, 247, 'QUEEN', 'This is mere madness:'), ('hamlet_act5_scene1', 221, 248, 'QUEEN', 'And thus awhile the fit will work on him;'), ('hamlet_act5_scene1', 222, 249, 'QUEEN', 'Anon, as patient as the female dove,'), ('hamlet_act5_scene1', 223, 250, 'QUEEN', 'When that her golden couplets are disclosed,'), ('hamlet_act5_scene1', 224, 251, 'QUEEN', 'His silence will sit drooping.'), ('hamlet_act5_scene1', 224, 252, 'HAMLET', 'Hear you, sir;'), ('hamlet_act5_scene1', 225, 253, 'HAMLET', 'What is the reason that you use me thus?'), ('hamlet_act5_scene1', 226, 254, 'HAMLET', 'I loved you ever: but it is no matter;'), ('hamlet_act5_scene1', 227, 255, 'HAMLET', 'Let Hercules himself do what he may,'), ('hamlet_act5_scene1', 228, 256, 'HAMLET', 'The cat will mew and dog will have his day.'), ('hamlet_act5_scene1', 229, 257, 'KING', 'I pray you, good Horatio, wait upon him.'), ('hamlet_act5_scene1', 230, 258, 'KING', 'Strengthen your patience in our last night’s speech;'), ('hamlet_act5_scene1', 231, 259, 'KING', 'We’ll put the matter to the present push.'), ('hamlet_act5_scene1', 232, 260, 'KING', 'Good Gertrude, set some watch over your son.'), ('hamlet_act5_scene1', 233, 261, 'KING', 'This grave shall have a living monument:'), ('hamlet_act5_scene1', 234, 262, 'KING', 'An hour of quiet shortly shall we see;'), ('hamlet_act5_scene1', 235, 263, 'KING', 'Till then, in patience our proceeding be.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene2', 1, 0, 'HAMLET', 'So much for this, sir: now shall you see the other;'), ('hamlet_act5_scene2', 2, 1, 'HAMLET', 'You do remember all the circumstance?'), ('hamlet_act5_scene2', 2, 2, 'HORATIO', 'Remember it, my lord?'), ('hamlet_act5_scene2', 3, 3, 'HAMLET', 'Sir, in my heart there was a kind of fighting,'), ('hamlet_act5_scene2', 4, 4, 'HAMLET', 'That would not let me sleep: methought I lay'), ('hamlet_act5_scene2', 5, 5, 'HAMLET', 'Worse than the mutines in the bilboes. Rashly,'), ('hamlet_act5_scene2', 6, 6, 'HAMLET', 'And praised be rashness for it, let us know,'), ('hamlet_act5_scene2', 7, 7, 'HAMLET', 'Our indiscretion sometimes serves us well,'), ('hamlet_act5_scene2', 8, 8, 'HAMLET', 'When our deep plots do pall: and that should teach us'), ('hamlet_act5_scene2', 9, 9, 'HAMLET', 'There’s a divinity that shapes our ends,'), ('hamlet_act5_scene2', 10, 10, 'HAMLET', 'Rough-hew them how we will—'), ('hamlet_act5_scene2', 10, 11, 'HORATIO', 'That is most certain.'), ('hamlet_act5_scene2', 11, 12, 'HAMLET', 'Up from my cabin,'), ('hamlet_act5_scene2', 12, 13, 'HAMLET', 'My sea-gown scarf’d about me, in the dark'), ('hamlet_act5_scene2', 13, 14, 'HAMLET', 'Groped I to find out them; had my desire,'), ('hamlet_act5_scene2', 14, 15, 'HAMLET', 'Finger’d their packet, and in fine withdrew'), ('hamlet_act5_scene2', 15, 16, 'HAMLET', 'To mine own room again; making so bold,'), ('hamlet_act5_scene2', 16, 17, 'HAMLET', 'My fears forgetting manners, to unseal'), ('hamlet_act5_scene2', 17, 18, 'HAMLET', 'Their grand commission; where I found, Horatio—'), ('hamlet_act5_scene2', 18, 19, 'HAMLET', 'O royal knavery!—an exact command,'), ('hamlet_act5_scene2', 19, 20, 'HAMLET', 'Larded with many several sorts of reasons'), ('hamlet_act5_scene2', 20, 21, 'HAMLET', 'Importing Denmark’s health and England’s too,'), ('hamlet_act5_scene2', 21, 22, 'HAMLET', 'With, ho! such bugs and goblins in my life,'), ('hamlet_act5_scene2', 22, 23, 'HAMLET', 'That, on the supervise, no leisure bated,'), ('hamlet_act5_scene2', 23, 24, 'HAMLET', 'No, not to stay the grinding of the axe,'), ('hamlet_act5_scene2', 24, 25, 'HAMLET', 'My head should be struck off.'), ('hamlet_act5_scene2', 24, 26, 'HORATIO', 'Is’t possible?'), ('hamlet_act5_scene2', 25, 27, 'HAMLET', 'Here’s the commission: read it at more leisure.'), ('hamlet_act5_scene2', 26, 28, 'HAMLET', 'But wilt thou hear me how I did proceed?'), ('hamlet_act5_scene2', 27, 29, 'HORATIO', 'I beseech you.'), ('hamlet_act5_scene2', 27, 30, 'HAMLET', 'Being thus be-netted round with villainies—'), ('hamlet_act5_scene2', 28, 31, 'HAMLET', 'Ere I could make a prologue to my brains,'), ('hamlet_act5_scene2', 29, 32, 'HAMLET', 'They had begun the play—I sat me down,'), ('hamlet_act5_scene2', 30, 33, 'HAMLET', 'Devised a new commission, wrote it fair:'), ('hamlet_act5_scene2', 31, 34, 'HAMLET', 'I once did hold it, as our statists do,'), ('hamlet_act5_scene2', 32, 35, 'HAMLET', 'A baseness to write fair and labour’d much'), ('hamlet_act5_scene2', 33, 36, 'HAMLET', 'How to forget that learning, but, sir, now'), ('hamlet_act5_scene2', 34, 37, 'HAMLET', 'It did me yeoman’s service: wilt thou know'), ('hamlet_act5_scene2', 35, 38, 'HAMLET', 'The effect of what I wrote?'), ('hamlet_act5_scene2', 35, 39, 'HORATIO', 'Ay, good my lord.'), ('hamlet_act5_scene2', 36, 40, 'HAMLET', 'An earnest conjuration from the king,'), ('hamlet_act5_scene2', 37, 41, 'HAMLET', 'As England was his faithful tributary,'), ('hamlet_act5_scene2', 38, 42, 'HAMLET', 'As love between them like the palm might flourish,'), ('hamlet_act5_scene2', 39, 43, 'HAMLET', 'As peace should still her wheaten garland wear'), ('hamlet_act5_scene2', 40, 44, 'HAMLET', 'And stand a comma ’tween their amities,'), ('hamlet_act5_scene2', 41, 45, 'HAMLET', 'And many such-like “As”es of great charge,'), ('hamlet_act5_scene2', 42, 46, 'HAMLET', 'That, on the view and knowing of these contents,'), ('hamlet_act5_scene2', 43, 47, 'HAMLET', 'Without debatement further, more or less,'), ('hamlet_act5_scene2', 44, 48, 'HAMLET', 'He should the bearers put to sudden death,'), ('hamlet_act5_scene2', 45, 49, 'HAMLET', 'Not shriving-time allow’d.'), ('hamlet_act5_scene2', 45, 50, 'HORATIO', 'How was this seal’d?'), ('hamlet_act5_scene2', 46, 51, 'HAMLET', 'Why, even in that was heaven ordinant.'), ('hamlet_act5_scene2', 47, 52, 'HAMLET', 'I had my father’s signet in my purse,'), ('hamlet_act5_scene2', 48, 53, 'HAMLET', 'Which was the model of that Danish seal;'), ('hamlet_act5_scene2', 49, 54, 'HAMLET', 'Folded the writ up in form of the other,'), ('hamlet_act5_scene2', 50, 55, 'HAMLET', 'Subscribed it, gave’t the impression, placed it safely,'), ('hamlet_act5_scene2', 51, 56, 'HAMLET', 'The changeling never known. Now, the next day'), ('hamlet_act5_scene2', 52, 57, 'HAMLET', 'Was our sea-fight; and what to this was sequent'), ('hamlet_act5_scene2', 53, 58, 'HAMLET', 'Thou know’st already.'), ('hamlet_act5_scene2', 53, 59, 'HORATIO', 'So Guildenstern and Rosencrantz go to’t.'), ('hamlet_act5_scene2', 54, 60, 'HAMLET', 'Why, man, they did make love to this employment;'), ('hamlet_act5_scene2', 55, 61, 'HAMLET', 'They are not near my conscience; their defeat'), ('hamlet_act5_scene2', 56, 62, 'HAMLET', 'Does by their own insinuation grow:'), ('hamlet_act5_scene2', 57, 63, 'HAMLET', '’Tis dangerous when the baser nature comes'), ('hamlet_act5_scene2', 58, 64, 'HAMLET', 'Between the pass and fell incensed points'), ('hamlet_act5_scene2', 59, 65, 'HAMLET', 'Of mighty opposites.'), ('hamlet_act5_scene2', 59, 66, 'HORATIO', 'Why, what a king is this!'), ('hamlet_act5_scene2', 60, 67, 'HAMLET', 'Does it not, think’st thee, stand me now upon—'), ('hamlet_act5_scene2', 61, 68, 'HAMLET', 'He that hath kill’d my king and whored my mother,'), ('hamlet_act5_scene2', 62, 69, 'HAMLET', 'Popp’d in between the election and my hopes,'), ('hamlet_act5_scene2', 63, 70, 'HAMLET', 'Thrown out his angle for my proper life,'), ('hamlet_act5_scene2', 64, 71, 'HAMLET', 'And with such cozenage—is’t not perfect conscience,'), ('hamlet_act5_scene2', 65, 72, 'HAMLET', 'To quit him with this arm? and is’t not to be damn’d,'), ('hamlet_act5_scene2', 66, 73, 'HAMLET', 'To let this canker of our nature come'), ('hamlet_act5_scene2', 67, 74, 'HAMLET', 'In further evil?'), ('hamlet_act5_scene2', 68, 75, 'HORATIO', 'It must be shortly known to him from England'), ('hamlet_act5_scene2', 69, 76, 'HORATIO', 'What is the issue of the business there.'), ('hamlet_act5_scene2', 70, 77, 'HAMLET', 'It will be short: the interim is mine;'), ('hamlet_act5_scene2', 71, 78, 'HAMLET', 'And a man’s life’s no more than to say “One.”'), ('hamlet_act5_scene2', 72, 79, 'HAMLET', 'But I am very sorry, good Horatio,'), ('hamlet_act5_scene2', 73, 80, 'HAMLET', 'That to Laertes I forgot myself;'), ('hamlet_act5_scene2', 74, 81, 'HAMLET', 'For, by the image of my cause, I see'), ('hamlet_act5_scene2', 75, 82, 'HAMLET', 'The portraiture of his: I’ll court his favours:'), ('hamlet_act5_scene2', 76, 83, 'HAMLET', 'But, sure, the bravery of his grief did put me'), ('hamlet_act5_scene2', 77, 84, 'HAMLET', 'Into a towering passion.'), ('hamlet_act5_scene2', 77, 85, 'HORATIO', 'Peace! who comes here?'), ('hamlet_act5_scene2', 78, 86, 'OSRIC', 'Your lordship is right welcome back to Denmark.'), ('hamlet_act5_scene2', 79, 87, 'HAMLET', 'I humbly thank you, sir. Dost know this water-fly?'), ('hamlet_act5_scene2', 80, 88, 'HORATIO', 'No, my good lord.'), ('hamlet_act5_scene2', 81, 89, 'HAMLET', 'Thy state is the more gracious; for ’tis a vice to know'), ('hamlet_act5_scene2', 82, 90, 'HAMLET', 'him. He hath much land, and fertile: let a beast be lord'), ('hamlet_act5_scene2', 83, 91, 'HAMLET', 'of beasts, and his crib shall stand at the king’s mess: ’tis'), ('hamlet_act5_scene2', 84, 92, 'HAMLET', 'a chough; but, as I say, spacious in the possession of dirt.'), ('hamlet_act5_scene2', 85, 93, 'OSRIC', 'Sweet lord, if your lordship were at leisure, I should impart a'), ('hamlet_act5_scene2', 86, 94, 'OSRIC', 'thing to you from his majesty.'), ('hamlet_act5_scene2', 87, 95, 'HAMLET', 'I will receive it, sir, with all diligence of spirit. Put your'), ('hamlet_act5_scene2', 88, 96, 'HAMLET', 'bonnet to his right use; ’tis for the head.'), ('hamlet_act5_scene2', 89, 97, 'OSRIC', 'I thank your lordship, it is very hot.'), ('hamlet_act5_scene2', 90, 98, 'HAMLET', 'No, believe me, ’tis very cold; the wind is northerly.'), ('hamlet_act5_scene2', 91, 99, 'OSRIC', 'It is indifferent cold, my lord, indeed.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene2', 92, 100, 'HAMLET', 'But yet methinks it is very sultry and hot for my complexion.'), ('hamlet_act5_scene2', 93, 101, 'OSRIC', 'Exceedingly, my lord; it is very sultry—as ’twere—I cannot tell how. But,'), ('hamlet_act5_scene2', 94, 102, 'OSRIC', 'my lord, his majesty bade me signify to you that he has'), ('hamlet_act5_scene2', 95, 103, 'OSRIC', 'laid a great wager on your head: sir, this is the matter—'), ('hamlet_act5_scene2', 96, 104, 'HAMLET', 'I beseech you, remember—'), ('hamlet_act5_scene2', 97, 105, 'OSRIC', 'Nay, good my lord; for mine ease, in good faith. Sir, here'), ('hamlet_act5_scene2', 98, 106, 'OSRIC', 'is newly come to court Laertes; believe me, an absolute gentleman, full'), ('hamlet_act5_scene2', 99, 107, 'OSRIC', 'of most excellent differences, of very soft society and great showing: indeed,'), ('hamlet_act5_scene2', 100, 108, 'OSRIC', 'to speak feelingly of him, he is the card or calendar of'), ('hamlet_act5_scene2', 101, 109, 'OSRIC', 'gentry, for you shall find in him the continent of what part'), ('hamlet_act5_scene2', 102, 110, 'OSRIC', 'a gentleman would see.'), ('hamlet_act5_scene2', 103, 111, 'HAMLET', 'Sir, his definement suffers no perdition in you; though, I know, to'), ('hamlet_act5_scene2', 104, 112, 'HAMLET', 'divide him inventorially would dizzy the arithmetic of memory, and yet but'), ('hamlet_act5_scene2', 105, 113, 'HAMLET', 'yaw neither, in respect of his quick sail. But, in the verity'), ('hamlet_act5_scene2', 106, 114, 'HAMLET', 'of extolment, I take him to be a soul of great article;'), ('hamlet_act5_scene2', 107, 115, 'HAMLET', 'and his infusion of such dearth and rareness, as, to make true'), ('hamlet_act5_scene2', 108, 116, 'HAMLET', 'diction of him, his semblable is his mirror; and who else would'), ('hamlet_act5_scene2', 109, 117, 'HAMLET', 'trace him, his umbrage, nothing more.'), ('hamlet_act5_scene2', 110, 118, 'OSRIC', 'Your lordship speaks most infallibly of him.'), ('hamlet_act5_scene2', 111, 119, 'HAMLET', 'The concernancy, sir? why do we wrap the gentleman in our more rawer breath?'), ('hamlet_act5_scene2', 112, 120, 'OSRIC', 'Sir?'), ('hamlet_act5_scene2', 113, 121, 'HORATIO', 'Is’t not possible to understand in another tongue? You will do’t, sir, really.'), ('hamlet_act5_scene2', 114, 122, 'HAMLET', 'What imports the nomination of this gentleman?'), ('hamlet_act5_scene2', 115, 123, 'OSRIC', 'Of Laertes?'), ('hamlet_act5_scene2', 116, 124, 'HORATIO', 'His purse is empty already; all’s golden words are spent.'), ('hamlet_act5_scene2', 117, 125, 'HAMLET', 'Of him, sir.'), ('hamlet_act5_scene2', 117, 126, 'OSRIC', 'I know you are not ignorant—'), ('hamlet_act5_scene2', 118, 127, 'HAMLET', 'I would you did, sir; yet, in faith, if you did, it'), ('hamlet_act5_scene2', 119, 128, 'HAMLET', 'would not much approve me. Well, sir?'), ('hamlet_act5_scene2', 120, 129, 'OSRIC', 'You are not ignorant of what excellence Laertes is—'), ('hamlet_act5_scene2', 121, 130, 'HAMLET', 'I dare not confess that, lest I should compare with him in'), ('hamlet_act5_scene2', 122, 131, 'HAMLET', 'excellence; but, to know a man well, were to know himself.'), ('hamlet_act5_scene2', 123, 132, 'OSRIC', 'I mean, sir, for his weapon; but in the imputation laid on'), ('hamlet_act5_scene2', 124, 133, 'OSRIC', 'him by them, in his meed he’s unfellowed.'), ('hamlet_act5_scene2', 125, 134, 'HAMLET', 'What’s his weapon?'), ('hamlet_act5_scene2', 125, 135, 'OSRIC', 'Rapier and dagger.'), ('hamlet_act5_scene2', 126, 136, 'HAMLET', 'That’s two of his weapons: but, well.'), ('hamlet_act5_scene2', 127, 137, 'OSRIC', 'The king, sir, hath wagered with him six Barbary horses: against the'), ('hamlet_act5_scene2', 128, 138, 'OSRIC', 'which he has imponed, as I take it, six French rapiers and'), ('hamlet_act5_scene2', 129, 139, 'OSRIC', 'poniards, with their assigns, as girdle, hangers, and so: three of the'), ('hamlet_act5_scene2', 130, 140, 'OSRIC', 'carriages, in faith, are very dear to fancy, very responsive to the'), ('hamlet_act5_scene2', 131, 141, 'OSRIC', 'hilts, most delicate carriages, and of very liberal conceit.'), ('hamlet_act5_scene2', 132, 142, 'HAMLET', 'What call you the carriages?'), ('hamlet_act5_scene2', 133, 143, 'HORATIO', 'I knew you must be edified by the margent ere you had done.'), ('hamlet_act5_scene2', 134, 144, 'OSRIC', 'The carriages, sir, are the hangers.'), ('hamlet_act5_scene2', 135, 145, 'HAMLET', 'The phrase would be more german to the matter, if we could'), ('hamlet_act5_scene2', 136, 146, 'HAMLET', 'carry cannon by our sides: I would it might be hangers till'), ('hamlet_act5_scene2', 137, 147, 'HAMLET', 'then. But, on: six Barbary horses against six French swords, their assigns,'), ('hamlet_act5_scene2', 138, 148, 'HAMLET', 'and three liberal-conceited carriages; that’s the French bet against the Danish. Why'), ('hamlet_act5_scene2', 139, 149, 'HAMLET', 'is this “imponed,” as you call it?'), ('hamlet_act5_scene2', 140, 150, 'OSRIC', 'The king, sir, hath laid, that in a dozen passes between yourself'), ('hamlet_act5_scene2', 141, 151, 'OSRIC', 'and him, he shall not exceed you three hits: he hath laid'), ('hamlet_act5_scene2', 142, 152, 'OSRIC', 'on twelve for nine; and it would come to immediate trial, if'), ('hamlet_act5_scene2', 143, 153, 'OSRIC', 'your lordship would vouchsafe the answer.'), ('hamlet_act5_scene2', 143, 154, 'HAMLET', 'How if I answer “no”?'), ('hamlet_act5_scene2', 144, 155, 'OSRIC', 'I mean, my lord, the opposition of your person in trial.'), ('hamlet_act5_scene2', 145, 156, 'HAMLET', 'Sir, I will walk here in the hall: if it please his'), ('hamlet_act5_scene2', 146, 157, 'HAMLET', 'majesty, ’tis the breathing time of day with me; let the foils'), ('hamlet_act5_scene2', 147, 158, 'HAMLET', 'be brought, the gentleman willing, and the king hold his purpose, I'), ('hamlet_act5_scene2', 148, 159, 'HAMLET', 'will win for him an I can; if not, I will gain'), ('hamlet_act5_scene2', 149, 160, 'HAMLET', 'nothing but my shame and the odd hits.'), ('hamlet_act5_scene2', 150, 161, 'OSRIC', 'Shall I re-deliver you e’en so?'), ('hamlet_act5_scene2', 151, 162, 'HAMLET', 'To this effect, sir; after what flourish your nature will.'), ('hamlet_act5_scene2', 152, 163, 'OSRIC', 'I commend my duty to your lordship.'), ('hamlet_act5_scene2', 153, 164, 'HAMLET', 'Yours, yours. He does well to commend it himself; there are no'), ('hamlet_act5_scene2', 154, 165, 'HAMLET', 'tongues else for’s turn.'), ('hamlet_act5_scene2', 155, 166, 'HORATIO', 'This lapwing runs away with the shell on his head.'), ('hamlet_act5_scene2', 156, 167, 'HAMLET', 'He did comply with his dug, before he sucked it. Thus has'), ('hamlet_act5_scene2', 157, 168, 'HAMLET', 'he—and many more of the same bevy that I know the drossy'), ('hamlet_act5_scene2', 158, 169, 'HAMLET', 'age dotes on—only got the tune of the time and outward habit'), ('hamlet_act5_scene2', 159, 170, 'HAMLET', 'of encounter; a kind of yesty collection, which carries them through and'), ('hamlet_act5_scene2', 160, 171, 'HAMLET', 'through the most fond and winnowed opinions; and do but blow them'), ('hamlet_act5_scene2', 161, 172, 'HAMLET', 'to their trial, the bubbles are out.'), ('hamlet_act5_scene2', 162, 173, 'LORD', 'My lord, his majesty commended him to you by young Osric, who'), ('hamlet_act5_scene2', 163, 174, 'LORD', 'brings back to him that you attend him in the hall: he'), ('hamlet_act5_scene2', 164, 175, 'LORD', 'sends to know if your pleasure hold to play with Laertes, or'), ('hamlet_act5_scene2', 165, 176, 'LORD', 'that you will take longer time.'), ('hamlet_act5_scene2', 166, 177, 'HAMLET', 'I am constant to my purpose; they follow the king’s pleasure: if'), ('hamlet_act5_scene2', 167, 178, 'HAMLET', 'his fitness speaks, mine is ready; now or whensoever, provided I be'), ('hamlet_act5_scene2', 168, 179, 'HAMLET', 'so able as now.'), ('hamlet_act5_scene2', 169, 180, 'LORD', 'The king and queen and all are coming down.'), ('hamlet_act5_scene2', 170, 181, 'HAMLET', 'In happy time.'), ('hamlet_act5_scene2', 171, 182, 'LORD', 'The queen desires you to use some gentle entertainment to Laertes before'), ('hamlet_act5_scene2', 172, 183, 'LORD', 'you fall to play.'), ('hamlet_act5_scene2', 172, 184, 'HAMLET', 'She well instructs me.'), ('hamlet_act5_scene2', 173, 185, 'HORATIO', 'You will lose this wager, my lord.'), ('hamlet_act5_scene2', 174, 186, 'HAMLET', 'I do not think so: since he went into France, I have'), ('hamlet_act5_scene2', 175, 187, 'HAMLET', 'been in continual practice: I shall win at the odds. But thou'), ('hamlet_act5_scene2', 176, 188, 'HAMLET', 'wouldst not think how ill all’s here about my heart: but it'), ('hamlet_act5_scene2', 177, 189, 'HAMLET', 'is no matter.'), ('hamlet_act5_scene2', 177, 190, 'HORATIO', 'Nay, good my lord—'), ('hamlet_act5_scene2', 178, 191, 'HAMLET', 'It is but foolery; but it is such a kind of gain-giving,'), ('hamlet_act5_scene2', 179, 192, 'HAMLET', 'as would perhaps trouble a woman.'), ('hamlet_act5_scene2', 180, 193, 'HORATIO', 'If your mind dislike any thing, obey it: I will forestall their'), ('hamlet_act5_scene2', 181, 194, 'HORATIO', 'repair hither, and say you are not fit.'), ('hamlet_act5_scene2', 182, 195, 'HAMLET', 'Not a whit, we defy augury: there’s a special providence in the'), ('hamlet_act5_scene2', 183, 196, 'HAMLET', 'fall of a sparrow. If it be now, ’tis not to come;'), ('hamlet_act5_scene2', 184, 197, 'HAMLET', 'if it be not to come, it will be now; if it'), ('hamlet_act5_scene2', 185, 198, 'HAMLET', 'be not now, yet it will come: the readiness is all: since'), ('hamlet_act5_scene2', 186, 199, 'HAMLET', 'no man has aught of what he leaves, what is’t to leave');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene2', 187, 200, 'HAMLET', 'betimes?'), ('hamlet_act5_scene2', 188, 201, 'KING', 'Come, Hamlet, come, and take this hand from me.'), ('hamlet_act5_scene2', 189, 202, 'HAMLET', 'Give me your pardon, sir: I’ve done you wrong;'), ('hamlet_act5_scene2', 190, 203, 'HAMLET', 'But pardon’t, as you are a gentleman.'), ('hamlet_act5_scene2', 191, 204, 'HAMLET', 'This presence knows,'), ('hamlet_act5_scene2', 192, 205, 'HAMLET', 'And you must needs have heard, how I am punish’d'), ('hamlet_act5_scene2', 193, 206, 'HAMLET', 'With sore distraction. What I have done,'), ('hamlet_act5_scene2', 194, 207, 'HAMLET', 'That might your nature, honour and exception'), ('hamlet_act5_scene2', 195, 208, 'HAMLET', 'Roughly awake, I here proclaim was madness.'), ('hamlet_act5_scene2', 196, 209, 'HAMLET', 'Was’t Hamlet wrong’d Laertes? Never Hamlet:'), ('hamlet_act5_scene2', 197, 210, 'HAMLET', 'If Hamlet from himself be ta’en away,'), ('hamlet_act5_scene2', 198, 211, 'HAMLET', 'And when he’s not himself does wrong Laertes,'), ('hamlet_act5_scene2', 199, 212, 'HAMLET', 'Then Hamlet does it not, Hamlet denies it.'), ('hamlet_act5_scene2', 200, 213, 'HAMLET', 'Who does it, then? His madness: if’t be so,'), ('hamlet_act5_scene2', 201, 214, 'HAMLET', 'Hamlet is of the faction that is wrong’d;'), ('hamlet_act5_scene2', 202, 215, 'HAMLET', 'His madness is poor Hamlet’s enemy.'), ('hamlet_act5_scene2', 203, 216, 'HAMLET', 'Sir, in this audience,'), ('hamlet_act5_scene2', 204, 217, 'HAMLET', 'Let my disclaiming from a purposed evil'), ('hamlet_act5_scene2', 205, 218, 'HAMLET', 'Free me so far in your most generous thoughts,'), ('hamlet_act5_scene2', 206, 219, 'HAMLET', 'That I have shot mine arrow o’er the house,'), ('hamlet_act5_scene2', 207, 220, 'HAMLET', 'And hurt my brother.'), ('hamlet_act5_scene2', 207, 221, 'LAERTES', 'I am satisfied in nature,'), ('hamlet_act5_scene2', 208, 222, 'LAERTES', 'Whose motive, in this case, should stir me most'), ('hamlet_act5_scene2', 209, 223, 'LAERTES', 'To my revenge: but in my terms of honour'), ('hamlet_act5_scene2', 210, 224, 'LAERTES', 'I stand aloof; and will no reconcilement,'), ('hamlet_act5_scene2', 211, 225, 'LAERTES', 'Till by some elder masters, of known honour,'), ('hamlet_act5_scene2', 212, 226, 'LAERTES', 'I have a voice and precedent of peace,'), ('hamlet_act5_scene2', 213, 227, 'LAERTES', 'To keep my name ungored. But till that time,'), ('hamlet_act5_scene2', 214, 228, 'LAERTES', 'I do receive your offer’d love like love,'), ('hamlet_act5_scene2', 215, 229, 'LAERTES', 'And will not wrong it.'), ('hamlet_act5_scene2', 215, 230, 'HAMLET', 'I embrace it freely;'), ('hamlet_act5_scene2', 216, 231, 'HAMLET', 'And will this brother’s wager frankly play.'), ('hamlet_act5_scene2', 217, 232, 'HAMLET', 'Give us the foils. Come on.'), ('hamlet_act5_scene2', 217, 233, 'LAERTES', 'Come, one for me.'), ('hamlet_act5_scene2', 218, 234, 'HAMLET', 'I’ll be your foil, Laertes: in mine ignorance'), ('hamlet_act5_scene2', 219, 235, 'HAMLET', 'Your skill shall, like a star i’ the darkest night,'), ('hamlet_act5_scene2', 220, 236, 'HAMLET', 'Stick fiery off indeed.'), ('hamlet_act5_scene2', 220, 237, 'LAERTES', 'You mock me, sir.'), ('hamlet_act5_scene2', 221, 238, 'HAMLET', 'No, by this hand.'), ('hamlet_act5_scene2', 222, 239, 'KING', 'Give them the foils, young Osric. Cousin Hamlet,'), ('hamlet_act5_scene2', 223, 240, 'KING', 'You know the wager?'), ('hamlet_act5_scene2', 223, 241, 'HAMLET', 'Very well, my lord;'), ('hamlet_act5_scene2', 224, 242, 'HAMLET', 'Your grace hath laid the odds o’ the weaker side.'), ('hamlet_act5_scene2', 225, 243, 'KING', 'I do not fear it; I have seen you both:'), ('hamlet_act5_scene2', 226, 244, 'KING', 'But since he is better’d, we have therefore odds.'), ('hamlet_act5_scene2', 227, 245, 'LAERTES', 'This is too heavy, let me see another.'), ('hamlet_act5_scene2', 228, 246, 'HAMLET', 'This likes me well. These foils have all a length?'), ('hamlet_act5_scene2', 229, 247, 'OSRIC', 'Ay, my good lord.'), ('hamlet_act5_scene2', 230, 248, 'KING', 'Set me the stoups of wine upon that table.'), ('hamlet_act5_scene2', 231, 249, 'KING', 'If Hamlet give the first or second hit,'), ('hamlet_act5_scene2', 232, 250, 'KING', 'Or quit in answer of the third exchange,'), ('hamlet_act5_scene2', 233, 251, 'KING', 'Let all the battlements their ordnance fire;'), ('hamlet_act5_scene2', 234, 252, 'KING', 'The king shall drink to Hamlet’s better breath;'), ('hamlet_act5_scene2', 235, 253, 'KING', 'And in the cup an union shall he throw,'), ('hamlet_act5_scene2', 236, 254, 'KING', 'Richer than that which four successive kings'), ('hamlet_act5_scene2', 237, 255, 'KING', 'In Denmark’s crown have worn. Give me the cups;'), ('hamlet_act5_scene2', 238, 256, 'KING', 'And let the kettle to the trumpet speak,'), ('hamlet_act5_scene2', 239, 257, 'KING', 'The trumpet to the cannoneer without,'), ('hamlet_act5_scene2', 240, 258, 'KING', 'The cannons to the heavens, the heavens to earth,'), ('hamlet_act5_scene2', 241, 259, 'KING', '“Now the king drinks to Hamlet.” Come, begin:'), ('hamlet_act5_scene2', 242, 260, 'KING', 'And you, the judges, bear a wary eye.'), ('hamlet_act5_scene2', 243, 261, 'HAMLET', 'Come on, sir.'), ('hamlet_act5_scene2', 243, 262, 'LAERTES', 'Come, my lord.'), ('hamlet_act5_scene2', 244, 263, 'HAMLET', 'One.'), ('hamlet_act5_scene2', 244, 264, 'LAERTES', 'No.'), ('hamlet_act5_scene2', 245, 265, 'HAMLET', 'Judgment.'), ('hamlet_act5_scene2', 245, 266, 'OSRIC', 'A hit, a very palpable hit.'), ('hamlet_act5_scene2', 246, 267, 'LAERTES', 'Well; again.'), ('hamlet_act5_scene2', 247, 268, 'KING', 'Stay; give me drink. Hamlet, this pearl is thine;'), ('hamlet_act5_scene2', 248, 269, 'KING', 'Here’s to thy health. Give him the cup.'), ('hamlet_act5_scene2', 249, 270, 'HAMLET', 'I’ll play this bout first; set it by awhile. Come. Another hit; what say you?'), ('hamlet_act5_scene2', 250, 271, 'LAERTES', 'A touch, a touch, I do confess.'), ('hamlet_act5_scene2', 251, 272, 'KING', 'Our son shall win.'), ('hamlet_act5_scene2', 251, 273, 'QUEEN', 'He’s fat, and scant of breath.'), ('hamlet_act5_scene2', 252, 274, 'QUEEN', 'Here, Hamlet, take my napkin, rub thy brows:'), ('hamlet_act5_scene2', 253, 275, 'QUEEN', 'The queen carouses to thy fortune, Hamlet.'), ('hamlet_act5_scene2', 254, 276, 'HAMLET', 'Good madam!'), ('hamlet_act5_scene2', 254, 277, 'KING', 'Gertrude, do not drink.'), ('hamlet_act5_scene2', 255, 278, 'QUEEN', 'I will, my lord; I pray you, pardon me.'), ('hamlet_act5_scene2', 256, 279, 'KING', 'It is the poison’d cup: it is too late.'), ('hamlet_act5_scene2', 257, 280, 'HAMLET', 'I dare not drink yet, madam; by and by.'), ('hamlet_act5_scene2', 258, 281, 'QUEEN', 'Come, let me wipe thy face.'), ('hamlet_act5_scene2', 258, 282, 'LAERTES', 'My lord, I’ll hit him now.'), ('hamlet_act5_scene2', 259, 283, 'KING', 'I do not think’t.'), ('hamlet_act5_scene2', 260, 284, 'LAERTES', 'And yet ’tis almost ’gainst my conscience.'), ('hamlet_act5_scene2', 261, 285, 'HAMLET', 'Come, for the third, Laertes: you but dally;'), ('hamlet_act5_scene2', 262, 286, 'HAMLET', 'I pray you, pass with your best violence;'), ('hamlet_act5_scene2', 263, 287, 'HAMLET', 'I am afeard you make a wanton of me.'), ('hamlet_act5_scene2', 264, 288, 'LAERTES', 'Say you so? come on.'), ('hamlet_act5_scene2', 264, 289, 'OSRIC', 'Nothing, neither way.'), ('hamlet_act5_scene2', 265, 290, 'LAERTES', 'Have at you now!'), ('hamlet_act5_scene2', 265, 291, 'KING', 'Part them; they are incensed.'), ('hamlet_act5_scene2', 266, 292, 'HAMLET', 'Nay, come, again.'), ('hamlet_act5_scene2', 266, 293, 'OSRIC', 'Look to the queen there, ho!'), ('hamlet_act5_scene2', 267, 294, 'HORATIO', 'They bleed on both sides. How is it, my lord?'), ('hamlet_act5_scene2', 268, 295, 'OSRIC', 'How is’t, Laertes?'), ('hamlet_act5_scene2', 269, 296, 'LAERTES', 'Why, as a woodcock to mine own springe, Osric;'), ('hamlet_act5_scene2', 270, 297, 'LAERTES', 'I am justly kill’d with mine own treachery.'), ('hamlet_act5_scene2', 271, 298, 'HAMLET', 'How does the queen?'), ('hamlet_act5_scene2', 271, 299, 'KING', 'She swounds to see them bleed.');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene2', 272, 300, 'QUEEN', 'No, no, the drink, the drink—O my dear Hamlet—'), ('hamlet_act5_scene2', 273, 301, 'QUEEN', 'The drink, the drink! I am poison’d.'), ('hamlet_act5_scene2', 274, 302, 'HAMLET', 'O villany! Ho! let the door be lock’d:'), ('hamlet_act5_scene2', 275, 303, 'HAMLET', 'Treachery! Seek it out.'), ('hamlet_act5_scene2', 276, 304, 'LAERTES', 'It is here, Hamlet: Hamlet, thou art slain;'), ('hamlet_act5_scene2', 277, 305, 'LAERTES', 'No medicine in the world can do thee good;'), ('hamlet_act5_scene2', 278, 306, 'LAERTES', 'In thee there is not half an hour of life;'), ('hamlet_act5_scene2', 279, 307, 'LAERTES', 'The treacherous instrument is in thy hand,'), ('hamlet_act5_scene2', 280, 308, 'LAERTES', 'Unbated and envenom’d: the foul practice'), ('hamlet_act5_scene2', 281, 309, 'LAERTES', 'Hath turn’d itself on me; lo, here I lie,'), ('hamlet_act5_scene2', 282, 310, 'LAERTES', 'Never to rise again: thy mother’s poison’d:'), ('hamlet_act5_scene2', 283, 311, 'LAERTES', 'I can no more: the king, the king’s to blame.'), ('hamlet_act5_scene2', 284, 312, 'HAMLET', 'The point envenom’d too!'), ('hamlet_act5_scene2', 285, 313, 'HAMLET', 'Then, venom, to thy work.'), ('hamlet_act5_scene2', 285, 314, 'ALL', 'Treason! treason!'), ('hamlet_act5_scene2', 286, 315, 'KING', 'O, yet defend me, friends; I am but hurt.'), ('hamlet_act5_scene2', 287, 316, 'HAMLET', 'Here, thou incestuous, murderous, damned Dane,'), ('hamlet_act5_scene2', 288, 317, 'HAMLET', 'Drink off this potion. Is thy union here?'), ('hamlet_act5_scene2', 289, 318, 'HAMLET', 'Follow my mother.'), ('hamlet_act5_scene2', 289, 319, 'LAERTES', 'He is justly served;'), ('hamlet_act5_scene2', 290, 320, 'LAERTES', 'It is a poison temper’d by himself.'), ('hamlet_act5_scene2', 291, 321, 'LAERTES', 'Exchange forgiveness with me, noble Hamlet:'), ('hamlet_act5_scene2', 292, 322, 'LAERTES', 'Mine and my father’s death come not upon thee,'), ('hamlet_act5_scene2', 293, 323, 'LAERTES', 'Nor thine on me!'), ('hamlet_act5_scene2', 294, 324, 'HAMLET', 'Heaven make thee free of it! I follow thee.'), ('hamlet_act5_scene2', 295, 325, 'HAMLET', 'I am dead, Horatio. Wretched queen, adieu!'), ('hamlet_act5_scene2', 296, 326, 'HAMLET', 'You that look pale and tremble at this chance,'), ('hamlet_act5_scene2', 297, 327, 'HAMLET', 'That are but mutes or audience to this act,'), ('hamlet_act5_scene2', 298, 328, 'HAMLET', 'Had I but time—as this fell sergeant, death,'), ('hamlet_act5_scene2', 299, 329, 'HAMLET', 'Is strict in his arrest—O, I could tell you—'), ('hamlet_act5_scene2', 300, 330, 'HAMLET', 'But let it be. Horatio, I am dead;'), ('hamlet_act5_scene2', 301, 331, 'HAMLET', 'Thou livest; report me and my cause aright'), ('hamlet_act5_scene2', 302, 332, 'HAMLET', 'To the unsatisfied.'), ('hamlet_act5_scene2', 302, 333, 'HORATIO', 'Never believe it:'), ('hamlet_act5_scene2', 303, 334, 'HORATIO', 'I am more an antique Roman than a Dane:'), ('hamlet_act5_scene2', 304, 335, 'HORATIO', 'Here’s yet some liquor left.'), ('hamlet_act5_scene2', 304, 336, 'HAMLET', 'As thou’rt a man,'), ('hamlet_act5_scene2', 305, 337, 'HAMLET', 'Give me the cup: let go; by heaven, I’ll have’t.'), ('hamlet_act5_scene2', 306, 338, 'HAMLET', 'O good Horatio, what a wounded name,'), ('hamlet_act5_scene2', 307, 339, 'HAMLET', 'Things standing thus unknown, shall live behind me!'), ('hamlet_act5_scene2', 308, 340, 'HAMLET', 'If thou didst ever hold me in thy heart,'), ('hamlet_act5_scene2', 309, 341, 'HAMLET', 'Absent thee from felicity awhile,'), ('hamlet_act5_scene2', 310, 342, 'HAMLET', 'And in this harsh world draw thy breath in pain,'), ('hamlet_act5_scene2', 311, 343, 'HAMLET', 'To tell my story. What warlike noise is this?'), ('hamlet_act5_scene2', 312, 344, 'OSRIC', 'Young Fortinbras, with conquest come from Poland,'), ('hamlet_act5_scene2', 313, 345, 'OSRIC', 'To the ambassadors of England gives'), ('hamlet_act5_scene2', 314, 346, 'OSRIC', 'This warlike volley.'), ('hamlet_act5_scene2', 314, 347, 'HAMLET', 'O, I die, Horatio;'), ('hamlet_act5_scene2', 315, 348, 'HAMLET', 'The potent poison quite o’er-crows my spirit:'), ('hamlet_act5_scene2', 316, 349, 'HAMLET', 'I cannot live to hear the news from England;'), ('hamlet_act5_scene2', 317, 350, 'HAMLET', 'But I do prophesy the election lights'), ('hamlet_act5_scene2', 318, 351, 'HAMLET', 'On Fortinbras: he has my dying voice;'), ('hamlet_act5_scene2', 319, 352, 'HAMLET', 'So tell him, with the occurrents, more and less,'), ('hamlet_act5_scene2', 320, 353, 'HAMLET', 'Which have solicited. The rest is silence.'), ('hamlet_act5_scene2', 321, 354, 'HORATIO', 'Now cracks a noble heart. Good night, sweet prince;'), ('hamlet_act5_scene2', 322, 355, 'HORATIO', 'And flights of angels sing thee to thy rest!'), ('hamlet_act5_scene2', 323, 356, 'HORATIO', 'Why does the drum come hither?'), ('hamlet_act5_scene2', 323, 357, 'PRINCE FORTINBRAS', 'Where is this sight?'), ('hamlet_act5_scene2', 324, 358, 'HORATIO', 'What is it ye would see?'), ('hamlet_act5_scene2', 325, 359, 'HORATIO', 'If aught of woe or wonder, cease your search.'), ('hamlet_act5_scene2', 326, 360, 'PRINCE FORTINBRAS', 'This quarry cries on havoc. O proud death,'), ('hamlet_act5_scene2', 327, 361, 'PRINCE FORTINBRAS', 'What feast is toward in thine eternal cell,'), ('hamlet_act5_scene2', 328, 362, 'PRINCE FORTINBRAS', 'That thou so many princes at a shot'), ('hamlet_act5_scene2', 329, 363, 'PRINCE FORTINBRAS', 'So bloodily hast struck?'), ('hamlet_act5_scene2', 329, 364, 'FIRST AMBASSADOR', 'The sight is dismal;'), ('hamlet_act5_scene2', 330, 365, 'FIRST AMBASSADOR', 'And our affairs from England come too late:'), ('hamlet_act5_scene2', 331, 366, 'FIRST AMBASSADOR', 'The ears are senseless that should give us hearing,'), ('hamlet_act5_scene2', 332, 367, 'FIRST AMBASSADOR', 'To tell him his commandment is fulfill’d,'), ('hamlet_act5_scene2', 333, 368, 'FIRST AMBASSADOR', 'That Rosencrantz and Guildenstern are dead:'), ('hamlet_act5_scene2', 334, 369, 'FIRST AMBASSADOR', 'Where should we have our thanks?'), ('hamlet_act5_scene2', 334, 370, 'HORATIO', 'Not from his mouth,'), ('hamlet_act5_scene2', 335, 371, 'HORATIO', 'Had it the ability of life to thank you:'), ('hamlet_act5_scene2', 336, 372, 'HORATIO', 'He never gave commandment for their death.'), ('hamlet_act5_scene2', 337, 373, 'HORATIO', 'But since, so jump upon this bloody question,'), ('hamlet_act5_scene2', 338, 374, 'HORATIO', 'You from the Polack wars, and you from England,'), ('hamlet_act5_scene2', 339, 375, 'HORATIO', 'Are here arrived give order that these bodies'), ('hamlet_act5_scene2', 340, 376, 'HORATIO', 'High on a stage be placed to the view;'), ('hamlet_act5_scene2', 341, 377, 'HORATIO', 'And let me speak to the yet unknowing world'), ('hamlet_act5_scene2', 342, 378, 'HORATIO', 'How these things came about: so shall you hear'), ('hamlet_act5_scene2', 343, 379, 'HORATIO', 'Of carnal, bloody, and unnatural acts,'), ('hamlet_act5_scene2', 344, 380, 'HORATIO', 'Of accidental judgments, casual slaughters,'), ('hamlet_act5_scene2', 345, 381, 'HORATIO', 'Of deaths put on by cunning and forced cause,'), ('hamlet_act5_scene2', 346, 382, 'HORATIO', 'And, in this upshot, purposes mistook'), ('hamlet_act5_scene2', 347, 383, 'HORATIO', 'Fall’n on the inventors’ heads: all this can I'), ('hamlet_act5_scene2', 348, 384, 'HORATIO', 'Truly deliver.'), ('hamlet_act5_scene2', 348, 385, 'PRINCE FORTINBRAS', 'Let us haste to hear it,'), ('hamlet_act5_scene2', 349, 386, 'PRINCE FORTINBRAS', 'And call the noblest to the audience.'), ('hamlet_act5_scene2', 350, 387, 'PRINCE FORTINBRAS', 'For me, with sorrow I embrace my fortune:'), ('hamlet_act5_scene2', 351, 388, 'PRINCE FORTINBRAS', 'I have some rights of memory in this kingdom,'), ('hamlet_act5_scene2', 352, 389, 'PRINCE FORTINBRAS', 'Which now to claim my vantage doth invite me.'), ('hamlet_act5_scene2', 353, 390, 'HORATIO', 'Of that I shall have also cause to speak,'), ('hamlet_act5_scene2', 354, 391, 'HORATIO', 'And from his mouth whose voice will draw on more:'), ('hamlet_act5_scene2', 355, 392, 'HORATIO', 'But let this same be presently perform’d,'), ('hamlet_act5_scene2', 356, 393, 'HORATIO', 'Even while men’s minds are wild; lest more mischance,'), ('hamlet_act5_scene2', 357, 394, 'HORATIO', 'On plots and errors, happen.'), ('hamlet_act5_scene2', 357, 395, 'PRINCE FORTINBRAS', 'Let four captains'), ('hamlet_act5_scene2', 358, 396, 'PRINCE FORTINBRAS', 'Bear Hamlet, like a soldier, to the stage;'), ('hamlet_act5_scene2', 359, 397, 'PRINCE FORTINBRAS', 'For he was likely, had he been put on,'), ('hamlet_act5_scene2', 360, 398, 'PRINCE FORTINBRAS', 'To have proved most royally: and, for his passage,'), ('hamlet_act5_scene2', 361, 399, 'PRINCE FORTINBRAS', 'The soldiers’ music and the rites of war');
INSERT INTO lines (section_id, number, array_index, speaker, text) VALUES ('hamlet_act5_scene2', 362, 400, 'PRINCE FORTINBRAS', 'Speak loudly for him.'), ('hamlet_act5_scene2', 363, 401, 'PRINCE FORTINBRAS', 'Take up the bodies: such a sight as this'), ('hamlet_act5_scene2', 364, 402, 'PRINCE FORTINBRAS', 'Becomes the field, but here shows much amiss.'), ('hamlet_act5_scene2', 365, 403, 'PRINCE FORTINBRAS', 'Go, bid the soldiers shoot.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act1_scene1', 0, 'Francisco at his post. Enter to him Bernardo.'), ('hamlet_act1_scene1', 12, 'Enter Horatio and Marcellus.'), ('hamlet_act1_scene1', 16, 'Exit.'), ('hamlet_act1_scene1', 37, 'Enter Ghost.'), ('hamlet_act1_scene1', 49, 'Exit Ghost.'), ('hamlet_act1_scene1', 124, 'Reenter Ghost.'), ('hamlet_act1_scene1', 124, 'I’ll cross it, though it blast me. Stay, illusion! If thou hast any sound, or use of voice, Speak to me: If there be any good thing to be done, That may to thee do ease and grace to me, Speak to me: Cock crows. If thou art privy to thy country’s fate, Which, happily, foreknowing may avoid, O, speak! Or if thou hast uphoarded in thy life Extorted treasure in the womb of earth, For which, they say, you spirits oft walk in death, Speak of it: stay, and speak! Stop it, Marcellus.'), ('hamlet_act1_scene1', 127, 'Exit Ghost.'), ('hamlet_act1_scene1', 160, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act1_scene2', 0, 'Enter King, Queen, Hamlet, Polonius, Laertes, Voltimand, Cornelius, Lords, and Attendants.'), ('hamlet_act1_scene2', 41, 'Exeunt Voltimand and Cornelius.'), ('hamlet_act1_scene2', 65, 'Aside.'), ('hamlet_act1_scene2', 128, 'Exeunt all but Hamlet.'), ('hamlet_act1_scene2', 159, 'Enter Horatio, Marcellus, and Bernardo.'), ('hamlet_act1_scene2', 251, 'Exeunt all but Hamlet.'), ('hamlet_act1_scene2', 255, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act1_scene3', 0, 'Enter Laertes and Ophelia.'), ('hamlet_act1_scene3', 53, 'Enter Polonius.'), ('hamlet_act1_scene3', 53, 'A double blessing is a double grace; Occasion smiles upon a second leave.'), ('hamlet_act1_scene3', 86, 'Exit.'), ('hamlet_act1_scene3', 135, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act1_scene4', 0, 'Enter Hamlet, Horatio, and Marcellus.'), ('hamlet_act1_scene4', 6, 'A flourish of trumpets, and ordnance shot off, within.'), ('hamlet_act1_scene4', 38, 'Enter Ghost.'), ('hamlet_act1_scene4', 57, 'Ghost beckons Hamlet.'), ('hamlet_act1_scene4', 86, 'Exeunt Ghost and Hamlet.'), ('hamlet_act1_scene4', 91, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act1_scene5', 0, 'Enter Ghost and Hamlet.'), ('hamlet_act1_scene5', 90, 'Exit.'), ('hamlet_act1_scene5', 108, 'Writing.'), ('hamlet_act1_scene5', 111, 'Within.'), ('hamlet_act1_scene5', 112, 'Within.'), ('hamlet_act1_scene5', 112, 'Within.'), ('hamlet_act1_scene5', 113, 'Within.'), ('hamlet_act1_scene5', 114, 'Enter Horatio and Marcellus.'), ('hamlet_act1_scene5', 147, 'Beneath.'), ('hamlet_act1_scene5', 152, 'Beneath.'), ('hamlet_act1_scene5', 153, 'Hic et ubique?'), ('hamlet_act1_scene5', 157, 'Beneath.'), ('hamlet_act1_scene5', 177, 'Beneath.'), ('hamlet_act1_scene5', 178, 'They swear.'), ('hamlet_act1_scene5', 186, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act2_scene1', 0, 'Enter Polonius and Reynaldo.'), ('hamlet_act2_scene1', 71, 'Exit Reynaldo.'), ('hamlet_act2_scene1', 71, 'Enter Ophelia.'), ('hamlet_act2_scene1', 71, 'How now, Ophelia! what’s the matter?'), ('hamlet_act2_scene1', 116, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act2_scene2', 0, 'Enter King, Queen, Rosencrantz, Guildenstern, and Attendants.'), ('hamlet_act2_scene2', 38, 'Exeunt Rosencrantz, Guildenstern, and some Attendants.'), ('hamlet_act2_scene2', 38, 'Enter Polonius.'), ('hamlet_act2_scene2', 52, 'Exit Polonius.'), ('hamlet_act2_scene2', 57, 'Reenter Polonius, with Voltimand and Cornelius.'), ('hamlet_act2_scene2', 57, 'Welcome, my good friends! Say, Voltimand, what from our brother Norway?'), ('hamlet_act2_scene2', 74, 'Giving a paper.'), ('hamlet_act2_scene2', 83, 'Exeunt Voltimand and Cornelius.'), ('hamlet_act2_scene2', 105, 'Reads.'), ('hamlet_act2_scene2', 105, 'Reads.'), ('hamlet_act2_scene2', 114, 'Reads.'), ('hamlet_act2_scene2', 142, 'Pointing to his head and shoulder.'), ('hamlet_act2_scene2', 156, 'Exeunt King, Queen, and Attendants.'), ('hamlet_act2_scene2', 156, 'Enter Hamlet, reading.'), ('hamlet_act2_scene2', 156, 'O, give me leave: How does my good Lord Hamlet?'), ('hamlet_act2_scene2', 172, 'Aside.'), ('hamlet_act2_scene2', 183, 'Aside.'), ('hamlet_act2_scene2', 188, 'Aside.'), ('hamlet_act2_scene2', 191, 'Enter Rosencrantz and Guildenstern.'), ('hamlet_act2_scene2', 193, 'To Polonius.'), ('hamlet_act2_scene2', 193, 'Exit Polonius.'), ('hamlet_act2_scene2', 246, 'Aside to Guildenstern.'), ('hamlet_act2_scene2', 247, 'Aside.'), ('hamlet_act2_scene2', 303, 'Flourish of trumpets within.'), ('hamlet_act2_scene2', 311, 'Reenter Polonius.'), ('hamlet_act2_scene2', 330, 'Aside.'), ('hamlet_act2_scene2', 337, 'Enter four or five Players.'), ('hamlet_act2_scene2', 337, 'You are welcome, masters; welcome, all. I am glad to see thee well. Welcome, good friends. O, my old friend! thy face is valanced since I saw thee last: comest thou to beard me in Denmark? What, my young lady and mistress! By’r lady, your ladyship is nearer to heaven than when I saw you last, by the altitude of a chopine. Pray God, your voice, like apiece of uncurrent gold, be not cracked within the ring. Masters, you are all welcome. We’ll e’en to’t like French falconers, fly at any thing we see: we’ll have a speech straight: come, give us a taste of your quality; come, a passionate speech.'), ('hamlet_act2_scene2', 409, 'Exit Polonius with all the Players but the First.'), ('hamlet_act2_scene2', 415, 'Exit First Player.'), ('hamlet_act2_scene2', 417, 'Exeunt Rosencrantz and Guildenstern.'), ('hamlet_act2_scene2', 476, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act3_scene1', 0, 'Enter King, Queen, Polonius, Ophelia, Rosencrantz, and Guildenstern.'), ('hamlet_act3_scene1', 28, 'Exeunt Rosencrantz and Guildenstern.'), ('hamlet_act3_scene1', 42, 'Exit Queen.'), ('hamlet_act3_scene1', 44, 'To Ophelia.'), ('hamlet_act3_scene1', 49, 'Aside.'), ('hamlet_act3_scene1', 55, 'Exeunt King and Polonius.'), ('hamlet_act3_scene1', 55, 'Enter Hamlet.'), ('hamlet_act3_scene1', 140, 'Exit.'), ('hamlet_act3_scene1', 152, 'Reenter King and Polonius.'), ('hamlet_act3_scene1', 179, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act3_scene2', 0, 'Enter Hamlet and Players.'), ('hamlet_act3_scene2', 36, 'Exeunt Players.'), ('hamlet_act3_scene2', 36, 'Enter Polonius, Rosencrantz, and Guildenstern.'), ('hamlet_act3_scene2', 36, 'How now, my lord! I will the king hear this piece of work?'), ('hamlet_act3_scene2', 38, 'Exit Polonius.'), ('hamlet_act3_scene2', 39, 'Exeunt Rosencrantz and Guildenstern.'), ('hamlet_act3_scene2', 39, 'Enter Horatio.'), ('hamlet_act3_scene2', 78, 'Danish march. A flourish. Enter King, Queen, Polonius, Ophelia, Rosencrantz, Guildenstern, and others.'), ('hamlet_act3_scene2', 82, 'To Polonius.'), ('hamlet_act3_scene2', 91, 'To the King.'), ('hamlet_act3_scene2', 92, 'Lying down at Ophelia’s feet.'), ('hamlet_act3_scene2', 111, 'Hautboys play. The dumb-show enters.'), ('hamlet_act3_scene2', 111, 'Enter a King and a Queen very lovingly; the Queen embracing him, and he her. She kneels, and makes show of protestation unto him. He takes her up, and declines his head upon her neck: lays him down upon a bank of flowers: she, seeing him asleep, leaves him. Anon comes in a fellow, takes off his crown, kisses it, and pours poison in the King’s ears, and exit. The Queen returns; finds the King dead, and makes passionate action. The Poisoner, with some two or three Mutes, comes in again, seeming to lament with her. The dead body is carried away. The Poisoner wooes the Queen with gifts: she seems loath and unwilling awhile, but in the end accepts his love. Exeunt.'), ('hamlet_act3_scene2', 114, 'Enter Prologue.'), ('hamlet_act3_scene2', 122, 'Exit.'), ('hamlet_act3_scene2', 124, 'Enter two Players, King and Queen.'), ('hamlet_act3_scene2', 151, 'Aside.'), ('hamlet_act3_scene2', 196, 'Sleeps.'), ('hamlet_act3_scene2', 197, 'Exit.'), ('hamlet_act3_scene2', 208, 'Enter Lucianus.'), ('hamlet_act3_scene2', 208, 'This is one Lucianus, nephew to the king.'), ('hamlet_act3_scene2', 221, 'Pours the poison into the sleeper’s ears.'), ('hamlet_act3_scene2', 227, 'Exeunt all but Hamlet and Horatio.'), ('hamlet_act3_scene2', 243, 'Reenter Rosencrantz and Guildenstern.'), ('hamlet_act3_scene2', 277, 'Reenter Players with recorders.'), ('hamlet_act3_scene2', 277, 'O, the recorders! let me see one. To withdraw with you:—why do you go about to recover the wind of me, as if you would drive me into a toil?'), ('hamlet_act3_scene2', 294, 'Enter Polonius.'), ('hamlet_act3_scene2', 294, 'God bless you, sir!'), ('hamlet_act3_scene2', 303, 'Exit Polonius.'), ('hamlet_act3_scene2', 303, 'Exeunt all but Hamlet.'), ('hamlet_act3_scene2', 315, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act3_scene3', 0, 'Enter King, Rosencrantz, and Guildenstern.'), ('hamlet_act3_scene3', 26, 'Exeunt Rosencrantz and Guildenstern.'), ('hamlet_act3_scene3', 26, 'Enter Polonius.'), ('hamlet_act3_scene3', 35, 'Exit Polonius.'), ('hamlet_act3_scene3', 72, 'Retires and kneels.'), ('hamlet_act3_scene3', 72, 'Enter Hamlet.'), ('hamlet_act3_scene3', 96, 'Exit.'), ('hamlet_act3_scene3', 97, 'Rising.'), ('hamlet_act3_scene3', 98, 'Exit.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act3_scene4', 0, 'Enter Queen and Polonius.'), ('hamlet_act3_scene4', 5, 'Within.'), ('hamlet_act3_scene4', 7, 'Polonius hides behind the arras.'), ('hamlet_act3_scene4', 7, 'Enter Hamlet.'), ('hamlet_act3_scene4', 22, 'Behind.'), ('hamlet_act3_scene4', 23, 'Drawing.'), ('hamlet_act3_scene4', 23, 'Makes a pass through the arras.'), ('hamlet_act3_scene4', 24, 'Behind.'), ('hamlet_act3_scene4', 24, 'Falls and dies.'), ('hamlet_act3_scene4', 30, 'Lifts up the arras and discovers Polonius.'), ('hamlet_act3_scene4', 102, 'Enter Ghost.'), ('hamlet_act3_scene4', 102, 'Save me, and hover o’er me with your wings, You heavenly guards! What would your gracious figure?'), ('hamlet_act3_scene4', 132, 'Exit Ghost.'), ('hamlet_act3_scene4', 168, 'Pointing to Polonius.'), ('hamlet_act3_scene4', 214, 'Exeunt severally; Hamlet dragging in Polonius.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act4_scene1', 0, 'Enter King, Queen, Rosencrantz, and Guildenstern.'), ('hamlet_act4_scene1', 4, 'Exeunt Rosencrantz and Guildenstern.'), ('hamlet_act4_scene1', 32, 'Reenter Rosencrantz and Guildenstern.'), ('hamlet_act4_scene1', 32, 'Friends both, go join you with some further aid: Hamlet in madness hath Polonius slain, And from his mother’s closet hath he dragg’d him: Go seek him out; speak fair, and bring the body Into the chapel. I pray you, haste in this. Exeunt Rosencrantz and Guildenstern. Come, Gertrude, we’ll call up our wisest friends; And let them know, both what we mean to do, And what’s untimely done. So haply slander—2 Whose whisper o’er the world’s diameter, As level as the canon to his blank, Transports his poison’d shot, may miss our name, And hit the woundless air. O, come away! My soul is full of discord and dismay. Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act4_scene2', 0, 'Enter Hamlet.'), ('hamlet_act4_scene2', 1, 'Within.'), ('hamlet_act4_scene2', 2, 'Enter Rosencrantz and Guildenstern.'), ('hamlet_act4_scene2', 24, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act4_scene3', 0, 'Enter King, attended.'), ('hamlet_act4_scene3', 11, 'Enter Rosencrantz.'), ('hamlet_act4_scene3', 11, 'How now! what hath befall’n?'), ('hamlet_act4_scene3', 15, 'Enter Hamlet and Guildenstern.'), ('hamlet_act4_scene3', 33, 'To some Attendants.'), ('hamlet_act4_scene3', 33, 'Exeunt Attendants.'), ('hamlet_act4_scene3', 46, 'Exit.'), ('hamlet_act4_scene3', 50, 'Exeunt Rosencrantz and Guildenstern.'), ('hamlet_act4_scene3', 61, 'Exit.');
