INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act4_scene5', 0, 'Enter Queen, Horatio, and a Gentleman.'), ('hamlet_act4_scene5', 14, 'Exit Horatio.'), ('hamlet_act4_scene5', 18, 'Reenter Horatio, with Ophelia.'), ('hamlet_act4_scene5', 22, 'Sings.'), ('hamlet_act4_scene5', 26, 'Sings.'), ('hamlet_act4_scene5', 27, 'Sings.'), ('hamlet_act4_scene5', 27, 'Enter King.'), ('hamlet_act4_scene5', 29, 'Sings.'), ('hamlet_act4_scene5', 39, 'Sings.'), ('hamlet_act4_scene5', 45, 'Sings.'), ('hamlet_act4_scene5', 50, 'Exit.'), ('hamlet_act4_scene5', 51, 'Exit Horatio.'), ('hamlet_act4_scene5', 72, 'A noise within.'), ('hamlet_act4_scene5', 73, 'Enter another Gentleman.'), ('hamlet_act4_scene5', 73, 'What is the matter?'), ('hamlet_act4_scene5', 87, 'Noise within.'), ('hamlet_act4_scene5', 87, 'Enter Laertes, armed; Danes following.'), ('hamlet_act4_scene5', 90, 'They retire without the door.'), ('hamlet_act4_scene5', 128, 'Within.'), ('hamlet_act4_scene5', 129, 'Reenter Ophelia.'), ('hamlet_act4_scene5', 129, 'O heat, dry up my brains! tears seven times salt, Burn out the sense and virtue of mine eye! By heaven, thy madness shall be paid by weight, Till our scale turn the beam. O rose of May! Dear maid, kind sister, sweet Ophelia! O heavens! is’t possible, a young maid’s wits Should be as moral as an old man’s life? Nature is fine in love, and where ’tis fine, It sends some precious instance of itself After the thing it loves.'), ('hamlet_act4_scene5', 132, 'Sings.'), ('hamlet_act4_scene5', 137, 'Sings.'), ('hamlet_act4_scene5', 145, 'Sings.'), ('hamlet_act4_scene5', 152, 'Sings.'), ('hamlet_act4_scene5', 152, 'Exit.'), ('hamlet_act4_scene5', 171, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act4_scene6', 0, 'Enter Horatio and a Servant.'), ('hamlet_act4_scene6', 4, 'Exit Servant.'), ('hamlet_act4_scene6', 4, 'Enter Sailors.'), ('hamlet_act4_scene6', 25, 'Reads.'), ('hamlet_act4_scene6', 25, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act4_scene7', 0, 'Enter King and Laertes.'), ('hamlet_act4_scene7', 35, 'Enter a Messenger.'), ('hamlet_act4_scene7', 35, 'How now! what news?'), ('hamlet_act4_scene7', 47, 'Exit Messenger.'), ('hamlet_act4_scene7', 47, 'Reads.'), ('hamlet_act4_scene7', 159, 'Enter Queen.'), ('hamlet_act4_scene7', 159, 'How now, sweet queen!'), ('hamlet_act4_scene7', 188, 'Exit.'), ('hamlet_act4_scene7', 191, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act5_scene1', 0, 'Enter two Clowns, with spades, etc.'), ('hamlet_act5_scene1', 39, 'Enter Hamlet and Horatio, at a distance.'), ('hamlet_act5_scene1', 46, 'Exit Second Clown.'), ('hamlet_act5_scene1', 46, 'He digs and sings.'), ('hamlet_act5_scene1', 52, 'Sings.'), ('hamlet_act5_scene1', 52, 'Throws up a skull.'), ('hamlet_act5_scene1', 68, 'Sings.'), ('hamlet_act5_scene1', 68, 'Throws up another skull.'), ('hamlet_act5_scene1', 87, 'Sings.'), ('hamlet_act5_scene1', 145, 'Takes the skull.'), ('hamlet_act5_scene1', 147, 'Puts down the skull.'), ('hamlet_act5_scene1', 161, 'Enter Priests, etc. in procession; the Corpse of Ophelia, Laertes and Mourners following; King, Queen, their trains, etc.'), ('hamlet_act5_scene1', 161, 'The queen, the courtiers: who is this they follow? And with such maimed rites? This doth betoken The corse they follow did with desperate hand Fordo its own life: ’twas of some estate. Couch we awhile, and mark. Retiring with Horatio.'), ('hamlet_act5_scene1', 181, 'Scattering flowers.'), ('hamlet_act5_scene1', 188, 'Leaps into the grave.'), ('hamlet_act5_scene1', 192, 'Advancing.'), ('hamlet_act5_scene1', 196, 'Leaps into the grave.'), ('hamlet_act5_scene1', 196, 'Grappling with him.'), ('hamlet_act5_scene1', 203, 'The Attendants part them, and they come out of the grave.'), ('hamlet_act5_scene1', 228, 'Exit.'), ('hamlet_act5_scene1', 229, 'Exit Horatio.'), ('hamlet_act5_scene1', 230, 'To Laertes.'), ('hamlet_act5_scene1', 235, 'Exeunt.');
INSERT INTO stage_directions (section_id, after_line, text) VALUES ('hamlet_act5_scene2', 0, 'Enter Hamlet and Horatio.'), ('hamlet_act5_scene2', 77, 'Enter Osric.'), ('hamlet_act5_scene2', 96, 'Hamlet moves him to put on his hat.'), ('hamlet_act5_scene2', 154, 'Exit Osric.'), ('hamlet_act5_scene2', 161, 'Enter a Lord.'), ('hamlet_act5_scene2', 172, 'Exit Lord.'), ('hamlet_act5_scene2', 187, 'Enter King, Queen, Laertes, Lords, Osric, and Attendants with foils, etc.'), ('hamlet_act5_scene2', 188, 'The King puts Laertes’ hand into Hamlet’s.'), ('hamlet_act5_scene2', 228, 'They prepare to play.'), ('hamlet_act5_scene2', 243, 'They play.'), ('hamlet_act5_scene2', 248, 'Trumpets sound, and cannon shot off within.'), ('hamlet_act5_scene2', 249, 'They play.'), ('hamlet_act5_scene2', 256, 'Aside.'), ('hamlet_act5_scene2', 260, 'Aside.'), ('hamlet_act5_scene2', 264, 'They play.'), ('hamlet_act5_scene2', 265, 'Laertes wounds Hamlet; then, in scuffling, they change rapiers, and Hamlet wounds Laertes.'), ('hamlet_act5_scene2', 266, 'The Queen falls.'), ('hamlet_act5_scene2', 273, 'Dies.'), ('hamlet_act5_scene2', 285, 'Stabs the King.'), ('hamlet_act5_scene2', 289, 'King dies.'), ('hamlet_act5_scene2', 293, 'Dies.'), ('hamlet_act5_scene2', 311, 'March afar off, and shot within.'), ('hamlet_act5_scene2', 320, 'Dies.'), ('hamlet_act5_scene2', 323, 'March within.'), ('hamlet_act5_scene2', 323, 'Enter Fortinbras, the English Ambassadors, and others.'), ('hamlet_act5_scene2', 365, 'A dead march. Exeunt, bearing off the dead bodies; after which a peal of ordnance is shot off.');
INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('hamlet_act1_scene1_gloss1', 'hamlet_act1_scene1', 2, 'unfold yourself', 'reveal your identity'), ('hamlet_act1_scene1_gloss2', 'hamlet_act1_scene1', 9, 'rivals of my watch', 'partners sharing my watch-duty'), ('hamlet_act1_scene1_gloss3', 'hamlet_act1_scene1', 11, 'liegemen to the Dane', 'loyal subjects to the King of Denmark'), ('hamlet_act1_scene1_gloss4', 'hamlet_act1_scene1', 15, 'this relief', 'this change of guard'), ('hamlet_act1_scene1_gloss5', 'hamlet_act1_scene1', 15, 'sore', 'bitterly; intensely'), ('hamlet_act1_scene1_gloss6', 'hamlet_act1_scene1', 17, 'this thing', 'the ghost (a cautious, non-committal phrase)'), ('hamlet_act1_scene1_gloss7', 'hamlet_act1_scene1', 21, 'fantasy', 'imagination; delusion'), ('hamlet_act1_scene1_gloss8', 'hamlet_act1_scene1', 22, 'dreaded sight', 'feared apparition'), ('hamlet_act1_scene1_gloss9', 'hamlet_act1_scene1', 23, 'approve our eyes', 'confirm what our eyes have seen'), ('hamlet_act1_scene1_gloss10', 'hamlet_act1_scene1', 24, 'speak to it', 'address the ghost (necessary to learn its purpose)'), ('hamlet_act1_scene1_gloss11', 'hamlet_act1_scene1', 29, 'assail your ears', 'attack (surprise) your ears with our tale'), ('hamlet_act1_scene1_gloss12', 'hamlet_act1_scene1', 30, 'fortified', 'guarded; made resistant'), ('hamlet_act1_scene1_gloss13', 'hamlet_act1_scene1', 33, 'yond same star', 'that same star over there'), ('hamlet_act1_scene1_gloss14', 'hamlet_act1_scene1', 40, 'thou art a scholar', 'you are educated (scholars knew Latin, the tongue for addressing spirits)'), ('hamlet_act1_scene1_gloss15', 'hamlet_act1_scene1', 41, 'speak to it, Horatio', 'address the ghost (Horatio''s Latin learning makes him fit)'), ('hamlet_act1_scene1_gloss16', 'hamlet_act1_scene1', 43, 'harrows me with fear', 'agitates me deeply; rends me'), ('hamlet_act1_scene1_gloss17', 'hamlet_act1_scene1', 46, 'usurp’st this time of night', 'wrongfully take over the night hours