INSERT INTO glosses (id, section_id, line, phrase, definition) VALUES ('hamlet_act5_scene2_gloss101', 'hamlet_act5_scene2', 365, 'dismal', 'ill-fated'), ('hamlet_act5_scene2_gloss102', 'hamlet_act5_scene2', 371, 'unknowing', 'ignorant of'), ('hamlet_act5_scene2_gloss103', 'hamlet_act5_scene2', 377, 'carnal, bloody, and unnatural acts', 'lustful, murderous, and unnatural deeds'), ('hamlet_act5_scene2_gloss104', 'hamlet_act5_scene2', 378, 'casual slaughters', 'slaughters by chance'), ('hamlet_act5_scene2_gloss105', 'hamlet_act5_scene2', 379, 'purposes mistook fall''n on the inventors'' heads', 'schemes that rebounded on their schemers'), ('hamlet_act5_scene2_gloss106', 'hamlet_act5_scene2', 386, 'rights of memory in this kingdom', 'remembered claims to this kingdom'), ('hamlet_act5_scene2_gloss107', 'hamlet_act5_scene2', 390, 'put on', 'advanced to'), ('hamlet_act5_scene2_gloss108', 'hamlet_act5_scene2', 391, 'soldier''s music', 'military funeral music'), ('hamlet_act5_scene2_gloss109', 'hamlet_act5_scene2', 392, 'field', 'battlefield');
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act1_scene1_ann1', 'hamlet_act1_scene1', 1, 12, 'Hamlet 1.1.1–12', 'structural', 'The exchange that opens a tragedy', 'Shakespeare begins not with a king or a murder but with two frightened sentries challenging each other in the dark. The first line — ''Who''s there?'' — is the question the entire play will ask of ghosts, of fathers, of the self. Critics since Maynard Mack have noted that Hamlet is built on a structure of interrogation: every major scene poses a question and refuses an easy answer. The sentries'' midnight, bitter-cold, and ''sick at heart'' place us immediately in a world where something has gone wrong before the play began. This is the formal opposite of Shakespeare''s comedies, which typically begin at court in daylight with a stated problem to be solved.', ARRAY['Maynard Mack, ''The World of Hamlet'' (1952)']::TEXT[]), ('hamlet_act1_scene1_ann2', 'hamlet_act1_scene1', 37, 70, 'Hamlet 1.1.37–70', 'historical', 'Armed ghosts and Elizabethan belief', 'Horatio is called to speak to the ghost because he is ''a scholar'' — in Elizabethan belief, Latin was the language that bound or banished spirits, and only educated men knew it. The ghost appears in full armor, ''cap-a-pe,'' which was the convention of revenant kings: the armor that killed the rival Fortinbras is the armor the ghost wears. The Protestant reforms had officially abolished purgatory, and with it the theological place from which a ghost could lawfully return. Belief persisted, however, and Elizabethan accounts distinguished between holy spirits (truthful), damned goblins (lying), and hallucinations (worthless). The question ''Is thy soul damned?'' will organize the first three acts.', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)','Keith Thomas, Religion and the Decline of Magic (1971)']::TEXT[]), ('hamlet_act1_scene1_ann3', 'hamlet_act1_scene1', 79, 107, 'Hamlet 1.1.79–107', 'historical', 'The political backstory and Fortinbras', 'Horatio''s long speech establishes the political frame: old Hamlet once killed old Fortinbras in single combat over territory, gaining lands for Denmark; now young Fortinbras is mustering an army to reclaim them. The audience will not meet Fortinbras until Act 4, but he shadows every scene — the son who acts decisively to avenge his father, against whom Hamlet is implicitly measured. The ''seal''d compact, well ratified by law and heraldry'' signals that Shakespeare''s Denmark observes chivalric rules; Claudius''s later murder by poison is thus doubly monstrous, not just fratricide but a violation of the code that gave his predecessor his crown.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act1_scene1_ann4', 'hamlet_act1_scene1', 108, 125, 'Hamlet 1.1.108–125', 'thematic', 'The Roman auspices and a world out of joint', 'Horatio invokes the portents before Julius Caesar''s assassination — graves opening, comets, the moon eclipsed — to suggest that the ghost is such a warning for Denmark. The comparison is precise: both kings were killed by men close to them; both murders ushered in civil catastrophe; both produced sons who delayed their revenge. Shakespeare had staged Julius Caesar the year before Hamlet (1599), and audiences would hear the echo. The image of the dead returning as omens of political collapse sits at the heart of both plays: private crimes become public signs, and the state begins to hemorrhage meaning.', ARRAY['Jonathan Bate, Soul of the Age (2008)']::TEXT[]), ('hamlet_act1_scene1_ann5', 'hamlet_act1_scene1', 158, 165, 'Hamlet 1.1.158–165', 'historical', 'The ''season wherein our Saviour''s birth is celebrated''', 'Marcellus''s lines about Christmas driving away spirits preserve a pre-Reformation folk belief that Shakespeare''s audience still half-held. The speech''s beauty — ''no spirit dare stir abroad'' — is also its theological retreat: Horatio replies ''in part I do believe it,'' registering the Protestant intellectual''s partial dissent. Shakespeare places this devotional lyric just before daybreak, allowing the scene''s dread to thin into tenderness. The tonal shift prepares the audience for Hamlet''s more skeptical voice in the following scene, and for the play''s unresolved tension between a Catholic cosmology that gives the ghost meaning and a Protestant one that would deny it.', ARRAY['Stephen Greenblatt, Will in the World (2004)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act1_scene2_ann1', 'hamlet_act1_scene2', 1, 16, 'Hamlet 1.2.1–16', 'thematic', 'The rhetoric of the usurper', 'Claudius''s opening speech is a masterclass in calculated balance: ''mirth in funeral,'' ''dirge in marriage,'' ''defeated joy,'' ''auspicious and a dropping eye.'' The rhetorical figure is oxymoron, and its density signals a speaker who needs language to do what his position cannot — reconcile mourning with celebration, legitimacy with haste. Elizabethan audiences would have heard a voice that sounds a great deal like their own Queen''s accession speeches. What they would also have heard, and what Hamlet will later name, is that rhetorical poise functions here as concealment. The play''s opening human voice is the voice of successful dissembling.', ARRAY['Harry Berger Jr., Imaginary Audition (1989)']::TEXT[]), ('hamlet_act1_scene2_ann2', 'hamlet_act1_scene2', 64, 74, 'Hamlet 1.2.64–74', 'linguistic', '''A little more than kin, and less than kind''', 'Hamlet''s first line in the play is a pun that turns three times. ''Kin'' means ''related,'' now intensified by the incestuous marriage. ''Kind'' means both ''natural'' (he is too close in blood) and ''affectionate'' (he feels nothing like it for Claudius). Beneath both runs the Old English sense of ''kind'' as species or race: Claudius is not of Hamlet''s kind. The line establishes a verbal strategy Hamlet will use for five acts: turning the simplest words against those who use them. When Claudius calls him ''son,'' Hamlet hears ''sun''; when the King asks about his melancholy, Hamlet punctures ''seems'' with ''I know not seems.'' Wordplay is weaponry here, because open speech would be suicidal.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]), ('hamlet_act1_scene2_ann3', 'hamlet_act1_scene2', 129, 159, 'Hamlet 1.2.129–159', 'thematic', 'The first soliloquy: the problem of the remarriage', 'Hamlet''s first soliloquy grieves less for his father than for his mother. ''Frailty, thy name is woman'' is not a general philosophical claim but a specific accusation: Gertrude''s ''most wicked speed'' has poisoned the mourning. The speech moves through classical analogies — Hyperion to a satyr, Niobe all tears — and arrives at the unspeakable: ''incestuous sheets.'' Elizabethan canon law did forbid marriage to a deceased brother''s wife; Henry VIII''s divorce from Catherine of Aragon had turned precisely on this point, and Shakespeare''s audience would recognize the charge. What drives the soliloquy is not yet the ghost''s murder but the mother''s remarriage — a private sexual grief that the public political scene has forced Hamlet to swallow.', ARRAY['Janet Adelman, Suffocating Mothers (1992)']::TEXT[]), ('hamlet_act1_scene2_ann4', 'hamlet_act1_scene2', 180, 258, 'Hamlet 1.2.180–258', 'structural', 'Hearsay and the delayed encounter', 'Shakespeare delays Hamlet''s meeting with the ghost by staging Horatio''s report of it first. The effect is to make the ghost simultaneously present (Horatio''s testimony is detailed, specific) and absent (Hamlet must wait until 1.4 to see for himself). The narrative technique multiplies the voices that attest to the apparition, building evidentiary pressure; it also gives Hamlet time to react to the news before the ghost makes its revelation. ''Foul deeds will rise, / Though all the earth o''erwhelm them, to men''s eyes'' — this is Hamlet''s first articulation of a principle the play will test to destruction: that hidden truths cannot stay hidden. The plot from here will press that claim against the opposing pressure of concealment.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act1_scene3_ann1', 'hamlet_act1_scene3', 10, 44, 'Hamlet 1.3.10–44', 'thematic', 'Laertes''s lecture and the economy of female chastity', 'Laertes''s warnings to Ophelia treat her virginity as a family asset subject to market risks: ''your chaste treasure,'' the ''canker'' that ''galls the infants of the spring.'' The lecture is conventional Elizabethan doctrine — a brother''s duty to police his sister''s sexual conduct — but Shakespeare sharpens the ironies. Ophelia''s reply, delivered with the cool grace of a younger sister who has heard the speech before, turns it back on him: ''show me the steep and thorny way to heaven / Whiles, like a puff''d and reckless libertine, / Himself the primrose path of dalliance treads.'' She sees through the sermon''s asymmetry. It is the last time in the play she will be permitted this much rhetorical authority over a man.', ARRAY['Carol Thomas Neely, Broken Nuptials in Shakespeare''s Plays (1985)']::TEXT[]), ('hamlet_act1_scene3_ann2', 'hamlet_act1_scene3', 59, 82, 'Hamlet 1.3.59–82', 'linguistic', 'Polonius''s precepts as verbal portraiture', 'Polonius''s famous advice (''Neither a borrower nor a lender be,'' ''to thine own self be true'') has been quoted out of context so often that readers forget its dramatic function. The maxims are recycled commonplaces from late-Tudor conduct manuals; what Shakespeare does is stitch them end-to-end without connecting logic, producing the effect of a mind that values sententious phrasing above any coherent philosophy. Modern productions often play this speech for comedy; Elizabethan audiences heard a magistrate who has mistaken the cadences of wisdom for its substance. The final line — ''This above all: to thine own self be true'' — is the phrase most liable to moral inversion, since the play will show Polonius''s self to be precisely the thing one ought not to be true to.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]), ('hamlet_act1_scene3_ann3', 'hamlet_act1_scene3', 90, 135, 'Hamlet 1.3.90–135', 'thematic', 'Ophelia''s ''I do not know, my lord, what I should think''', 'Polonius''s interrogation of Ophelia about Hamlet''s love-tokens is the scene''s emotional crux. Ophelia begins with guarded confidence (''He hath, my lord, of late made many tenders'') and ends with obedience so complete it erases her own perception: ''I shall obey, my lord.'' Between these poles Polonius pries open a private experience she can barely articulate and reframes it as a family political problem. The line ''Tender yourself more dearly'' puns on ''tender'' as a coin, and its financial register makes clear that Ophelia''s love is being appraised as capital. Janet Adelman observes that Ophelia''s tragedy begins here, not with Hamlet''s cruelty — she loses, in this scene, the language to think her own experience.', ARRAY['Janet Adelman, Suffocating Mothers (1992)']::TEXT[]), ('hamlet_act1_scene3_ann4', 'hamlet_act1_scene3', 115, 118, 'Hamlet 1.3.115–118', 'close_reading', '''Springes to catch woodcocks''', 'Polonius''s phrase describing Hamlet''s vows to Ophelia compares them to snares set for woodcocks — birds so proverbially stupid that they walk into the same trap twice. The image reduces Hamlet''s love to predation and Ophelia to a dim bird. The spring-trap (a springe) was a familiar rural device, triggered by the victim''s own footstep; Polonius''s metaphor thus blames Ophelia for her susceptibility while pretending only to warn her. This is the scene''s quiet cruelty: the father speaks the language of protection and performs the work of a cynic. Shakespeare''s hunting imagery recurs throughout the play — the ''hawk from a handsaw,'' the ''galled jade,'' the pirate-ship ambush — and always accompanies characters who are being trapped or trapping.', ARRAY['Caroline Spurgeon, Shakespeare''s Imagery (1935)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act1_scene4_ann1', 'hamlet_act1_scene4', 8, 38, 'Hamlet 1.4.8–38', 'historical', 'The Danes as drunkards: Shakespeare''s political diplomacy', 'Hamlet''s discourse on Danish drinking customs (''heavy-headed revel east and west / Makes us traduced and taxed of other nations'') appears only in the Second Quarto, not in the Folio. Why the cut? One reading: by 1603 James I, married to Anne of Denmark, had drawn England into closer diplomatic relations with Denmark, and Shakespeare''s company suppressed a passage that called their new queen''s countrymen swine. Whether or not the cut was deliberately political, the speech is the play''s most sustained meditation on the ''one defect'' — how a small flaw of nature can undo a whole character. That diagnostic will become Hamlet''s own self-indictment by Act 4.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act1_scene4_ann2', 'hamlet_act1_scene4', 43, 62, 'Hamlet 1.4.43–62', 'thematic', '''Spirit of health or goblin damn''d''', 'Hamlet''s first address to the ghost carefully preserves the Elizabethan threefold uncertainty: he may be a holy spirit, a damned devil in disguise, or a hallucination. The phrase ''questionable shape'' puts the ghost in the category of things one may legitimately interrogate. Hamlet''s skepticism here is theological as much as personal — a Protestant''s wariness of Catholic ghost-lore — and it prepares the ground for the ''play within a play'' trap in Act 3, by which he will test the ghost''s credibility. Until then, any action Hamlet might take on the ghost''s word would be imprudent, possibly damnable. This is the play''s first principled defense of delay.', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)']::TEXT[]), ('hamlet_act1_scene4_ann3', 'hamlet_act1_scene4', 65, 85, 'Hamlet 1.4.65–85', 'structural', 'The ghost''s silence and the platform''s edge', 'The ghost will not speak in the presence of others; it beckons Hamlet away. Horatio''s warning — that the spirit may ''assume some other horrible form'' or tempt Hamlet toward the cliff — is the play''s first suggestion that the revenant might be diabolical. The image of the cliff that ''beetles o''er his base'' would have been staged with the trapdoor and gallery architecture of the Globe: the ghost leading Hamlet ''off-stage'' is physically leading him upward or downward in the Elizabethan three-tiered cosmos. The geography matters because the truth the ghost is about to deliver will depend on where it comes from — purgatorial fire, hellish fraud, or the mind''s own projection.', ARRAY['Andrew Gurr, The Shakespearean Stage 1574–1642 (3rd ed., 1992)']::TEXT[]), ('hamlet_act1_scene4_ann4', 'hamlet_act1_scene4', 89, 90, 'Hamlet 1.4.89–90', 'close_reading', '''Something is rotten in the state of Denmark''', 'Marcellus''s line is one of the most quoted in all of Shakespeare, and its iconic status tends to strip its dramatic force. Coming at the end of the scene, after the ghost has exited and Hamlet has followed against his friends'' pleas, the line serves as a choric comment: the ghost is a symptom, not a cause. The word ''state'' is precise and political — not ''condition'' but commonwealth, body politic. The metaphor of rot implies something dead within a living organism, corruption hidden inside a ceremonial surface. Everything that will unfold — the assassination plot, the spying, the poisoning at a royal feast — is already implied in this one sentence.', ARRAY['Jonathan Dollimore, Radical Tragedy (1984)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act1_scene5_ann1', 'hamlet_act1_scene5', 9, 22, 'Hamlet 1.5.9–22', 'historical', 'The ghost''s purgatorial fires', 'The ghost''s self-description — ''confined to fast in fires'' until ''the foul crimes done in my days of nature / Are burnt and purged away'' — places him unambiguously in purgatory, a doctrine the Church of England had officially abolished in 1547. Stephen Greenblatt argues that Hamlet is structured around this confessional impossibility: a son at a Protestant university receives a commission from a father whose very existence depends on a theology his education has taught him to reject. The ghost cannot reveal ''the secrets of my prison-house''; if he could, the fires would stop making sense within the play''s official Protestant frame. Shakespeare keeps the ghost''s ontology just fuzzy enough to allow both Catholic and Protestant audiences their own reading.', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)']::TEXT[]), ('hamlet_act1_scene5_ann2', 'hamlet_act1_scene5', 35, 80, 'Hamlet 1.5.35–80', 'structural', 'The murder narrated in real time', 'The ghost does not merely report the murder; he re-enacts it. ''Sleeping within my orchard'' establishes the scene; ''the juice of cursed hebenon'' is poured; the poison''s progress is tracked through blood, skin, and ''natural gates and alleys of the body.'' The narrative takes its time — some forty lines — so that the audience experiences the murder in something close to its own duration. The technique is a Shakespearean innovation: the ghost makes his son an eyewitness to a crime he did not see. The scene Hamlet will later stage for Claudius in 3.2 is this same murder performed again, now by actors before its architect. Revenge in Hamlet is always a rehearsal of the original crime.', ARRAY['Harold Bloom, Shakespeare: The Invention of the Human (1998)']::TEXT[]), ('hamlet_act1_scene5_ann3', 'hamlet_act1_scene5', 82, 92, 'Hamlet 1.5.82–92', 'thematic', '''Taint not thy mind'' — the ghost''s ethical commission', 'The ghost''s final instruction complicates the commission of revenge: ''But howsoever thou pursuest this act, / Taint not thy mind, nor let thy soul contrive / Against thy mother aught.'' The son is to avenge the murder but spare the guilty wife, and he is to do it without corrupting himself. This ethical double-bind will drive Hamlet''s behavior for four acts. Recent critics from Margreta de Grazia to Rhodri Lewis have argued that the play is less about delay than about the impossibility of carrying out this commission honorably — a truly revenging son would be a ruined man. ''Taint not thy mind'' is the instruction on which the whole plot founders.', ARRAY['Rhodri Lewis, Hamlet and the Vision of Darkness (2017)','Margreta de Grazia, Hamlet without Hamlet (2007)']::TEXT[]), ('hamlet_act1_scene5_ann4', 'hamlet_act1_scene5', 96, 112, 'Hamlet 1.5.96–112', 'close_reading', '''My tables — meet it is I set it down''', 'Hamlet''s note-taking after the ghost''s departure is the scene''s strangest moment. He is a man who has just been commissioned by his murdered father''s spirit, and his immediate response is scholarly: he reaches for his writing-tablet to record the observation that ''one may smile, and smile, and be a villain.'' Elizabethan tables were small erasable booklets of plaster-coated pages, used by students and lawyers; Hamlet''s reach for his is a signal that his training at Wittenberg still governs him. The dissonance is precisely what Shakespeare exploits — in the moment of purest emotion, his hero behaves like a graduate student. This comic undertone recurs throughout the play and prevents its tragedy from curdling into melodrama.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]), ('hamlet_act1_scene5_ann5', 'hamlet_act1_scene5', 158, 175, 'Hamlet 1.5.158–175', 'thematic', '''The time is out of joint'' — the tragedy of restoration', 'Hamlet''s closing couplet — ''The time is out of joint: O cursed spite, / That ever I was born to set it right!'' — names the tragic task with eerie precision. ''Out of joint'' is anatomical: a time dislocated from itself. ''Set it right'' is reparative: to put a bone back in its socket. The tragedy will consist in Hamlet''s discovery that restoration is not available to him; setting the time right will require destroying everyone who occupies it, including himself. The line is also where the play first admits that Hamlet did not choose his role — ''born to set it right'' — a determinism the Wittenberg student never reconciles with his Protestant theology of free will.', ARRAY['G. Wilson Knight, The Wheel of Fire (1930)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act2_scene1_ann1', 'hamlet_act2_scene1', 1, 72, 'Hamlet 2.1.1–72', 'thematic', 'Polonius''s indirections and the poetics of surveillance', 'Polonius instructs Reynaldo to investigate Laertes by a technique he calls ''indirections find directions out'': gossip about the son''s drabbing, drinking, and quarreling to elicit, from the listener, confirmation of the son''s true behavior. The method is a miniature of Polonius''s whole epistemology, and by extension of Claudius''s court. No one asks direct questions because no one can afford honest answers. The scene is often cut in performance but is theoretically crucial: it establishes, before we see Hamlet''s ''antic disposition'' exposed, that this is a state in which surveillance has replaced trust. When Polonius later plans to ''loose'' Ophelia to Hamlet and eavesdrop, the technique will be the same.', ARRAY['John Dover Wilson, What Happens in Hamlet (1935)']::TEXT[]), ('hamlet_act2_scene1_ann2', 'hamlet_act2_scene1', 79, 110, 'Hamlet 2.1.79–110', 'textual', 'Ophelia''s report: a scene Shakespeare does not stage', 'The encounter between Hamlet and Ophelia that Ophelia describes — Hamlet silent, ungartered, pale, holding her wrist and studying her face — is never shown on stage. Shakespeare consistently reports through speech the most intimate crises in the play (Ophelia''s drowning, the pirate attack, the England voyage), staging instead the public consequences. The strategy concentrates dramatic power: the unseen scene becomes more vivid in Ophelia''s telling than it could in a staged rendering. Editors from Dover Wilson to Harold Jenkins have debated whether Hamlet''s visit signals genuine distress or the beginning of the ''antic disposition'' — a question the play refuses to settle because Ophelia herself cannot tell.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act2_scene1_ann3', 'hamlet_act2_scene1', 108, 119, 'Hamlet 2.1.108–119', 'thematic', 'The father''s error — ''I am sorry''', 'Polonius''s response to Ophelia''s report is revealing: ''This is the very ecstasy of love,'' and he assumes her obedient refusal to admit Hamlet''s letters has caused the madness. The comic irony is that Polonius is half-right and wholly wrong: Hamlet''s distress is real but not about love, and Polonius''s remedy — to march Ophelia to the King and weaponize her distress for political intelligence — will catalyze the next four acts of catastrophe. The line ''I had not quoted him'' (''I had not interpreted him'') is the scene''s quiet admission that Polonius has misread everything, and he will now commit Ophelia, Hamlet, and himself to acting on that misreading.', ARRAY['Carol Thomas Neely, Broken Nuptials in Shakespeare''s Plays (1985)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act2_scene2_ann1', 'hamlet_act2_scene2', 1, 40, 'Hamlet 2.2.1–40', 'thematic', 'Rosencrantz and Guildenstern: the instruments of friendship', 'Claudius and Gertrude''s charge to Hamlet''s school-friends is a small masterpiece of political language. They are summoned ''of so young days brought up with him'' — the friendship is real, which is why its weaponization will be ethically grave — but the request is surveillance with the manners of hospitality. Hamlet will later see through it instantly: ''Were you not sent for?'' The scene also shows the play''s mature political intelligence: Claudius does not command, he asks, and he frames the asking as a gift the young men may decline. The very shape of courtly tyranny, Stoppard''s Rosencrantz and Guildenstern Are Dead would later argue, is that no one is ever quite forced.', ARRAY['Stephen Greenblatt, Will in the World (2004)']::TEXT[]), ('hamlet_act2_scene2_ann2', 'hamlet_act2_scene2', 86, 168, 'Hamlet 2.2.86–168', 'structural', 'Polonius''s diagnosis and the politics of madness', 'Polonius''s long-winded display before the King — ''brevity is the soul of wit'' delivered in the least brief speech imaginable — is a set-piece of dramatic irony. Shakespeare plays it for comedy while making the political stakes serious: the chamberlain is committing royal resources to the theory that Hamlet is lovesick, and the decision to ''loose'' Ophelia as bait follows directly. Polonius''s reading of the private letter to Ophelia — ''Doubt thou the stars are fire'' — violates every courtesy and weaponizes a love poem for intelligence. It is Shakespeare''s finest portrait of the officious counselor whose ambition to serve has eaten his conscience.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]), ('hamlet_act2_scene2_ann3', 'hamlet_act2_scene2', 265, 270, 'Hamlet 2.2.265–270', 'thematic', '''What a piece of work is a man''', 'Hamlet''s paean to human nature — ''in action how like an angel! in apprehension how like a god!'' — would be Renaissance commonplace if he left it there. The speech''s power lies in its collapse: ''And yet, to me, what is this quintessence of dust?'' In a handful of lines Hamlet traverses the distance from Pico della Mirandola''s Oration on the Dignity of Man to Ecclesiastes''s ''all is vanity.'' Modern productions play the passage ironically; original Elizabethan audiences would have heard it as a genuine hymn to humanism undercut by the speaker''s own grief. The speech announces a philosophical problem the play will not solve: why is a creature capable of so much unable to act even once?', ARRAY['A. C. Bradley, Shakespearean Tragedy (1904)','Tony Tanner, Prefaces to Shakespeare (2010)']::TEXT[]), ('hamlet_act2_scene2_ann4', 'hamlet_act2_scene2', 496, 554, 'Hamlet 2.2.496–554', 'thematic', 'The second soliloquy: the player and the prince', 'Hamlet''s soliloquy after the player''s weeping speech about Hecuba is the play''s most self-lacerating. The comparison is cruel: a professional actor, prompted by nothing, can summon tears for a fiction; Hamlet, prompted by a father''s murder, has summoned nothing at all. The accusation — ''rogue and peasant slave,'' ''muddy-mettled rascal,'' ''John-a-dreams'' — is both genuine self-contempt and a kind of self-flagellating performance, an attempt to will himself into feeling by describing his insufficiency. The soliloquy''s turn at ''About, my brain!'' is the play''s first concrete plan: the Mousetrap. Hamlet discovers, under the pressure of shame, that he cannot act immediately but he can direct a play.', ARRAY['Stephen Orgel, The Illusion of Power (1975)','Harold Bloom, Shakespeare: The Invention of the Human (1998)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act3_scene1_ann1', 'hamlet_act3_scene1', 34, 55, 'Hamlet 3.1.34–55', 'structural', 'The trap is set: eavesdropping as tragic architecture', 'Claudius and Polonius conceal themselves to overhear Hamlet with Ophelia. Shakespeare returns to this device repeatedly — Polonius behind the arras in 3.4, Claudius watching the play in 3.2, Claudius and Laertes plotting Hamlet''s duel in 4.7. Eavesdropping is the governing shape of the play''s middle acts: no one can speak without being overheard, no privacy is real. The consequence is that every soliloquy we hear, the audience overhears too, and Shakespeare''s original Globe staging made this geometry visible: the groundlings surrounded the platform on three sides, so a speaker ''alone'' was always ringed by watchers. The King''s plan here — ''Her father and myself, lawful espials'' — turns the word ''lawful'' into bitter irony. The state has no legitimate access to a man''s private grief; what begins as statecraft ends as the machinery of tragedy.', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)','Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act3_scene1_ann2', 'hamlet_act3_scene1', 56, 90, 'Hamlet 3.1.56–90', 'thematic', 'The geometry of doubt', 'The soliloquy is often read as contemplating suicide, but its grammar resists that reading. Hamlet speaks in the first-person plural — ''who would bear,'' ''we have shuffled,'' ''makes us rather bear'' — generalizing his question into a problem of the human condition. The verbs (''to be,'' ''to suffer,'' ''to take arms,'' ''to die,'' ''to sleep,'' ''to dream'') climb a ladder of infinitives, each action dissolving into the next without a subject ever performing it. That grammatical paralysis is the speech''s argument: the will to act is undone by the capacity to reflect on acting. Coleridge called Hamlet''s disease ''an overbalance of the imaginative power''; Bradley called it ''melancholy''; Eliot, reading the play against itself, called the speech an ''objective correlative'' that never quite finds its object. What the lines finally describe is not Hamlet''s problem but consciousness''s problem — the way thought ''sicklies o''er'' action with reflection.', ARRAY['A. C. Bradley, Shakespearean Tragedy (1904)','T. S. Eliot, ''Hamlet and His Problems'' (1919)']::TEXT[]), ('hamlet_act3_scene1_ann3', 'hamlet_act3_scene1', 77, 80, 'Hamlet 3.1.77–80', 'historical', 'The ''undiscovered country'' and Renaissance eschatology', 'Hamlet''s claim that no traveler returns from death is theologically strange coming from a man whose father''s ghost has just returned from precisely there. The contradiction is not a lapse but a clue: the ghost belongs to purgatory (a doctrine officially abolished by the English Reformation but still culturally alive), while the soliloquy''s frame is the Wittenberg Protestantism Hamlet studied. Protestant theology had no purgatory — only heaven or hell, entered at death and never left. When Hamlet speaks of the undiscovered country, he speaks as a Wittenberg student; when he listens to the ghost, he listens as a medieval Catholic son. The play is built on this confessional split. Greenblatt has argued that Hamlet is Shakespeare''s most sustained meditation on a culture that no longer knew what to do with its dead.', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)']::TEXT[]), ('hamlet_act3_scene1_ann4', 'hamlet_act3_scene1', 87, 140, 'Hamlet 3.1.87–140', 'thematic', '''Get thee to a nunnery'': the cruelty of the known audience', 'Hamlet''s treatment of Ophelia here has puzzled productions for four centuries. The actress must play a woman being verbally abused by the man she loves; the actor must play a son who has just guessed, somewhere between ''soft you now'' and ''are you honest?'', that Polonius and the King are listening. Once Hamlet registers the eavesdropping, every line is spoken twice: to Ophelia and to the watchers behind the arras. The phrase ''Where''s your father?'' at line 120 is often played as the moment of realization — after Ophelia lies (''at home''), Hamlet''s cruelty sharpens into performance. The nunnery speech, read this way, is an audition-piece of misogyny put on for the King''s benefit. What Ophelia cannot know, and what the staging must decide, is whether Hamlet''s tenderness toward her survives underneath.', ARRAY['Carol Thomas Neely, Broken Nuptials in Shakespeare''s Plays (1985)']::TEXT[]), ('hamlet_act3_scene1_ann5', 'hamlet_act3_scene1', 133, 145, 'Hamlet 3.1.133–145', 'structural', 'Ophelia''s lament as the play''s counter-soliloquy', 'Ophelia''s twelve-line speech — ''O, what a noble mind is here o''erthrown'' — functions as the mirror of Hamlet''s own soliloquy moments earlier. Where Hamlet''s language is abstract (the thousand natural shocks, the fardels, the quietus), Ophelia''s is concrete (the courtier''s, soldier''s, scholar''s eye, tongue, sword). Where Hamlet generalizes to ''us all,'' Ophelia particularizes to a single beloved man, now ruined. This is the only speech she delivers in the play that is not interrupted by a man''s instruction; it is also the speech that foreshadows her own undoing. Shakespeare frequently uses the lament of an onlooker to crystallize what the protagonist cannot say about himself. Ophelia''s grief here lays the groundwork for her madness in Act 4.', ARRAY['Elaine Showalter, ''Representing Ophelia'' (1985)']::TEXT[]), ('hamlet_act3_scene1_ann6', 'hamlet_act3_scene1', 151, 176, 'Hamlet 3.1.151–176', 'historical', 'The England trip as political maneuver', 'Claudius''s decision to send Hamlet to England on diplomatic business — collecting ''neglected tribute'' — is presented as a measured statesmanlike response to a son whose madness may be political. In Elizabethan political theater, a troublesome royal relative was regularly dispatched abroad on the pretext of an embassy; audiences recognized the gesture. The historical source Shakespeare draws from, the Latin Historiae Danicae of Saxo Grammaticus, has Amleth sent to Britain with two retainers whose commission is to procure his death. Shakespeare preserves that plot but layers it with political reasoning: even if Hamlet is only melancholic, he must be kept from the people. Polonius''s counter-proposal — let the Queen try to draw him out first — is the play''s last gesture toward a domestic resolution; after 3.4 it will be impossible.', ARRAY['Geoffrey Bullough, Narrative and Dramatic Sources of Shakespeare, vol. 7 (1973)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act3_scene2_ann1', 'hamlet_act3_scene2', 1, 35, 'Hamlet 3.2.1–35', 'biographical', 'Hamlet''s lecture on acting — Shakespeare the director', 'Hamlet''s advice to the players (''speak the speech trippingly on the tongue,'' ''suit the action to the word, the word to the action'') is the most sustained theory of acting in Elizabethan drama. It is also the closest Shakespeare ever comes to direct autobiography. The critic A. R. Humphreys argued that the speech reflects the working principles of the Lord Chamberlain''s Men — restraint over noise, naturalism over ranting, the actor as the age''s ''abstract and brief chronicle.'' What Hamlet attacks — actors who ''saw the air,'' ''out-herod Herod,'' ''tear a passion to tatters'' — is the older, bombastic style of Edward Alleyn and the Admiral''s Men. Shakespeare is, through his prince, staking a claim for a new theatrical aesthetic.', ARRAY['Andrew Gurr, The Shakespearean Stage 1574–1642 (3rd ed., 1992)']::TEXT[]), ('hamlet_act3_scene2_ann2', 'hamlet_act3_scene2', 55, 85, 'Hamlet 3.2.55–85', 'thematic', 'Hamlet''s praise of Horatio and the stoic ideal', 'Hamlet''s tribute to Horatio — ''Give me that man / That is not passion''s slave'' — articulates the stoic ideal the prince himself cannot achieve. The virtues Hamlet names (not being ''a pipe for fortune''s finger,'' being unmoved by both blessing and blow) are those of Seneca and Boethius, standard fare in the Wittenberg curriculum. The emotional force of the speech lies in its confession: Hamlet knows what he ought to be and is not. Horatio is the character the play preserves at its end, the one who will ''live behind to tell my story,'' because his temperament is what the world of the play systematically destroys.', ARRAY['Rhodri Lewis, Hamlet and the Vision of Darkness (2017)']::TEXT[]), ('hamlet_act3_scene2_ann3', 'hamlet_act3_scene2', 236, 260, 'Hamlet 3.2.236–260', 'structural', '''The Mousetrap'' and the logic of the play-within', 'The play Hamlet has commissioned — The Murder of Gonzago — re-enacts his father''s murder: poison poured into an ear, a widow queen who remarries the murderer. Hamlet''s ironic renaming (''the Mousetrap'') is precise; the play is a trap, and the target is Claudius''s conscience. The theory that drives the plot is one articulated by Puritan preachers and Shakespeare''s own Henry V: theatrical representation has the power to prick the guilty. When Claudius rises at the poisoning scene and calls for light, the test has worked. What the test does not give Hamlet is a legally admissible confession or a path to action. The scene ends with him no closer to revenge than he began, only more certain.', ARRAY['Stephen Greenblatt, Shakespearean Negotiations (1988)']::TEXT[]), ('hamlet_act3_scene2_ann4', 'hamlet_act3_scene2', 338, 356, 'Hamlet 3.2.338–356', 'linguistic', '''Play upon this pipe'' — the music of being read', 'Hamlet''s image of the recorder is among the play''s most precise metaphors for agency. ''It is as easy as lying,'' he tells Guildenstern, who cannot play the pipe. ''Govern these ventages with your finger and thumb, give it breath with your mouth, and it will discourse most eloquent music.'' The instrument, Hamlet means, is simpler than a man, and yet Guildenstern cannot make it speak; how then does he imagine he can play Hamlet? The scene ends with Hamlet''s most direct accusation of his friends: ''You would seem to know my stops; you would pluck out the heart of my mystery.'' The pipe image reveals the play''s theory of selfhood — there is something in a man that resists being played.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act3_scene3_ann1', 'hamlet_act3_scene3', 36, 72, 'Hamlet 3.3.36–72', 'thematic', 'Claudius''s prayer: the conscience that cannot repent', 'Claudius''s soliloquy is the only moment in the play where the King speaks alone, and it is Shakespeare''s most searching portrait of unrepentant guilt. ''My offence is rank, it smells to heaven'' — the imagery echoes the ghost''s description of being poisoned through the ear with corrupting ''leperous distilment.'' But Claudius cannot repent because he will not give up what the murder bought him: ''my crown, mine own ambition, and my queen.'' He knows the theological logic perfectly (''May one be pardoned and retain the offence?'') and knows his answer damns him. The scene gives us the first real interior of Claudius, and it is the interior of a man who sees his own damnation clearly and chooses it anyway.', ARRAY['Harold Goddard, The Meaning of Shakespeare (1951)']::TEXT[]), ('hamlet_act3_scene3_ann2', 'hamlet_act3_scene3', 73, 96, 'Hamlet 3.3.73–96', 'thematic', '''Now might I do it pat'' — Hamlet''s terrible calculation', 'Hamlet''s decision not to kill the praying King is the play''s most theologically fraught moment, and its most debated. The logic is precise: if he kills Claudius at prayer, the King goes to heaven; the ghost was damned at the hour of his death and confined to purgatorial fires. To send the murderer to salvation would be ''hire and salary, not revenge.'' Critics from Samuel Johnson onward have found the calculation repellent — ''too horrible to be read or to be uttered,'' Johnson wrote. Others, from Bradley to Lewis, have argued that Hamlet is lying to himself, that the theological reasoning is a rationalization for continued delay. Either reading, the scene is devastating because Claudius''s following couplet reveals that the prayer did not reach heaven: the King would have died unforgiven.', ARRAY['Samuel Johnson, ''Notes on Shakespeare'' (1765)','A. C. Bradley, Shakespearean Tragedy (1904)']::TEXT[]), ('hamlet_act3_scene3_ann3', 'hamlet_act3_scene3', 97, 98, 'Hamlet 3.3.97–98', 'close_reading', '''My words fly up, my thoughts remain below''', 'Claudius''s closing couplet is the play''s most compressed tragedy. He has just prayed, and the prayer has not worked; the words ascended, the thoughts — the penitent heart required for efficacy — stayed on earth. ''Words without thoughts never to heaven go'' is at once an admission of theological failure and a piece of reformed doctrine: the Protestant reformers insisted that mere vocal prayer without an examined conscience was nothing. The audience exits the scene knowing what Hamlet did not: the revenger missed a moral opportunity. Dramatic irony rarely cuts deeper than this.', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act3_scene4_ann1', 'hamlet_act3_scene4', 22, 34, 'Hamlet 3.4.22–34', 'structural', 'The killing of Polonius: catastrophe as reflex', 'Hamlet''s stabbing of the man behind the arras is the play''s central structural pivot. For three acts Hamlet has been unable to act; now he acts impulsively and kills the wrong man. The moment is the tragic inverse of the prayer scene moments before: there Hamlet reasoned himself out of a killing he could have done, here he kills without reasoning. Freud''s famous reading — that the delayed revenge masks an unconscious identification with Claudius that Polonius accidentally triggers — is one way to read the inconsistency. Another, more structural reading: Shakespeare needed the accident to set in motion Laertes''s parallel revenge plot, Ophelia''s madness, and Hamlet''s exile. The play''s second half depends on this one impulsive thrust.', ARRAY['Sigmund Freud, The Interpretation of Dreams (1900)','Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act3_scene4_ann2', 'hamlet_act3_scene4', 53, 104, 'Hamlet 3.4.53–104', 'thematic', 'The closet scene: portraits and the ethics of remarriage', 'Hamlet confronts his mother with what appears to be two miniature portraits (some productions use life-size wall paintings) — his father''s and Claudius''s. The comparison uses a Renaissance technique: Hamlet reads virtues out of faces. His father has ''Hyperion''s curls; the front of Jove himself; / An eye like Mars''; Claudius is ''a mildew''d ear / Blasting his wholesome brother.'' The passage is Shakespeare''s sharpest treatment of the marriage''s illegitimacy — not legal but aesthetic and ethical. Janet Adelman has argued that the scene''s force comes from its Oedipal charge: Hamlet''s rage at the remarriage is inseparable from his horror at his mother''s sexuality. ''Stew''d in corruption, honeying and making love / Over the nasty sty'' is not the language of political indignation.', ARRAY['Janet Adelman, Suffocating Mothers (1992)']::TEXT[]), ('hamlet_act3_scene4_ann3', 'hamlet_act3_scene4', 102, 135, 'Hamlet 3.4.102–135', 'textual', 'Does Gertrude see the ghost?', 'The ghost''s re-entry in 3.4, visible only to Hamlet, is one of the play''s most contested textual cruxes. Some critics read Gertrude''s blindness as evidence that the ghost is a hallucination projected by Hamlet''s guilt about his mother; others see it as a sign that Gertrude, unlike Hamlet, has not been inducted into the secret knowledge. The First Quarto (Q1) has a different stage direction — the ghost appears ''in his night-gown'' — suggesting a more domestic, private apparition than the armored figure of 1.1. In performance, a director must decide whether to let the audience see the ghost (affirming his reality) or to stage him as Hamlet''s subjective experience (suggesting madness). Either choice reshapes the scene.', ARRAY['Paul Werstine, ''The Textual Mystery of Hamlet'' (1988)','Margreta de Grazia, Hamlet without Hamlet (2007)']::TEXT[]), ('hamlet_act3_scene4_ann4', 'hamlet_act3_scene4', 172, 173, 'Hamlet 3.4.172–173', 'thematic', '''I must be cruel only to be kind''', 'Hamlet''s line to Gertrude — ''I must be cruel only to be kind'' — sums up the ethical logic he has been attempting since 1.5: the violence is therapeutic, the harshness serves a larger good. The argument is essentially pastoral: a physician''s pain for a patient''s healing. But the scene has not produced Gertrude''s redemption — it has produced Polonius''s corpse and Gertrude''s pragmatic survival instinct (''Be thou assured, if words be made of breath... I have no life to breathe what thou hast said to me''). The gap between Hamlet''s theory of cruelty and its practice is the gap the whole second half of the play opens onto.', ARRAY['Stanley Cavell, Disowning Knowledge (1987)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene1_ann1', 'hamlet_act4_scene1', 1, 16, 'Hamlet 4.1.1–16', 'thematic', 'Gertrude''s equivocal loyalty', 'The scene opens with Gertrude reporting to Claudius in terms that protect Hamlet: his madness is ''as the sea and wind,'' the killing of Polonius a ''brainish apprehension.'' She does not reveal what Hamlet has told her — that Claudius murdered King Hamlet — and she does not tell the King that Hamlet is only feigning madness. Gertrude has always been one of the play''s critical puzzles: is she complicit, merely survivalist, or confusedly loving both her son and her husband? This short scene contains her most decisive act of protection. Carolyn Heilbrun''s influential reading argues that critics systematically underestimate Gertrude, who here emerges as the play''s most skillful diplomat.', ARRAY['Carolyn Heilbrun, ''The Character of Hamlet''s Mother'' (1957)']::TEXT[]), ('hamlet_act4_scene1_ann2', 'hamlet_act4_scene1', 17, 38, 'Hamlet 4.1.17–38', 'structural', 'Claudius''s political instincts', 'Claudius''s immediate concern after hearing of Polonius''s death is not grief but damage control: ''to us whose providence / Should have kept short, restrain''d and out of haunt / This mad young man.'' His phrasing reveals the political mind — the killing reflects poorly on his management, and the King begins already to plan the concealment. By the end of his twenty lines he has arranged for the body''s disposal, anticipated the slander to come, and resolved to accelerate the England voyage. This is Claudius at his most functional: not the tortured penitent of 3.3 but the professional sovereign managing a crisis. Shakespeare lets us see the King''s competence precisely so we can measure its moral hollowness.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene2_ann1', 'hamlet_act4_scene2', 10, 22, 'Hamlet 4.2.10–22', 'thematic', '''A sponge that soaks up the king''s countenance''', 'Hamlet''s accusation of Rosencrantz — ''you shall be dry again'' — uses one of the play''s cleanest political metaphors. Courtiers are sponges: they absorb royal favor and are squeezed dry when the King has had his use of them. The image reduces the technique of flattery to a fluid mechanics. It is also a warning Rosencrantz cannot hear: Hamlet knows the King''s ambassadors are disposable, as we will learn when the sealed commission turns out to contain their own death warrants. The short scene is otherwise almost entirely comic, the corpse-hide-and-seek played for grotesque laughter. Shakespeare allows himself this tonal variety because the tragedy''s center has already tilted toward inevitability.', ARRAY['Harold Bloom, Shakespeare: The Invention of the Human (1998)']::TEXT[]), ('hamlet_act4_scene2_ann2', 'hamlet_act4_scene2', 24, 29, 'Hamlet 4.2.24–29', 'close_reading', '''The body is with the king, but the king is not with the body''', 'Hamlet''s cryptic reply to Rosencrantz — about Polonius''s body, addressed to Claudius — is more than madman''s evasion. ''The body is with the king, but the king is not with the body'' plays simultaneously on the medieval doctrine of the king''s two bodies (the immortal body politic and the mortal body natural) and on the fact that Polonius''s corpse is somewhere in the castle but the King it served is no longer honored by it. The phrase ''a thing, my lord... of nothing'' prefigures the meditations on death and dust in the graveyard scene. Hamlet''s madness here is intellectual — each line a small riddle the audience is asked to decode.', ARRAY['Ernst Kantorowicz, The King''s Two Bodies (1957)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene3_ann1', 'hamlet_act4_scene3', 17, 32, 'Hamlet 4.3.17–32', 'thematic', '''Your worm is your only emperor for diet''', 'Hamlet''s lecture to Claudius on worms, kings, and beggars is one of the play''s great meditations on mortality: ''we fat all creatures else to fat us, and we fat ourselves for maggots.'' The argument moves through the food chain and arrives at a leveling truth: a king may travel, via a fish, through the guts of a beggar. The rhetoric is grotesque but philosophically precise — it dismantles the doctrine of the king''s two bodies. A king is meat like any other meat. The speech is Hamlet''s cruelest to Claudius, because it is delivered in the code of madness the King must accept while understanding perfectly its content. Only in Act 5, in the graveyard, will Hamlet return to this meditation with a different spirit.', ARRAY['Harold Bloom, Shakespeare: The Invention of the Human (1998)']::TEXT[]), ('hamlet_act4_scene3_ann2', 'hamlet_act4_scene3', 55, 70, 'Hamlet 4.3.55–70', 'structural', 'The sealed commission and the secret plot', 'Claudius''s final soliloquy reveals what the audience has suspected and the play has not yet confirmed: the letter Hamlet carries to England is a death warrant. The monarch who in 3.3 could not pray effectively now directs the pen with cold efficiency. The lines ''thou must cure me: till I know ''tis done, / Howe''er my haps, my joys were ne''er begun'' are a small masterpiece of compromised hope. Shakespeare holds two portraits of Claudius in superposition throughout the play — the penitent and the manager — and the second is what we see here. The commission will become the hinge of Act 5, when Hamlet, aboard ship, discovers and rewrites it.', ARRAY['Geoffrey Bullough, Narrative and Dramatic Sources of Shakespeare, vol. 7 (1973)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene4_ann1', 'hamlet_act4_scene4', 1, 32, 'Hamlet 4.4.1–32', 'structural', 'Fortinbras''s army and the politics of honor', 'Fortinbras appears briefly en route to Poland, his army marching to fight over a patch of ground Hamlet''s captain dismisses as ''the plot whereon the numbers cannot try the cause.'' Shakespeare stages the man against whom Hamlet has been measured all along: a prince whose father was killed by King Hamlet, and who has organized an entire military campaign to recover the family honor. Hamlet''s whole strategic horizon — delay, interrogation, doubt — has no corollary in Fortinbras. The scene poses the play''s sharpest question: is Fortinbras''s decisive honor-seeking noble, or is it the waste of twenty thousand lives over an eggshell? The final soliloquy will refuse to settle it.', ARRAY['Jonathan Bate, Soul of the Age (2008)']::TEXT[]), ('hamlet_act4_scene4_ann2', 'hamlet_act4_scene4', 32, 66, 'Hamlet 4.4.32–66', 'thematic', '''How all occasions do inform against me''', 'Hamlet''s final soliloquy — absent from the Folio but present in the Second Quarto — is the prince''s most thorough self-examination. ''What is a man, / If his chief good and market of his time / Be but to sleep and feed?'' echoes the earlier ''what is this quintessence of dust?'' but turns the question from species to self. The speech''s climax — ''Rightly to be great / Is not to stir without great argument, / But greatly to find quarrel in a straw / When honour''s at the stake'' — is both a critique of Fortinbras and an envy of him. The closing couplet, ''O, from this time forth, / My thoughts be bloody, or be nothing worth,'' is the play''s last soliloquy of resolution, and the next time we see Hamlet he will already be different.', ARRAY['A. C. Bradley, Shakespearean Tragedy (1904)','Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act4_scene4_ann3', 'hamlet_act4_scene4', 52, 58, 'Hamlet 4.4.52–58', 'textual', 'The soliloquy''s textual ghost', 'This entire soliloquy (about 35 lines) is missing from the 1623 First Folio. Many editors assume Shakespeare''s company cut it in later performance for length; some scholars, including Paul Werstine and Barbara Mowat, argue the cut was thematic — the Folio Hamlet is a less meditative figure, closer to a man of action. Whichever theory is right, modern editions typically restore the speech from the Second Quarto because it is a pivot point for the character. Without it, Hamlet''s decisiveness in Act 5 — the letter forgery, the pirate-ship escape, the readiness for the duel — arrives unearned.', ARRAY['Paul Werstine, ''The Textual Mystery of Hamlet'' (1988)','Barbara Mowat and Paul Werstine, eds., Folger Shakespeare Library edition']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene5_ann1', 'hamlet_act4_scene5', 20, 70, 'Hamlet 4.5.20–70', 'thematic', 'Ophelia''s songs: the breaking of a voice', 'Ophelia''s mad scenes substitute singing for speech, and the songs are not madness but scraps of a coherent emotional truth. The pilgrim song (''How should I your true love know / From another one?''), the Valentine''s Day song with its sexual frankness (''Young men will do''t, if they come to''t; / By Cock, they are to blame''), and the song of the dead father (''He is gone, he is gone'') articulate, through the displacement of received lyric, what Ophelia cannot say directly. Showalter''s influential ''Representing Ophelia'' argues that feminist criticism must recover the scene''s meaning from the long tradition that aestheticized her madness as picturesque pathos. The songs are sharp instruments of accusation.', ARRAY['Elaine Showalter, ''Representing Ophelia'' (1985)']::TEXT[]), ('hamlet_act4_scene5_ann2', 'hamlet_act4_scene5', 177, 188, 'Hamlet 4.5.177–188', 'historical', 'The flowers and the language of herbs', 'Ophelia distributes flowers by their traditional meanings: rosemary for remembrance, pansies for thoughts, fennel for flattery, columbines for marital infidelity, rue for sorrow and repentance, daisy for dissembled love, violets (withered) for faithfulness. Elizabethan herbals, particularly John Gerard''s Herball (1597), catalogued these significations and audiences would have read the tableau in real time. Ophelia''s distributions are targeted: fennel and columbines (flattery and infidelity) to the King and Queen; rue to Gertrude; the withered violets since ''they all withered when my father died.'' The scene is Ophelia''s most articulate political speech, disguised as a flower game.', ARRAY['Dympna Callaghan, Shakespeare without Women (2000)','John Gerard, Herball (1597)']::TEXT[]), ('hamlet_act4_scene5_ann3', 'hamlet_act4_scene5', 95, 132, 'Hamlet 4.5.95–132', 'structural', 'Laertes''s insurrection and Hamlet''s absent parallel', 'Laertes storms the castle with an armed mob shouting ''Laertes shall be king,'' threatening Claudius with immediate deposition. The contrast with Hamlet is structural: given the same provocation (a father murdered), Laertes acts at once and politically, raising popular support and confronting the sovereign. Shakespeare deliberately places Laertes''s vengeance beside Hamlet''s to force comparison — but the comparison does not favor either man. Laertes will let Claudius turn his revenge into the King''s own instrument within twenty lines. The play keeps showing us characters who act decisively and are destroyed by their decisiveness, and characters who delay and are destroyed by their delay. There is no correct speed at which to avenge a father.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act4_scene5_ann4', 'hamlet_act4_scene5', 188, 196, 'Hamlet 4.5.188–196', 'close_reading', '''There''s rosemary, that''s for remembrance''', 'The most quoted of Ophelia''s flower lines is also the most theatrically charged: she gives rosemary to someone — the stage direction in modern editions is ambiguous, and Laertes''s ''A document in madness'' suggests he recognizes its pointedness. Rosemary was associated with both weddings and funerals, and the double resonance fits Ophelia''s condition — the bride-never-to-be who is already mourning. ''Pray, love, remember'' is an instruction to the living to honor the dead, and in performance its recipient matters: Gertrude? Laertes? The King? Ophelia gives herself no rosemary, which the tradition would have noted: she is asking to be the one whose own loss is carried forward by others.', ARRAY['Carol Thomas Neely, Distracted Subjects (2004)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene6_ann1', 'hamlet_act4_scene6', 13, 31, 'Hamlet 4.6.13–31', 'structural', 'Hamlet''s letter and the pirate attack', 'Hamlet''s letter to Horatio, delivered by sailors, is the play''s most improbable plot device: pirates attack the ship, Hamlet boards them in the fight, and they return him to Denmark. Shakespeare adapted this from Belleforest''s Histoires Tragiques, where a similar escape occurs. The randomness is essential — the providence Hamlet will later credit (''There''s a divinity that shapes our ends'') requires a genuinely unscripted event. Critics have noted the structural parallel to the shipwreck in Twelfth Night and the maritime accidents that reshape The Tempest. In Hamlet, the ocean becomes the place where the prince''s fate escapes Claudius''s careful management and returns to him transformed.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act4_scene6_ann2', 'hamlet_act4_scene6', 22, 26, 'Hamlet 4.6.22–26', 'close_reading', '''Thieves of mercy''', 'Hamlet''s oxymoron — ''thieves of mercy'' — is as compact a piece of rhetoric as anything in the play. Pirates who spared his life and set him back on his own quest have behaved better than the Christian courtiers who sent him to die. The paradox preserves the play''s moral disorientation: an honorable thief, a loyal pirate, a treacherous king. The short scene is a technical marvel — four speeches of report that move the plot from England to Denmark without a single on-stage action. Shakespeare trusts the audience to register the transition on the strength of letter-reading alone.', ARRAY['Frank Kermode, Shakespeare''s Language (2000)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act4_scene7_ann1', 'hamlet_act4_scene7', 60, 140, 'Hamlet 4.7.60–140', 'structural', 'The plot-making scene: Claudius at his most Machiavellian', 'The King''s exchange with Laertes is a masterclass in manipulation. Claudius does not propose the murder directly; he asks leading questions (''Was your father dear to you?'') and lets Laertes arrive at the solution Claudius already has in mind. The staged fencing match, the unblunted rapier, the anointing with a ''mountebank''s'' poison, and the backup plan of a poisoned cup — all are introduced as if Laertes is the improviser and the King merely the sounding board. Shakespeare''s Claudius is not the cardboard villain of the revenge-tragedy tradition. He is the political intelligence that revenge tragedy requires to generate its catastrophes, and his technique here is nearer Iago''s than to any Senecan stereotype.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]), ('hamlet_act4_scene7_ann2', 'hamlet_act4_scene7', 140, 180, 'Hamlet 4.7.140–180', 'thematic', 'Gertrude''s elegy for Ophelia', 'The report of Ophelia''s drowning is one of the most famous speeches in English poetry, and also one of the most theatrically strange. It is delivered in past tense, as if by an eyewitness, by a queen who was certainly not there. The language — ''crow-flowers, nettles, daisies, and long purples'' — is botanically precise and visually suspended. Critics from Coleridge onward have noted that the speech behaves less like a report than like a tableau. The pastoral mode (weeping willow, garlands, mermaid-like singing) softens the violence; Ophelia ''dies'' into a painting before she actually dies. Tennyson and Millais would later build their Ophelia on these very lines. What Gertrude does not say — whether the death was accident or suicide — the gravediggers will debate in 5.1.', ARRAY['Elaine Showalter, ''Representing Ophelia'' (1985)','Linda Charnes, Hamlet''s Heirs (2006)']::TEXT[]), ('hamlet_act4_scene7_ann3', 'hamlet_act4_scene7', 107, 128, 'Hamlet 4.7.107–128', 'close_reading', 'The poison plot and the logic of the foil', 'Laertes''s proposed poisoned rapier-tip is the scene''s ethical nadir. Under Renaissance honor-code, a duel was a ritual combat that tested fate and skill; poisoning a foil turns the ritual into a secret assassination while preserving the ceremonial surface. The word ''unction,'' applied to the poison, is theologically loaded — it is the word for the sacrament of anointing, here reversed into damnation. Shakespeare is noting a specific corruption of chivalry. The fallback plan — a poisoned cup, should the sword fail — represents the total betrayal of the duel''s pretense. When the plan turns on its makers in Act 5, the rhetorical closure is near-surgical: poisons kill their compounders.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act5_scene1_ann1', 'hamlet_act5_scene1', 1, 55, 'Hamlet 5.1.1–55', 'historical', 'The gravediggers and the theology of suicide', 'The clowns'' opening argument about whether Ophelia deserves Christian burial parodies a real 1560 legal case, Hales v. Pettit, which asked whether a suicide could legally transfer property. The First Clown''s ''Argal'' (a corruption of ''ergo'') mocks the legalistic reasoning of the original case. Shakespeare''s audience would have laughed at the bad Latin and recognized the grim topic underneath: the Church of England denied Christian burial rites to self-murderers, and exceptions required ''great command o''ersways the order.'' The scene establishes, before Hamlet arrives, that Ophelia''s death sits under a theological and legal ambiguity — the play will never quite say whether her drowning was suicide, accident, or something between the two.', ARRAY['Harold Jenkins, Hamlet (Arden 2nd ed., 1982)','Susan Snyder, ''The Genres of Shakespeare''s Plays'' (1979)']::TEXT[]), ('hamlet_act5_scene1_ann2', 'hamlet_act5_scene1', 55, 100, 'Hamlet 5.1.55–100', 'thematic', 'Hamlet in the graveyard: the return of the body', 'The prince who spent Act 3 in a state of abstract meditation on death now handles actual skulls. The change is registered in the verse: ''That skull had a tongue in it, and could sing once'' is plain English, no longer dressed in the rhetoric of ''this mortal coil.'' Hamlet has been in a boat with pirates, seen his own execution order, and confronted death as a specific thing rather than a philosophical topic. The graveyard scene tracks this development — skulls become individuals (a lawyer, a politician, a courtier, a jester) rather than types. The meditation is the inverse of Ecclesiastes: not ''all is vanity'' but ''someone once kissed these bones.''', ARRAY['Stephen Greenblatt, Hamlet in Purgatory (2001)']::TEXT[]), ('hamlet_act5_scene1_ann3', 'hamlet_act5_scene1', 166, 188, 'Hamlet 5.1.166–188', 'close_reading', '''Alas, poor Yorick!''', 'Hamlet''s encounter with Yorick''s skull is the play''s most anthologized moment, and the one most liable to sentimental misreading. The speech is not melancholy but astonished: the jester who carried young Hamlet on his back now fits in the prince''s hand. ''Where be your gibes now? your gambols? your songs? your flashes of merriment, that were wont to set the table on a roar?'' The specific memory makes the grief personal in a way the abstract soliloquies could not. What follows (''Alexander died, Alexander was buried, Alexander returneth into dust'') pushes the lesson outward again — but the Yorick moment itself is irreducible. A remembered child''s laughter survives in an empty skull, and that survival is stranger than any philosophy can manage.', ARRAY['Tony Tanner, Prefaces to Shakespeare (2010)']::TEXT[]), ('hamlet_act5_scene1_ann4', 'hamlet_act5_scene1', 228, 275, 'Hamlet 5.1.228–275', 'structural', 'The grave-leap and the staging of rivalry', 'Laertes leaps into Ophelia''s grave; Hamlet leaps in after him. The physical confrontation inside the grave is one of Shakespeare''s most daring stage images: two mourners fighting for possession of a corpse, each claiming to have loved Ophelia more. The First Quarto''s stage direction — ''Hamlet leaps in after Laertes'' — is disputed in later editions, and modern productions handle the moment variously. The textual uncertainty mirrors the scene''s ethical uncertainty: the declaration of love (''forty thousand brothers / Could not, with all their quantity of love, / Make up my sum'') is passionate but also bizarrely competitive. Hamlet loves Ophelia in retrospect, against Laertes, in public — a form of love her living self never got.', ARRAY['Paul Werstine, ''The Textual Mystery of Hamlet'' (1988)']::TEXT[]);
INSERT INTO scene_annotations (id, section_id, line_start, line_end, citation_display, category, title, body, sources) VALUES ('hamlet_act5_scene2_ann1', 'hamlet_act5_scene2', 4, 70, 'Hamlet 5.2.4–70', 'thematic', 'Providence and the altered commission', 'Hamlet''s narrative of the voyage — ''Rashly, / And praised be rashness for it'' — articulates the play''s only positive theology. ''There''s a divinity that shapes our ends, / Rough-hew them how we will'' is a claim the earlier Hamlet could not have made. The man who spent three acts immobilized by questions of action now ascribes the sealed commission''s discovery to providence rather than to his own cleverness. The theological turn is easy to sentimentalize; Rhodri Lewis has argued that the play''s providence-talk is not consolation but the calm that comes with surrendering agency. Hamlet is not saved; he is spared long enough to complete the revenge that will destroy him. The speech''s peace is the peace of a man who has stopped trying to master his fate.', ARRAY['Rhodri Lewis, Hamlet and the Vision of Darkness (2017)','Stanley Cavell, Disowning Knowledge (1987)']::TEXT[]), ('hamlet_act5_scene2_ann2', 'hamlet_act5_scene2', 197, 215, 'Hamlet 5.2.197–215', 'thematic', '''The readiness is all''', 'Hamlet''s response to Horatio''s warning about the duel — ''We defy augury. There''s a special providence in the fall of a sparrow... The readiness is all'' — echoes Matthew 10:29 (''one sparrow shall not fall on the ground without your Father'') and Edgar''s ''ripeness is all'' in King Lear. What the prince arrives at, after five acts of deliberation, is not a philosophy of action but a philosophy of availability. One cannot control when one is called; one can only be ready when called. The speech is Hamlet''s final utterance before the catastrophe, and its stoic-Christian fusion is where the play''s religious and philosophical traditions quiet into a single voice.', ARRAY['A. D. Nuttall, Shakespeare the Thinker (2007)']::TEXT[]), ('hamlet_act5_scene2_ann3', 'hamlet_act5_scene2', 315, 360, 'Hamlet 5.2.315–360', 'structural', 'The choreography of death', 'The final fencing match is a tragic mechanism: one instrument of death, two accidental redirections, four bodies. Laertes is wounded with the poisoned foil he meant for Hamlet; Gertrude drinks from the cup intended for Hamlet; Hamlet, learning the truth, poisons Claudius with his own potion. Each death is an inversion of the killer''s intent. Shakespeare''s revenge-tragedy precursors, particularly Kyd''s Spanish Tragedy, tended toward operatic pile-ups of corpses; Hamlet''s ending is more economical, each death following from a specific choice. The King is killed last, and by his own contrivance; the revenge Hamlet never managed to design, Claudius has done for him.', ARRAY['Jonathan Bate, Soul of the Age (2008)']::TEXT[]), ('hamlet_act5_scene2_ann4', 'hamlet_act5_scene2', 353, 359, 'Hamlet 5.2.353–359', 'close_reading', '''The rest is silence''', 'Hamlet''s last words are simultaneously a statement about what cannot be said and an acknowledgment of what will be said after him — Fortinbras will inherit, Horatio will tell the story, the theater of Denmark will continue. The Folio has four additional syllables (''O, o, o, o'') that some editors print and others suppress. If performed, these dying groans convert the neat aphorism into something more ragged. T. S. Eliot famously called ''the rest is silence'' the cleanest ending in Shakespeare; others, including Bradley, found in the ''O, o, o, o'' a more honest human ending. Either way, the phrase is Shakespeare''s most condensed meditation on the limits of speech at the edge of death.', ARRAY['T. S. Eliot, ''Hamlet and His Problems'' (1919)','A. C. Bradley, Shakespearean Tragedy (1904)']::TEXT[]), ('hamlet_act5_scene2_ann5', 'hamlet_act5_scene2', 360, 390, 'Hamlet 5.2.360–390', 'structural', 'Fortinbras''s arrival and the restoration', 'Fortinbras enters as the play closes, returning from the Polish campaign and stepping almost by chance into the throne of Denmark. His claim — ''some rights of memory in this kingdom'' — recalls his father''s lost lands. The restoration he provides is not consoling. The young man who organized an army to ''find quarrel in a straw'' inherits a kingdom emptied by a more meditative son. Shakespeare''s political vision is bleak: the state that has consumed itself through corruption is passed to an outsider whose decisiveness is untouched by the questions Hamlet could not stop asking. The final ''soldier''s music'' given to Hamlet honors the prince who never quite got to be a warrior.', ARRAY['Marjorie Garber, Shakespeare After All (2004)']::TEXT[]);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act1_scene1_q1', 'hamlet_act1_scene1', 'comprehension', 'What do Bernardo and Marcellus want Horatio to witness?', ARRAY['A military review of the night watch.','An apparition that has appeared to them on two previous nights.','The new king''s first royal proclamation.','A strange comet passing over Elsinore.']::TEXT[], 1, 10, 22, 35), ('hamlet_act1_scene1_q2', 'hamlet_act1_scene1', 'inference', 'Why do the sentries want Horatio specifically to address the ghost?', ARRAY['He is the King''s personal secretary and has royal authority.','As a scholar, he knows the Latin needed to address spirits properly.','He is Hamlet''s closest friend and the ghost will speak only to him.','He has seen ghosts before and knows how to drive them off.']::TEXT[], 1, 15, 40, 42), ('hamlet_act1_scene1_q3', 'hamlet_act1_scene1', 'comprehension', 'What does Horatio recount to explain why Denmark is arming for war?', ARRAY['Claudius has declared a war of succession against Norway.','Young Fortinbras is assembling men to reclaim lands his father lost to King Hamlet.','A Polish invasion is expected before spring.','The English king has refused to pay his long-standing tribute.']::TEXT[], 1, 15, 79, 107), ('hamlet_act1_scene1_q4', 'hamlet_act1_scene1', 'theme', 'What function do Horatio''s references to ''the mightiest Julius'' and the omens before his assassination serve?', ARRAY['They establish Hamlet''s Roman education.','They signal that the ghost is a political warning of coming catastrophe.','They suggest Horatio is a superstitious man whom we should not trust.','They foreshadow Hamlet''s own death by stabbing.']::TEXT[], 1, 20, 108, 120), ('hamlet_act1_scene1_q5', 'hamlet_act1_scene1', 'close_reading', 'Why does Marcellus describe the Christmas season as a time when ''no spirit dare stir abroad''?', ARRAY['It is a reference to the cold weather driving ghosts indoors.','He invokes a folk belief that the holiness of Christmas banishes wandering spirits.','He is quoting a Latin liturgy for the feast of the Nativity.','He is reassuring Horatio that the ghost cannot harm them in December.']::TEXT[], 1, 20, 158, 165);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act1_scene2_q1', 'hamlet_act1_scene2', 'close_reading', 'What rhetorical figure dominates Claudius''s opening speech (''mirth in funeral,'' ''dirge in marriage'')?', ARRAY['Anaphora: repeated phrases at the start of successive clauses.','Oxymoron: the pairing of contradictory terms.','Hyperbole: deliberate exaggeration for emphasis.','Chiasmus: a reversed repetition of words.']::TEXT[], 1, 20, 8, 12), ('hamlet_act1_scene2_q2', 'hamlet_act1_scene2', 'close_reading', 'In Hamlet''s first line — ''A little more than kin, and less than kind'' — what does the pun on ''kind'' convey?', ARRAY['Claudius is both overly familiar and insufficiently affectionate toward him.','Claudius is related by marriage but not by blood.','He means the word only in its modern sense of ''generous.''','He is contrasting Claudius to his father''s courteous manner.']::TEXT[], 0, 20, 64, 64), ('hamlet_act1_scene2_q3', 'hamlet_act1_scene2', 'comprehension', 'What does Claudius deny Hamlet at the end of their first exchange?', ARRAY['Permission to return to his university at Wittenberg.','The right to bear arms at court.','Access to the royal treasury for mourning expenses.','Admission to the Privy Council.']::TEXT[], 0, 10, 110, 118), ('hamlet_act1_scene2_q4', 'hamlet_act1_scene2', 'theme', 'What grievance drives Hamlet''s first soliloquy, ''O, that this too too solid flesh would melt''?', ARRAY['Claudius''s murder of his father, which he has just discovered.','His mother''s rapid remarriage to his uncle.','The threat of invasion from young Fortinbras.','Ophelia''s rejection of his love-letters.']::TEXT[], 1, 15, 129, 159), ('hamlet_act1_scene2_q5', 'hamlet_act1_scene2', 'inference', 'When Hamlet calls Claudius ''no more like my father / Than I to Hercules,'' what is he asserting?', ARRAY['That he resembles Hercules in strength.','That he, like Claudius, is unimposing — but the resemblance between the two kings is even weaker.','That Hercules is the proper Greek analog for his father.','That Claudius fancies himself a Hercules and must be disabused.']::TEXT[], 1, 20, 150, 152), ('hamlet_act1_scene2_q6', 'hamlet_act1_scene2', 'comprehension', 'What does Horatio tell Hamlet at the end of the scene?', ARRAY['That Claudius poisoned his father''s wine at a banquet.','That a figure resembling the late King has appeared on the watch platform at night.','That Ophelia has refused his gifts and letters.','That Fortinbras has crossed into Danish territory.']::TEXT[], 1, 10, 185, 235);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act1_scene3_q1', 'hamlet_act1_scene3', 'comprehension', 'What does Laertes warn Ophelia about before leaving for France?', ARRAY['The political danger of associating with Prince Hamlet.','Hamlet''s affections toward her, which he calls passing and unreliable.','The rumor that Polonius intends to send her to a convent.','That the King has designs of his own on her.']::TEXT[], 1, 10, 4, 44), ('hamlet_act1_scene3_q2', 'hamlet_act1_scene3', 'inference', 'When Ophelia tells Laertes to show her the way to heaven while he himself treads the ''primrose path of dalliance,'' what is she doing?', ARRAY['Accepting his advice and resolving to live more chastely.','Pointing out the hypocrisy of a brother who polices her conduct while indulging his own.','Mocking him as a hypocritical Puritan.','Confessing that she has already compromised her virtue.']::TEXT[], 1, 20, 46, 51), ('hamlet_act1_scene3_q3', 'hamlet_act1_scene3', 'close_reading', 'Which of these is NOT a precept Polonius delivers to Laertes in this scene?', ARRAY['''Give every man thy ear, but few thy voice.''','''Neither a borrower nor a lender be.''','''This above all: to thine own self be true.''','''Trust not a friend who praises you too much.''']::TEXT[], 3, 15, 60, 82), ('hamlet_act1_scene3_q4', 'hamlet_act1_scene3', 'theme', 'What does Polonius''s phrase ''springes to catch woodcocks'' imply about Hamlet''s expressions of love?', ARRAY['That they are genuine declarations suitable for marriage.','That they are traps set for a gullible victim.','That they are harmless jests among courtiers.','That they are Latin exercises Hamlet is practicing.']::TEXT[], 1, 20, 115, 118), ('hamlet_act1_scene3_q5', 'hamlet_act1_scene3', 'comprehension', 'What does Polonius order Ophelia to do at the end of the scene?', ARRAY['Return all of Hamlet''s letters and refuse to see him.','Report any meetings with Hamlet directly to the King.','Stop speaking with Hamlet and not give him any of her time.','Accept Hamlet''s proposals but on her father''s terms.']::TEXT[], 2, 10, 131, 135);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act1_scene4_q1', 'hamlet_act1_scene4', 'close_reading', 'What is Hamlet criticizing when he describes the ''heavy-headed revel east and west''?', ARRAY['The peasant classes'' drunkenness at harvest festivals.','The Danish custom of heavy drinking during royal celebrations.','Claudius''s personal habit of drugging his wine.','The soldiers on the night watch, who he fears are drunk.']::TEXT[], 1, 15, 8, 22), ('hamlet_act1_scene4_q2', 'hamlet_act1_scene4', 'theme', 'What is Hamlet arguing in the passage about the ''vicious mole of nature'' and the ''dram of eale''?', ARRAY['That no one can overcome their inherited flaws.','That a single defect can undo the virtues of an otherwise noble character.','That illness is contagious and must be quarantined.','That the Danish court is corrupt beyond redemption.']::TEXT[], 1, 20, 24, 40), ('hamlet_act1_scene4_q3', 'hamlet_act1_scene4', 'inference', 'Why does Hamlet address the ghost as both ''spirit of health'' and ''goblin damn''d''?', ARRAY['He believes the ghost is two different spirits at once.','He is preserving theological uncertainty about whether the ghost is holy or diabolical.','He is mocking the ghost to test its patience.','He is quoting a Latin incantation Horatio taught him.']::TEXT[], 1, 20, 43, 46), ('hamlet_act1_scene4_q4', 'hamlet_act1_scene4', 'comprehension', 'What do Horatio and Marcellus fear when the ghost beckons Hamlet away?', ARRAY['That the ghost will reveal Hamlet''s secrets to the King.','That the spirit may tempt Hamlet to leap from the cliff or drive him mad.','That Hamlet will be delayed from his studies.','That Claudius''s spies are watching and will report them.']::TEXT[], 1, 15, 69, 82), ('hamlet_act1_scene4_q5', 'hamlet_act1_scene4', 'close_reading', 'Marcellus''s closing line — ''Something is rotten in the state of Denmark'' — uses which metaphor?', ARRAY['A legal metaphor: corruption as a miscarriage of justice.','An organic metaphor: hidden decay within a living body politic.','A military metaphor: an enemy within the walls.','A theological metaphor: damnation seeping into the soul.']::TEXT[], 1, 20, 89, 90);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act1_scene5_q1', 'hamlet_act1_scene5', 'comprehension', 'According to the ghost, how did he die?', ARRAY['A serpent bit him while he slept in his orchard — the official story.','Claudius poured poison into his ear while he slept in his orchard.','He was stabbed in the night by an unknown assailant.','He died of an illness Claudius had secretly encouraged.']::TEXT[], 1, 10, 35, 80), ('hamlet_act1_scene5_q2', 'hamlet_act1_scene5', 'historical', 'The ghost''s description of being ''confined to fast in fires'' most precisely places him in which theological location?', ARRAY['Hell, the Catholic place of damnation.','Purgatory, the Catholic place of purification — officially abolished in the Church of England.','Limbo, the place of unbaptized souls.','Sheol, the Old Testament place of the dead.']::TEXT[], 1, 25, 9, 22), ('hamlet_act1_scene5_q3', 'hamlet_act1_scene5', 'inference', 'What specific constraint does the ghost place on how Hamlet should carry out his revenge?', ARRAY['He must do it publicly before the whole court.','He must not harm his mother and must not corrupt his own mind in the process.','He must do it within the month or the ghost will return to haunt him.','He must do it without the help of any friends.']::TEXT[], 1, 20, 82, 92), ('hamlet_act1_scene5_q4', 'hamlet_act1_scene5', 'close_reading', 'What does Hamlet mean by reaching for his ''tables'' immediately after the ghost''s departure?', ARRAY['He is about to write a letter to Ophelia.','He is taking out a small writing-tablet to record his observations — a scholar''s instinct in a moment of tragedy.','He is preparing to cast a spell to summon the ghost back.','He is setting up a table for Horatio''s interrogation.']::TEXT[], 1, 20, 107, 110), ('hamlet_act1_scene5_q5', 'hamlet_act1_scene5', 'theme', 'What strategy does Hamlet announce he will adopt for the rest of the play?', ARRAY['Open rebellion against the King.','Secret flight to Wittenberg to gather allies.','An ''antic disposition'' — a put-on madness — to disguise his intentions.','Waiting silently until the ghost returns with further instructions.']::TEXT[], 2, 15, 162, 170), ('hamlet_act1_scene5_q6', 'hamlet_act1_scene5', 'close_reading', 'What does the image ''the time is out of joint'' suggest?', ARRAY['That winter has come unseasonably early.','That time is dislocated like a bone out of its socket, and Hamlet is called to reset it.','That Hamlet''s wristwatch has broken.','That Denmark has abandoned the Christian calendar.']::TEXT[], 1, 20, 174, 175);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act2_scene1_q1', 'hamlet_act2_scene1', 'comprehension', 'What does Polonius instruct Reynaldo to do in Paris?', ARRAY['Deliver a sealed letter directly to Laertes.','Spread rumors about Laertes''s misbehavior to see who confirms them.','Confront Laertes about his debts and drinking.','Arrange for Laertes to return home at once.']::TEXT[], 1, 15, 10, 45), ('hamlet_act2_scene1_q2', 'hamlet_act2_scene1', 'close_reading', 'What does Polonius mean by ''indirections find directions out''?', ARRAY['Take the long road so you are not followed.','Roundabout methods uncover straight truths.','Lies always reveal themselves in time.','Young men go astray before they find their path.']::TEXT[], 1, 20, 63, 66), ('hamlet_act2_scene1_q3', 'hamlet_act2_scene1', 'comprehension', 'How does Ophelia describe Hamlet''s appearance when he visited her closet?', ARRAY['Elegantly dressed and composed, reciting a love poem.','Disheveled — doublet unbraced, stockings fouled and fallen, pale as his shirt, staring at her silently.','Armed and furious, accusing her of betrayal.','Laughing wildly and throwing letters into the fire.']::TEXT[], 1, 10, 82, 100), ('hamlet_act2_scene1_q4', 'hamlet_act2_scene1', 'inference', 'What does Polonius conclude is the cause of Hamlet''s distress?', ARRAY['Political anxiety about the Norwegian threat.','The ''very ecstasy of love'' — Ophelia''s refusal to see him has driven him mad.','Grief for his father that has festered into melancholy.','Fear of being deposed by Claudius.']::TEXT[], 1, 15, 105, 110), ('hamlet_act2_scene1_q5', 'hamlet_act2_scene1', 'theme', 'What is the dramatic function of this scene?', ARRAY['To establish Reynaldo as a major character in later acts.','To introduce a new subplot about Laertes''s education.','To set up Polonius''s erroneous diagnosis, which will drive the eavesdropping of Act 3.','To provide comic relief before the play''s first soliloquy.']::TEXT[], 2, 20, 105, 121);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act2_scene2_q1', 'hamlet_act2_scene2', 'comprehension', 'Why do the King and Queen summon Rosencrantz and Guildenstern?', ARRAY['To serve as witnesses at Hamlet''s trial.','To befriend Hamlet and discover the cause of his madness.','To deliver a diplomatic letter to Wittenberg.','To serve as guards during the ambassadors'' visit.']::TEXT[], 1, 10, 1, 40), ('hamlet_act2_scene2_q2', 'hamlet_act2_scene2', 'inference', 'When Polonius says ''brevity is the soul of wit,'' what is the dramatic irony?', ARRAY['He is speaking Latin, though the audience hears English.','He delivers the maxim in the most long-winded speech in the play.','He is quoting Hamlet''s private letter without permission.','He is teaching Ophelia how to speak concisely to the King.']::TEXT[], 1, 20, 88, 110), ('hamlet_act2_scene2_q3', 'hamlet_act2_scene2', 'close_reading', 'How does Hamlet''s speech ''What a piece of work is a man'' conclude?', ARRAY['In an ecstatic affirmation of human nobility.','By collapsing into the question ''what is this quintessence of dust?'' — undercutting the praise.','With a prayer that God restore Denmark''s peace.','With a vow to kill Claudius before nightfall.']::TEXT[], 1, 25, 264, 270), ('hamlet_act2_scene2_q4', 'hamlet_act2_scene2', 'theme', 'What troubles Hamlet about the player''s speech on Hecuba?', ARRAY['That the actor has misquoted the Aeneid.','That a hired player can summon real tears for a fiction, while he has summoned none for his real father''s murder.','That the speech contains unflattering references to Claudius.','That the player refuses to join Hamlet''s plot against the King.']::TEXT[], 1, 20, 496, 520), ('hamlet_act2_scene2_q5', 'hamlet_act2_scene2', 'comprehension', 'What concrete plan does Hamlet form by the end of the scene?', ARRAY['To stab Claudius at the next banquet.','To stage a play that re-enacts his father''s murder and observe Claudius''s reaction.','To flee to England with Horatio.','To confront Gertrude in her bedchamber.']::TEXT[], 1, 15, 540, 554), ('hamlet_act2_scene2_q6', 'hamlet_act2_scene2', 'inference', 'Why does Hamlet admit he must first test the ghost''s testimony through the play?', ARRAY['Because Horatio demanded evidence before joining the plot.','Because the ghost ''may be the devil'' who ''hath power to assume a pleasing shape'' to damn him.','Because Claudius has sworn an oath of innocence in public.','Because the Queen has forbidden him to act without proof.']::TEXT[], 1, 20, 545, 550);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act3_scene1_q1', 'hamlet_act3_scene1', 'comprehension', 'In the opening of the scene, what do Rosencrantz and Guildenstern report about their conversation with Hamlet?', ARRAY['Hamlet confessed the cause of his madness but asked them to keep it secret.','Hamlet admits he feels disturbed but refuses to say why.','Hamlet denies any madness and accuses the King of paranoia.','Hamlet spoke lucidly about politics but avoided all personal questions.']::TEXT[], 1, 10, 5, 15), ('hamlet_act3_scene1_q2', 'hamlet_act3_scene1', 'inference', 'Why do Claudius and Polonius arrange for Ophelia to ''accidentally'' meet Hamlet in this scene?', ARRAY['To give Ophelia a chance to comfort him.','To test whether thwarted love is the cause of Hamlet''s madness.','To distract Hamlet while the King plans the England voyage.','To provoke Hamlet into attacking Polonius.']::TEXT[], 1, 15, 32, 47), ('hamlet_act3_scene1_q3', 'hamlet_act3_scene1', 'close_reading', 'In the line ''To be, or not to be, that is the question,'' what best describes the grammatical structure of Hamlet''s opening question?', ARRAY['A direct question about whether Hamlet should commit suicide.','Two infinitives placed in opposition, abstracting the question beyond any single speaker.','An imperative command to himself to choose action over inaction.','A conditional statement waiting for a ''then'' clause.']::TEXT[], 1, 25, 56, 56), ('hamlet_act3_scene1_q4', 'hamlet_act3_scene1', 'theme', 'What is the central obstacle to action that Hamlet identifies in the soliloquy?', ARRAY['The fear of the unknown that lies beyond death.','His uncertainty about whether the Ghost was honest.','His mother''s remarriage to Claudius.','His inability to find a weapon suitable for the deed.']::TEXT[], 0, 20, 76, 86), ('hamlet_act3_scene1_q5', 'hamlet_act3_scene1', 'close_reading', 'What does Hamlet mean by ''the native hue of resolution / Is sicklied o''er with the pale cast of thought''?', ARRAY['Illness makes us indecisive.','The healthy color of determination is made pale and sickly by over-reflection.','Cold weather drains us of our courage.','Grief turns our complexion pale, showing our sorrow.']::TEXT[], 1, 20, 82, 83), ('hamlet_act3_scene1_q6', 'hamlet_act3_scene1', 'inference', 'When does Hamlet most likely realize that he is being overheard by Polonius and Claudius?', ARRAY['From the very start of the scene, which is why he pretends to be mad.','When he asks Ophelia ''Where''s your father?'' — her lie reveals she is a pawn.','Only at the end, when he hears the King and Polonius re-enter.','He never realizes; his cruelty to Ophelia is entirely sincere.']::TEXT[], 1, 20, 120, 121), ('hamlet_act3_scene1_q7', 'hamlet_act3_scene1', 'theme', 'What is the dramatic function of Ophelia''s lament (''O, what a noble mind is here o''erthrown'')?', ARRAY['To express her personal relief that Hamlet no longer loves her.','To crystallize, in concrete images, what Hamlet''s abstract soliloquy could not say about his own ruin.','To warn the King that Hamlet is genuinely dangerous.','To signal to the audience that Ophelia has begun her own descent into madness.']::TEXT[], 1, 20, 133, 145), ('hamlet_act3_scene1_q8', 'hamlet_act3_scene1', 'comprehension', 'What does Claudius decide to do with Hamlet at the end of the scene?', ARRAY['Have him imprisoned in the castle under guard.','Send him to England on the pretext of collecting neglected tribute.','Force him to marry Ophelia immediately.','Banish him permanently from Denmark.']::TEXT[], 1, 10, 151, 158);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act3_scene2_q1', 'hamlet_act3_scene2', 'close_reading', 'What style of acting does Hamlet criticize in his advice to the players?', ARRAY['The naturalistic whisper of boy actors in girls'' roles.','The bombastic, air-slashing ranting of actors who ''out-herod Herod.''','The monotone declamation of foreign troupes.','The mumbling of country actors who cannot be heard in the galleries.']::TEXT[], 1, 20, 4, 17), ('hamlet_act3_scene2_q2', 'hamlet_act3_scene2', 'theme', 'What quality in Horatio does Hamlet admire most?', ARRAY['His physical courage in battle.','His calm imperviousness to fortune — he is ''not passion''s slave.''','His knowledge of Latin and Greek.','His connections at the English court.']::TEXT[], 1, 20, 55, 75), ('hamlet_act3_scene2_q3', 'hamlet_act3_scene2', 'comprehension', 'Why does Hamlet arrange the performance of ''The Murder of Gonzago''?', ARRAY['To entertain the King at a festival.','To re-enact his father''s murder and observe Claudius for signs of guilt.','To impress Ophelia with his poetic skill.','To raise money for the traveling players.']::TEXT[], 1, 10, 70, 85), ('hamlet_act3_scene2_q4', 'hamlet_act3_scene2', 'inference', 'What does Claudius''s reaction to the play''s poisoning scene confirm?', ARRAY['That the ghost was a malign spirit deceiving Hamlet.','That the ghost''s account of the murder was accurate.','That Claudius is unable to tolerate violent drama.','That Gertrude was complicit in the murder.']::TEXT[], 1, 15, 260, 285), ('hamlet_act3_scene2_q5', 'hamlet_act3_scene2', 'close_reading', 'In the recorder scene, what is Hamlet''s accusation against Rosencrantz and Guildenstern?', ARRAY['That they have poisoned the King''s wine.','That they imagine they can play upon him though they cannot even play a simple pipe.','That they plan to betray him to the English king.','That they have stolen his signet ring.']::TEXT[], 1, 20, 340, 355), ('hamlet_act3_scene2_q6', 'hamlet_act3_scene2', 'theme', 'What is the dramatic function of the play-within-the-play?', ARRAY['To give the audience a break from Hamlet''s soliloquies.','To convert a private testimony (the ghost''s) into public theatrical evidence Claudius cannot evade.','To introduce the character of Lucianus, who returns in Act 5.','To allow Hamlet to audition for a career as a playwright.']::TEXT[], 1, 25, 236, 290);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act3_scene3_q1', 'hamlet_act3_scene3', 'comprehension', 'What does Claudius instruct Rosencrantz and Guildenstern to prepare for?', ARRAY['A banquet for the visiting ambassadors.','A speedy voyage to escort Hamlet to England.','The coronation of Prince Hamlet as heir.','A military campaign against Fortinbras.']::TEXT[], 1, 10, 1, 30), ('hamlet_act3_scene3_q2', 'hamlet_act3_scene3', 'theme', 'Why can Claudius not repent fully in his soliloquy?', ARRAY['Because he believes God will forgive him regardless.','Because he refuses to give up the crown, the queen, and the ambition the murder secured.','Because he does not believe in Christianity.','Because he is convinced Hamlet will kill him anyway.']::TEXT[], 1, 20, 36, 72), ('hamlet_act3_scene3_q3', 'hamlet_act3_scene3', 'close_reading', 'What biblical ''primal eldest curse'' does Claudius invoke to describe his crime?', ARRAY['The fall of Adam and Eve.','The flood in the days of Noah.','Cain''s murder of his brother Abel.','Judas''s betrayal of Christ.']::TEXT[], 2, 15, 42, 43), ('hamlet_act3_scene3_q4', 'hamlet_act3_scene3', 'inference', 'Why does Hamlet decide not to kill Claudius at prayer?', ARRAY['Because he fears divine punishment for killing in a chapel.','Because killing Claudius in a state of grace would send his soul to heaven — a reward, not a revenge.','Because he recognizes his sword is not sharp enough for armor.','Because he has promised Gertrude he will not act that night.']::TEXT[], 1, 20, 73, 96), ('hamlet_act3_scene3_q5', 'hamlet_act3_scene3', 'theme', 'What is the dramatic irony of Claudius''s closing couplet, ''My words fly up, my thoughts remain below''?', ARRAY['Hamlet has just spared Claudius on the assumption that his prayer has reached heaven — but the audience knows it has not.','Claudius is revealing his plan to have Hamlet killed in England.','The audience is informed that Gertrude has overheard the prayer.','Claudius is silently recanting his plan to send Hamlet away.']::TEXT[], 0, 25, 97, 98);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act3_scene4_q1', 'hamlet_act3_scene4', 'comprehension', 'Who is killed when Hamlet stabs through the tapestry?', ARRAY['Claudius, disguised as a courtier.','Polonius, who had hidden there to eavesdrop.','Rosencrantz, sent by the King.','A palace guard following orders.']::TEXT[], 1, 10, 22, 30), ('hamlet_act3_scene4_q2', 'hamlet_act3_scene4', 'inference', 'Why does Hamlet''s killing of Polonius function as a structural pivot for the play?', ARRAY['It removes Hamlet''s chief obstacle to the throne.','It triggers Laertes''s revenge plot, Ophelia''s madness, and Hamlet''s exile.','It convinces Claudius to repent.','It ends the war with Norway.']::TEXT[], 1, 25, 22, 35), ('hamlet_act3_scene4_q3', 'hamlet_act3_scene4', 'close_reading', 'How does Hamlet describe his father when holding the two portraits?', ARRAY['A ''pajock'' with the mind of a fool.','''Hyperion''s curls, the front of Jove himself, an eye like Mars.''','''A king of shreds and patches.''','A warrior whose glory was bought with his subjects'' blood.']::TEXT[], 1, 15, 55, 62), ('hamlet_act3_scene4_q4', 'hamlet_act3_scene4', 'theme', 'What does it signify that Gertrude cannot see the ghost?', ARRAY['The ghost has died a second time and disappeared.','It is genuinely unclear: either she lacks Hamlet''s initiation into the secret, or the ghost is his hallucination.','The ghost is refusing to show himself to her out of anger.','The stage lights are dimmed to signal a dream.']::TEXT[], 1, 25, 102, 140), ('hamlet_act3_scene4_q5', 'hamlet_act3_scene4', 'comprehension', 'What does Hamlet reveal to Gertrude at the end of the scene?', ARRAY['That Claudius murdered his father.','That he knows he is being sent to England and suspects a plot, and that he will ''hoist the engineer with his own petard.''','That he has forgiven Ophelia.','That the ghost has commanded him to spare Claudius.']::TEXT[], 1, 15, 194, 205), ('hamlet_act3_scene4_q6', 'hamlet_act3_scene4', 'close_reading', 'What does Hamlet mean by ''I must be cruel only to be kind''?', ARRAY['The harshness he shows Gertrude is meant to produce her moral awakening.','He will be cruel to his enemies to reward his friends.','A proverbial lament that life rewards cruelty over kindness.','An apology for his treatment of Ophelia.']::TEXT[], 0, 20, 172, 173);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene1_q1', 'hamlet_act4_scene1', 'inference', 'What does Gertrude withhold from Claudius in her report of the closet scene?', ARRAY['That Polonius was killed.','That Hamlet''s madness is feigned, and that he has accused Claudius of murdering King Hamlet.','That Hamlet saw the ghost during their conversation.','That Ophelia is wandering mad in the castle.']::TEXT[], 1, 25, 5, 16), ('hamlet_act4_scene1_q2', 'hamlet_act4_scene1', 'comprehension', 'What is Claudius''s chief concern after learning of Polonius''s death?', ARRAY['Punishing Hamlet with immediate execution.','Concealing the crime and accelerating Hamlet''s voyage to England.','Offering consolation to Laertes in France.','Consulting the priests about a proper burial.']::TEXT[], 1, 15, 15, 38), ('hamlet_act4_scene1_q3', 'hamlet_act4_scene1', 'theme', 'What does Gertrude''s phrase ''Mad as the sea and wind'' accomplish in context?', ARRAY['It diagnoses Hamlet as genuinely deranged, reinforcing Polonius''s earlier theory.','It is a poetic evasion that protects Hamlet while giving Claudius a plausible story.','It signals to Claudius that Gertrude has lost faith in her son.','It quotes a proverb about the dangers of sea travel.']::TEXT[], 1, 20, 8, 10);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene2_q1', 'hamlet_act4_scene2', 'close_reading', 'What does Hamlet mean by calling Rosencrantz a ''sponge''?', ARRAY['That he dries up quickly under pressure.','That he absorbs the King''s favor and will be squeezed dry when no longer useful.','That he is soft and easily destroyed.','That he is dishonorable like an old wet rag.']::TEXT[], 1, 20, 11, 22), ('hamlet_act4_scene2_q2', 'hamlet_act4_scene2', 'inference', 'What is Hamlet''s state in this scene?', ARRAY['Truly mad and unable to speak coherently.','Feigning madness while using riddles to insult his captors and elude their questions.','Weeping inconsolably over Polonius''s death.','Preparing to surrender himself to the King''s justice.']::TEXT[], 1, 15, 5, 29), ('hamlet_act4_scene2_q3', 'hamlet_act4_scene2', 'theme', 'What does the refrain ''Hide fox, and all after'' invoke?', ARRAY['A hunting call used by Danish nobility.','A children''s game of hide-and-seek, casting Hamlet as the fox being chased.','A nursery rhyme about Reynard the Fox.','A proverb about cowardice.']::TEXT[], 1, 15, 28, 29);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene3_q1', 'hamlet_act4_scene3', 'close_reading', 'What is Hamlet''s parable of the ''politic worms,'' the fisherman, and the fish meant to demonstrate?', ARRAY['That worms will inherit the earth.','That death levels kings and beggars: a monarch may end in a beggar''s belly.','That fishing is a noble art.','That Denmark is being eaten away by corrupt politicians.']::TEXT[], 1, 20, 19, 28), ('hamlet_act4_scene3_q2', 'hamlet_act4_scene3', 'comprehension', 'Where does Hamlet finally say Polonius may be found?', ARRAY['In the castle cellars, preserved in salt.','In heaven — and if the messenger does not find him there, he should check hell.','Buried beneath the orchard where old Hamlet died.','In the chapel where Claudius prays.']::TEXT[], 1, 10, 30, 36), ('hamlet_act4_scene3_q3', 'hamlet_act4_scene3', 'inference', 'What does Claudius''s soliloquy at the end of the scene reveal?', ARRAY['That he has repented of his crime and will confess.','That the sealed commission to England instructs the English king to execute Hamlet at once.','That Gertrude has joined the plot against Hamlet.','That Polonius is not dead but hiding.']::TEXT[], 1, 20, 55, 70), ('hamlet_act4_scene3_q4', 'hamlet_act4_scene3', 'theme', 'What is the function of the comparison Claudius makes between Denmark''s claim on England and a ''hectic'' fever?', ARRAY['It suggests that English politics are feverishly disordered.','It frames Hamlet''s execution as a kind of political medicine — a treatment for a raging illness within Claudius himself.','It is a joke at the expense of the English king''s cowardice.','It indicates that Hamlet has contracted a fever in the voyage.']::TEXT[], 1, 20, 66, 70);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene4_q1', 'hamlet_act4_scene4', 'comprehension', 'Where is Fortinbras leading his army in this scene?', ARRAY['To reclaim his father''s lost lands in Denmark.','To fight the Poles over a worthless patch of ground.','To invade England with the support of Denmark.','To assist the King of Norway against a rebellion.']::TEXT[], 1, 10, 14, 27), ('hamlet_act4_scene4_q2', 'hamlet_act4_scene4', 'inference', 'What does the Captain admit about the campaign?', ARRAY['That the Poles will surrender without a fight.','That the land is not worth five ducats to farm, yet thousands will die for it.','That Fortinbras is a secret agent of Claudius.','That the soldiers will mutiny before reaching Poland.']::TEXT[], 1, 15, 16, 23), ('hamlet_act4_scene4_q3', 'hamlet_act4_scene4', 'theme', 'What does Hamlet''s final soliloquy contrast his own behavior with?', ARRAY['The courage of Fortinbras, who acts decisively for mere honor while Hamlet delays.','The piety of Claudius, whose prayers Hamlet cannot match.','The loyalty of Rosencrantz and Guildenstern.','The cunning of Polonius, whose methods he admires.']::TEXT[], 0, 20, 44, 60), ('hamlet_act4_scene4_q4', 'hamlet_act4_scene4', 'close_reading', 'What does Hamlet mean by ''Rightly to be great / Is not to stir without great argument, / But greatly to find quarrel in a straw''?', ARRAY['True greatness avoids all conflict.','True greatness can turn a trifle into a cause of honor when honor is at stake.','Nobles should not quarrel over farmland.','Ambition is always a petty motive.']::TEXT[], 1, 25, 53, 56), ('hamlet_act4_scene4_q5', 'hamlet_act4_scene4', 'comprehension', 'What vow does Hamlet make at the end of the soliloquy?', ARRAY['To return to Wittenberg and pursue his studies.','That his thoughts, from this moment, must be bloody or worthless.','To spare Claudius for his mother''s sake.','To reveal all to Horatio.']::TEXT[], 1, 15, 63, 66);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene5_q1', 'hamlet_act4_scene5', 'comprehension', 'What condition does Ophelia demonstrate in her first appearance here?', ARRAY['She is composed and demands justice for her father.','She is mad, singing fragments of old songs about lost love and dead fathers.','She is weeping silently and refuses to speak.','She has joined Laertes''s armed uprising.']::TEXT[], 1, 10, 17, 45), ('hamlet_act4_scene5_q2', 'hamlet_act4_scene5', 'inference', 'What does the Valentine''s Day song suggest about Ophelia''s distress?', ARRAY['That she has taken up a new religion.','That sexual betrayal (by a lover who promised marriage then refused) is among the griefs driving her madness.','That she misses her time at court festivals.','That Polonius promised her marriage to a stranger.']::TEXT[], 1, 20, 47, 65), ('hamlet_act4_scene5_q3', 'hamlet_act4_scene5', 'comprehension', 'What does Laertes do when he returns to Denmark?', ARRAY['He presents himself humbly to Claudius for counsel.','He bursts in with a mob of followers shouting ''Laertes shall be king,'' ready to kill the King.','He searches the castle for Polonius''s body.','He challenges Hamlet to a duel by proxy.']::TEXT[], 1, 15, 95, 115), ('hamlet_act4_scene5_q4', 'hamlet_act4_scene5', 'close_reading', 'Which flower does Ophelia associate with ''thoughts''?', ARRAY['Rosemary','Pansies','Fennel','Rue']::TEXT[], 1, 15, 177, 180), ('hamlet_act4_scene5_q5', 'hamlet_act4_scene5', 'theme', 'What does the contrast between Laertes''s immediate revenge and Hamlet''s delay suggest?', ARRAY['That Laertes is the morally superior brother.','That Shakespeare is demonstrating the correct way to avenge a father.','That neither speed nor delay is safe — both revengers will be destroyed.','That Hamlet''s philosophy has paralyzed him while Laertes acts freely.']::TEXT[], 2, 25, 115, 145), ('hamlet_act4_scene5_q6', 'hamlet_act4_scene5', 'inference', 'Why are the violets Ophelia mentions ''withered''?', ARRAY['The season is late in summer and they have died.','They withered when her father died — faithfulness has died with Polonius.','A servant has neglected to water them.','She is referring to a plant disease in Denmark.']::TEXT[], 1, 20, 185, 188);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene6_q1', 'hamlet_act4_scene6', 'comprehension', 'How did Hamlet escape the voyage to England?', ARRAY['A storm forced the ship back to Denmark.','He swam ashore when the ship anchored near the coast.','Pirates attacked the ship; Hamlet boarded their vessel in the fight and was returned to Denmark.','He bribed Rosencrantz and Guildenstern to turn the ship around.']::TEXT[], 2, 15, 14, 25), ('hamlet_act4_scene6_q2', 'hamlet_act4_scene6', 'close_reading', 'What does Hamlet''s phrase ''thieves of mercy'' express?', ARRAY['Thieves of pity who stole his valuables.','The pirates who spared his life and returned him home — honorable behavior from dishonorable men.','Merciful thieves who work only by night.','A metaphor for Claudius and his courtiers, who steal justice from the kingdom.']::TEXT[], 1, 20, 22, 26), ('hamlet_act4_scene6_q3', 'hamlet_act4_scene6', 'inference', 'What does Hamlet ask Horatio to do in the letter?', ARRAY['Bring his weapons and armor immediately.','Deliver a letter to the King and bring him to Hamlet''s location.','Flee to Wittenberg and await further instructions.','Tell Ophelia that Hamlet is alive.']::TEXT[], 1, 15, 12, 27);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act4_scene7_q1', 'hamlet_act4_scene7', 'inference', 'How does Claudius convert Laertes''s revenge into his own instrument?', ARRAY['By offering Laertes the throne.','By leading Laertes to propose a treacherous fencing match that Claudius in fact designed.','By forging a letter that incriminates Hamlet.','By locking Laertes in a dungeon until he agrees.']::TEXT[], 1, 25, 60, 140), ('hamlet_act4_scene7_q2', 'hamlet_act4_scene7', 'comprehension', 'What does Laertes propose to do to the rapier for the duel?', ARRAY['Polish it with a secret rust remover.','Anoint its tip with a poison bought from a mountebank, so that even a scratch will kill.','Weigh it down with lead to favor him in the strike.','Have it blessed by a priest so God will favor his cause.']::TEXT[], 1, 20, 118, 128), ('hamlet_act4_scene7_q3', 'hamlet_act4_scene7', 'comprehension', 'What backup plan does Claudius propose if Laertes''s poisoned rapier fails?', ARRAY['A second swordsman hidden in the gallery.','A poisoned cup of wine for Hamlet to drink ''for the nonce.''','A carriage accident on the return from the duel.','A hidden pistol behind the arras.']::TEXT[], 1, 20, 128, 138), ('hamlet_act4_scene7_q4', 'hamlet_act4_scene7', 'close_reading', 'What peculiar aspect of Gertrude''s speech reporting Ophelia''s drowning has puzzled critics?', ARRAY['It is spoken in prose rather than verse.','She describes the death in precise, pastoral detail as if she had witnessed it, though she cannot have been present.','It contains anachronistic references to modern flowers.','It is delivered in Latin.']::TEXT[], 1, 20, 140, 162), ('hamlet_act4_scene7_q5', 'hamlet_act4_scene7', 'theme', 'What does the metaphor of a ''tree'' in Gertrude''s speech — the ''envious sliver'' that breaks — suggest about Ophelia''s death?', ARRAY['That the death is partly a natural accident and not clearly a suicide.','That Ophelia was deliberately pushed by an unseen assailant.','That the tree itself is a metaphor for King Hamlet''s spirit.','That the willow carries biblical weight as a symbol of mourning.']::TEXT[], 0, 25, 150, 160);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act5_scene1_q1', 'hamlet_act5_scene1', 'historical', 'What do the gravediggers debate at the start of the scene?', ARRAY['Whether to dig Polonius''s grave or Ophelia''s first.','Whether Ophelia deserves Christian burial rites given her apparent suicide.','How much they should charge the King for digging.','Whether a new cemetery should be opened outside Elsinore.']::TEXT[], 1, 15, 1, 30), ('hamlet_act5_scene1_q2', 'hamlet_act5_scene1', 'comprehension', 'Whose skull does Hamlet particularly remember and mourn?', ARRAY['His father''s.','Polonius''s.','Yorick''s, the court jester.','A lawyer unnamed.']::TEXT[], 2, 10, 160, 175), ('hamlet_act5_scene1_q3', 'hamlet_act5_scene1', 'theme', 'How does Hamlet''s meditation on mortality in the graveyard differ from his ''To be, or not to be'' soliloquy?', ARRAY['It is more abstract and philosophical than the soliloquy.','It is concrete and personal — particular skulls remembered as particular persons — rather than abstract.','It is delivered in Latin.','It concludes that death is to be welcomed without reservation.']::TEXT[], 1, 25, 55, 175), ('hamlet_act5_scene1_q4', 'hamlet_act5_scene1', 'close_reading', 'What does Hamlet''s tracing of Alexander''s dust through ''loam'' and a ''beer-barrel'' argue?', ARRAY['That great men should be embalmed rather than buried.','That even the noblest dust ends up stopping a bung-hole — a radical leveling of human greatness.','That beer is a fitter drink for a king than wine.','That Alexander was buried in Denmark.']::TEXT[], 1, 25, 186, 208), ('hamlet_act5_scene1_q5', 'hamlet_act5_scene1', 'inference', 'Why does Hamlet leap into Ophelia''s grave after Laertes?', ARRAY['To rescue a sword he has dropped.','To insist — publicly and passionately — that he loved Ophelia more than Laertes could.','To prevent the priest from finishing the curtailed rites.','To attack Claudius, who is standing at the graveside.']::TEXT[], 1, 20, 235, 260), ('hamlet_act5_scene1_q6', 'hamlet_act5_scene1', 'comprehension', 'What does Hamlet declare about his love for Ophelia at the graveside?', ARRAY['That he never loved her and all his letters were pretense.','That forty thousand brothers could not have loved her as he did.','That he will follow her into death immediately.','That he forgives her for rejecting his suit.']::TEXT[], 1, 15, 247, 253);
INSERT INTO trials (id, section_id, kind, prompt, options, answer_index, wisdom_reward, anchor_line_start, anchor_line_end) VALUES ('hamlet_act5_scene2_q1', 'hamlet_act5_scene2', 'comprehension', 'What does Hamlet discover when he unseals the commission on the ship?', ARRAY['Claudius''s confession of the murder.','An order to the King of England to execute Hamlet on arrival.','A ransom demand for his release.','A letter of abdication in Hamlet''s favor.']::TEXT[], 1, 10, 15, 25), ('hamlet_act5_scene2_q2', 'hamlet_act5_scene2', 'theme', 'What does Hamlet mean by ''There''s a divinity that shapes our ends, rough-hew them how we will''?', ARRAY['That Hamlet has become a carpenter.','That a providential design operates beyond human attempts to shape events.','That fate is entirely indifferent to human action.','That only kings can shape history.']::TEXT[], 1, 25, 8, 12), ('hamlet_act5_scene2_q3', 'hamlet_act5_scene2', 'close_reading', 'What biblical passage does ''There''s a special providence in the fall of a sparrow'' echo?', ARRAY['The Sermon on the Mount (Matthew 5).','Jesus''s instruction to the apostles — Matthew 10:29 (''one sparrow shall not fall on the ground without your Father'').','Psalm 23 (''The Lord is my shepherd'').','The book of Job.']::TEXT[], 1, 25, 208, 212), ('hamlet_act5_scene2_q4', 'hamlet_act5_scene2', 'inference', 'How does Gertrude die?', ARRAY['Laertes stabs her with the poisoned foil.','She drinks from the poisoned cup Claudius intended for Hamlet.','She collapses from grief.','Hamlet poisons her to punish her remarriage.']::TEXT[], 1, 15, 295, 312), ('hamlet_act5_scene2_q5', 'hamlet_act5_scene2', 'comprehension', 'How does Hamlet finally kill Claudius?', ARRAY['He stabs him with the poisoned foil and forces him to drink the poisoned cup.','He strangles him with his own crown''s circlet.','He has Horatio run him through with a sword.','He drowns him in a font.']::TEXT[], 0, 15, 315, 335), ('hamlet_act5_scene2_q6', 'hamlet_act5_scene2', 'theme', 'What does Hamlet ask Horatio to do after his death?', ARRAY['Flee Denmark immediately.','Live on to tell Hamlet''s story and report the truth aright.','Poison himself to accompany Hamlet.','Destroy the letter that proved Claudius''s guilt.']::TEXT[], 1, 15, 344, 351), ('hamlet_act5_scene2_q7', 'hamlet_act5_scene2', 'close_reading', 'What is the significance of Hamlet''s final words, ''The rest is silence''?', ARRAY['A literal request for quiet in the room.','An acknowledgment that what remains — of his story, of the afterlife, of himself — cannot be spoken.','A reference to a musical score.','A coded instruction to Horatio about a hidden document.']::TEXT[], 1, 20, 358, 358);
